window.NOTES_META = {"generatedAt": "2026-07-20 15:24", "bookCount": 416, "highlightCount": 1742, "ideaCount": 152};
window.NOTES = [{"id": "38088030", "title": "技术与文明：我们的时代和未来", "author": "张笑宇", "cover": "https://cdn.weread.qq.com/weread/cover/98/YueWen_38088030/s_YueWen_38088030.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=1db32d9072452d5e1dbf27c", "progress": 100, "finished": 1, "hlCount": 40, "ideaCount": 1, "highlights": [{"text": "还有那些沉溺于消费主义产品、虚拟娱乐和社交网络的人，对虚拟世界的狭小和偏隘一无所知，并且认为自己处在幸福之中，这样的人如果不是末人，还有谁是末人？", "chapter": "结语 从“铁笼状态”到“汇流模型”", "date": "2022-06-12", "color": null}, {"text": "我的建议是，如果你是技术型人才，不妨借鉴一下社会科学的视角；如果你更擅长人文社科领域，不妨试着关心一下技术上的“硬变量”。", "chapter": "结语 从“铁笼状态”到“汇流模型”", "date": "2022-06-12", "color": null}, {"text": "“跨域”能力的核心又是什么？——是认识技术与社会之间互动关系的能力。", "chapter": "结语 从“铁笼状态”到“汇流模型”", "date": "2022-06-12", "color": null}, {"text": "正如弗洛伊德在消费者时代开始前所指出的，没有像快乐状态这样的事情，只有当一个令人烦恼的需求得到满足的时候，我们才会有短暂的快乐，但事后的无聊感立即侵入。一旦欲求的理由消失，那么欲望对象也就失去诱惑力。事实证明，消费者市场比弗洛伊德所想象的还具有创造力。", "chapter": "第十一章 粮食与人口", "date": "2022-06-12", "color": null}, {"text": "齐格蒙德·鲍曼非常犀利地指出，“无聊”是技术进步后失业者的一种普遍心理状态，消费主义则宣称自己要解决“无聊”的精神状态，事实上，它却依赖“无聊”为生。", "chapter": "第十一章 粮食与人口", "date": "2022-06-12", "color": null}, {"text": "凯恩斯说，欧洲文明的危机，源于人口爆炸。德国、奥匈帝国和俄国的总人口在1914年达到2.68亿，这样密集增长的庞大人口会造就大量展开激烈竞争的无产阶级，一旦他们忍耐不住，就要从资本家手中夺取更多产品，其结果就是比第一次世界大战更激烈的战乱和动荡。因此，巴黎和会主张单方面惩罚德国根本无益于问题的解决。如果想要解决人口问题，唯一的道路就是繁荣和工业化，而其中的枢纽就是德国。因此，欧洲和平的关键在于德国的再工业化，而不是德国的去工业化。", "chapter": "第十一章 粮食与人口", "date": "2022-06-12", "color": null}, {"text": "小麦在大约九千年前就已经被人类驯化，或者说驯化了人类，其标志是麦穗不会破碎，从而像自然生长的植物一样令种子四处播撒。麦穗不会破碎，意味着小麦知道人类一定会来收割播种，从而将自己的繁衍过程放心地交给人类。", "chapter": "第十一章 粮食与人口", "date": "2022-06-12", "color": null}, {"text": "可以说，自核武器发明开始，人类就已经进入一场永无止境的危险旅途：一旦一个国家有可能掌握毁灭全人类文明的武器，为了制衡和避免它取得绝对优势，其他国家势必要赶上，这种武器也势必要“普及化”，然而经手它的人越多，人类本身被它毁灭的可能性就越大——无论这种武器是核弹、基因武器，还是人工智能武器。技术进步如同文明的毒品，为了避免马上被毁灭，文明不得不发展更强的自我毁灭能力。", "chapter": "第十章 钢丝上的人类", "date": "2022-06-12", "color": null}, {"text": "马克斯·韦伯曾经给过一个经典定义：国家就是一片土地上合法的暴力垄断者。", "chapter": "第十章 钢丝上的人类", "date": "2022-06-12", "color": null}, {"text": "第一次世界大战就像是上帝跟人类开了一个巨大而残酷的玩笑：铁路和工业化把数以千万计的士兵以前所未有的效率送上前线，然后机枪再以前所未有的效率杀死他们。", "chapter": "第九章 枪下亡魂", "date": "2022-06-11", "color": null}, {"text": "1884年，英国人马克沁（Hiram Maxim）发明了马克沁机枪，射速可达每分钟550—600发。", "chapter": "第九章 枪下亡魂", "date": "2022-06-11", "color": null}, {"text": "威权政府应运而生，极大地促进了这些技术的发展，这些技术又反过来促进了威权政府的能力。这个相互促进的过程会造成某种错觉，使威权政府误以为真正的成功经验就是它自己。如果这个威权政府还恰巧被军国主义化，那就更要命，因为被技术作用放大的军事冒险往往有瞬间毁掉一个国家的危险，可惜的是，领导国家的军国主义者们却往往并不自知。", "chapter": "第八章 铁轨上的霸权", "date": "2022-06-11", "color": null}, {"text": "德意志这个民族，确实更愿意贯彻“哲学引领实践”的信条，它和欧洲其他一些善于思辨的民族有个共同特点，那就是善于用体系化方式表达自己要做的事情，设计完整方案，经过论证认为合理之后，再付诸实践。这里的体系化不是简单的写报告列ABC，而是提出一套完整的、有深厚学术基础的理论体系。", "chapter": "第八章 铁轨上的霸权", "date": "2022-06-11", "color": null}, {"text": "回顾第一次工业革命，从宏观上讲，一个国家、一个社会为了给新一轮科技革命创造条件，至少有一件事还是可以做的：塑造一个规模足够大的、工资收入相对消费水平足够高的大众消费群体，让那些给他们提供新产品和新技术服务的人/企业能够持续赚到钱。因为新技术刚诞生时，并不总是能马上表现出无法匹敌的效率，恰恰相反，它有可能是拙劣的、非常狭隘的，就如纽卡门的蒸汽机。但只要它能够面向某个特定的小众市场生存下来，那么终有一天，它总能释放自己的潜力。", "chapter": "第七章 蒸汽机的胜利", "date": "2022-06-11", "color": null}, {"text": "这就是棉纺织业对英国社会的意义，也是为什么工业革命早期的技术革新发端于纺织业。这不是精心设计的结果，也不是被牛顿这类天才自上而下推动的革命；相反，它的根基是一个足够庞大的需求市场，一个受教育水平相对较高的从业者群体，以及能够持续予以创新者经济回报的宽松投资机制。从飞梭到骡机，中间仅相隔五十年，而一个社会能如此持续地产出各种创新，必然意味着一种蓬勃发展的、宽松的经济环境，使得一代又一代不断提供“微创新”的技术从业者能够从市场中持续赚到钱，如此聚沙成塔，才有可能。", "chapter": "第七章 蒸汽机的胜利", "date": "2022-06-11", "color": null}, {"text": "英国人实行长子继承制，家主的财产基本上全部由长子继承，其他子女必须自谋出路。因此，父亲往往要求出生较晚的子孙学习贸易或者某种技艺，以获得不错的经济收入。这一方面导致英国社会鼓励人们投资教育，另一方面则导致整个社会，尤其是贵族阶级和地主阶层对商业的态度比较宽容，因为这些家庭的第四、五个孩子往往也很有可能成为商人", "chapter": "第七章 蒸汽机的胜利", "date": "2022-06-11", "color": null}, {"text": "科学革命是“上等人”的创新，而工业革命，或者至少早期的纺织业革命则是“下等人”的创新。虽然后者社会地位不高，不入贵族的法眼，却更为坚实、持久地改造着这个世界的物质基础。", "chapter": "第七章 蒸汽机的胜利", "date": "2022-06-11", "color": null}, {"text": "许多自由主义学者过分鼓吹立宪是对王权的限制，实际上，其关键不在于限制王权，而在于工商业新贵和国王之间达成协议，并且建立起法定的代理关系：以工商业新贵为代表的资产阶级在政府议会中获得代表席位，通过限制贵族使得国王成为他们的代理人；国王则要帮他们解决好法律环境，扫清产业发展的障碍，同时通过议会立法征取必要的、维系暴力的费用。这两者哪一个也不可缺少。换句话说，凯撒的归凯撒，企业家的归企业家。", "chapter": "第六章 枪炮与国家", "date": "2022-06-11", "color": null}, {"text": "许多人以为，这种机械的流水线生产模式及将人异化的规训手段来自工厂，来自产业资本。真实的历史是，流水线生产模式源自战争，源自生存的迫切渴望，源自战胜敌人的根本需求。", "chapter": "第六章 枪炮与国家", "date": "2022-06-11", "color": null}, {"text": "火枪取代冷兵器事实上是一个极为漫长的过程。", "chapter": "第六章 枪炮与国家", "date": "2022-06-11", "color": null}, {"text": "今天的教育体系实则来源于普鲁士时代的职业教育，其本质是培养能够胜任工作要求的“劳动力产品”，并不关注灵魂提升。", "chapter": "第五章 知识分子与生意人", "date": "2022-06-11", "color": null}, {"text": "书籍不是奢侈品，不是王侯公爵出于个人好恶就可以决定销路的消遣之物，它的价值根植于民众对思想和知识的巨大需求。", "chapter": "第五章 知识分子与生意人", "date": "2022-06-10", "color": null}, {"text": "在制度主义者看来，一项制度到底是由政府还是由市场推动，实际上并没有那么重要，重要的是它能否降低交易成本，从而创造更大的价值。如果是市场来推动搭建这类制度，那么它要克服部分企业利用信息不对称创造利润差的冲动；如果是政府来推动，那么它要克服直接运用政策手段扭曲价格信号的冲动。两种行为主体都必须学会如何运用更灵巧的手段来创造出好的生态，而不是争论谁该作为主导而发挥作用。", "chapter": "第四章 流通的力量", "date": "2022-06-10", "color": null}, {"text": "这其实就是商人跟我们大多数普通人思维之间的根本区别。在商人看来，花掉的钱可以转换成资产，因此每一笔钱应该花得有价值；负债也可以成为资产，因为它在短时间内促成了资金的周转。这就是会计恒等式的伟大之处。这个简单的思维差异，造就了商人的行事风格。再大的商人也有可能在一些事上锱铢必较，在另一些事上一掷千金，关键是看在商人心中的那个复式账本里，哪些是资产，哪些是负债。在这个问题上，15世纪的商人与今天的商人一样理性。", "chapter": "第四章 流通的力量", "date": "2022-06-10", "color": null}, {"text": "正如印刷术的价值在于让思想更快流通，而货币技术的价值则是让商品更快地流通。", "chapter": "第四章 流通的力量", "date": "2022-06-10", "color": null}, {"text": "如果人类不付出巨大努力，科技完全可能倒退，甚至可能崩溃，即使是现代社会，这种情况也常常出现。", "chapter": "第二章 两千年前的蒸汽机", "date": "2022-06-10", "color": null}, {"text": "文明的煌煌之绩与文明的血腥残酷，经常既非针锋相对，也非全然无关，而是一枚硬币的两面。", "chapter": "第二章 两千年前的蒸汽机", "date": "2022-06-10", "color": null}, {"text": "这便是由古希腊著名思想家毕达哥拉斯建立起来的世界观：世界的本原是数字，数学可以描述世界背后的一切规律。", "chapter": "第二章 两千年前的蒸汽机", "date": "2022-06-10", "color": null}, {"text": "外儒内法", "chapter": "第一章 弩与大一统", "date": "2022-06-10", "color": null}, {"text": "简单说来，“弩机猜想”的内容是：当“弩机”这种军事技术在一国内大范围普及时，它会给这个国家的统治者提供一种战略优势，那便是用技术的力量将原先无法有效动员的平民百姓充分动员起来，变成（在特定作战环境中）可以驱策的部队，以适应战国时代的大规模冲突。而统治者可以这样做，又是以能够彻底变革封建时代的治理结构，摆脱“小圈子”和“血缘家族”的桎梏，建立一种“科层化”的现代管理体系为前提条件的。", "chapter": "第一章 弩与大一统", "date": "2022-06-10", "color": null}, {"text": "何先生认为，秦献公即位后的第四年，亦即墨家钜子孟胜及其百八墨徒为阳城君死难那一年，秦献公就已经与墨家合作，不仅如此，秦之由弱变强，亦开始于由墨家奠定的基础，而不是秦孝公时期的商鞅变法。", "chapter": "第一章 弩与大一统", "date": "2022-06-10", "color": null}, {"text": "这里的“学习”并不意味着成为另一个领域的专家，而是学会另一个领域的思考方式。", "chapter": "结语 从“铁笼状态”到“汇流模型”", "date": "2022-06-09", "color": null}, {"text": "利率的本质是什么？是时间的贴现，是“未来”的价值。如果一个国家预计自己未来创造财富的人口数量将减少，那么正利率当然无法继续维系。", "chapter": "结语 从“铁笼状态”到“汇流模型”", "date": "2022-06-09", "color": null}, {"text": "你并不是要把一项技术卖给什么人，而是要发现，某项技术能够为什么领域带来价值。要实现这一点，既要真正了解这项技术能够实现什么，它的优缺点和发展进程大致是怎样的，又要了解它所施展的领域，它真正的需求在哪里，市场规模是怎样的，能够取得多大的替代效应。", "chapter": "结语 从“铁笼状态”到“汇流模型”", "date": "2022-06-09", "color": null}, {"text": "但到了今天，如果政府再实施此类政策，实际等于补贴自动化生产线和人工智能算法，即便建设的工厂再宏伟，运送工厂的道路再宽阔，生产产品的却是机器人，老百姓口袋里依然还是没有钱。正因此，再分配的方式必须发生根本变化。", "chapter": "第十三章 中国与世界", "date": "2022-06-09", "color": null}, {"text": "自动化革命不单单需要高技术人才，而且需要高额资本投入，并挤压很多工作机遇。这种变化之下，技术进步对社会公平感的破坏，才是最值得我们担忧的问题。这意味着，自动化越是飞速发展，“产业合法性”就丧失得越快。", "chapter": "第十三章 中国与世界", "date": "2022-06-09", "color": null}, {"text": "最切实的方案是走第四条道路，也就是以发展劳动密集型产业为主，切入“国际大循环”，为工业发展创汇的同时，解决劳动力转移问题。", "chapter": "第十三章 中国与世界", "date": "2022-06-09", "color": null}, {"text": "中国供应商的优势在于，因为中国有足够庞大的市场和需求，中国供应商能够启用的产能规模是巨大的，不仅成本可以下降，而且市场议价能力也会增强。", "chapter": "第十三章 中国与世界", "date": "2022-06-09", "color": null}, {"text": "消费性的现代工业产品，如汽车、手机等，很大一部分技术门槛并不在于纯粹的技术制造能力，而在于产品设计和供应链整合能力。", "chapter": "第十三章 中国与世界", "date": "2022-06-09", "color": null}, {"text": "中国的教育体制是在苏联基础上发展起来的，而苏联的教育体制其实是普鲁士教育体系的加强版，是拿破仑战争后从普鲁士传入法国，又从法国传入俄国的。在很大程度上，普鲁士教育体系就是为了适应工业化的进展应运而生的。它有这么几个主要的特点：第一，初级教育向所有国民敞开，而且免费。从产业化的角度，这当然不是提供福利，而是人力资本投资，为的是训练大量有基本技术水准的产业工人；第二，担任教职的老师必须先接受专业院校（师范院校）训练，培训合格后由国家给付薪水，把老师变成类“公务员”，背后用意是以标准化的手段保证教师水准；第三，有专门的考核机制来确保教学质量，也就是我们熟悉的教学大纲和标准化考试，而且与研究生教育不同，这一阶段的教育考核以考察学生不出错的能力为主。", "chapter": "第十三章 中国与世界", "date": "2022-06-09", "color": null}], "ideas": [{"content": "新能源汽车", "abstract": "回顾第一次工业革命，从宏观上讲，一个国家、一个社会为了给新一轮科技革命创造条件，至少有一件事还是可以做的：塑造一个规模足够大的、工资收入相对消费水平足够高的大众消费群体，让那些给他们提供新产品和新技术服务的人/企业能够持续赚到钱。因为新技术刚诞生时，并不总是能马上表现出无法匹敌的效率，恰恰相反，它有可能是拙劣的、非常狭隘的，就如纽卡门的蒸汽机。但只要它能够面向某个特定的小众市场生存下来，那么终有一天，它总能释放自己的潜力。", "chapter": "", "date": "2022-06-11", "star": null}]}, {"id": "31304265", "title": "自驱型成长：如何科学有效地培养孩子的自律", "author": "[美]威廉·斯蒂克斯鲁德 [美]奈德·约翰逊", "cover": "https://cdn.weread.qq.com/weread/cover/80/YueWen_31304265/s_YueWen_31304265.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=4083237071ddaa4940852a2", "progress": 64, "finished": 0, "hlCount": 28, "ideaCount": 3, "highlights": [{"text": "教师可以教导孩子，教练可以训练孩子，辅导员可以跟孩子强调毕业有要求，但是父母要做的只有一件事：无条件地爱自己的孩子，并为孩子提供一个安全的归宿。对于在学校或生活中其他地方遭遇压力的儿童，家庭应该是一个安全的避风港、一个休息和恢复的地方。当孩子感受到，他们即便身处困境之中，也深深地被父母爱着，他的韧性就会增强。", "chapter": "为什么大脑喜欢顾问模型", "date": "2022-04-17", "color": null}, {"text": "多年来，对禅定的研究表明，每天两次，每次冥想10～15分钟的孩子会体验到压力水平、焦虑水平和抑郁症状的显著下降，同时也会更少地表达出敌意与愤怒。[插图]同时，他们也睡得更好，思维变得更有创造力，健康水平增高，自尊水平提升，并且有更佳的校内表现，在认知和学业技能测试方面也做得更好。", "chapter": "禅定", "date": "2021-06-03", "color": null}, {"text": "彻底停工是指不需高度集中思想，也不带什么目的，单纯地无所事事。", "chapter": "第6章 彻底停工期", "date": "2021-05-06", "color": null}, {"text": "如果你既聪明又积极，那你去哪里上学其实并不重要。对于一些孩子来说，明白这一点会让他们更容易关注那些对自己来说真正重要的东西。", "chapter": "动机方面的常见问题及其解决方法", "date": "2021-05-06", "color": null}, {"text": "经常运动。即使短时间的运动也足以激活大脑开始投入于某些事情，部分原因在于前额皮质中的多巴胺增多。此外，一定要动起来，那才算运动。", "chapter": "动机方面的常见问题及其解决方法", "date": "2021-05-06", "color": null}, {"text": "尽管15岁的孩子可能要在重点攻克学业问题的同时，还热爱着滑雪、绘画、音乐，但在道理上其实和8岁孩子的情况差不多。想引导他做你觉得他该做的事情，最好的方法就是先给他空间去做他想做的事情。", "chapter": "什么东西吸引着我们", "date": "2021-05-06", "color": null}, {"text": "那么该如何帮助孩子建立健康的多巴胺系统呢？答案非常简单：鼓励他们在自己感兴趣的领域努力。", "chapter": "什么东西吸引着我们", "date": "2021-05-06", "color": null}, {"text": "我们要做的，是帮孩子自己激励自己，并让他们察觉，他们身上总有一些能影响世界的重要东西。我们要帮着他们学会运营自己的生活，并努力去赋予生活意义。", "chapter": "第5章 内驱力：如何培养孩子的积极性", "date": "2021-05-06", "color": null}, {"text": "别惧怕未来事实上，我们作为父母，所有的焦虑都关乎我们控制不了的未来。", "chapter": "怎样成为一个“非焦虑临在”", "date": "2021-05-06", "color": null}, {"text": "养育中最首要的一点，是欣赏你的孩子", "chapter": "怎样成为一个“非焦虑临在”", "date": "2021-05-06", "color": null}, {"text": "如果我们自己都无法接受我们的孩子，我们怎能指望他们接受自己呢？", "chapter": "涓流焦虑", "date": "2021-05-06", "color": null}, {"text": "孩子是伟大的观察者，同时也是糟糕的翻译官。", "chapter": "涓流焦虑", "date": "2021-05-06", "color": null}, {"text": "告诉你家孩子：“你就是你自己的专家。没有人能比你更了解自己，因为没有人能真正知道，对你来说，做自己是什么感觉。”", "chapter": "难处何来：一些常见的问题", "date": "2021-05-06", "color": null}, {"text": "他还专门指出，保障孩子的生活能成功并非父母的责任，父母真正的责任所在是支持女儿，表达出同理心，在必要时设下边界，以及塑造孩子的自信心。", "chapter": "难处何来：一些常见的问题", "date": "2021-05-06", "color": null}, {"text": "我们的终极目标不是为了培养一个顺从的孩子，而是为了培养出能够理解在生活中如何正确行动和理性交流的孩子。", "chapter": "“你来定”不该有如此意味", "date": "2021-05-06", "color": null}, {"text": "考多高的分数并非成长的目的，最重要的还是真正的好奇心和发自内心地学习。", "chapter": "总结", "date": "2021-05-06", "color": null}, {"text": "为什么老师说什么你就要听什么。", "chapter": "“但是……”家长作为顾问的挑战", "date": "2021-05-03", "color": null}, {"text": "生活里有四件事会让人紧张起来：第一，发生新情况；第二，出了之前没想到的事；第三，发生了让你觉得自己可能会受到伤害、挨批评或者感到尴尬的情况；第四，出现了你觉得自己难以把控的局面。", "chapter": "对控制的警告", "date": "2021-05-03", "color": null}, {"text": "你可能听说过《平静祷文》，其中写道：“上帝啊！恳求你赐我恩典，安详接受不能改的事件；鼓我义念，勇敢改变可以改的事件；赠我慧剑，能够分辨接受还是改变。”", "chapter": "“家庭作业之战”", "date": "2021-05-03", "color": null}, {"text": "借由你，他们来到这个世界，但他们不属于你。", "chapter": "第2章 “我那么爱你，才不愿跟你吵家庭作业的事”：顾问型父母", "date": "2021-05-03", "color": null}, {"text": "（1）你不能让你的孩子违背他自己的意愿去行事。（2）你不能让你的孩子想要他们本不想要的东西。（3）你不能让你的孩子不想要他们本想要的东西。（4）让他们想要他们想要的东西，不想要他们不想要的东西，至少在当下没什么不好。", "chapter": "“家庭作业之战”", "date": "2021-05-02", "color": null}, {"text": "但往往忽略了更基本的目标：培养一个有好奇心、能自主学习的人。", "chapter": "“家庭作业之战”", "date": "2021-05-02", "color": null}, {"text": "控制感就是应对压力的解药。所谓的压力，都来自我们未知的、嫌弃的和惧怕的事物。对我们来说，小到感觉有点失衡，大到为生命而战，都和压力有关。", "chapter": "第1章 天底下最让人紧张的事", "date": "2021-04-15", "color": null}, {"text": "当家长的，终点在哪里？不是孩子过上了你想让他过的生活，而是你帮孩子过上他自己想过的生活。", "chapter": "译者序", "date": "2021-04-15", "color": null}, {"text": "帮助你的孩子营造一个合适的学习环境，必要时，帮他建立起自己的奖励模式", "chapter": "总结", "date": "2020-08-24", "color": null}, {"text": "我们希望孩子成为善于思考的学习者，希望他们自律，而不需要他们被纪律驱使。你靠着高高在上的权威凌驾于孩子之上，但这会消耗你很多宝贵的时间，也会让家庭不再是一个“安全港湾”。", "chapter": "总结", "date": "2020-08-24", "color": null}, {"text": "“你的作业需要帮助吗？你有个写作业的规划吗？你的规划完成了吗？”", "chapter": "“但是……”家长作为顾问的挑战", "date": "2020-08-24", "color": null}, {"text": "父母最重要的事不是让孩子取得成功，而是让孩子努力活出自己人生的意愿。", "chapter": "赞誉", "date": "2020-08-24", "color": null}], "ideas": [{"content": "感谢作者的忠告。", "abstract": "我们希望孩子成为善于思考的学习者，希望他们自律，而不需要他们被纪律驱使。你靠着高高在上的权威凌驾于孩子之上，但这会消耗你很多宝贵的时间，也会让家庭不再是一个“安全港湾”。", "chapter": "", "date": "2020-08-24", "star": null}, {"content": "让孩子做自己人生的主人", "abstract": "最好的成长是自我成长，最好的控制是自我控制。", "chapter": "", "date": "2020-08-24", "star": null}, {"content": "到位", "abstract": "父母最重要的事不是让孩子取得成功，而是让孩子努力活出自己人生的意愿。", "chapter": "", "date": "2020-08-24", "star": null}]}, {"id": "32441975", "title": "高维智慧 : 发现你的内在成长力", "author": "李淡", "cover": "https://cdn.weread.qq.com/weread/cover/97/yuewen_32441975/s_yuewen_324419751734060600.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=e2b32d2071ef0677e2b2859", "progress": 61, "finished": 0, "hlCount": 29, "ideaCount": 1, "highlights": [{"text": "一旦心智不安，能量转为低频，月光动力下达关锁指令，思维方式便有了一扇闭合的门，人心由此出现分别、评判。", "chapter": "“评判”是泛化的魔咒 资源的锁", "date": "2021-05-23", "color": null}, {"text": "生而为人，第一条必须掌握的文明准则是“不能随地便溺”，弗洛伊德把这个时期叫作“肛欲期”。", "chapter": "文明进化之路", "date": "2021-05-23", "color": null}, {"text": "但是，父母透过目光反馈给孩童的态度太重要了！多少人一辈子都在向父母、世界证明自己，在与父母、世界的互动中验证态度，然而在执着验证的过程中，却不小心弄丢了真实的自己。", "chapter": "太阳资源与月光动力", "date": "2021-05-23", "color": null}, {"text": "小时候，孩童在父母的眼睛里寻找答案，长大后，在关系，尤其重要关系里寻找答案。", "chapter": "能量投资与不安全感", "date": "2021-05-23", "color": null}, {"text": "因为“感觉”触角是我们连通环境、连通内心的桥（外感官连通世界，内感官连通内心）。没有向外感觉周遭环境的能力，我们将会与世界脱离开来，陷入可怕的混沌与黑暗；没有向内觉察身体和心灵的能力，我们将会与生命隔离开来，如行尸走肉。", "chapter": "丢失的耐性", "date": "2021-05-18", "color": null}, {"text": "越是完整保留“感觉”触角的人，越能凭借“直觉”取得智慧、交予“认知”，于是越能看得更深、感知更透。", "chapter": "丢失的耐性", "date": "2021-05-18", "color": null}, {"text": "人们时常忘记了“感觉”这个维度，尤其遭遇困境，焦虑、痛苦时，人们更容易沦陷在“意识流”里，忘记多留一点时间给“感觉”，也忘记多留一点耐性等待“直觉”。", "chapter": "丢失的耐性", "date": "2021-05-18", "color": null}, {"text": "这种神秘强大的能力，是来自高维的灵性洞察。那些能够敏觉到未来趋势，缔造或影响人类文明的人，诸如伟大的领袖、恬淡的修行人、探索真理的科学家、杰出的企业家和思想者，他们的直觉必定时常和高维保持连接。", "chapter": "攫取智慧的本领", "date": "2021-05-18", "color": null}, {"text": "有意识地运用“直觉”连接“高维”，运用“思维”抓住“未知的奥义”。在感应到高维信息的一刹那，直觉触到了灵感，思维也接过了灵感。", "chapter": "攫取智慧的本领", "date": "2021-05-18", "color": null}, {"text": "人的直觉决策可以跳过大脑直接驱动行为，比如赛车手弯道刹车的例子；", "chapter": "攫取智慧的本领", "date": "2021-05-18", "color": null}, {"text": "无法到达高维也无妨，若能谦卑下来，接受自身局限，便能敞开心智，相信高维的存在，然后，在自主意识主导下，运用直觉接收自高维降下的灵感，发现人类未曾发现的新内容。有如此心智的人不但会拥有超强的“感知力”，还会逐步提升出超强的“灵性直觉”。", "chapter": "攫取智慧的本领", "date": "2021-05-18", "color": null}, {"text": "创新能力需要感觉、直觉、认知三个维度整体发展，进而提升个体的心智模式和思维方式。", "chapter": "攫取智慧的本领", "date": "2021-05-18", "color": null}, {"text": "脱离思维的直觉是动物性的、无意识的本能反应，比如蜜蜂筑巢，大雁列队，河狸建坝……", "chapter": "攫取智慧的本领", "date": "2021-05-18", "color": null}, {"text": "人们要学会连接潜意识，听懂不安的呼唤、痛苦的呐喊，听懂生命原初的力量和渴望。与生命实相、宇宙奥义相关的一切答案，都记录在潜意识里！", "chapter": "宇宙全息投影", "date": "2021-05-18", "color": null}, {"text": "内感官，即内视、内听、内感，是帮助人们打开潜意识之门、读取潜意识中信息、与高维空间取得联系的能力。", "chapter": "宇宙全息投影", "date": "2021-05-18", "color": null}, {"text": "生命力、感觉、直觉、认知，是造物主对人类的恩赐，因为有了这些精神维度，人类得以构建三维、十维，乃至更大的精神世界。", "chapter": "宇宙全息投影", "date": "2021-05-18", "color": null}, {"text": "潜意识是人类精神世界最为神秘的一部分，人类拥有它，却对其所知甚少。那里储存着与无限时间维度、因果维度相关的无穷信息，如同一个巨大的数据仓库，里面尽是无数代生命积累下来的感觉记忆、直觉经验，尽是世界演进变化的影像、声音，尽是重重关联、彼此映射、互为因果，却又难以捉摸的信息之间的神秘联系，即：宇宙逻辑。", "chapter": "宇宙全息投影", "date": "2021-05-18", "color": null}, {"text": "再小的生命也连接着世界，再大的宇宙也投影于一花、一叶、一心之中。", "chapter": "宇宙全息投影", "date": "2021-05-18", "color": null}, {"text": "人类的心灵世界容纳了无穷无尽的潜藏信息（个人潜意识及集体潜意识），是整个宇宙的全息投影，当心灵借助直觉到达更高维度时，将会连接一只能够纵观全局、勘破隐藏在无穷信息中奥秘的眼睛——“高维之眼”。", "chapter": "零至三维", "date": "2021-05-18", "color": null}, {"text": "一个人终究可以活出怎样的人生、拥有多大的世界，是由他的“心智模式”决定的。", "chapter": "零至三维", "date": "2021-05-18", "color": null}, {"text": "这张地图共有两种形式：心智开放时，为“成长型心智网络”；心智封闭时，为“防御型心智网络”", "chapter": "零至三维", "date": "2021-05-18", "color": null}, {"text": "“认知”是第三个精神维度，它是上天赐予人类的意识火种。", "chapter": "零至三维", "date": "2021-05-18", "color": null}, {"text": "理虽能顿悟，事仍需渐修", "chapter": "自序", "date": "2021-05-18", "color": null}, {"text": "生而为人是一场修心的旅程，说长，用来真正生活的时间总是不够用；说短，在混沌中纠扰的每一分一秒都冗复难耐。", "chapter": "自序", "date": "2021-05-18", "color": null}, {"text": "人类则不同，“认知”虽是人类凭借直觉智慧进化、获得的礼物，但是，当人们急于掌控自己、掌控环境，而这份礼物又貌似能够快速帮助人们实现掌控欲望时，人们变得越来越依赖“认知”，越来越上脑（生命能量无法沉淀至丹田，而是向上驱动大脑思绪万千）。", "chapter": "奇妙的心灵进化", "date": "2021-05-18", "color": null}, {"text": "“外感”是身体或机器的触角，不能探出三维；而“内感”和“直觉”是灵魂的触角，它们可以自由连接无极世界中的任何一个维度。通过这份连接，人类才得以共情万物、接收灵感，不断提升经验网络，创造人类文明。", "chapter": "缘起", "date": "2021-05-18", "color": null}, {"text": "心智的开放度越高，直觉对高维的感应越强，越能将更多灵感交与思维，于是思维能够触及的高维智慧就越多，双手对世界的创造力也会越大。", "chapter": "缘起", "date": "2021-05-18", "color": null}, {"text": "如今，引力波的发现已经证明：时空在能量作用下会发生变化；速度可以改变一切，甚至时间和空间。", "chapter": "缘起", "date": "2021-05-18", "color": null}, {"text": "就像很多存在思维局限的人，当他们理解不了经验之外的某些现象（包括超维现象）时，既不愿打破局限的心智模式，也不愿相信直觉的力量，自然也就无法连通高维、获取灵感。", "chapter": "缘起", "date": "2021-05-18", "color": null}], "ideas": [{"content": "思考快与慢  系统一", "abstract": "人的直觉决策可以跳过大脑直接驱动行为，比如赛车手弯道刹车的例子；", "chapter": "", "date": "2021-05-18", "star": null}]}, {"id": "28347240", "title": "袁隆平的世界", "author": "陈启文", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/240/28347240/s_28347240.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=a4932c1071b08b68a495579", "progress": 100, "finished": 1, "hlCount": 25, "ideaCount": 0, "highlights": [{"text": "按哲学家冯友兰的分析，可以把人生境界从低到高划分为四个层次，第一层次是自然境界，人只是顺着本能或风俗习惯做事，然而他“并无觉解，或不甚觉解。他所做的事，对于他就没有意义，或很少意义”。第二层次为功利境界，“人意识到他自己，为自己而做各种事。这并不意味着他必然是不道德的人。他可以做些事，其后果有利于他人，其动机则是利己的。所以他所做的各种事，对于他，有功利的意义”。第三层次为道德境界，“人了解到社会的存在，他是社会的一员。这个社会是一个整体，他是这个整体的一部分。有这种觉解，他就为社会的利益做各种事，或如儒家所说，他做事是为了‘正其义不谋其利’，他真正是有道德的人，他所做的都是符合严格的道德意义的道德行为”。一个人，能达到这等境界已经非常难得了。第四层次为天地境界，也是人生的最高境界，“人了解到超乎社会整体之上，还有一个更大的整体，即宇宙。他不仅是社会的一员，同时还是宇宙的一员，也就是孟子所说的‘天民’。有这种觉解，他就为宇宙的利益而做各种事。他了解他所做的事的意义，自觉他正在做他所做的事。天地境界有超道德价值”。", "chapter": "后记", "date": "2022-08-22", "color": null}, {"text": "他们所用的杂交稻种子，百分之八十以上从中国进口，生产出大米之后又源源不断地出口中国，", "chapter": "人类的福音", "date": "2022-08-22", "color": null}, {"text": "这样的飞机振动授粉，何时才能飞翔在中国的稻田上空呢？如今，袁隆平的愿望实现了，在三亚南繁基地也采用无人机辅助授粉技术，一天就可以给三百多亩稻田授粉，授粉效率比以前提高了十倍。", "chapter": "人类的福音", "date": "2022-08-22", "color": null}, {"text": "“分子生物技术是科学发展的必然趋势，分子技术和常规技术相结合是今后的发展方向。”", "chapter": "舌尖上的安危", "date": "2022-08-22", "color": null}, {"text": "我们最担忧的是国外大公司，他们广泛搜集了我国各类作物的种质资源，并对其进行基因挖掘和申请专利，这样的话，我国的育种家以后如果要用这些材料进行科研和新品种选育，就得向他们支付巨额的知识产权费用，一旦种业市场、种质资源被外国大公司控制，国家的粮食安全就会真正受到威胁，人家动不动就可以卡我们的脖子，唉。”", "chapter": "舌尖上的安危", "date": "2022-08-22", "color": null}, {"text": "此时雨越下越大了，张克松和舒友林看着一个在风雨中迟迟不肯离去的老人、一张被雨水淋湿的脸，两人都感觉被一种难以言说的东西渗透了。", "chapter": "第三次飞跃", "date": "2022-08-21", "color": null}, {"text": "“我有两个梦，一个是‘禾下乘凉梦’，一个是杂交水稻覆盖全球梦，这就是我的中国梦。”", "chapter": "第三次飞跃", "date": "2022-08-21", "color": null}, {"text": "无论是在湖南还是中央主持工作期间，华国锋对杂交水稻的研究和发展都起到了很重要的历史作用，这在那动乱岁月也是一个难以复制的传奇。", "chapter": "第五大发明", "date": "2022-08-21", "color": null}, {"text": "面对一双双咄咄逼人的眼睛，袁隆平不疾不徐地开口了：“结果不用我说了，杂种优势利用是为了增产，但我们的稻谷减了产，的确，从表面看，我们这个试验是失败了。但如果换一个角度，从本质上看，我们又是成功的，为什么？刚才大家争论的焦点，就是水稻这个自花授粉作物究竟有没有杂种优势，这是个大前提，我们现在用试验证明了，有！水稻具有强大的杂种优势！这个大家都看到了，杂交水稻的稻草比常规稻增加了七成，这不是优势是什么？至于这个优势是表现在稻谷上，还是稻草上，这不是水稻有没有杂种优势的根本问题，这是我们的经验不足，在杂交优势组合上配组不当，结果使杂交稻的优势表现在稻草上了。既然不是根本问题，而是技术问题，那就不能从根本上否定杂交水稻，我们可以通过改进技术，选择优良品种重新配组，使其优势发挥在稻谷上，这是完全做得到的。”", "chapter": "第五大发明", "date": "2022-08-21", "color": null}, {"text": "这年9月，在长沙马坡岭实验田，袁隆平和周坤炉转育的“二九南1号”不育系，经过连续三年共七代的测交和回交，十个株系共三千株实验稻，终于达到百分之百不育且性状与父本完全一致的标准。百分之百，这意味着，三系配套，成啦！", "chapter": "第五大发明", "date": "2022-08-21", "color": null}, {"text": "概率看，“野败”的发现几可称为一个无法复制的传奇，但“野败”的基因却可以无限复制，这是科学的本质规律，具有可重复、可检验原则；", "chapter": "第五大发明", "date": "2022-08-21", "color": null}, {"text": "李必湖几乎是跪在淤泥里的，用双手一点一点地把带有三个穗子的稻株连根带泥挖出来，又小心地捧到岸上，然后脱下衬衣，像包裹刚出娘胎的婴儿，严严实实地把稻株连着泥巴一起包好，最少也有二十多斤，他抱在胸前，既不敢抱紧也不敢放松，生怕一个闪失，就把那襁褓里的婴儿挤了、伤了。", "chapter": "第五大发明", "date": "2022-08-21", "color": null}, {"text": "农业科学的进步，离开了农民和土地，是不可能成功的。", "chapter": "第五大发明", "date": "2022-08-21", "color": null}, {"text": "“从亲缘关系较远的野生稻身上寻找突破口”", "chapter": "第五大发明", "date": "2022-08-21", "color": null}, {"text": "事实上，在一个科学论断被验证之前，很多东西已被提前验证了，并且一直在验证，无论怎样风云变幻，总有一群追逐太阳的人，不只是袁隆平和他的助手，还有张孔湉、陈国平和许多我没有提及的人，他们都是追逐太阳的人。", "chapter": "追逐太阳的人", "date": "2022-08-21", "color": null}, {"text": "他一边看，一边在心里感叹，在一个动荡的年代，一个条件这样艰苦简陋和技术队伍薄弱的山区农校，还有人在兢兢业业地搞科研，搞试验，而且是向世界级的难题攻关，这本身就是奇迹啊！而袁隆平所勾画出的一条清晰的思路和各种试验数据，让这位遗传学专家已经看到了杂交水稻成功的希望。", "chapter": "追逐太阳的人", "date": "2022-08-21", "color": null}, {"text": "那也是在中国杂交水稻发展史上值得铭记的名字——中科院遗传研究所的张孔湉教授，他既是一位遗传学家，也是一位研究杂交高粱的专家。", "chapter": "追逐太阳的人", "date": "2022-08-21", "color": null}, {"text": "为了争取时间，他们从安江或长沙出发时就把稻种浸湿催芽，在旅途上把浸过的谷种捆在身上，利用体温催芽。人非草木，而生命却是相通的，人的体温正好是稻种催芽的适合温度，但那浸湿的稻种捆在身上却很不舒适，然而为了给种子催芽，又哪里顾得上自己舒适不舒适？", "chapter": "追逐太阳的人", "date": "2022-08-21", "color": null}, {"text": "他把三系法杂交水稻比喻为“一女嫁二夫”的奇异婚姻关系，而且是包办婚姻。生儿育女，第一步要有母亲。水稻是雌雄同花作物，好比一出生就是夫妻成双，从一株稻子看，根本就没有公母之分。要想让它出现杂交，必须找到一个天生的“寡妇”，它没有丈夫，或丈夫丧失了性功能，这样的母水稻就是具有单一性功能的雄性不育株（不育系）；第二步就是给母水稻找一个特定的丈夫，这个丈夫的外表酷似母本，但有健全的花粉和发达的柱头，用它的花粉给母本授粉后，生出来的是长得和母亲一模一样的女儿，也是没有生育能力但仍能保持雄性不育的特性的母本，如此才能其雄性不育性不断遗传下去（保持系）；在此基础上，再给母本一个特定的丈夫（恢复系），这是一个外表与母本截然不同的丈夫，一般要比母本高大，也有健全的花粉和发达的柱头，它既能自繁，还能用其亲和的血缘医治母本（不育系）不孕的创伤，迅速圆满地恢复其生育能力（恢复系），通过杂交，生产出来的是儿子，长得比父母亲都要健壮，并且高产优质，而不育系和保持系杂交，仍旧只生女儿，用来继续做不育系繁殖，另一部分的后代则要恢复水稻天生的雌雄同花，“夫妻成双”，用于具有杂种优势的杂交水稻种子生产。", "chapter": "追逐太阳的人", "date": "2022-08-21", "color": null}, {"text": "袁隆平先生就是从这一前提出发，在国内首次勾画出了的一条“三系法”杂交水稻技术路线图——    第一步，寻找天然的雄性不育株，这一步是培育不育系的基础。这关键的第一步，袁隆平已经迈开了。    第二步，筛选和培育保持系，即必须培育出一种和雄性不育系杂交，使其后代永远能保持雄性不育的性状，以解决雄性不育系传宗接代的遗传问题。保持系的遗传组成为N（rfrf），不育系的遗传组成为S（rfrf），当保持系作为父本与不育系杂交时，它们杂交后所产生的F1（杂种一代）能够保持雄性不育性。为此，保持系的细胞核必须具有与不育系一样的纯合不育基因或上位基因（rfrf），而它们的细胞质则具有能育基因“N”，这样，保持系的雄性器官仍能正常发育并自交结实，又能作为父本与不育系杂交、使不育系的雄性不育性不断遗传下去，所以保持系是不育系赖以传代的必不可少的父本品系。    第三步，筛选和培育恢复系，即寻找和培育一种和雄性不育系杂交，使它们的杂种第一代恢复雄性可育的能力，能自交结实，只要它们表现的优势强，就可以将它们用于大田生产，这也就是水稻的杂种优势利用。", "chapter": "追逐太阳的人", "date": "2022-08-21", "color": null}, {"text": "啊，这不是退化了的雄蕊吗？这种特有水稻植株有一个鲜明特征，就是雄蕊花药不开裂，从而导致雄性功能丧失而不育，对于雌雄同花的水稻，既然其雄性功能丧失了，那就是具有单一性功能的母稻了，也就可以用来作为杂交的母本了。他又一次凑近了稻花，千真万确，那花药没有开裂！好半天，他都没有吭声，只感觉心头一阵阵狂跳，连手里的放大镜都兴奋得颤抖了。", "chapter": "神奇的发现", "date": "2022-08-21", "color": null}, {"text": "从事杂交水稻的研究，乃是洞悉生命的本质，推动生命的进程，是培植人类文明的事业。从事这样的事业，乃是生命的价值所在", "chapter": "神奇的发现", "date": "2022-08-21", "color": null}, {"text": "基因是具有遗传效应的DNA片段，每个DNA分子上有多个基因，不同的基因就含有不同的遗传信息。", "chapter": "神奇的发现", "date": "2022-08-21", "color": null}, {"text": "黄泰先生或许也有自己的遗憾，如果他能留美，他也许就不是当一名数学教师而是一个科学家，但作为一位教育家他也倍感欣慰了，在他的学生中，竟然涌现出了包括袁隆平在内的十二位院士，而在国家科技最高奖得主中，竟然有他的三位学生：袁隆平、吴征镒和黄纬禄，六个子女全都成为科学精英。", "chapter": "人就像一粒种子", "date": "2022-08-20", "color": null}, {"text": "1968年 遭受“5·18”毁苗事件，安江农校中古盘7号田的不育材料秧苗被全部拔除毁坏，成为至今未破的谜案。事发后的第四天，袁隆平才在校园的一口废井里找到了五根残存的秧苗，继续坚持试验。", "chapter": "袁隆平年表", "date": "2022-08-20", "color": null}], "ideas": []}, {"id": "22523868", "title": "生命3.0：AI超级智能与伦理边界重构", "author": "迈克斯·泰格马克", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/868/22523868/s_22523868.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=ce2328907157afdcce27eed", "progress": 100, "finished": 1, "hlCount": 22, "ideaCount": 0, "highlights": [{"text": "从这个意义上来讲，虽然人工智能可能会取代人类，但它们可以让我们从容地退出历史舞台，并把它们视为自己的后裔。", "chapter": "后裔", "date": "2023-11-11", "color": 1}, {"text": "我们人类会从人工智能的劳动中获得一时的利益，但是，就像自然出生的孩子一样，它们迟早都会去追求自己的命运，而我们这些衰老的父母，就会安静地逝去。", "chapter": "后裔", "date": "2023-11-11", "color": 1}, {"text": "当我们做好准备，谦卑地迎接更加智慧的机器时，我建议咱们给自己起个新名字——意人（Homo sentiens）！", "chapter": "意义", "date": "2021-04-27", "color": null}, {"text": "虽然我们在这本书中将注意力放在智能的未来上，但实际上，意识的未来更为重要，因为意识才是意义之所在。", "chapter": "意义", "date": "2021-04-27", "color": null}, {"text": "虽然他也认同我们的宇宙是毫无意义的，但他相信生命正在让宇宙充满越来越多的意义；如果生命的种子成功地散播到整个宇宙，那未来一定是光明的。", "chapter": "意义", "date": "2021-04-27", "color": null}, {"text": "并不是我们的宇宙将意义赋予了有意识的实体，而是有意识的实体将意义赋予了我们的宇宙。", "chapter": "意义", "date": "2021-04-27", "color": null}, {"text": "一个地球大小的“盖亚”人工智能每秒钟大约只能产生10个意识体验，和人类差不多；而一个星系大小的人工智能每10万年才能产生一个全局思维。", "chapter": "人工智能的意识是什么感觉", "date": "2021-04-27", "color": null}, {"text": "意识这么复杂的东西，怎么会是由粒子这样简单的东西组成的呢？我认为这是因为意识拥有一些高于和超越粒子性质的性质。在物理学里，我们称这种现象为“涌现”（emergent）[插图]。", "chapter": "意识理论", "date": "2021-04-27", "color": null}, {"text": "同样地，从这个意义上说，任何体验到痛苦的系统都是有意识的，即使它不能移动。", "chapter": "什么是意识", "date": "2021-04-27", "color": null}, {"text": "，在经济学模型中，人们总想要最大化所谓的“效用函数”，还有许多人工智能设计师训练智能体的方法是最大化所谓的“奖赏函数”", "chapter": "终极目标", "date": "2021-04-27", "color": null}, {"text": "比如，“不被饿死”的子目标带来了对高热量食物的欲望，使得当今社会肥胖的人数激增，很难找到合适的约会对象。繁殖后代的子目标在执行时却变成了对性行为的欲望，而不是捐精或捐卵的欲望，但其实后者才能以最小的成本产生最多的后代。", "chapter": "目标的进化：生物学", "date": "2021-04-27", "color": null}, {"text": "因此，从这个意义上说，我们的宇宙发明生命是为了更快地走向“热寂”。", "chapter": "目标的进化：生物学", "date": "2021-04-27", "color": null}, {"text": "复制有助于实现耗散，因为一个充满生命的星球在能量耗散上会更高效。", "chapter": "目标的进化：生物学", "date": "2021-04-27", "color": null}, {"text": "信息与人类过去抢夺的资源是截然不同的，因为你把它们送给别人的同时，自己还可以保留一份。", "chapter": "宇宙等级", "date": "2021-04-27", "color": null}, {"text": "在一个充满超级智能的宇宙中，只有一种商品值得远距离运送，那就是信息", "chapter": "宇宙等级", "date": "2021-04-27", "color": null}, {"text": "从物理学的角度来看，未来生命可能想要创造的一切——从栖息地、机器到新的生命形式，都只是以某种特定方式对基本粒子进行重新排列。就像蓝鲸实际上是重新排列的磷虾，而磷虾是重新排列的浮游生物一样，我们的整个太阳系也只是在138亿年的宇宙演化过程中对氢元素进行了重新排列：万有引力将氢元素重新排列成恒星，恒星将氢元素重新排列成重原子，之后，万有引力将这些原子重新排列成我们的星球，然后，化学和生物过程将它们重新排列成生命。", "chapter": "让资源物尽其用", "date": "2021-04-27", "color": null}, {"text": "没有野心的文明在宇宙尺度上是无关紧要的，因为宇宙大部分的资源禀赋最终都会被最有野心的生命形式所占领。", "chapter": "06 挑战宇宙禀赋：接下来的10亿年以及以后", "date": "2021-04-27", "color": null}, {"text": "在人类所有的智力特质中，意识（consciousness）是最了不起的。我认为，意识正是宇宙的意义之来源。星系之所以美丽，是因为我们的目光触及它们，并在主观上体验到它们的存在。", "chapter": "被奴役的神", "date": "2021-04-27", "color": null}, {"text": "人们总在问，人与机器的关系如何。我的回答是，这很明显：机器是我们的奴隶。", "chapter": "被奴役的神", "date": "2021-04-27", "color": null}, {"text": "在“新天堂”里，你得到的不是你应得的东西，而是你想要的东西。然而矛盾的是，许多人对总能得偿所愿这一事实感到很悲哀。", "chapter": "善意的“独裁者”", "date": "2021-04-27", "color": null}, {"text": "事实上，虽然人类总是习惯性的感恩，但我们中的许多人也没对我们智慧的创造者DNA表现出多么的感激，而是选择用避孕的方式来阻挠它实现自己的目标。", "chapter": "自由主义乌托邦", "date": "2021-04-27", "color": null}, {"text": "它是一个能保持自身复杂性并能进行复制的过程。复制的对象并不是由原子组成的物质，而是能阐明原子是如何排列的信息，这种信息由比特组成。", "chapter": "生命的三个阶段：生命1.0、生命2.0和生命3.0", "date": "2021-04-26", "color": null}], "ideas": []}, {"id": "36927973", "title": "破茧", "author": "施展", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/973/36927973/s_36927973.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=5b3322a0723379e55b397d5", "progress": 100, "finished": 1, "hlCount": 22, "ideaCount": 0, "highlights": [{"text": "历史学才是真正的未来学”", "chapter": "各界推荐", "date": "2021-12-22", "color": null}, {"text": "治理联盟可以让先发国家/地区与后发国家/地区之间的“数字鸿沟”被“数据分红”所替代，为未来人类秩序的伦理基础找到制度前提。", "chapter": "新经济伦理：以“数据分红”超越“数字鸿沟”", "date": "2021-12-22", "color": null}, {"text": "小强的各种活动所产生的数据就变成了他的收入，将来有一天甚至会发展为数据的“货币化”。", "chapter": "让每一次深蹲都变成你的收入", "date": "2021-12-22", "color": null}, {"text": "“全球数字治理联盟”、商人秩序等都是对民族主义的超越。", "chapter": "政有政策，商有商策", "date": "2021-12-22", "color": null}, {"text": "这些公司有着深刻的共同利益，也就有动力在政治空间之外建立一种超越于国家的规则空间，结成商人自治秩序——这会是一种天然的“非政治化”的秩序。", "chapter": "政有政策，商有商策", "date": "2021-12-22", "color": null}, {"text": "世界已经走到了需要再次突破既有秩序的时刻，以全球数字治理联盟为基础的商人秩序可能是未来的一个方向。", "chapter": "数据监管联盟", "date": "2021-12-22", "color": null}, {"text": "数据监管商的市场角色，有些类似服务于商业公司的会计师事务所。一个公司聘请好的会计师事务所做财务审计，其财务报表的公信力才会好，它在股市上也就更容易获得投资者的信任。聘请一个好的数据监管商，会成为一个数据公司的公信力的重要来源。", "chapter": "数据监管联盟", "date": "2021-12-22", "color": null}, {"text": "独立的数据监管商。", "chapter": "数据监管联盟", "date": "2021-12-22", "color": null}, {"text": "回顾人类历史会发现，与革命性新技术/新经济的技术特性相违背的政治方案，从来没有成功过；最终的结果一定是政治秩序进行自我调整，以适应新技术/新经济。", "chapter": "数据监管联盟", "date": "2021-12-22", "color": null}, {"text": "至于第四次工业革命的核心产业——信息技术产业，它还在发展中，其核心动力是创新。这一轮创新是由两条腿支撑的：一条腿是技术创新，它依赖的首先是足够自由的经济生态环境和法律生态环境，美国在这方面有明显的优势；另一条腿是商业模式创新，它依赖的首先是足够大的市场规模，中国在这方面有一定的优势。", "chapter": "四次工业革命的核心产业", "date": "2021-12-21", "color": null}, {"text": "第三次工业革命的核心产业是电子技术产业，其生产过程以重化工业为基础设施。", "chapter": "四次工业革命的核心产业", "date": "2021-12-21", "color": null}, {"text": "中国经济的高速增长在相当程度上是由西方的创新经济拉动起来的，这种增长无法脱离世界大势而获得解释。", "chapter": "中国供应链成长的奥秘", "date": "2021-12-21", "color": null}, {"text": "为了确保创新效率，这种大公司就必须将自己的生产流程外包出去，不能放在自己手里。因为只要它们把生产流程握在自己手里，一旦有了新的创意，就得调整整条生产线，转型成本非常高，这会严重拖累它们的创新效率，所以大规模外包便成了西方这一轮创新经济的内在需求。", "chapter": "《拜杜法案》与美国创新经济的转型", "date": "2021-12-21", "color": null}, {"text": "《拜杜法案》被英国《经济学人》杂志评价为“美国国会在过去半个世纪中通过的最具鼓舞力的法案”，它极大地促进了小企业的发展，推动了产业创新。", "chapter": "《拜杜法案》与美国创新经济的转型", "date": "2021-12-21", "color": null}, {"text": "美国的创新能力必须与中国大规模制造的能力结合，才能把创意真正地产业化。", "chapter": "《拜杜法案》与美国创新经济的转型", "date": "2021-12-21", "color": null}, {"text": "这些低技术行业却仍然有超强的成本控制能力，从而具有强大的竞争力，这一切更能反映出这个体系本身的力量", "chapter": "第四章 中国经济成长的逻辑[1]", "date": "2021-12-21", "color": null}, {"text": "市场规模决定了经济效率，效率低的小市场迟早会被效率高的大市场击败并吸收掉，这是最基本的经济规律，不以人的意志为转移。", "chapter": "全球化到底会走向何方", "date": "2021-12-21", "color": null}, {"text": "中国的规模太大了，它要买啥，就会在世界市场上形成巨大的需求，当然就会引起价格上涨；它要卖啥，也会在世界市场上形成巨大的供给，当然就会引起价格下跌。", "chapter": "中国逻辑与世界运行逻辑", "date": "2021-12-21", "color": null}, {"text": "这是近年来网络上各种“战狼”式情绪的根本来源。", "chapter": "香港对于中国的重要性", "date": "2021-12-19", "color": null}, {"text": "香港的这种特殊地位，是基于其普通法逻辑的；而普通法的运转，又是基于大社会小政府的逻辑以及背后的一整套生活方式的。", "chapter": "香港对于中国的重要性", "date": "2021-12-19", "color": null}, {"text": "普通法国家是大社会小政府的结构；成文法国家跟它相比，多半是大政府小社会的结构。并且只有海洋国家能把普通法的秩序维系下来，大陆国家则做不到。", "chapter": "被发明的法律与被发现的法律", "date": "2021-12-19", "color": null}, {"text": "英国是岛国，不面临任何陆地上的威胁，不需要强大的陆军，所以国王就没有办法压制贵族和各种民间自治的利益群体，只能继续和各种利益群体博弈，普通法因此得以延续。", "chapter": "被发明的法律与被发现的法律", "date": "2021-12-19", "color": null}], "ideas": []}, {"id": "25058095", "title": "枢纽：3000年的中国（新版增订4万字）", "author": "施展", "cover": "https://cdn.weread.qq.com/weread/cover/80/yuewen_25058095/s_yuewen_250580951688374200.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=3ee32110717e5b2f3eedab0", "progress": 87, "finished": 0, "hlCount": 18, "ideaCount": 4, "highlights": [{"text": "分税制改革", "chapter": "第七章 中国经济的崛起与世界秩序的失衡", "date": "2022-03-07", "color": null}, {"text": "通过网络内部每一家企业的高度专业化，确保效率；随着发包任务的不同，企业间的相互配套关系可以不断动态重组，以此来确保弹性。", "chapter": "第七章 中国经济的崛起与世界秩序的失衡", "date": "2022-03-07", "color": null}, {"text": "真正重要的是另外两个条件：一个是西方世界进入创新经济的时代，带来了制造业流程的大规模外包，在全球范围内寻找能够承接外包的对象；另一个是中国的土地财政，让中国以一种令人意外的方式获得了最为强大的承接外包能力。", "chapter": "第七章 中国经济的崛起与世界秩序的失衡", "date": "2022-03-07", "color": null}, {"text": "对海洋霸主来说，其生存线在于海洋安全，其财富线在于以本土的经济实力支撑起来的海外贸易，生存与财富在某种意义上可以合并为一条线。有了对这条线的掌握，对于海外领土的实际占有并不成为必须，国家的财政自由度更加提高。", "chapter": "第二节 大国的自我超越", "date": "2021-12-22", "color": null}, {"text": "美国经济在20世纪90年代以来的复苏，被前任IMF（国际货币基金组织）首席经济学家拉詹称为“失业型复苏”，尚属有力的增长却无法提供足够的就业。", "chapter": "第二节 世界秩序的变迁与失衡", "date": "2021-02-28", "color": null}, {"text": "中国的经济奇迹，完全是依托于世界大势而成，中国的自主决策在其中有一定作用，但更多的是一种时间性的耦合，中国顺势而为。", "chapter": "第七章 中国经济的崛起与世界秩序的失衡", "date": "2021-02-28", "color": null}, {"text": "大陆帝国与海洋帝国的两种不同战略选择：前者渴望着尽可能多的土地，将此定义为自己的根本利益，贸易是从属于土地的；后者则追求着更大的贸易机会，并努力通过对于海洋航道的控制以及对贸易规则的输出来获取利益，土地是从属于贸易的。", "chapter": "第二节 远东的力量格局", "date": "2021-02-27", "color": null}, {"text": "儒家尚德性，凝聚着理想；法家赏功能，规训着欲望，儒法二途通过士大夫政治而融合起来。", "chapter": "第三章 第二轮历史大循环：豪族社会", "date": "2021-02-23", "color": null}, {"text": "荀子熟悉典章制度，以君子为枢纽来兼综礼法[插图]，认为君子掌握礼义治道之本，文法吏则为治道之器，将礼与法安顿在不同的位阶上来构建总体秩序。", "chapter": "第三章 第二轮历史大循环：豪族社会", "date": "2021-02-23", "color": null}, {"text": "文明的冲突”", "chapter": "第七章 中国经济的崛起与世界秩序的失衡", "date": "2020-08-18", "color": null}, {"text": "消费着中国产品输出的诸多国家，通过向中国融资来获得消费力，但这种经济过程背后并没有稳定的政治基础，以便治理在此过程中形成的失衡，以至于国际社会在经济上丧失对中国产品的购买能力之前，可能会先丧失掉对中国出口的政治容忍度。", "chapter": "第二节 世界秩序的变迁与失衡", "date": "2020-08-18", "color": null}, {"text": "资本自由流动、汇率稳定和货币政策独立性这三个目标不可能同时达成。", "chapter": "第二节 世界秩序的变迁与失衡", "date": "2020-08-18", "color": null}, {"text": "让经济的回归经济、社会的回归社会、政治的回归政治、法律的回归法律，中国社会自会内生性地涌现出各种可能性，带给我们各种想象力。", "chapter": "第二节 世界秩序的变迁与失衡", "date": "2020-08-18", "color": null}, {"text": "双循环", "chapter": "第二节 世界秩序的变迁与失衡", "date": "2020-08-18", "color": null}, {"text": "大规模生产外包至少有两个技术性前提：一是大规模数据的处理能力，二是高速的信息传递能力。", "chapter": "第七章 中国经济的崛起与世界秩序的失衡", "date": "2020-08-18", "color": null}, {"text": "草原秩序与中原秩序深刻的互构关系。没有中原的统一，就不会有草原的崛起；而草原崛起形成巨大的军事压力，遂给中原带来巨大的财政压力。", "chapter": "第三章 第二轮历史大循环：豪族社会", "date": "2020-08-18", "color": null}, {"text": "儒家起自古代巫史系统的祭司官员，是礼的仪式过程的具体操作者与记录者。", "chapter": "第四节 思想的自由奔流", "date": "2020-08-18", "color": null}, {"text": "铁器与牛耕的出现，是春秋时期的重要技术进步，到了战国时期开始普遍应用。", "chapter": "第三节 封建的巅峰与瓦解", "date": "2020-08-18", "color": null}], "ideas": [{"content": "文明的冲突，这本书也值得一看。", "abstract": "文明的冲突”", "chapter": "", "date": "2020-08-18", "star": null}, {"content": "中美贸易战就是这个逻辑的结果。", "abstract": "消费着中国产品输出的诸多国家，通过向中国融资来获得消费力，但这种经济过程背后并没有稳定的政治基础，以便治理在此过程中形成的失衡，以至于国际社会在经济上丧失对中国产品的购买能力之前，可能会先丧失掉对中国出口的政治容忍度。", "chapter": "", "date": "2020-08-18", "star": null}, {"content": "需要强调的是，中国转换为新结构中的枢纽地位，并不是说中国从此成为世界的中心，而是说中国作为中介，使得全球经贸循环得以完成；但中国并未因此成为全球经济的首要发动机。在可预见未来，全球经济的首要发动机仍然是美国为主的西方世界，它拥有最强大的创新能力，也提供最重要的市场需求；但是这个首要发动机要拉动全球经济，却必须以中国作为一个必要中介。", "abstract": "双循环", "chapter": "", "date": "2020-08-18", "star": null}, {"content": "94年进行财税改革的时候，应该不能想到2000年的加入WTO以及互联网对信息管理效率提升带来的众包现象。", "abstract": "中国的经济奇迹，完全是依托于世界大势而成，中国的自主决策在其中有一定作用，但更多的是一种时间性的耦合，中国顺势而为。", "chapter": "", "date": "2020-08-18", "star": null}]}, {"id": "32764984", "title": "社会性动物（第12版）", "author": "艾略特·阿伦森 乔舒亚·阿伦森", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/984/32764984/s_32764984.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=fcb322c071f3f438fcb5e8c", "progress": 100, "finished": 1, "hlCount": 21, "ideaCount": 0, "highlights": [{"text": "社会比较（social comparison）： 通过与他人比较来评价自己的能力、成就、态度和其他属性的过程。社会影响（social influence）： 人们对他人的信念、情感和行为的影响。社会学习（social learning）： 通过观察他人来学习社会行为的过程。社会心理学（social psychology）： 研究人们的思想、感情和行为受他人真实的或暗示的存在影响的科学。", "chapter": "术语表", "date": "2021-04-08", "color": null}, {"text": "出丑效应（pratfall effect）： 一种值得关注的现象，即使一个人有很高的能力，一些易犯错误的证据也会增加他（她）的吸引力。", "chapter": "术语表", "date": "2021-04-08", "color": null}, {"text": "登门槛技术（foot-in-the-door technique）： 利用让人们提供较小的帮助来向他们进一步提出更大帮助请求的过程。", "chapter": "术语表", "date": "2021-04-08", "color": null}, {"text": "性爱（eros）： 弗洛伊德提出的人类所具有的生的本能。", "chapter": "术语表", "date": "2021-04-08", "color": null}, {"text": "情绪传染（emotional contagion）： 情绪或行为在人群中的快速传播。", "chapter": "术语表", "date": "2021-04-08", "color": null}, {"text": "赞扬和施惠的效果戴尔·卡内基建议他的读者，赢得朋友的一个好方法就是“慷慨地给予赞扬”。", "chapter": "8 喜欢、爱与联系", "date": "2021-04-08", "color": null}, {"text": "结果证实了我们所说的破绽效应：犯错误的优等生被评价为最有吸引力；犯同样错误的普通人被评价为最没有吸引力。完美的人（没有错误）在吸引力上名列第二位，平庸的人（没有错误）排在第三位。", "chapter": "8 喜欢、爱与联系", "date": "2021-04-07", "color": null}, {"text": "通过合作和相互依存减少偏见", "chapter": "7 偏见", "date": "2021-04-07", "color": null}, {"text": "一旦一个人把我们和他们区别开来，就会出现刻板印象、偏见、歧视和随之而来的合理化。群体保护机制和由此产生的群体偏见是一种生物的生存机制，促使我们偏爱自己的亲属和部落，并对外人保持警惕。", "chapter": "7 偏见", "date": "2021-04-07", "color": null}, {"text": "偏见是人类经验中最常见和最令人不安的固定习惯之一", "chapter": "7 偏见", "date": "2021-04-07", "color": null}, {"text": "同情心对人类生活至关重要，它是非人性化的解药。正如我们所看到的那样，如果大多数人将受害者非人化，以此作为对他们实施攻击行为的理由，那么通过在人们之间建立同情心，攻击行为将变得更加难以实施。", "chapter": "6 人类的攻击性", "date": "2021-04-07", "color": null}, {"text": "实验", "chapter": "2 社会认知", "date": "2021-04-07", "color": null}, {"text": "喜剧电视中的背景笑声无所不在，以致我们很难注意到，然而它们所传达的信息——其他人都发现了可笑的事——会深刻地影响着我们对同一件事情的反应。", "chapter": "4 从众", "date": "2021-04-07", "color": null}, {"text": "镜像神经元能够产生同理心，但一定不能保证：当人们看到自己不喜欢的人或比自己拥有更少权力和地位的人时，它们便会关闭。", "chapter": "4 从众", "date": "2021-04-07", "color": null}, {"text": "自尊与自恋", "chapter": "3 自我辩护", "date": "2021-04-07", "color": null}, {"text": "但是，如果你想让那个人形成一套价值观或信念，即使你不在场，他们也会按照这些价值观或信念行事，那么你就给那个人一个最小的奖励，这个奖励会带来你所希望看到的行为。让他们自我说服，这样确保他们在你离开房间之后的几年里还会继续做这些事情（或者不再做这些事情）。", "chapter": "3 自我辩护", "date": "2021-04-07", "color": null}, {"text": "简言之，没有威胁，就不会出现失调；没有失调，便不会去贬低他人。无论我们谈论的是电器还是恋人，一旦作出了某种坚定的承诺，人们便会倾向于关注自己所做选择的积极方面，而忽略自己所拒绝的其他选择的吸引力。", "chapter": "3 自我辩护", "date": "2021-04-07", "color": null}, {"text": "首因效应，指的是前期获取的信息比后期信息有更大的影响力。", "chapter": "2 社会认知", "date": "2021-04-07", "color": null}, {"text": "最幸福的人不是通过关注他人的行为来评价自己，而是通过调整和参考自己的内在成功标准来评价自己。", "chapter": "2 社会认知", "date": "2021-04-07", "color": null}, {"text": "社会比较是导致缺憾和不满情绪的主要原因", "chapter": "2 社会认知", "date": "2021-04-07", "color": null}, {"text": "对比效应与社会比较 一个物体可能看起来比它自身好，也可能比它自身差，这取决于我们用什么来衡量它。", "chapter": "2 社会认知", "date": "2021-04-07", "color": null}], "ideas": []}, {"id": "23723812", "title": "走到人生边上：自问自答（增订本）", "author": "杨绛", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/812/23723812/s_23723812.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=b9a325207169ff24b9a44bb", "progress": 93, "finished": 0, "hlCount": 12, "ideaCount": 9, "highlights": [{"text": "人性并未泯灭，乌云镶着金边。许多革命群众，甚至管教人员，虽然随着指挥棒也对我们这些“牛鬼蛇神”挥拳怒吼，实际不过是一群披着狼皮的羊。", "chapter": "三", "date": "2020-05-28", "color": null}, {"text": "因为悲痛是不能对抗的，只能逃避。", "chapter": "二", "date": "2020-05-28", "color": null}, {"text": "那年我十四岁，只是最低的一等工，工分是八分五。我拾鸡屎，也能挣工分，养了鸡卖蛋，也能挣钱。我家大门口有棵栀子树，栀子花开，又肥又大，我每天一清早采了花，摆渡过河到集市上去卖。我宁可少挣钱，只求卖得快，一分钱一朵，卖完就回家赚工分。", "chapter": "十二 她的自述", "date": "2020-05-28", "color": null}, {"text": "只有相信灵魂不灭，才能对人生有合理的价值观，相信灵魂不灭，得是有信仰的人。有了信仰，人生才有价值。", "chapter": "十一 人生的价值", "date": "2020-05-27", "color": null}, {"text": "所以受锻炼的是肉体，由肉体的媒介，锻炼出来的是精神。", "chapter": "十 受锻炼的是灵魂", "date": "2020-05-27", "color": null}, {"text": "灵性良心", "chapter": "八 人需要锻炼", "date": "2020-05-27", "color": null}, {"text": "天生万物，人为万物之灵。天地生人的目的，该是堪称万物之灵的人。人虽然渺小，人生虽然短促，但是人能学，人能修身，人能自我完善。人的可贵在人自身。", "chapter": "六 人类的文明", "date": "2020-05-27", "color": null}, {"text": "苏格拉底", "chapter": "六 人类的文明", "date": "2020-05-27", "color": null}, {"text": "性格决定，或由自由意志，值得追究。", "chapter": "四 命与天命", "date": "2020-05-27", "color": null}, {"text": "生死有命", "chapter": "四 命与天命", "date": "2020-05-27", "color": null}, {"text": "孔子常常说：“不患人之不己知，患不知人也。”我还要进一步说，患不自知也。", "chapter": "三 灵与肉的斗争和统一", "date": "2020-05-27", "color": null}, {"text": "灵性良心属于灵，“食色性也”属于肉，灵与肉是不和谐的。", "chapter": "二 有关人的问题", "date": "2020-05-27", "color": null}], "ideas": [{"content": "突然想到佛学里面的阿赖耶识", "abstract": "灵魂", "chapter": "", "date": "2020-05-27", "star": null}, {"content": "勒奈·笛卡尔(René Descartes，1596年3月31日于法国土伦省莱耳市-1650年2月11日逝于瑞典斯德哥尔摩)，法国哲学家、数学家、物理学家。", "abstract": "所以一位哲学家说：我思维，所以感觉到我的存在。", "chapter": "", "date": "2020-05-27", "star": null}, {"content": "笛卡尔说我思故我在。", "abstract": "所以一位哲学家说：我思维，所以感觉到我的存在。", "chapter": "", "date": "2020-05-27", "star": null}, {"content": "除了礼乐，还有运动的锻炼。", "abstract": "所以受锻炼的是肉体，由肉体的媒介，锻炼出来的是精神。", "chapter": "", "date": "2020-05-27", "star": null}, {"content": "在于礼乐。", "abstract": "修身之道", "chapter": "", "date": "2020-05-27", "star": null}, {"content": "活着的目的与意义就是不断让自己止于至善。通过格物而悟道，依大道做人。", "abstract": "要求世界和谐，首先得治理本国。要治国，先得齐家。要齐家，先得修身。要修身，先得正心，就是说，不能偏心眼儿。要摆正自己的心，先得有诚意，也就是对自己老老实实，勿自欺自骗。不自欺，就得切切实实了解自己。要了解自己，就得对自己有客观的认识，所谓格物致知。", "chapter": "", "date": "2020-05-27", "star": null}, {"content": "原来删诗是从3000多首3到305首啊。", "abstract": "当时流行的诗歌有三千多，孔子从中选了三百零五首", "chapter": "", "date": "2020-05-27", "star": null}, {"content": "春秋笔法", "abstract": "就是在左丘明的传记上，加上按语，用简约而恰当的一字、两字，或贬或褒，评点了某人某事的是与非、该或不该。他的评语真是一字千钧，能“使天下乱臣贼子惧”。", "chapter": "", "date": "2020-05-27", "star": null}, {"content": "有空也要读", "abstract": "自省录", "chapter": "", "date": "2020-05-27", "star": null}]}, {"id": "39457314", "title": "宇宙", "author": "卡尔·萨根", "cover": "https://cdn.weread.qq.com/weread/cover/54/YueWen_39457314/s_YueWen_39457314.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=371322e0725a12223719991", "progress": 98, "finished": 0, "hlCount": 19, "ideaCount": 0, "highlights": [{"text": "我们由星辰所铸，如今眺望群星", "chapter": "第十三章 谁为地球代言", "date": "2022-07-12", "color": null}, {"text": "人类的过往，也是意识逐渐觉醒，发现自己是更大群体一员的历史", "chapter": "第十三章 谁为地球代言", "date": "2022-07-12", "color": null}, {"text": "宇宙中可能有许许多多的智慧生物，但达尔文演化论告诉我们，人类只存在于这里，存在于这颗小小的行星。我们是濒临灭绝的珍稀物种。从宇宙角度来看，我们每一个人都很宝贵。即使有人不同意你的观点，也与他和平共处吧。因为就算踏遍千亿星系，你也找不出另一种人类来。", "chapter": "第十三章 谁为地球代言", "date": "2022-07-12", "color": null}, {"text": "我们由星尘所铸。我们的起源和演化与遥远的天体事件相关。探索宇宙的过程也是发现自我之旅。", "chapter": "第十三章 谁为地球代言", "date": "2022-07-12", "color": null}, {"text": "万物同源", "chapter": "第十一章 记忆挥之不去", "date": "2022-07-11", "color": null}, {"text": "美国生物学家罗杰·佩恩发现，两头鲸鱼能够利用深海频道，在世界的任何地方以20赫兹的频率进行交流。就是说一头在南极罗斯冰架的鲸鱼，可以跟阿留申群岛的同胞聊天。漫长的历史中，鲸鱼也许已经发展出了一种全球通信网络。没准隔着1.5万千米的深海，它们依然情歌对唱。", "chapter": "第十一章 记忆挥之不去", "date": "2022-07-11", "color": null}, {"text": "但如果宇宙是封闭的，光线无法逃逸，那完全可以说宇宙就是个大黑洞。想知道黑洞里什么模样，也许看看你周围就行了", "chapter": "第十章 永恒的尽头", "date": "2022-07-11", "color": null}, {"text": "印度教里有个迷人的观念，即宇宙不过是神的梦。梵天在百年过后，会陷入无梦的睡眠，宇宙也将因此消融。而另一个百年后，他会心头一凛，然后镇静下来做另一场宏大的宇宙之梦。其他地方还存在无数宇宙，都是不同神明做的宇宙之梦。这想象宏大玄妙，但被另一种或许更加伟大的观念所调和。有人说，也许人类不是神的梦，正相反，神才是人的梦。", "chapter": "第十章 永恒的尽头", "date": "2022-07-11", "color": null}, {"text": "宇宙是神奇的地方，它诞生了生命，但它同样毁灭星系、恒星与行星。宇宙既不仁慈，也不恶毒，只是对我们这样的小东西漠不关心。", "chapter": "第十章 永恒的尽头", "date": "2022-07-11", "color": null}, {"text": "有一些罕见的元素诞生于超新星爆发。地球拥有储量相对丰富的金和铀，这是因为太阳系形成前有许多超新星爆发。", "chapter": "第九章 恒星的一生", "date": "2022-07-10", "color": null}, {"text": "我们DNA里的氮、牙齿里的钙、血液里的铁，还有苹果派里的碳全部出自恒星内部。人类是由星际物质构成的。", "chapter": "第九章 恒星的一生", "date": "2022-07-10", "color": null}, {"text": "我们必须小心谨慎，以免温室效应失控：即便全球平均气温只升高一两度，也可能带来毁灭性的后果。", "chapter": "第四章 天堂和地狱", "date": "2022-07-09", "color": null}, {"text": "牛顿不打算掩饰这份自豪，他为万有引力定律写道：“我以此论证世界的结构。”", "chapter": "第三章 和谐世界", "date": "2022-07-09", "color": null}, {"text": "“我昔日测量天空，而今测量幽冥。天空心之所向，大地身之所往。”", "chapter": "第三章 和谐世界", "date": "2022-07-09", "color": null}, {"text": "不要以为我的工作全是单调无聊的数学计算——我还需要时间冥想，那给了我无上的快乐。", "chapter": "第三章 和谐世界", "date": "2022-07-09", "color": null}, {"text": "开普勒第三定律，是指行星周期（即它们绕轨一圈的时间）的平方，与它们和太阳的平均距离的立方成正比。", "chapter": "第三章 和谐世界", "date": "2022-07-09", "color": null}, {"text": "黄金是由超新星爆发产生的", "chapter": "第三章 和谐世界", "date": "2022-07-09", "color": null}, {"text": "物种演化需要在基因突变和自然选择中取得精确的平衡，才能展现出非凡的适应性。", "chapter": "第二章 宇宙的复调", "date": "2022-06-27", "color": null}, {"text": "细胞的复杂和优雅不亚于银河与群星。", "chapter": "第二章 宇宙的复调", "date": "2022-06-27", "color": null}], "ideas": []}, {"id": "26846974", "title": "一生家国：李光耀传奇", "author": "李克 郭江妮", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/974/26846974/s_26846974.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=7e9324a07199a6fe7e98f4b", "progress": 98, "finished": 0, "hlCount": 19, "ideaCount": 0, "highlights": [{"text": "“中国有自己的方式”，这是李光耀的第一个预言。他在书中说：“5000年来，中国人一直认为，只有中央强大，国家才能安全；中央软弱则意味着混乱和动荡。每个中国人都理解这一点，这也是中国人的根本原则。西方一些人希望中国变成西方传统意义上的民主国家，但这不会发生。中国是一个有着13亿人口的巨大国家，文化和历史都与西方不同，中国有自己的方式。”", "chapter": "新加坡的外交之道", "date": "2021-06-14", "color": null}, {"text": "李光耀后来在国会演讲时说，“有关当局能调查我并针对我的行为提出报告，证明了我所定下的制度是无私和有效的。这次事件也再次证明（在新加坡）没有人可以枉法”", "chapter": "新加坡的“霸道”家长", "date": "2021-06-14", "color": null}, {"text": "李光耀耐心地等待着收获季的到来。事实证明了李光耀的远虑是对的。他看到，年复一年，越来越多的华人家长选择把孩子送进英文学校接受教育。原因是，他们的子女在英文学校毕业后，就业的出路更广阔，职业前途更理想。", "chapter": "新加坡的“霸道”家长", "date": "2021-06-14", "color": null}, {"text": "他认为，外来的人才越多，不但不会抢本地人的饭碗，反而会促进新加坡经济增长，从而创造更多的就业机会。这确实是一种目光长远的思维。", "chapter": "新加坡的“霸道”家长", "date": "2021-06-14", "color": null}, {"text": "李光耀说过这样的一段话：“我强调自由只能存在于一个秩序井然的国家，一个斗争不断、处于无政府状态的混局，自由不可能存在。”", "chapter": "新加坡的“霸道”家长", "date": "2021-06-14", "color": null}, {"text": "在他看来，在新加坡推行过的所有城市建设计划中，城市绿化的效益最高。", "chapter": "新加坡的“霸道”家长", "date": "2021-06-14", "color": null}, {"text": "从成立之初起，三方代表都同意遵守一个原则：加薪幅度不能大于生产力的提高。", "chapter": "新加坡的“霸道”家长", "date": "2021-06-14", "color": null}, {"text": "李光耀留了个心，他嘱咐相关部门，要定期地好好保养从新加坡的机场到酒店，和到总理公署的道路，在两旁种满灌木和乔木，使道路两旁整洁美观。", "chapter": "新加坡的“霸道”家长", "date": "2021-06-14", "color": null}, {"text": "有时候李光耀会想，这些以前的帝国花了很长的时间在殖民时代建立社会秩序，发展贸易和投资，中间却又畏缩退场，而美国、日本的投资者大举进入，“这等于把自己犁过的土地白白送给别人来播种。”", "chapter": "新加坡的“霸道”家长", "date": "2021-06-14", "color": null}, {"text": "李光耀和同事们制定了双管齐下的策略以打开局面，不外乎两条：一是大力兴建新加坡的基建设施，创造良好的投资环境；再就是大力招商引资了。", "chapter": "新加坡的“霸道”家长", "date": "2021-06-14", "color": null}, {"text": "李光耀可不认为英国人的慷慨对马耳他人是一件好事，在他看来，虽然过得了一时，但过不了一世。这么一来，人民的自力更生精神没了，却养成了依赖心和惰性。", "chapter": "新加坡的“霸道”家长", "date": "2021-06-14", "color": null}, {"text": "也正是由于共产党人在殖民地的法律之外，组织群众进行了一系列的暴力对抗，给殖民地当局造成很大的压力和麻烦，这时两厢对比之下，英国人的殖民地政府对于李光耀这样的温和反对派的接受度就增加了。换句话说，英国人倒更愿意向李光耀所代表的温和派屈服，而不是共产党人和左翼人士。", "chapter": "从殖民地居民到国父", "date": "2021-06-14", "color": null}, {"text": "他对英国式的政治运作方式欣赏得不得了，但又认为这种方式还存在着诸多问题，比如低效、高福利导致社会的懒惰。在李光耀的理想中，新加坡既不要搞苏联的那种社会主义，也不要照搬英国人的那一套。", "chapter": "从殖民地居民到国父", "date": "2021-06-13", "color": null}, {"text": "1952年李光耀的大儿子李显龙出世。出于对三一法学院的感情，李光耀果然写信给三一法学院的高级导师，给儿子预订了一个学校名额，而李显龙后来也果然进入三一法学院就读。", "chapter": "在历史巨变中成长", "date": "2021-06-13", "color": null}, {"text": "正因为其中的廓尔喀战俘不屈的面貌给李光耀留下很深刻的印象，新加坡政府从60年代起，就开始雇佣一定数量的廓尔喀雇佣兵当防暴警察，维持新加坡治安。", "chapter": "在历史巨变中成长", "date": "2021-06-13", "color": null}, {"text": "在中国的明末清初，由于清军入关，击败明朝军队，导致大量的战争难民、抗清失败的明军余部、被清兵打散的农民军，以及不愿被清朝统治的旧明遗民，为了躲避战乱，纷纷逃亡出大陆，这就掀起了波澜壮阔的移民东南亚的高潮。", "chapter": "引子：华人的南洋", "date": "2021-06-13", "color": null}, {"text": "在中国近代史上，为众人熟知的，有三次大的移民潮，分别是“闯关东”、“走西口”、“下南洋”。", "chapter": "引子：华人的南洋", "date": "2021-06-13", "color": null}, {"text": "一方面李光耀崇尚英式的精英民主政治，另一方面他又把这种精英文化与东方儒家教化式的治理方式结合起来，形成一种有法可循、有规可依的家长式领导。", "chapter": "序言", "date": "2021-06-13", "color": null}, {"text": "自1959年6月起，担任新加坡总理长达31年又5个月。", "chapter": "李光耀纪事年表", "date": "2021-06-13", "color": null}], "ideas": []}, {"id": "3300148591", "title": "中国心法：用传统智慧解答人生关键问题", "author": "赵昱鲲", "cover": "https://cdn.weread.qq.com/weread/cover/0/cpplatform_rggnxlzogdmaknb4uxwwxc/s_cpplatform_rggnxlzogdmaknb4uxwwxc1749725158.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=65732290813aba08bg011a62", "progress": 60, "finished": 0, "hlCount": 18, "ideaCount": 1, "highlights": [{"text": "李泽厚先生干脆把整个中国文化都归结为“情本体”，即中国文化传统以“情”为“人生的真谛、存在的真实、最后的意义”。", "chapter": "第六章 情理交融：理性思考，情感用事", "date": "2025-09-01", "color": 1}, {"text": "因为工业时代的人们热衷于追求物质、名声、外表等外在目标，而忽略了乐于人生本身这一内在目标。", "chapter": "第五章 人本善：人间值得，人生值得", "date": "2025-09-01", "color": 1}, {"text": "因此，“乐”的关键不在于你从一件事情中得到多少积极情绪，而在于你做这件事情是出于内在动机，也就是做一件事情就是因为你喜欢、享受这件事情本身，而不是因为这件事情带来的其他好处。", "chapter": "第五章 人本善：人间值得，人生值得", "date": "2025-09-01", "color": 1}, {"text": "著名哲学家李泽厚先生提出，中国文化跟日本文化、西方文化都不一样，他把它称为“乐感文化”。", "chapter": "第五章 人本善：人间值得，人生值得", "date": "2025-09-01", "color": 1}, {"text": "这个方法叫“三件好事”，很简单，就是每天晚上你写下当天发生的三件好事。不用是升职、加薪、结婚、生子那样的大事，可以是日常生活中常见的“小确幸”", "chapter": "第五章 人本善：人间值得，人生值得", "date": "2025-09-01", "color": 1}, {"text": "不迁怒，不贰过。", "chapter": "第四章 中庸之道：不走极端，不求完美", "date": "2025-09-01", "color": 1}, {"text": "我在本书中采用传统的中国立场，“以人为本，以学为用”，只要能够让人变得更好，那不管是东方的还是西方的，我们就都拿来用。", "chapter": "第一章 中国文化助现代人走出心理困境", "date": "2025-09-01", "color": 1}, {"text": "修身、克己、节制、责任", "chapter": "第一章 中国文化助现代人走出心理困境", "date": "2025-09-01", "color": 1}, {"text": "中国人就会觉得，如果没有我们人类的香火供奉，神也会饥寒交迫。", "chapter": "第一章 中国文化助现代人走出心理困境", "date": "2025-09-01", "color": 1}, {"text": "人类经常是欲望大于喜欢，想要的东西很多，但真正喜欢的相对较少", "chapter": "第一章 中国文化助现代人走出心理困境", "date": "2025-09-01", "color": 1}, {"text": "但近年来的研究发现，多巴胺带来的不是快乐本身，而是对快乐的期待。", "chapter": "第一章 中国文化助现代人走出心理困境", "date": "2025-09-01", "color": 1}, {"text": "“伊卡洛斯陷阱”听上去只是一个比喻。毕竟，没有一只鸭子能活着逃出南京，没有一个浮士德能拒绝魔鬼的诱惑，也没有一个希腊神话能免于被心理学家过度诠释。", "chapter": "第一章 中国文化助现代人走出心理困境", "date": "2025-09-01", "color": 1}, {"text": "同样地，如果你获取了一堆信息，却不用来解决你的现实问题，那大脑也会变得“肥胖”，即混乱、冗余、功能低下。", "chapter": "第一章 中国文化助现代人走出心理困境", "date": "2025-09-01", "color": 1}, {"text": "适量接触危险，可以使人变得更强壮。一味躲避危险的过度保护，反而使人更加脆弱。", "chapter": "第一章 中国文化助现代人走出心理困境", "date": "2025-09-01", "color": 1}, {"text": "基因仍然在那里默默地发挥着它盲目的强大力量。", "chapter": "第一章 中国文化助现代人走出心理困境", "date": "2025-09-01", "color": 1}, {"text": "“食色性也”，食如此，色也一样。", "chapter": "第一章 中国文化助现代人走出心理困境", "date": "2025-09-01", "color": 1}, {"text": "“超常刺激”：原本进化出来帮助动物的正常刺激其强度远远超过了生存所需，但由于基因是盲目的，动物无法意识到此时这些刺激已经对自己有害了，所以仍然会以超常的热情响应。", "chapter": "第一章 中国文化助现代人走出心理困境", "date": "2025-09-01", "color": 1}, {"text": "多年前我就相信，财务自由、时间自由、心灵自由是我们在人生路上追求的三大自由。", "chapter": "赞誉", "date": "2025-09-01", "color": 1}], "ideas": [{"content": "尽人事，听天命", "abstract": "强打精神，强颜欢笑", "chapter": "第五章 人本善：人间值得，人生值得", "date": "2025-09-01", "star": null}]}, {"id": "23914003", "title": "苦难英雄任正非", "author": "王育琨", "cover": "https://cdn.weread.qq.com/weread/cover/84/YueWen_23914003/s_YueWen_23914003.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=b4a32c20716ce613b4a1b9d", "progress": 100, "finished": 1, "hlCount": 18, "ideaCount": 0, "highlights": [{"text": "血性是会夭折的，所以需要养护，需要培育；血性也是会沉睡的，所以需要唤醒，需要点燃。牺牲是军人最大的付出，但不是军人的最高奉献。军人的最高奉献是胜利。灵魂赋予尊严，血性赢得光荣；灵魂与血性永远是军人的脊梁、胜利的刀锋。", "chapter": "1．“铁三角”背景下的机制变革", "date": "2022-06-28", "color": null}, {"text": "授权不是分权，授出去的是决策权，保留下来的是监督权。", "chapter": "管住边界，简化考核，重塑共同的奋斗精神——在华为人力资源管理纲要2.0沟通会上的讲话", "date": "2022-06-28", "color": null}, {"text": "华为能量方程式=愿景目标×专注死磕×拿出绝活", "chapter": "2．华为灰度的自由和进取精神", "date": "2022-06-28", "color": null}, {"text": "中庸是强调每一个时点都要保持动态平衡。保持不了动态平衡的事物，就面临死亡。", "chapter": "1．灰度哲学的缘起与内涵", "date": "2022-06-28", "color": null}, {"text": "被赋予高度精神力量的人，过着思想丰富、多姿多彩、充满生命活力和意义的人生，其自身就承载着最高尚的乐趣之源。", "chapter": "1．灰度哲学的缘起与内涵", "date": "2022-06-28", "color": null}, {"text": "思想是一柄双刃剑。想不通，就纠结和抑郁；想通了，可以从高处俯瞰惹你烦心的事，“烦事”反而成了营养的能源。", "chapter": "1．灰度哲学的缘起与内涵", "date": "2022-06-28", "color": null}, {"text": "连动物都知道内涵第一，俗人却偏偏看重虚名。世俗看重外形和名利权的光环。", "chapter": "3．他的身上有哀骀它的影子", "date": "2022-06-28", "color": null}, {"text": "当下的危难或至暗时刻，是注定要来成全我的，是注定要来磨砺我的，让我愈加坚韧与平和。", "chapter": "导引 至暗时刻，原力觉醒", "date": "2022-06-28", "color": null}, {"text": "一个深刻的灵魂，即使痛苦也是美的。——黑格尔", "chapter": "导引 至暗时刻，原力觉醒", "date": "2022-06-28", "color": null}, {"text": "一、不要做一个完人，做完人很痛苦的。要充分发挥自己的优点，使自己充满信心去做一个有益于社会的人。", "chapter": "我的优点与缺点", "date": "2022-06-28", "color": null}, {"text": "我的观察和体会，就是该干什么就干什么。无论什么事和难题，只要到了你的头上，就全心全意把它干好、解决好，哪怕是你不喜欢的，哪怕是你厌恶的。这是上苍来敲你激发潜能的门，你还有你不知道的天赋潜能。", "chapter": "3．他的身上有哀骀它的影子", "date": "2022-06-28", "color": null}, {"text": "那些可以战胜自己的人，可以战胜自是、自负、自矜、自傲、自闭的人，才是真正的强者。", "chapter": "3．他的身上有哀骀它的影子", "date": "2022-06-28", "color": null}, {"text": "不自是，不自夸，不自傲，不自矜，不自闭，成为天下谷，成为天下溪，成为天下势，所有高处的能量向华为聚集而来。", "chapter": "3．他的身上有哀骀它的影子", "date": "2022-06-28", "color": null}, {"text": "“价廉物美是个伪命题”，很切中时弊。商家只拼低价，可能带来市场上的灾难。", "chapter": "3．他的身上有哀骀它的影子", "date": "2022-06-28", "color": null}, {"text": "为无为，事无事，味无味。大小多少，报怨以德。图难于其易，为大于其细。天下之难作于易，天下之大作于细。是以圣人终不为大，故能成其大。夫轻诺必寡信，多易必多难。是以圣人犹难之，故终于无难。", "chapter": "3．他的身上有哀骀它的影子", "date": "2022-06-28", "color": null}, {"text": "去领导化、去科层、去审批、去岗位，一切数据驱动，一切都在阳光下，全员对准利润目标，利润目标对准全员。贪腐怠惰藏无处藏，躲无处躲", "chapter": "3．他的身上有哀骀它的影子", "date": "2022-06-28", "color": null}, {"text": "层次三：保持原力觉醒，形成正向能量场。", "chapter": "3．他的身上有哀骀它的影子", "date": "2022-06-28", "color": null}, {"text": "大智慧的人，自然而然，率性而为，抱素守朴，无欲、无事、无为、无我，使别人自发自动激发潜能，而且让喜悦、畅快和创意泉涌，成就他人的自性爆发，生万法", "chapter": "3．他的身上有哀骀它的影子", "date": "2022-06-28", "color": null}], "ideas": []}, {"id": "44026191", "title": "纳瓦尔宝典", "author": "埃里克·乔根森", "cover": "https://cdn.weread.qq.com/weread/cover/89/YueWen_44026191/s_YueWen_44026191.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=e1e32b00729fc94fe1e824d", "progress": 100, "finished": 1, "hlCount": 14, "ideaCount": 4, "highlights": [{"text": "我精读的书其实并不多。我会略读很多书，但精读的只有几本，而这几本书构成了我知识的基础。", "chapter": "第二章 增强判断力", "date": "2023-06-20", "color": 5}, {"text": "阅读自己喜欢的题材，直到热爱阅读。读书的唯一原因应该是喜欢，不需要其他任何理由。", "chapter": "第二章 增强判断力", "date": "2023-06-20", "color": 5}, {"text": "从本质上说，人类是无知的，是极不善于预测未来的。[4]", "chapter": "第二章 增强判断力", "date": "2023-06-20", "color": 5}, {"text": "普通人把时间浪费在短期思考上，浪费在毫无价值的繁重工作上。而巴菲特会用一年斟酌判断，然后用一天采取行动。他一天的行动可以影响未来几十年。", "chapter": "第一章 积累财富", "date": "2023-06-20", "color": 1}, {"text": "任何时刻都是独一无二的。每一刻都转瞬即逝，时光是抓不住的。[4]你每时每刻都在死亡和重生。是遗忘还是牢记，取决于你自己。[2]", "chapter": "第五章 哲学", "date": "2023-06-20", "color": 1}, {"text": "勇气不是在枪林弹雨中冲锋陷阵，而是不在乎别人怎么想。", "chapter": "第四章 自我救赎", "date": "2023-06-20", "color": 1}, {"text": "从愤怒中解脱的自由，从悲伤中解脱的自由，无须做出反应的自由，无须被迫做事的自由，", "chapter": "第四章 自我救赎", "date": "2023-06-20", "color": 1}, {"text": "冥想是屏蔽社会的噪声，倾听自己的声音。只有以冥想本身为目的，冥想才会“起作用”。徒步旅行是行走冥想。写日记是书写冥想。冲澡是意外冥想。静坐是直接冥想。", "chapter": "第四章 自我救赎", "date": "2023-06-20", "color": 1}, {"text": "最了不起的超能力就是改变自我的能力。", "chapter": "第四章 自我救赎", "date": "2023-06-20", "color": 1}, {"text": "我学到的第四种冥想方法是，坐在那里闭上眼睛，每天至少一个小时。此时，你以臣服的姿态接受发生的一切，不争取，不对抗。如果有想法在头脑中涌现，那就任其涌现。", "chapter": "第四章 自我救赎", "date": "2023-06-19", "color": 1}, {"text": "如果你问贝赫扎德有什么幸福的秘诀，他只会抬头望天，然后说：“停止追问，开始欣赏。”", "chapter": "第三章 学习幸福", "date": "2023-06-12", "color": 1}, {"text": "嫉妒是一种很难克服的情绪。", "chapter": "第三章 学习幸福", "date": "2023-06-12", "color": 1}, {"text": "我们的根本错觉是：总有一样东西会让我一直满足、永远快乐。", "chapter": "第三章 学习幸福", "date": "2023-06-12", "color": 1}, {"text": "如果认为通过改变外部世界就能获得内心的平静、永久的开心、应得的幸福，那本质上就是痴心妄想。每个人都深受这种想法的毒害，包括我自己。我们一遍又一遍地坚持着自己的执念，认为“等得到那个东西，我就快乐了”。这就是一个我们时时刻刻都在犯的根本错误。[4]", "chapter": "第三章 学习幸福", "date": "2023-06-12", "color": 1}], "ideas": [{"content": "是人必死，死期不定，死亡方式不定，唯一拥有的是当下", "abstract": "只因在劫难逃", "chapter": "第五章 哲学", "date": "2023-06-20", "star": null}, {"content": "宇宙就是你，你就是宇宙，所以你必须创造出自己的意义", "abstract": "一个人必须创造自己人生的意义。", "chapter": "第五章 哲学", "date": "2023-06-20", "star": null}, {"content": "生命处于有无之间", "abstract": "第二个答案：生命没有意义，生活没有目的。", "chapter": "第五章 哲学", "date": "2023-06-20", "star": null}, {"content": "减少了不必要的欲望", "abstract": "而现在，我追求的是内在的自由，“无忧无虑即自由”。", "chapter": "第四章 自我救赎", "date": "2023-06-20", "star": null}]}, {"id": "921030", "title": "中国文化的深层结构", "author": "孙隆基", "cover": "https://cdn.weread.qq.com/weread/cover/53/yuewen_921030/s_yuewen_9210301707287100.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=86132be05e0dc6861100607", "progress": 67, "finished": 0, "hlCount": 17, "ideaCount": 0, "highlights": [{"text": "张国焘以中央代表的身份到了鄂豫皖苏区后，为了立威，也将创立该苏区的一批有经验的干部几乎全部杀光。", "chapter": "（四）不发展的“个人”对别人的伤害", "date": "2021-04-30", "color": null}, {"text": "康德的文化同乡尼采，即对此提出警惕：只要是出现牺牲、服务以及仁爱的眼光的场合，那里就同时有欲主宰别人的意志。", "chapter": "（四）不发展的“个人”对别人的伤害", "date": "2021-04-30", "color": null}, {"text": "中国人之生男育女，有“养儿防老”的构想。这个方针，就是中国人将人“工具化”的最原初的模型，它决定了其后的一切人际关系的模式。", "chapter": "（四）不发展的“个人”对别人的伤害", "date": "2021-04-30", "color": null}, {"text": "中国人的文化行为倾向于把“人”变成工具，而不是当作目的。", "chapter": "（四）不发展的“个人”对别人的伤害", "date": "2021-04-30", "color": null}, {"text": "可惜，中国人搞“自我扩张”，就必须做“人上人”，而不能像西方人那般，在同一个平面上让每一个“个人”都有“自我扩张”的权利。", "chapter": "（二）自我压缩的人格", "date": "2021-04-30", "color": null}, {"text": "美国人倾向于站在“个体化”的角度去对待“人”，也是站在这个立足点上去交朋友。然而，中国人则倾向于将人“类型化”，因此，不只将洋人“类型化”，也将自己“类型化”，结果，就下意识地将自己这个“个体”放入了一个较“低级”的“类”中。", "chapter": "（二）自我压缩的人格", "date": "2021-04-30", "color": null}, {"text": "老子说：“五色令人目盲，五音令人耳聋，五味令人口爽；驰骋田猎令人心发狂；难得之货令人行妨。是以圣人为腹不为目，故去彼取此。”[插图]老子提倡的这种半死亡状态，也是中国人植物化状态的最佳写照。", "chapter": "（二）自我压缩的人格", "date": "2021-04-30", "color": null}, {"text": "在中国这个“非性化”的社会中，就多少会使人觉得：这些非洲人与阿拉伯人有一点儿“动物化”。然而，如果站在这些人的立场看问题，就可能会觉得中国人多少地有一点儿“植物化”。", "chapter": "（二）自我压缩的人格", "date": "2021-04-30", "color": null}, {"text": "中国人“自我压缩的人格”的另一个表现，就是对世界采取“静”的态度。", "chapter": "（二）自我压缩的人格", "date": "2021-04-30", "color": null}, {"text": "像这种“一人”的活命哲学，与“存天理，灭人欲”这类“二人”的“死亡崇拜”，其实是相辅相成的。因为，要求一个人不要在生命中放光放热，只图保住臭皮囊，就是要他以“死”的方式去“活”。因此，这种“好死不如赖活”，其实也是一种慢性死亡。", "chapter": "（二）自我压缩的人格", "date": "2021-04-30", "color": null}, {"text": "道家哲学源自杨朱的“拔一毛以利天下不为也”的前提，就是连“身体”上的一根毛也比“身外”之物重要。", "chapter": "（二）自我压缩的人格", "date": "2021-04-30", "color": null}, {"text": "这种不要有“灵魂”的事业，不要让自己放光放热，只图保住臭皮囊，使它“可以尽年”的活命哲学，基本上是一种“身体化”的哲学——它的格调是十分低的。", "chapter": "（二）自我压缩的人格", "date": "2021-04-30", "color": null}, {"text": "在中国式的政治中，只有“仁者”才是“无敌”的。", "chapter": "（二）自我压缩的人格", "date": "2021-04-30", "color": null}, {"text": "因为，中国人凡涉及“一人”之“身”，总倾向于不让它突出于群众之外，大家不去做的事自己就不会去做，因此即使搞政治也躲在“群众”堆里。", "chapter": "（二）自我压缩的人格", "date": "2021-04-30", "color": null}, {"text": "毫不利己，专门利人”听起来是至为冠冕堂皇的。然而，世界上的事情却往往反其道而行。的确，一个人如果不十二分地爱自己，就不会尽量设法使自己“可爱”，因此这样的人基本上就是没有什么可爱", "chapter": "（二）自我压缩的人格", "date": "2021-04-30", "color": null}, {"text": "为了维持“和合”，就必须要求每一个“个体”做“自我压缩”，亦即是用“灭人欲”的方式去“存天理”。", "chapter": "（二）自我压缩的人格", "date": "2021-04-30", "color": null}, {"text": "在中国人之间常见的一个现象是：当自己的小孩子与邻家小孩子在打架时，父母将他们拆开后，总是先打自己的小孩子，也不管正义在何方。这种“做人”方式，其结果自然是使孩子也形成自我压缩的人格，认为自己的利益是不合法的，事事去迎合别人。其效果还包括见风使舵、不顾原则。", "chapter": "（二）自我压缩的人格", "date": "2021-04-30", "color": null}], "ideas": []}, {"id": "914613", "title": "千年金融史：金融如何塑造文明，从5000年前到21世纪", "author": "威廉·戈兹曼", "cover": "https://cdn.weread.qq.com/weread/cover/76/YueWen_914613/s_YueWen_914613.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=b3c32a205df4b5b3c640369", "progress": 100, "finished": 1, "hlCount": 17, "ideaCount": 0, "highlights": [{"text": "像卡尔·马克思这样的思想家偶尔也设想过消除货币和公司这样的金融机构，尽管这些建议呼吁发乎内心，但如果让金融工具倒退回从前的状态，就意味着我们要回到没有城市和大规模民族国家时的生活方式。", "chapter": "结论", "date": "2021-04-09", "color": null}, {"text": "还记得凯恩斯预言的国家投资基金终将取代个人投资者吗？一些国家设立了主权财富基金，这使得该预言正逐渐变为现实。", "chapter": "第29章 金融的未来何在", "date": "2021-04-09", "color": null}, {"text": "历史数据成为股票投资长期收益率的极佳预言者", "chapter": "第29章 金融的未来何在", "date": "2021-04-09", "color": null}, {"text": "可以预期，执行社保制度后，两代人一起生活的家庭会更少。当政府，而不是子女成为社会保险的主要形式时，人们会要更少的孩子。", "chapter": "第28章 再造未来", "date": "2021-04-09", "color": null}, {"text": "有效市场理论和诸如道氏理论等市场可预测理论的信徒之间的分裂，将投资市场分为了价值投资和技术投资这两大派别。", "chapter": "第27章 新金融世界", "date": "2021-04-09", "color": null}, {"text": "我们应该认真考虑，也许曼哈顿建造的摩天大楼才是真正的泡沫，它是由对债券的需求驱动的，而不是由对摩天大楼这个让土地升值的惊人的新机器的需求驱动的。", "chapter": "第27章 新金融世界", "date": "2021-04-09", "color": null}, {"text": "不幸的是，费雪是在1929年夏天做出的这一预测，美国公众永远也不会忘记它。欧文·费雪不仅失去了自己的毕生积蓄，同时也失去了他姻亲的储蓄，而且他非常后悔鼓动了全美的小投资者跟随他一起投资。", "chapter": "第27章 新金融世界", "date": "2021-04-09", "color": null}, {"text": "当就业率下降、前景黯淡时，人们储蓄更多、消费更少，从而导致就业率进一步下降。凯恩斯认为，政府行动可以改变这种循环：降低利率可以刺激投资，在极端情况下，如大萧条时期，能够增加就业机会的政府工程项目可以刺激需求，从而促进生产和就业。政府可以帮助经济摆脱停滞状态。", "chapter": "第26章 凯恩斯的救赎", "date": "2021-04-09", "color": null}, {"text": "买办不只提供了很多专业知识，而且提供了19世纪晚期通商口岸商业发展的资本", "chapter": "第24章 中国的金融家", "date": "2021-04-08", "color": null}, {"text": "在维多利亚时代，资本市场在短短几十年间扩散到全球：比任何宗教扩散得都要快。", "chapter": "第23章 马克思和市场", "date": "2021-04-08", "color": null}, {"text": "生产力的提高和失业的循环，导致资本主义经济出现周期性危机。", "chapter": "第23章 马克思和市场", "date": "2021-04-08", "color": null}, {"text": "政府债券这一诞生于威尼斯的发明，历经几个世纪的发展后，最终出现了一个国家的债券能被另一个国家的国民持有的情况。殖民化便是这种金融制度的后果", "chapter": "第四部分 全球市场的出现", "date": "2021-04-08", "color": null}, {"text": "美国人关于房地产证券化的冒险是从土地银行开始的。当土地银行的想法在欧洲基本维持在理论阶段时，在18世纪的北美却成为现实。", "chapter": "第22章 始于荷兰：新的世界金融市场", "date": "2021-04-08", "color": null}, {"text": "土地资产证券化的概念源自18世纪的金融构想。", "chapter": "第22章 始于荷兰：新的世界金融市场", "date": "2021-04-08", "color": null}, {"text": "约翰·劳", "chapter": "第20章 法国的泡沫", "date": "2021-04-08", "color": null}, {"text": "复利计算的想法来自何处？一种可能性是，它来自苏美尔经济体系中另一种具有内在指数级增长性质的基本产品：牲畜。无论是绵羊、山羊、奶牛还是公牛，其重要性都是不言而喻的：它们可以提供肉类、羊毛、乳制品，还有权力。", "chapter": "第2章 居民、契约和利息：金融与城市化", "date": "2021-04-08", "color": null}, {"text": "拥有360天的一年也使利息的计算非常方便。事实上，即使在今天，企业债券和市政债券也是基于360天为一年计息的。", "chapter": "第一部分 从楔形文字到古典文明", "date": "2021-04-08", "color": null}], "ideas": []}, {"id": "45369847", "title": "打开心智", "author": "李睿秋", "cover": "https://cdn.weread.qq.com/weread/cover/27/YueWen_24434684401178106/s_YueWen_24434684401178106.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=d13322c072b449f7d13b204", "progress": 100, "finished": 1, "hlCount": 15, "ideaCount": 2, "highlights": [{"text": "当我们从任务A切换到任务B时，如果A还没有做完，那么它就会有一部分残留在我们的脑海中，叫作“注意残留”，占用我们的认知资源，使得我们能够处理任务B的资源减少。", "chapter": "五个技巧，让你效率爆表", "date": "2023-03-22", "color": 1}, {"text": "试试让自己接受“意志力无限”的设定，将思维转变成：终于干完今天的活了，又有一段自由支配的时间，可以去做真正想做的、重要而不紧急的事情了。这会让你的生活变得更充实，更有“获得感”。", "chapter": "意志力真的存在吗？", "date": "2023-03-22", "color": 1}, {"text": "而焦虑的本质其实就是对于不确定性的恐惧。", "chapter": "稳定：拖累成长脚步的元凶", "date": "2023-03-22", "color": 1}, {"text": "它就会转向内部，开始通过DMN模式漫无目的地反刍，从而让你陷入不安定的情绪波动之中。", "chapter": "如何有效地休息", "date": "2023-03-22", "color": 1}, {"text": "，抑郁症的重要成因之一，就是这个负面循环", "chapter": "意义和兴趣：怎样找到喜欢的事情", "date": "2023-03-22", "color": 1}, {"text": "我们学习时间管理，最本质的目的，是为了尽量减少自己在各种日常事务上的消耗，尽量不去做不必要的事情，从而抽出更多的时间，去陪伴我们的家人，追求自己的梦想，享受生命的美好，体验不同的景致，去做我们真正想做的事情。", "chapter": "意义和兴趣：怎样找到喜欢的事情", "date": "2023-03-22", "color": 1}, {"text": "很多问题的本质，其实都是动力与阻力的博弈。动力超过阻力，改变就会发生，行为就会成立，反之，就会停滞——道理就是这么简单。", "chapter": "四个思维模型，看透事物本质", "date": "2023-03-22", "color": 1}, {"text": "成长就是不断地把“费力”的事情，变得不再费力。这背后的机制，就是大脑调整了自己的心智模型，把更多的资源集中在对应的功能上，让我们能够更好地去适应环境、处理环境。", "chapter": "预测：喂给大脑什么，它就会变成什么", "date": "2023-03-22", "color": 1}, {"text": "原因就在于：大脑通过你喝水和吃巧克力的动作，预测到身体很快能够得到水分和糖分的补充，于是消除了内部发出的饥渴信号，让我们能够更快地用更好的状态去行动。", "chapter": "预测：喂给大脑什么，它就会变成什么", "date": "2023-03-22", "color": 1}, {"text": "2022年的一项研究发现，大脑预测的素材，来自大约前15秒内我们所看到的信息的整合。也就是说，大脑每一瞬间，都在不断分析我们在15秒内看到的信息，通过这些信息预测我们在第16秒会看到什么，并把这个预测的结果呈现给我们，让我们以为这是我们实际所看到的", "chapter": "预测：喂给大脑什么，它就会变成什么", "date": "2023-03-22", "color": 1}, {"text": "我们的世界，其实是一个幻象", "chapter": "预测：喂给大脑什么，它就会变成什么", "date": "2023-03-22", "color": 1}, {"text": "大约是100毫秒。也就是说，我们实际看到的世界，其实是它在100毫秒之前的状态。", "chapter": "预测：喂给大脑什么，它就会变成什么", "date": "2023-03-22", "color": 1}, {"text": "它就像一颗星星，孤独地悬在无垠的幽暗宇宙之中，陪伴着它的只有其他无数颗星星所带来的引力。", "chapter": "预测：喂给大脑什么，它就会变成什么", "date": "2023-03-22", "color": 1}, {"text": "但大脑其实只是孤零零地悬浮在一片黑暗之中，环绕着它的只有来自860亿个神经元此起彼伏的电信号。大脑就是依靠这些电信号，理解着周围世界的一切", "chapter": "预测：喂给大脑什么，它就会变成什么", "date": "2023-03-22", "color": 1}, {"text": "大脑最基本的原理，是节能。", "chapter": "节能：为了不思考，人类什么都做得出来", "date": "2023-03-18", "color": 1}], "ideas": [{"content": "应该是找到了正反馈", "abstract": "我一直强调：一个人为什么能持续、长期地做一件事情？一定是因为你“乐在其中”", "chapter": "反馈缺失：如何战胜短期诱惑", "date": "2023-03-22", "star": null}, {"content": "很美妙的理解", "abstract": "大约是100毫秒。也就是说，我们实际看到的世界，其实是它在100毫秒之前的状态。", "chapter": "预测：喂给大脑什么，它就会变成什么", "date": "2023-03-22", "star": null}]}, {"id": "35942751", "title": "小习惯", "author": "吉井雅之", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/751/35942751/s_35942751.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=49832e007224715f4985ac0", "progress": 64, "finished": 1, "hlCount": 14, "ideaCount": 3, "highlights": [{"text": "循序渐进，一点一点地增加难度。", "chapter": "054 坚持好习惯⑹健身 关键在于循序渐进", "date": "2021-04-08", "color": null}, {"text": "写日记也是一样的。如果“为了自己”难以坚持下去，那就将目标设定成“为了将来给家人看”“为了让重要的人了解自己”，这也是把习惯坚持下去的方法之一。", "chapter": "050 坚持好习惯⑵写日记 1个字也OK，还可以试试“交换日记”", "date": "2021-04-08", "color": null}, {"text": "我们的大脑是属于我们自己的，所以请不必有顾虑，大胆地去欺骗它吧。", "chapter": "046 欺骗大脑，养成“确信习惯” 向大脑提出正面问题", "date": "2021-04-08", "color": null}, {"text": "只要是人类的大脑认为“能做到”的事情，就全都能做到。也就是说，只要让大脑养成不管面对多么困难的事情都相信“我肯定能做到”的确信习惯，任何人就都能够实现梦想，取得成功。", "chapter": "046 欺骗大脑，养成“确信习惯” 向大脑提出正面问题", "date": "2021-04-08", "color": null}, {"text": "回忆“曾经使自己感到兴奋的事情”。", "chapter": "045 寻找“曾经使自己感到兴奋的事情”和“憧憬的人” 无论如何也想象不出未来的应对办法", "date": "2021-04-08", "color": null}, {"text": "如果有总是将“简单”“能做到”“没问题”“太棒了”挂在嘴边的朋友，请你一定要珍惜和他的关系。", "chapter": "044 找一个能“谈论梦想”的朋友 与充满正能量的人交往", "date": "2021-04-08", "color": null}, {"text": "越是在失败的日子里越要找出优点，越是在成功的日子里越要找出改善点。", "chapter": "042 提高“大脑的兴奋度”，习惯就会变得更牢固 充满激情地描绘未来的梦想", "date": "2021-04-08", "color": null}, {"text": "即便不喜欢学习，但应该没有人不喜欢提高吧？因此，我们以后不说“现在开始学习”，而说“现在开始提高”，那么大脑就会产生接近反应，使我们愿意学习。", "chapter": "038 通过改变语言来替换“快乐”与“不快乐” “学习”→“提高”，“蛋糕”→“脂肪”", "date": "2021-04-06", "color": null}, {"text": "我们只要坦诚地接受自己的“喜欢”和“不喜欢”，将自己认为“想做”的事情坚持下去就好。", "chapter": "028 不失败的秘诀⑸不要强迫自己 重视“想做”和“不想做”的感情", "date": "2021-04-06", "color": null}, {"text": "通过加编号这种简单的技巧，我们就能将“作业”变成“游戏”。", "chapter": "020 像玩游戏一样坚持习惯 “通关感”可以提升干劲", "date": "2021-04-06", "color": null}, {"text": "“只是将脱下来的鞋子摆好，真的能够改变人生吗？”实际上这样做的重点不在于“做了什么”，而在于“遵守了与自己的约定”。将这些小事一天一天地坚持做下去，可以使自己产生自信，并从中获得成就感。", "chapter": "017 首先从“小习惯”开始 小习惯的积累也能给人生带来巨大的改变", "date": "2021-04-06", "color": null}, {"text": "选择充实的人生，不管多大年纪都能够取得成长。", "chapter": "015 究竟是什么在阻碍我们养成习惯 选择“轻松”还是“充实”是人生的分水岭", "date": "2021-04-06", "color": null}, {"text": "自己在无意识中做的事情，才是习惯。", "chapter": "011 习惯究竟是什么？ 习惯是“本性”", "date": "2021-04-06", "color": null}, {"text": "想把习惯坚持下去的关键，不是强迫自己做正确的事，而是努力让做正确的事变得快乐。", "chapter": "012 为什么你坚持不下来？ 大脑只能坚持快乐的事情，其他的事情都坚持不下来", "date": "2021-04-06", "color": null}], "ideas": [{"content": "每天进步一点点。", "abstract": "即便不喜欢学习，但应该没有人不喜欢提高吧？因此，我们以后不说“现在开始学习”，而说“现在开始提高”，那么大脑就会产生接近反应，使我们愿意学习。", "chapter": "", "date": "2021-04-06", "star": null}, {"content": "从小事开始，从简单的事情开始，慢慢建立自信，建立成就感。", "abstract": "“只是将脱下来的鞋子摆好，真的能够改变人生吗？”实际上这样做的重点不在于“做了什么”，而在于“遵守了与自己的约定”。将这些小事一天一天地坚持做下去，可以使自己产生自信，并从中获得成就感。", "chapter": "", "date": "2021-04-06", "star": null}, {"content": "选择幸福的人生。", "abstract": "选择充实的人生，不管多大年纪都能够取得成长。", "chapter": "", "date": "2021-04-06", "star": null}]}, {"id": "523272", "title": "和珅：帝王心腹", "author": "李师江", "cover": "https://cdn.weread.qq.com/weread/cover/35/yuewen_523272/s_yuewen_5232721692784800.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=0b43201057fc080b4087c48", "progress": 100, "finished": 1, "hlCount": 16, "ideaCount": 0, "highlights": [{"text": "拿不定主意", "chapter": "第三十七章 左右会试阴差阳错 权斗皇储危机潜伏", "date": "2026-02-17", "color": 1}, {"text": "《西招四时吟》，描写西藏四季的景色、感受。其中一句：“莫讶春来后，寒威倍胜前。小窗欣日色，大漠渺人烟。”", "chapter": "第三十五章 驻藏赋诗和琳淡泊明志 行医和珅陈渼左右为难", "date": "2026-02-17", "color": 1}, {"text": "山阳四五月，嫩绿渐渐生。草老刚盈寸，花稀不识名", "chapter": "第三十五章 驻藏赋诗和琳淡泊明志 行医和珅陈渼左右为难", "date": "2026-02-17", "color": 1}, {"text": "改翰林院庶吉士，授编修。庶吉士散馆后任，此", "chapter": "第三十四章 尹壮图报国空余恨 和大人用计得美人", "date": "2026-02-17", "color": null}, {"text": "。", "chapter": "第三十二章 淫戏百出玉体写墨书 杀人无形勋贵遭连罪", "date": "2026-02-17", "color": null}, {"text": "今权势，如果去他家里参加寿宴，意味着与他结朋", "chapter": "第三十二章 淫戏百出玉体写墨书 杀人无形勋贵遭连罪", "date": "2026-02-17", "color": null}, {"text": "乾隆上了一道请罪的奏折，说道：微臣到云南任职，与", "chapter": "第二十五章 揣测圣意违心保侍尧 攀龙附凤公主尚长子", "date": "2026-02-17", "color": null}, {"text": "眼镜，由于李侍尧贪污索贿，案情严重，众官一致认为和珅办案清楚，拟定的罪行过轻，应该重判斩立决。在大是大非面前，没有一个人同意和珅的判决建议。这个结果令乾隆非常郁闷，要当面驳回众官的意见是不可能了，但是要让李侍尧死，乾隆爷也绝对是不愿意的。他必须以一己之力来挽救这个朝廷依赖的重臣。一怒之下，他暂且搁下九卿的会审意见，下旨要让各地官员对李侍尧引以为戒，并以此为由，将案子发给各地的督抚，要求大家对案子的判决各抒己见，回奏必须把李侍尧的功劳与罪过都叙述一遍，然后说出自己的看法。这种做法前所未有，也是乾隆一生中唯一一次让督抚议定官员的罪行。乾隆在", "chapter": "第二十五章 揣测圣意违心保侍尧 攀龙附凤公主尚长子", "date": "2026-02-17", "color": null}, {"text": "和珅认为皇上不太可能想让李侍尧死，既如此，", "chapter": "第二十四章 虚虚实实和钦差审贪游山水 金蝉脱壳赵管家避祸居青楼", "date": "2026-02-17", "color": null}, {"text": "裁决，不能按照律例，应该按照皇上的心思才是对的", "chapter": "第二十四章 虚虚实实和钦差审贪游山水 金蝉脱壳赵管家避祸居青楼", "date": "2026-02-17", "color": null}, {"text": "喀宁阿道：“喀大人以为此罪如何裁决？”喀宁阿不假思", "chapter": "第二十四章 虚虚实实和钦差审贪游山水 金蝉脱壳赵管家避祸居青楼", "date": "2026-02-17", "color": null}, {"text": "赋的孩子，自与常人有所不同，你看哪吒，就是在李夫", "chapter": "第二十二章 说钱财和珅诉衷肠 为病僮妙计请御医", "date": "2026-02-17", "color": null}, {"text": "孩子在肚子里就这么聪明，不愧是我的孩子。”", "chapter": "第二十二章 说钱财和珅诉衷肠 为病僮妙计请御医", "date": "2026-02-17", "color": null}, {"text": "对联助兴。”纪晓岚有意炫耀，看了看这里众多尼姑", "chapter": "第十八章 宠纳兰后院涌风波 游泰山两臣斗文才", "date": "2026-02-16", "color": null}, {"text": "道：“和大人乃府上贵客，令我蓬荜生辉，大家都把第一杯酒敬和大人。”一时好话不尽，和", "chapter": "第十五章 使急智赚取乾隆赐名 赴私宴结交官僚子弟", "date": "2026-02-16", "color": null}, {"text": "再也离不开锦绣。刘全自己的老婆皮糙肉厚，即便", "chapter": "第十章 设机谋圣上夸拒贿 无寸功海成辱宠儿", "date": "2026-02-16", "color": null}], "ideas": []}, {"id": "3300104586", "title": "在峡江的转弯处：陈行甲人生笔记", "author": "陈行甲", "cover": "https://cdn.weread.qq.com/weread/cover/81/cpplatform_8al4mxpuzvvbhtnckcc7gc/s_cpplatform_8al4mxpuzvvbhtnckcc7gc1720420733.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=bca326a0813ab8f5ag016fc1", "progress": 100, "finished": 1, "hlCount": 16, "ideaCount": 0, "highlights": [{"text": "我这个人，虽然有些粗鄙，但还算个比较有审美的人，我当时真的觉得那就是美，一种纯真无瑕的情爱之美。", "chapter": "附录 我所了解的陈行甲", "date": "2025-06-26", "color": 1}, {"text": "脚下虽有万水千山，但行者必至。", "chapter": "第七记 你好，我的下半场", "date": "2025-06-26", "color": 1}, {"text": "假如我能够让一只昏厥的知更鸟重回它的巢穴，我便没有虚度此生；假如我能够让一颗心免予忧伤，我便没有虚度此生", "chapter": "第七记 你好，我的下半场", "date": "2025-06-26", "color": 1}, {"text": "我们的社会，什么时候能够把孩子的精神困惑当成和感冒一样的正常现象来平和地科学地对待呢？", "chapter": "第七记 你好，我的下半场", "date": "2025-06-26", "color": 1}, {"text": "可是，当他们精神上遇到困惑了，即使严重到了抑郁的程度，他们可能都还不知道这是生病了。", "chapter": "第七记 你好，我的下半场", "date": "2025-06-26", "color": 1}, {"text": "Attitude表示的是孩子通过审美教育获得的对于美好事物的体悟能力，通过开阔视野获得的对于世界的好奇心，通过梦想激励获得的对于人生成长的内动力。", "chapter": "第七记 你好，我的下半场", "date": "2025-06-26", "color": 1}, {"text": "贫困人口从社会底层往上升的通道越顺畅，社会才越和谐越有活力。我相信，教育是实现社会底层向上流动最公平、最有效的通道，阻止贫困代际传递的根本渠道只能在于教育。", "chapter": "第七记 你好，我的下半场", "date": "2025-06-26", "color": 1}, {"text": "在北大读书期间不幸罹患白血病、康复后创立了志在帮助白血病患者的北京新阳光慈善基金会的刘正琛", "chapter": "第七记 你好，我的下半场", "date": "2025-06-26", "color": 1}, {"text": "当跑的路我已经跑尽了，所信的道我已经守住了，这场美好的仗我已经打完了，而且胜利了。人生下半场，我可以轻装上阵去爬另一座山了。", "chapter": "第六记 在峡江的转弯处", "date": "2025-06-26", "color": 1}, {"text": "做一个有信仰的人，我感觉活得才有力量；做一个干净的人，我感觉活得很轻松；做一个有爱的人，我感觉活得很幸福；做一个心存敬畏的人，我感觉活得才踏实。", "chapter": "第六记 在峡江的转弯处", "date": "2025-06-26", "color": 1}, {"text": "面对这么明显的工程质量问题，如果我们几个部门联手都还查不出问题，那只能说明我们共产党的体制有问题！", "chapter": "第六记 在峡江的转弯处", "date": "2025-06-26", "color": 1}, {"text": "中国是个人情社会，完全出于感情的人情往来是社会的黏合剂，是美好的。我想说的是我希望和大家有这种美好的、没有负担的交往。", "chapter": "第六记 在峡江的转弯处", "date": "2025-06-26", "color": 1}, {"text": "我要求每一个副科级以上干部必须结一户穷亲，给穷亲多少钱物我不提要求，但是我要求干部必须每年至少到穷亲家去三次，至少在穷亲家住一晚。", "chapter": "第六记 在峡江的转弯处", "date": "2025-06-26", "color": 1}, {"text": "我下决心要在我的巴东任内走遍全县的每一个村。", "chapter": "第六记 在峡江的转弯处", "date": "2025-06-26", "color": 1}, {"text": "出国前一直跟班授课的华科外语系许主任给我们送行，他走到我面前轻声对我说，“行甲，从你身上我还是能看出清华并非浪得虚名的”。", "chapter": "第四记 人生的巴颜喀拉山", "date": "2025-06-26", "color": 1}, {"text": "后来霞告诉我，那天她是在街头用磁卡电话联系的我，因为她怕在办公室打电话被人听见。放下电话她骑着自行车狂奔回单位，一路上泪流满面，她觉得自己做了这一生中最重要的决定。", "chapter": "第二记 关于我们的事，他们统统猜错", "date": "2025-06-26", "color": 1}], "ideas": []}, {"id": "25615385", "title": "被讨厌的勇气：“自我启发之父”阿德勒的哲学课", "author": "岸见一郎 古贺史健", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/385/25615385/s_25615385.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=8b9329607186dc198b9bdab", "progress": 100, "finished": 1, "hlCount": 10, "ideaCount": 6, "highlights": [{"text": "一切烦恼皆源于人际关系", "chapter": "为什么讨厌自己？", "date": "2020-09-15", "color": null}, {"text": "他者贡献并不是舍弃“我”而为他人效劳，它反而是为了能够体会到“我”的价值而采取的一种手段。", "chapter": "过多的自我意识，反而会束缚自己", "date": "2020-09-15", "color": null}, {"text": "甚至包括宇宙整体在内的“一切”。", "chapter": "个体心理学和整体论", "date": "2020-09-15", "color": null}, {"text": "但是，父母们的行为有时候很明显是为了满足自己的目的——面子和虚荣又或者是支配欲。", "chapter": "自由就是不再寻求认可？", "date": "2020-09-15", "color": null}, {"text": "学习是孩子的课题。与此相对，父母命令孩子学习就是对别人的课题妄加干涉", "chapter": "自由就是不再寻求认可？", "date": "2020-09-15", "color": null}, {"text": "到现在的目的（报复父母", "chapter": "为什么讨厌自己？", "date": "2020-09-08", "color": null}, {"text": "我们不能上任何挑衅的当。", "chapter": "为什么讨厌自己？", "date": "2020-09-08", "color": null}, {"text": "哲人：你刚刚也说过吧？“无法真心祝福过得幸福的他人”，那就是因为站在竞争的角度来考虑人际关系，把他人的幸福看作“我的失败”，所以才无法给予祝福。", "chapter": "为什么讨厌自己？", "date": "2020-09-08", "color": null}, {"text": "“人的烦恼皆源于人际关系。”这是阿德勒心理学的一个基本概念", "chapter": "为什么讨厌自己？", "date": "2020-09-07", "color": null}, {"text": "只要躲在自己的壳里就可以不与任何人发生关联，而且万一遭到别人的拒绝，还可以以此为理由来安慰自己。", "chapter": "为什么讨厌自己？", "date": "2020-09-07", "color": null}], "ideas": [{"content": "这是不是个体心理学不证自明的公理？", "abstract": "一切烦恼皆源于人际关系", "chapter": "", "date": "2020-09-15", "star": null}, {"content": "转念的力量", "abstract": "“世界”就会改变。世界不是靠他人改变而只能靠“我”来改变。", "chapter": "", "date": "2020-09-15", "star": null}, {"content": "人生也是一场旅行，我们并不是以最快的目的抵达死亡，而是在人生的一路风景中享受美好，感受每一个刹那的风景。", "abstract": "旅行的目的是什么？例如你要去埃及旅行。这时候你会想尽早尽快地到达胡夫金字塔，然后再以最短的距离返回吗？", "chapter": "", "date": "2020-09-15", "star": null}, {"content": "活在当下。", "abstract": "", "chapter": "", "date": "2020-09-15", "star": null}, {"content": "他者贡献并不是舍弃“我”而为他人效劳，它反而是为了能够体会到“我”的价值而采取的一种手段。", "abstract": "他者贡献并不是舍弃“我”而为他人效劳，它反而是为了能够体会到“我”的价值而采取的一种手段。", "chapter": "", "date": "2020-09-15", "star": null}, {"content": "学会转念，正念", "abstract": "阿德勒的目的论是说：“无论之前的人生发生过什么，都对今后的人生如何度过没有影响。”", "chapter": "", "date": "2020-09-07", "star": null}]}, {"id": "837618", "title": "自控力", "author": "凯利·麦格尼格尔", "cover": "https://cdn.weread.qq.com/weread/cover/9/YueWen_837618/s_YueWen_837618.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=d2f32b705cc7f2d2ff135f6", "progress": 98, "finished": 0, "hlCount": 9, "ideaCount": 7, "highlights": [{"text": "如果我们想拥有自控力，就需要区分让我们的生活有意义的真实奖励，和让我们分散精力、上瘾的虚假奖励。", "chapter": "05 大脑的弥天大谎：为什么我们误把渴望当幸福？", "date": "2020-08-24", "color": null}, {"text": "不够活跃的奖励系统正是抑郁症的生理学基础。", "chapter": "05 大脑的弥天大谎：为什么我们误把渴望当幸福？", "date": "2020-08-24", "color": null}, {"text": "多巴胺的奴隶", "chapter": "05 大脑的弥天大谎：为什么我们误把渴望当幸福？", "date": "2020-08-24", "color": null}, {"text": "多巴胺的神经递质。", "chapter": "05 大脑的弥天大谎：为什么我们误把渴望当幸福？", "date": "2020-08-24", "color": null}, {"text": "光环效应", "chapter": "04 容忍罪恶：为何善行之后会有恶行？", "date": "2020-08-24", "color": null}, {"text": "道德许可”不仅会批准我们做坏事，也会让我们错失做善事的机会。", "chapter": "04 容忍罪恶：为何善行之后会有恶行？", "date": "2020-08-24", "color": null}, {"text": "虚假疲惫", "chapter": "03 累到无力抵抗：为什么自控力和肌肉一样有极限？", "date": "2020-08-24", "color": null}, {"text": "整理花园、散步、跳舞、做瑜伽、团队运动、游泳、逗孩子、逗宠物，甚至是精神饱满地打扫房间或者逛商店，都可以是有效的锻炼途径。如果你坚信自己不适合运动，那么我建议你把运动的定义扩大一些。", "chapter": "02 意志力的本能：人生来就能抵制奶酪蛋糕的诱惑", "date": "2020-08-24", "color": null}, {"text": "虽然“三思而后行”和应激反应都是人类天性中的一部分，但你可能发现它们看起来不像本能。", "chapter": "02 意志力的本能：人生来就能抵制奶酪蛋糕的诱惑", "date": "2020-08-24", "color": null}], "ideas": [{"content": "可以用即时奖励和长远奖励进行区别。", "abstract": "如果我们想拥有自控力，就需要区分让我们的生活有意义的真实奖励，和让我们分散精力、上瘾的虚假奖励。", "chapter": "", "date": "2020-08-24", "star": null}, {"content": "值得我们深思", "abstract": "就像笼子里的小白鼠想再感受一次电击一样。", "chapter": "", "date": "2020-08-24", "star": null}, {"content": "发现内心有欲望的时候，需要调动系统二，三思而后行。", "abstract": "虽然“三思而后行”和应激反应都是人类天性中的一部分，但你可能发现它们看起来不像本能。", "chapter": "", "date": "2020-08-24", "star": null}, {"content": "外部世界的威胁以及内部心灵的欲望。", "abstract": "欲望", "chapter": "", "date": "2020-08-24", "star": null}, {"content": "这件事情对你来说很有意义，你自然就拥有相对应的意志力。", "abstract": "这就是你的意志力本能。", "chapter": "", "date": "2020-08-24", "star": null}, {"content": "意义感", "abstract": "比如健康、幸福，还有明天还能挤得进裤子里。", "chapter": "", "date": "2020-08-24", "star": null}, {"content": "系统一", "abstract": "应激反应。", "chapter": "", "date": "2020-08-24", "star": null}]}, {"id": "26435427", "title": "生死疲劳【中国诺奖得主代表作】", "author": "莫言", "cover": "https://cdn.weread.qq.com/weread/cover/79/yuewen_26435427/s_yuewen_264354271701758059.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=c2f320f071935f63c2f1313", "progress": 100, "finished": 1, "hlCount": 15, "ideaCount": 0, "highlights": [{"text": "这样你们艰难前行，你沉重的身体似乎随时都会把这", "chapter": "第四十九章 冒暴雨合作清厕所 受毒打解放做抉择", "date": "2025-12-28", "color": null}, {"text": "城的方向，但我真的要回县城吗？我回县城干什么？春苗在哪里，我就应该去哪里，可春苗在哪里呢？金龙的卡迪拉克追上来，无声地", "chapter": "第四十八章 惹众怒三堂会审 说私情兄弟反目", "date": "2025-12-28", "color": null}, {"text": "眼睛，对我说：妈妈是无疾而终，寿尽而亡，而且死后", "chapter": "第四十七章 逞英雄宠儿击名表 挽残局弃妇还故乡", "date": "2025-12-28", "color": null}, {"text": "子的全班同学都吃上她烙的葱花饼呢？她揉面，瘦削", "chapter": "第四十三章 黄合作烙饼泄愤怒 狗小四饮酒抒惆怅", "date": "2025-12-28", "color": null}, {"text": "准确、灵巧地接住那牛胯骨。在这个过程中，牛", "chapter": "第四十六章 黄合作发誓惊愚夫 洪泰岳聚众闹县府", "date": "2025-12-28", "color": null}, {"text": "不要；赔了，他要咱们没钱。再说了，这‘红’牌辣椒酱，", "chapter": "第三十三章 猪十六思旧探故里 洪泰岳大醉闹酒场", "date": "2025-12-28", "color": null}, {"text": "内接二连三地发生的离奇事件，想想刁小三的突然失踪", "chapter": "第三十一章 附骥尾莫言巴结常团长 抒愤懑蓝脸痛哭毛主席", "date": "2025-12-28", "color": null}, {"text": "莫言从来就不是一个好农民，他身在农村，却思念城市；他出身卑贱，却渴望富贵；他相貌丑陋，却追求美女；他一知半解，却冒充博士。", "chapter": "第三十章 神发救治小三活命 丹毒袭击群猪死亡", "date": "2025-12-27", "color": 1}, {"text": "华舍", "chapter": "第二十四章 庆喜讯社员燃篝火 偷学问猪王听美文", "date": "2025-12-27", "color": 1}, {"text": "东方红”牌链轨拖拉机。拖拉机马力巨大，本来是用来牵引", "chapter": "第十九章 金龙排戏迎新年 蓝脸宁死守旧志", "date": "2025-12-26", "color": null}, {"text": "前脸上，绣上一颗五角红星。她将军帽递给我哥，接着", "chapter": "第十八章 巧手整衣互助示爱 大雪封村金龙称王", "date": "2025-12-26", "color": null}, {"text": "因为我爹已经说过，此牛是他唯一的亲人。亲人受", "chapter": "第十七章 雁落人亡牛疯狂 狂言妄语即文章", "date": "2025-12-26", "color": null}, {"text": "回忆录，回忆当年他套着纸驴舞蹈的情景，我就明白了他脸上为什么有那痴痴的笑容。他说他只要一踏着锣鼓点，搬弄着纸壳驴舞蹈起来，就感到自己渐渐地变成了一头驴，变成了全县唯一的单干户蓝脸家的那匹黑驴，于是他的心思就飘飘荡荡，悠悠忽忽，似乎生活在现实，又恍惚进入了美妙的幻景。他感到自己的双脚分叉成了四蹄，屁股后生出了尾巴，胸脯之上与纸毛驴的头颈融为一体，就像希腊神话中那些半人半马的神，于是他也就体会到了做一匹驴的快乐和痛苦。“文革”期间的集市，并没有多少商品交易，集市上熙熙攘攘的人群，大都是来看热闹的。已经是初冬时节，人们多半穿上了棉袄，也有一些年轻人为了俏丽穿着单衣。人们的胳膊上都套着一个红色的袖标。穿着黄色或是蓝色的军便装单衣的年轻人，胳膊上套上红色袖标显得格外神气，是增色添彩，但那些穿着黑色的、", "chapter": "第十七章 雁落人亡牛疯狂 狂言妄语即文章", "date": "2025-12-26", "color": null}, {"text": "应", "chapter": "第八章 西门驴痛失一卵 庞英雄光临大院", "date": "2025-12-26", "color": null}, {"text": "噢——花花，你敢保证你怀孕了吗？废话，花花瞪我一眼，怒冲冲地说：闹闹啊闹闹，一夜六次，次次如灌如注，别说是一头正值发情高潮的母驴，就是一头木驴，一头石", "chapter": "第七章 花花畏难背誓约 闹闹发威咬猎户", "date": "2025-12-26", "color": null}], "ideas": []}, {"id": "40963066", "title": "明朝那些事儿·全集（2021年 增补版）", "author": "当年明月", "cover": "https://cdn.weread.qq.com/weread/cover/6/yuewen_40963066/s_yuewen_409630661678700087.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=f1e328e072710bfaf1e87e9", "progress": 100, "finished": 0, "hlCount": 15, "ideaCount": 0, "highlights": [{"text": "志去的地方，设个点收门票，那只能说明，他比徐宏祖还", "chapter": "第十五章 结束了", "date": "2024-05-16", "color": null}, {"text": "实如果张头领永远失踪，那也倒好，但考虑到他突", "chapter": "第十三章 选择", "date": "2024-05-16", "color": null}, {"text": "正当崇祯兄收拾清军进攻残局的时候，张献忠再次反叛，", "chapter": "第十三章 选择", "date": "2024-05-16", "color": null}, {"text": "除了脸，什么都要。崇祯每天打交道的，就是", "chapter": "第十一章 奇迹", "date": "2024-05-16", "color": null}, {"text": "后，李如松意识到，这是一个千载难逢的机会，如能一鼓作气冲入城去，攻占平壤，唾手可得！", "chapter": "第十四章 兵不厌诈", "date": "2024-05-13", "color": null}, {"text": "人指挥，而是分由八人统领，参与宁夏平乱的，只是其中一部", "chapter": "第十四章 兵不厌诈", "date": "2024-05-13", "color": null}, {"text": "镇定、他的直言不讳、他的狮子大开口，其实全都建立在一个基", "chapter": "第十三章 明朝的愤怒", "date": "2024-05-13", "color": null}, {"text": "他用他的人生告诉我们，良知和理想是不会消失的，不因富贵而逝去，不因权势而凋亡。不是好人，不是坏人，他是一个有理想、有良心的人。", "chapter": "第十章 千古，唯此一人", "date": "2024-05-13", "color": 1}, {"text": "所以最终能赢得公认，获此殊荣的，只有三个人：解缙、杨慎、徐渭。", "chapter": "第八章 天下第一幕僚", "date": "2024-05-12", "color": 1}, {"text": "人也很惨，个个被整得够呛，甚至连那个唯一不应该整的人也给收拾了。无论如何，张", "chapter": "第二十章 锋芒", "date": "2024-05-12", "color": null}, {"text": "不但可以管理宫中事务，甚至还有兵权在手（镇守太监），连地方都指挥使也要听这些武装太监的话。可惜朱厚照不争气，三十岁就没了，上面换了领导，于是梦醒之后，", "chapter": "第二十章 锋芒", "date": "2024-05-12", "color": null}, {"text": "娇生惯养，混在大城市的朱厚照不同，朱厚熜出生在一个偏僻的地方，而他这位所谓藩王之子，实际上是比较惨的，因为除了吃穿好点儿外，他是一个基本失去自由的人。在明代，由于之前有朱老四（朱棣）的光辉榜样和成功经验，历代皇", "chapter": "第二十章 锋芒", "date": "2024-05-12", "color": null}, {"text": "历史告诉我们，喜欢看课外书的孩子将来一般都是有出息的。", "chapter": "第五章 力挽狂澜", "date": "2024-05-10", "color": 1}, {"text": "但皇权的无限扩大性与皇帝的精力有限性的矛盾，必然导致丞相制度的产生。", "chapter": "第十七章 胡惟庸案件", "date": "2024-05-06", "color": 1}, {"text": "朱重八把这个最脆弱的地方变成了最强大的力量的来源。", "chapter": "第二章 灾难", "date": "2024-05-05", "color": 1}], "ideas": []}, {"id": "43168703", "title": "植物的战斗", "author": "汪诘 科学有故事团队", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/703/43168703/s_43168703.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=fc332f407292b3bffc303a7", "progress": 100, "finished": 1, "hlCount": 15, "ideaCount": 0, "highlights": [{"text": "地衣", "chapter": "泛植物不会动的生存优势", "date": "2022-12-04", "color": null}, {"text": "在所有的蔷薇科植物里，如果它们的果实只有一粒种子，类似樱桃、李子或者桃，那么它们就归属于桃亚科。如果它们像苹果、梨或者海棠一样，在一个果实里藏着不止一颗种子，那么它们就归属于蔷薇亚科", "chapter": "第五节 蔷薇，花开两朵，各表一枝", "date": "2022-09-20", "color": null}, {"text": "阿拉伯人把胡椒彻底磨碎，伪装成一种珍贵的矿物。欧洲人足足花了1000年的时间，才逐渐弄清楚胡椒的来历。", "chapter": "第二节 胡椒与薄荷，调味品的革命", "date": "2022-09-19", "color": null}, {"text": "辣椒素产生的灼热感，会让我们大脑产生一种机体受到了伤害的错觉。大脑为了减轻身体的痛苦，就会分泌出内啡肽来帮我们止疼。然而，我们的身体并没有真的受伤，在灼热感过后，我们就能快乐地享受消耗不掉的内啡肽和多巴胺了。", "chapter": "第四章 改变自己，顺带着改变了世界", "date": "2022-09-19", "color": null}, {"text": "20世纪50年代，进化生物学家丹·詹森提出，辣味是辣椒中的辣椒素激活痛觉感知神经元而产生的疼痛感。这个理论被接受以后，辣味就不再是一种味道，而是一种痛觉了", "chapter": "第四章 改变自己，顺带着改变了世界", "date": "2022-09-19", "color": null}, {"text": "百万分之十六浓度的辣椒素，就是普通人能够感受到辣味的底线", "chapter": "第四章 改变自己，顺带着改变了世界", "date": "2022-09-19", "color": null}, {"text": "这种通过模拟雌性昆虫吸引雄虫前来交配的策略，叫作性欺骗。", "chapter": "第五节 兰花，把昆虫玩弄于股掌之间", "date": "2022-09-19", "color": null}, {"text": "这种把自己伪装成食物的骗术，叫作食源性欺骗。", "chapter": "第五节 兰花，把昆虫玩弄于股掌之间", "date": "2022-09-19", "color": null}, {"text": "门、纲、目、科、属、种是我们现在最常用的植物分类方法。", "chapter": "第二节 走出非洲，景天科植物大迁徙", "date": "2022-09-19", "color": null}, {"text": "成长为参天大树，对于植物来说，并不是必备的生存技能，它只是争取阳光的一种方式而已。", "chapter": "第三节 爬藤植物，为攻城略地而生", "date": "2022-09-18", "color": null}, {"text": "在农业上，专门有一种肥料叫作叶面肥。叶面肥就是将肥料溶液直接喷洒在叶片的表面，让植物直接吸收。叶面肥所利用的，正是植物都会吃肉，或者说都能吸收氮元素这个原理。", "chapter": "第二节 食虫植物，植物学习吃肉的历史", "date": "2022-09-18", "color": null}, {"text": "回甘，就是吃过苦味食物之后，嘴里面留下的那种清甜的感觉。这种感觉其实与辣味是相似的，是我们人体受到外界伤害后，产生的一种自我修复的补偿效应。", "chapter": "第二章 它们全吃肉，它们都有毒", "date": "2022-09-18", "color": null}, {"text": "植物在亿万年的演化中，创造了无数种毒素，而动物则练就了一种迅速识别有毒物质的绝技。这种绝技，就是对苦味的感知。", "chapter": "第二章 它们全吃肉，它们都有毒", "date": "2022-09-18", "color": null}, {"text": "味精和鸡精都是很安全的食品添加剂，甚至国家都没有规定添加剂量的限制，凡是有关味精有害的各种说法都是谣言。", "chapter": "第三节 海带，不是只有植物才能进行光合作用", "date": "2022-09-18", "color": null}, {"text": "一些好氧细菌变成了现在的线粒体，蓝细菌变成了现在的叶绿体，一些善于运动的螺旋体细菌变成了现在细胞上会运动的纤毛。", "chapter": "第一章 它们不是植物，却选择当一株植物", "date": "2022-09-18", "color": null}], "ideas": []}, {"id": "436087", "title": "星云大师《心经》五讲", "author": "星云大师", "cover": "https://cdn.weread.qq.com/weread/cover/20/YueWen_436087/s_YueWen_436087.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=30f32cb056a77730fd18902", "progress": 100, "finished": 1, "hlCount": 14, "ideaCount": 1, "highlights": [{"text": "生理的六根，认识了物理的六尘，产生了心理的六识，这叫十八界。", "chapter": "第5讲：开般若的慧眼", "date": "2022-12-04", "color": null}, {"text": "宇宙万有虚空的本体，空里面可以涌现出万象", "chapter": "第4讲：色即是空，空即是色", "date": "2022-12-04", "color": null}, {"text": "可是起了风、起了浪，波浪和水它们两个是一个，不是分开的。", "chapter": "第4讲：色即是空，空即是色", "date": "2022-12-04", "color": null}, {"text": "这个不懂的人把有和无分成两个世界，中间有一条鸿沟，有的不是无，无的不是有，其实有的非真有，无的也非真无。", "chapter": "第4讲：色即是空，空即是色", "date": "2022-12-04", "color": null}, {"text": "要照见五蕴皆空，才能度一切苦厄。", "chapter": "第3讲：超脱之道", "date": "2022-12-04", "color": null}, {"text": "神通和般若不同，有了般若，人生很快乐，有了神通，人生就很痛苦。", "chapter": "第5讲：开般若的慧眼", "date": "2022-09-26", "color": null}, {"text": "有，还可以救，就怕你无。什么都没有，没有因果．没有菩萨，什么东西没有，这种断灭的空，叫断见，也是很可怕的。", "chapter": "第4讲：色即是空，空即是色", "date": "2022-09-26", "color": null}, {"text": "不过讲空，我们不能执著这个空，执著了空就是不空。", "chapter": "第4讲：色即是空，空即是色", "date": "2022-09-26", "color": null}, {"text": "菩萨二字是梵文，中文的意思就是觉悟有情的人，是有大道心的人、肯发大心的人就可以叫菩萨。", "chapter": "第3讲：超脱之道", "date": "2022-08-31", "color": null}, {"text": "擒山中之贼易，抓心中之贼难。", "chapter": "第2讲：修一颗般若心", "date": "2022-08-31", "color": null}, {"text": "我们每个人都有一个宝藏，一个我们的本来面目，我们的真我，它叫做般若，它其大无比、其高无限、其殊胜不可思议。", "chapter": "第1讲：什么是般若", "date": "2022-08-30", "color": null}, {"text": "所谓缘起，世间每一样东西都不能单独存在，包括人、房子、宇宙万有，它都有彼此的关系。很多条件下，相互依存，相互结合，具足这许多因缘的条件，才能生起，所以说缘起。", "chapter": "第1讲：什么是般若", "date": "2022-08-30", "color": null}, {"text": "何谓涅槃？我们时时刻刻没有得失的心，没有有无的念头，没有挂碍，没有生灭，没有生死的挂碍，那就是涅槃。", "chapter": "第5讲：开般若的慧眼", "date": "2022-06-24", "color": null}, {"text": "师父反过来对徒弟说：“徒弟，我种兰花不是为了生气才种的。”", "chapter": "第5讲：开般若的慧眼", "date": "2022-06-24", "color": null}], "ideas": [{"content": "有无相生", "abstract": "可是起了风、起了浪，波浪和水它们两个是一个，不是分开的。", "chapter": "", "date": "2022-12-04", "star": null}]}, {"id": "3300115447", "title": "人间清醒3：底层逻辑和顶层认知（心悦读丛书）", "author": "水木然", "cover": "https://cdn.weread.qq.com/weread/cover/5/cpplatform_h6ulp5xrzmkzf2fkans4k4/s_cpplatform_h6ulp5xrzmkzf2fkans4k41726816838.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=15a329b0813ab9398g017778", "progress": 99, "finished": 1, "hlCount": 14, "ideaCount": 0, "highlights": [{"text": "我们犯的最大的错误，就是经常站在现在的角度去批判当初的自己。", "chapter": "破 旧", "date": "2026-03-25", "color": 1}, {"text": "佛在灵山莫远求，灵山只在汝心头", "chapter": "《西游记》里的人生观", "date": "2026-03-25", "color": 1}, {"text": "调“空”，叫“空生妙有”；道家强调“无”，叫“无中生有”。修行人修的就是这种“空无”的境界，也就是禅宗一直强调的“空性”。", "chapter": "心流与奇迹", "date": "2026-03-25", "color": 1}, {"text": "得到未必是福，失去未必是祸。有些事你总是做不成，有些人你总是得不到，你以为错过了是遗憾，其实也可能是逃过一劫。", "chapter": "人生是一场体验", "date": "2026-03-25", "color": 1}, {"text": "人生除了生与死，其他都是小事", "chapter": "人生是一场体验", "date": "2026-03-25", "color": 1}, {"text": "人生是一场体验人生是用来体验的，不是用来演绎完美的。这是我活到现在才明白的深刻道理。", "chapter": "人生是一场体验", "date": "2026-03-25", "color": 1}, {"text": "其实恰恰相反，悲观到极致反而更容易走向乐观，因为接纳了最残酷的真相之后，哪怕是很小的一件好事都是惊喜。对这样的人来说，生活处处是惊喜，随时能收到生命的礼物，从而又活成了一个乐观的人", "chapter": "乐观的悲观主义", "date": "2026-03-25", "color": 1}, {"text": "红尘，是最好的修行道场。红尘炼心，是最好的修行方式。", "chapter": "习 新", "date": "2026-03-25", "color": 1}, {"text": "《周易》归根结底就是八个字：自强不息，厚德载物。就是教我们脚踏实地地做人，问心无愧地做事。", "chapter": "习 新", "date": "2026-03-25", "color": 1}, {"text": "思维的分裂本质就是开悟。检验一个人是否开悟，就是看他能不能在头脑中同时存在两种相反的想法，还维持正常行事的能力。", "chapter": "习 新", "date": "2026-03-25", "color": 1}, {"text": "万物不为我所有，万物皆为我所用。我们只有使用权，但没有绝对的拥有权，包括我们的生命，也只是阶段性地被我们使用而已，最终会烟消云散。", "chapter": "思 变", "date": "2026-03-25", "color": 1}, {"text": "真正的强大不是对抗，而是允许与接纳。允许世事无常，允许遗憾常在，允许有人不喜欢你。这是一种胸怀和格局。", "chapter": "破 局", "date": "2026-03-25", "color": 1}, {"text": "能想象富裕的人富到什么地步，也能体会到穷困的人穷到哪个程度。而你在他们面前不卑不亢，可以和他们和睦相处。", "chapter": "破 局", "date": "2026-03-25", "color": 1}, {"text": "见天地之道，见众生之相。世面就是世界的每一面，见过最好的，且不以物喜；知晓最坏的，且不以己悲。乱花渐欲，不坠青云志；腹有诗书，不夸夸其谈。", "chapter": "破 局", "date": "2026-03-25", "color": 1}], "ideas": []}, {"id": "855812", "title": "人类简史：从动物到上帝", "author": "尤瓦尔·赫拉利", "cover": "https://cdn.weread.qq.com/weread/cover/37/YueWen_855812/s_YueWen_855812.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=d4a322a05d0f04d4a01f0d6", "progress": 100, "finished": 1, "hlCount": 14, "ideaCount": 0, "highlights": [{"text": "我们生活在由和我们非常不同的人在我们出生很久以前发明的思想牢狱之中。", "chapter": "序言 《人类简史》出版10周年", "date": "2022-06-12", "color": null}, {"text": "“快乐不在于外在条件，而只在于我们内心的感受。我们应该别再追求像是财富、地位之类的外在成就，而是要多接触自己内心的情感。”或者说得简单一点，就是“快乐来自内心”。这与生物学家的说法不谋而合，但与佛教的说法几乎正是背道而驰。", "chapter": "第十九章 从此过着幸福快乐的日子", "date": "2020-12-28", "color": null}, {"text": "现在正面临着全球帝国的形成。", "chapter": "第十八章 一场永远的革命", "date": "2020-12-28", "color": null}, {"text": "从中国炼丹术士发现火药，到土耳其人用大炮粉碎君士坦丁堡的城墙，之间足足过了600年。", "chapter": "第十七章 工业的巨轮", "date": "2020-12-28", "color": null}, {"text": "有一些宗教（例如基督教和纳粹）杀害了数百万人，原因是出于仇恨。然而，资本主义也杀害了数百万人，原因则是出于冷漠和贪婪。", "chapter": "第十六章 资本主义教条", "date": "2020-12-28", "color": null}, {"text": "在过去500年间，科学、帝国和资本之间的回馈循环无疑正是推动历史演进的主要引擎。", "chapter": "第十四章 发现自己的无知", "date": "2020-12-04", "color": null}, {"text": "正如尼采所言，只要有了活下去的理由，几乎什么都能够忍受。生活有意义，就算在困境中也能甘之如饴；生活无意义，就算在顺境中也度日如年。", "chapter": "第十九章 从此过着幸福快乐的日子", "date": "2020-11-20", "color": null}, {"text": "生命整体有意义、有价值，就能得到快乐。", "chapter": "第十九章 从此过着幸福快乐的日子", "date": "2020-11-20", "color": null}, {"text": "演化就把快感当成奖赏，鼓励男性和女性发生性行为、将自己的基因传下去。", "chapter": "第十九章 从此过着幸福快乐的日子", "date": "2020-11-20", "color": null}, {"text": "过去在野外形成的种种需求，就算现在已经不是生存和繁殖所必要，仍然会持续造成主观的感受。", "chapter": "第十七章 工业的巨轮", "date": "2020-11-20", "color": null}, {"text": "演化心理学", "chapter": "第三章 亚当和夏娃的一天", "date": "2020-11-20", "color": null}, {"text": "工业革命的核心，其实就是能源转换的革命。", "chapter": "第十七章 工业的巨轮", "date": "2020-11-20", "color": null}, {"text": "所有人类创造的信念系统之中，只有金钱能够跨越几乎所有文化鸿沟，不会因为宗教、性别、种族、年龄或性取向而有所歧视。也多亏有了金钱制度，才让人就算互不相识、不清楚对方人品，也能携手合作。", "chapter": "第十章 金钱的味道", "date": "2020-08-24", "color": null}, {"text": "原因就在于宗教信仰的重点是自己相信，但金钱信仰的重点是“别人相信”。", "chapter": "第十章 金钱的味道", "date": "2020-08-24", "color": null}], "ideas": []}, {"id": "3300054526", "title": "5000天后的世界", "author": "凯文·凯利 大野和基", "cover": "https://cdn.weread.qq.com/weread/cover/97/cpplatform_njrxnfmrer9qb4vlz6e2x5/s_cpplatform_njrxnfmrer9qb4vlz6e2x51680751947.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=f5032700813ab7bccg0169dc", "progress": 99, "finished": 0, "hlCount": 13, "ideaCount": 1, "highlights": [{"text": "发", "chapter": "第三章 所有的产业都将因科技重塑", "date": "2024-07-30", "color": null}, {"text": "主义形态。近年来，平台的运营主要由GAFA以及腾讯、百度等大公司主导，但是人们渐渐认识到，平台是一个既不同于公司又有别于政府的事物，应该介于二者之间。直到20世纪80年代，有三种组织形式，即公司、政府和非", "chapter": "第二章 进化中的数字经济的现状", "date": "2024-07-26", "color": null}, {"text": "将来会增加到75%。因此，很有必要为了配合这一趋势研究出新的政策。", "chapter": "第四章 亚洲的时代与科技地缘政治", "date": "2024-06-26", "color": null}, {"text": "习的状态。但是，我相信只要不断追求，就可以在和自己职业无关的领域有所发现。我会经常参加一些和我的工作无", "chapter": "第五章 倾听科技洞见未来", "date": "2024-05-24", "color": null}, {"text": "农民都希望能够做到按需浇水施肥，只是从来没有一种技", "chapter": "第三章 所有的产业都将因科技重塑", "date": "2024-05-24", "color": null}, {"text": "由此我产生了一个想法，就是从长远发展的眼光看，工作和娱乐的界限终会消失。二者终有一天会完全重叠，无论从技术层面还是财富层面，我们终将无法界定到底是在工作还是在取悦自己。这将是我们的努力方向，也应该成为我们的目标。", "chapter": "第一章 数百万人一起工作的未来", "date": "2024-04-25", "color": 1}, {"text": "我一直认为政府有必要鼓励年轻人出门旅行，甚至应该为此设立援助资金和机构，甚至要求每个国民都完成为期两年的旅行任务也不为过。无论男女，也无论是否身体上有残疾，人人都应该在高中毕业后，在18岁之后的两年里拿出专门的时间去旅行。", "chapter": "第三章 所有的产业都将因科技重塑", "date": "2023-06-23", "color": 5}, {"text": "人们无须学习英语，苦练对话", "chapter": "第三章 所有的产业都将因科技重塑", "date": "2023-06-23", "color": 5}, {"text": "区块链可以用来证明和保证镜像世界的一切的真实性。", "chapter": "第三章 所有的产业都将因科技重塑", "date": "2023-06-23", "color": 5}, {"text": "万能的神并没有创造世界，而是创造了可以创造世界的生物。重点在于二次创造。", "chapter": "第二章 进化中的数字经济的现状", "date": "2023-06-23", "color": 5}, {"text": "100万人中有1个人觉得有趣就够了。视频平台和互联网可以让每个人都成为自媒体，通过它们，每个人都可以和几十亿人分享自己的作品，让数以千计的粉丝看到。", "chapter": "第二章 进化中的数字经济的现状", "date": "2023-06-23", "color": 5}, {"text": "把枯燥的工作丢给AI，去做创造性的工作我曾经提出过一个观点：只要能够获得几千个忠实", "chapter": "第二章 进化中的数字经济的现状", "date": "2023-06-23", "color": 5}, {"text": "，如今成为焦点的比特币等数字资产，以及区块链等技术，就会派上用场", "chapter": "第一章 数百万人一起工作的未来", "date": "2023-06-23", "color": 5}], "ideas": [{"content": "《科技想要什么》", "abstract": "我做的仅仅是倾听科技(listen tothe technology)，因为科技是有生命的。我会不断地追问：“科技想要什么？”然后努力帮其实现。", "chapter": "第一章 数百万人一起工作的未来", "date": "2023-06-23", "star": null}]}, {"id": "3300107165", "title": "类人意识与类人智能", "author": "蔡恒进 蔡天琪", "cover": "https://cdn.weread.qq.com/weread/cover/54/cpplatform_ejzjdkm6rgygl3yrzhpaai/s_cpplatform_ejzjdkm6rgygl3yrzhpaai1721630159.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=44632c90813ab905cg0150ec", "progress": 99, "finished": 1, "hlCount": 13, "ideaCount": 0, "highlights": [{"text": "我们都有共情的本能、利他的本能。本质上，在进化过程中，它们就藏在了我们的基因里和认知坎陷里。", "chapter": "第6章 情感与优化", "date": "2025-07-24", "color": 1}, {"text": "早期生命的细胞膜就可以看作是认知膜，两者作为最早的“自我”的边界是统一的，在这一阶段认知膜可以被认为是物质性的，而到了人类层面的认知膜则是主体建构的、心理性的。", "chapter": "第6章 情感与优化", "date": "2025-07-24", "color": 1}, {"text": "一个是直觉的、从自我的愿望出发的系统1，另一个是尽量讲道理、理性的系统2。", "chapter": "第6章 情感与优化", "date": "2025-07-24", "color": 1}, {"text": "实际上，我们使用语言就可以与机器进行有效交流，并不需要脑机接口。", "chapter": "第9章 未来可期", "date": "2025-07-24", "color": 1}, {"text": "所以认知坎陷就是智能的活动。", "chapter": "第9章 未来可期", "date": "2025-07-24", "color": 1}, {"text": "认知坎陷是生命主体经由自己的身体或大脑对四维时空中的内容进行非线性重构的产物。", "chapter": "第9章 未来可期", "date": "2025-07-24", "color": 1}, {"text": "意识就更无法用公式描述清楚了。", "chapter": "第9章 未来可期", "date": "2025-07-24", "color": 1}, {"text": "意识本质的特点就是要超脱物理世界四维时空的限制，所以意识几乎不可能也没有必要用数学公式来清晰描述。", "chapter": "第9章 未来可期", "date": "2025-07-24", "color": 1}, {"text": "这就是一个因果链重构的过程。", "chapter": "第9章 未来可期", "date": "2025-07-24", "color": 1}, {"text": "因果链重构理论，即在意识世界中，因果关系链条将被大幅简化。", "chapter": "第9章 未来可期", "date": "2025-07-24", "color": 1}, {"text": "特斯拉机器人已经在能耗优化、大规模制造过程以及未来的软件快速升级中迭代，随着各场景中的数据不断积累，后续再进行框架融合、升级，将会形成巨大的技术优势。", "chapter": "第8章 类人驾驶与人形机器人", "date": "2025-07-24", "color": 1}, {"text": "为机器构建出“自我”的原型架构，让机器学习与外界交互并实现理解。", "chapter": "第8章 类人驾驶与人形机器人", "date": "2025-07-24", "color": 1}, {"text": "华为前智能驾驶产品线总裁、首席架构师苏箐", "chapter": "第8章 类人驾驶与人形机器人", "date": "2025-07-24", "color": 1}], "ideas": []}, {"id": "848673", "title": "当下的力量（白金版）", "author": "埃克哈特·托利", "cover": "https://cdn.weread.qq.com/weread/cover/2/YueWen_848673/s_YueWen_848673.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=5b932bd05cf3215b92b7cd5", "progress": 61, "finished": 0, "hlCount": 13, "ideaCount": 0, "highlights": [{"text": "处于你内在的本质，它与这个世界是合一的，它从未离开过你", "chapter": "第七章 进入未显化状态的大门", "date": "2023-12-04", "color": null}, {"text": "短暂地感受到它，但是通过这些短暂的感受，你将会", "chapter": "第六章 内在身体", "date": "2023-12-04", "color": null}, {"text": "如果你过于注重目标，或许因为你在寻找幸福或成就，成为一个更圆满的自我感，这时你就没有在关注当下了。当下失去了固有的价值，而沦为通向未来的踏脚石。这样钟表时间就变成了心理时间。", "chapter": "第三章 深深地进入当下", "date": "2022-02-25", "color": null}, {"text": "当下这一刻，当时间缺席时，你所有的问题都会消失。苦难只有在时间中才能存在，在当下它无法存活。", "chapter": "第三章 深深地进入当下", "date": "2022-02-24", "color": null}, {"text": "时间一点儿也不珍贵，因为它仅仅是一种幻象。你认为珍贵的东西不是时间，而是不在时间内的那一点，即当下。实际上，当下才真正的珍贵。你越关注时间——过去和未来，你就会越多地错过当下。当下才是最为珍贵的东西。为什么？首先，因为它是唯一真正存在的东西，你的整个生命就是在这个永恒当下的空间中展开的，而这个永恒当下是唯一不变的常数。生命就是此刻，你的生命从来不会不在此刻，未来也不会。其次，当下是唯一可以带你超越有限大脑的切入点，也是唯一可以带你进入永恒的本体领域的关键。", "chapter": "第三章 深深地进入当下", "date": "2022-02-24", "color": null}, {"text": "当你与思维认同时，你就陷入了时间的陷阱：你会不由自主地完全生活在对过去的回忆和对未来的期待之中。这样你的心思会完全被过去和未来占据，而不愿意接纳当下时刻，并容许它存在。", "chapter": "第三章 深深地进入当下", "date": "2022-02-24", "color": null}, {"text": "小我的需求是无止境的。它感到自己很脆弱，容易受到威胁，所以它一直生活在一种恐惧和缺乏的状态中。", "chapter": "第三章 深深地进入当下", "date": "2022-02-24", "color": null}, {"text": "生命的秘密在于：“在你死亡之前死亡”——并发现原来根本没有死亡。", "chapter": "第二章 意识：摆脱痛苦的途径", "date": "2022-02-24", "color": null}, {"text": "你可能宁愿在痛苦中，与痛苦之身认同，也不愿冒风险去丢失你熟悉的不幸自我而跃入一个未知之中。", "chapter": "第二章 意识：摆脱痛苦的途径", "date": "2022-02-24", "color": null}, {"text": "思维的一个主要任务就是反抗或消除这种情绪上的痛苦，这也是思维活动如此之多的原因。然而思维顶多也只能暂时地将痛苦掩盖住。实际上，思维越是努力去摆脱这种痛苦，痛苦就会越深。思维永远不会找到解决方案，它也不会让你找到解决方案，因为它本身就是问题的一部分。", "chapter": "第一章 你不等于你的大脑", "date": "2022-02-23", "color": null}, {"text": "不能停止思考是一个可怕的烦恼，由于几乎每一个人都遭受着此种痛苦，而我们又无法意识到这一点，所以这就成了一件很正常的事情。这种不停的思维活动使你无法达到内心的宁静状态。同时，它创造了一个虚假的自我，不断投射出恐惧和苦难的阴影。", "chapter": "第一章 你不等于你的大脑", "date": "2022-02-23", "color": null}, {"text": "你已经有了，只是你感觉不到它的存在而已，因为你的思维产生了太多的噪声。", "chapter": "前言 本书的由来", "date": "2022-02-23", "color": null}, {"text": "“我无法再忍受我自己了。”那晚，这句话一直不断地出现在我的脑海中。这时，我突然意识到这种想法真的很奇怪：“我是一个人还是两个人？如果我不能忍受我自己，那么肯定有两个我：‘我’和‘自己’。”或许，我想，其中只有一个是真实的。", "chapter": "前言 本书的由来", "date": "2022-02-23", "color": null}], "ideas": []}, {"id": "853321", "title": "第三种黑猩猩：人类的身世与未来（简明版）", "author": "贾雷德·戴蒙德著 丽贝卡·斯黛芙奥夫改写", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/321/853321/s_853321.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=3a6326c05d05493a6e790f6", "progress": 100, "finished": 1, "hlCount": 12, "ideaCount": 1, "highlights": [{"text": "历史书经常会详细地诉说王朝更迭和野蛮人的入侵，但从长期来看，森林砍伐和水土流失才可能是影响我们人类历史进程的主要因素。", "chapter": "第14章 从不曾出现过的黄金时代", "date": "2020-09-07", "color": null}, {"text": "植物性食物对于文明的崛起起到至关重要的作用。实际上，人类所消耗的绝大部分热量都来源于植物，更为明确地说是来自谷物，即具有可食用的、含淀粉种子的稻科类植物，例如大麦或小麦仁。", "chapter": "第12章 意外的征服者", "date": "2020-09-06", "color": null}, {"text": "如果说啄树皮的特征在地球的生命历史中只演化出过一次，我们又怎么能寄希望于无线电设备建造的能力可以在宇宙中演化出不止一次呢？", "chapter": "第10章 拥挤世界中的孤独", "date": "2020-09-06", "color": null}, {"text": "质是会让人化学成瘾的。总体来看，饮酒、抽烟及使用毒品都是自我毁灭的行为。", "chapter": "第9章 我们为什么会吸烟、喝酒，还会服用有毒药物？", "date": "2020-09-06", "color": null}, {"text": "艺术通常可以作为个体具有优越素质或地位的可靠指标，因为需要具备一定技能才能创作艺术，也需要具备社会地位或财富才能接触到艺术。", "chapter": "第9章 我们为什么会吸烟、喝酒，还会服用有毒药物？", "date": "2020-09-06", "color": null}, {"text": "那就是猩猩的绘画仅仅是动物处于囚禁状态时的一种非自然行为。在野外的情况下，这些行为并不会发生。", "chapter": "第7章 艺术的动物起源", "date": "2020-09-06", "color": null}, {"text": "它一定是为了自己的满足感才去这样做的，因为它并没有把他的作品展示给其他黑猩猩看，而且当刷子被拿走时它就会发脾气", "chapter": "第7章 艺术的动物起源", "date": "2020-09-06", "color": null}, {"text": "艺术可能是人类的诸多特征中最为高贵独特的。它至少同语言一样，可以将我们和动物明确地区分开。然而，语言是有着实用性目的的，而艺术则没有什么显著的功能。它的起源被视为一件极为神秘的事。", "chapter": "第7章 艺术的动物起源", "date": "2020-09-06", "color": null}, {"text": "从洋泾浜语到克里奥尔语，或者说从两岁幼儿的词串到四岁幼儿的完整句子，是一次巨大的跨越", "chapter": "第6章 语言的神秘", "date": "2020-09-06", "color": null}, {"text": "形象印刻。", "chapter": "第4章 人类种族的起源", "date": "2020-09-06", "color": null}, {"text": "我们理想伴侣的心理画像", "chapter": "第3章 人类的性行为", "date": "2020-09-06", "color": null}, {"text": "恐龙是在大约6500万年前灭绝的。", "chapter": "第2章 大飞跃", "date": "2020-09-05", "color": null}], "ideas": [{"content": "现代人类还多了一个伦理目标，即人类整体演化能力最大化。", "abstract": "我们与其他动物的最大区别之一，就是在我们的生存目标中加入了伦理目标。", "chapter": "", "date": "2020-09-06", "star": null}]}, {"id": "713413", "title": "教出乐观的孩子：让孩子受用一生的幸福经典（经典版）", "author": "马丁·塞利格曼", "cover": "https://cdn.weread.qq.com/weread/cover/89/YueWen_713413/s_YueWen_713413.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=611325805ae2c561133540c", "progress": 50, "finished": 0, "hlCount": 6, "ideaCount": 7, "highlights": [{"text": "乐观的第一个技能是被称为“捕捉思维”。即在你感受最难过的时候，要尝试指认出闪过脑海里的那些想法，这些想法虽然不太能被感知到，但会严重影响你的情绪与行为。这项技能被称为“捕捉思维”。", "chapter": "第四部分 如何教出乐观的孩子", "date": "2020-09-05", "color": null}, {"text": "避免责怪孩子的个性或能力。", "chapter": "第三部分 你的孩子是乐观，还是悲观", "date": "2020-09-05", "color": null}, {"text": "行为性自责”", "chapter": "第三部分 你的孩子是乐观，还是悲观", "date": "2020-09-05", "color": null}, {"text": "普遍性自责", "chapter": "第三部分 你的孩子是乐观，还是悲观", "date": "2020-09-05", "color": null}, {"text": "变化中最令人吃惊的一项就是：抑郁在人的一生中具有普遍性，也就是在人的一生中至少都发生过一次抑郁。", "chapter": "第二部分 孩子不快乐，父母有责任", "date": "2020-09-04", "color": null}, {"text": "心理可以免疫吗", "chapter": "第一部分 为什么孩子需要乐观", "date": "2020-09-04", "color": null}], "ideas": [{"content": "用天眼觉知当下", "abstract": "乐观的第一个技能是被称为“捕捉思维”。即在你感受最难过的时候，要尝试指认出闪过脑海里的那些想法，这些想法虽然不太能被感知到，但会严重影响你的情绪与行为。这项技能被称为“捕捉思维”。", "chapter": "", "date": "2020-09-05", "star": null}, {"content": "对事不对人，不伤自尊", "abstract": "行为性自责”", "chapter": "", "date": "2020-09-05", "star": null}, {"content": "自责", "abstract": "长期怪罪自己", "chapter": "", "date": "2020-09-04", "star": null}, {"content": "悲观者将失败的标签贴死了，就很难撕下来", "abstract": "我是个失败者！", "chapter": "", "date": "2020-09-04", "star": null}, {"content": "让孩子打游戏也能做到", "abstract": "要使你的孩子经历掌控感，必须先让他经历失败、心情抑郁以及不断尝试直到成功为止。", "chapter": "", "date": "2020-09-04", "star": null}, {"content": "降低期望值原来与自尊相关！可以通过增加自己的成功或是降低对自己的期望来提高自尊。", "abstract": "自尊＝成功÷自我期望\n根据詹姆斯的说法，我们得到越多的成功，并且期望越低，那么自尊就会越高。我们可以通过增加自己的成功或是降低对自己的期望来提高自尊。", "chapter": "", "date": "2020-09-04", "star": null}, {"content": "提出一个好的问题，往往比解决问题重要的多。", "abstract": "心理可以免疫吗", "chapter": "", "date": "2020-09-04", "star": null}]}, {"id": "921568", "title": "原则", "author": "瑞·达利欧", "cover": "https://cdn.weread.qq.com/weread/cover/23/YueWen_921568/s_YueWen_921568.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=848324405e0fe08483ab6a4", "progress": 8, "finished": 0, "hlCount": 1, "ideaCount": 12, "highlights": [{"text": "我将重点强调我犯过的错误和我的弱点，以及我从这些错误和弱点中总结出的原则。", "chapter": "第一部分 我的历程", "date": "2018-03-05", "color": null}], "ideas": [{"content": "从大失败中总结经验，正视犯下的错误，难能可贵！", "abstract": "人生最惨重失利", "chapter": "", "date": "2018-03-21", "star": null}, {"content": "同感", "abstract": "我的工作一直能把我带到各种充满异国情调的场所，让我遇到有意思的人。如果我能从这些旅行中赚到钱的话，那不过是锦上添花。", "chapter": "", "date": "2018-03-10", "star": null}, {"content": "重点", "abstract": "尽管赚钱很好，但拥有有意义的工作和人际关系要比赚钱好得多。对我而言，有意义的工作是指一项我能全身心投入的使命；有意义的人际关系是指我既深深地关心对方，对方也深深地关心我。", "chapter": "", "date": "2018-03-10", "star": null}, {"content": "搞清因果关系", "abstract": "预报和降雨量数据预测谷物和豆类的产出时间与数量。对我而言，整个过程像是一部有着符合逻辑的因果关系的美丽机器。通过理解这些关系，我就能得出用来", "chapter": "", "date": "2018-03-10", "star": null}, {"content": "早鸟", "abstract": "但我确实知道的是，在那么小的时候就有这些工作，并有一些可以独立支配的钱，教给了我很多宝贵的经验，这些经验是我无法通过上学和玩耍学到的。", "chapter": "", "date": "2018-03-10", "star": null}, {"content": "中国那有这条件，现在区块链也一样，但很少小朋友有机会了解", "abstract": "。我从12岁起开始在那里做球童。于是我开始拿做球童挣的钱炒股。我的第一笔投资投给了东北航空。", "chapter": "", "date": "2018-03-10", "star": null}, {"content": "受教！", "abstract": "努力和朋友一起帮助客户打败市场，要比拥有一份真正的工作有意思得多。", "chapter": "", "date": "2018-03-10", "star": null}, {"content": "生老病死，人生无常，早日看透，将指导我们更好地活着！", "abstract": "得我再也不会笑了。现在每当我想起她时，我都会微笑。", "chapter": "", "date": "2018-03-06", "star": null}, {"content": "我们做事，更多的是听从自已的内心，而不是为了得到某个人的认可。", "abstract": "除了能得到母亲的认可之外，上学上得好还能带给我什么。", "chapter": "", "date": "2018-03-06", "star": null}, {"content": "", "abstract": "我将重点强调我犯过的错误和我的弱点，以及我从这些错误和弱点中总结出的原则。", "chapter": "", "date": "2018-03-05", "star": null}, {"content": "我们很多人到死都不知道自己的天赋是什么，因为他没有大敢去尝试，发现自己的 负熵内核 是很重要的事情！", "abstract": "我们不断了解自身和现实，然后做出新的决定。在一生中，我们会做出无数的决定，这些决定实质上都是赌博，一些是大赌，一些是小赌。思考我们如何做出决定是有好处的，因为这将最终决定我们的生活质量。", "chapter": "", "date": "2018-03-05", "star": null}, {"content": "我怎么知道呢？好奇！", "abstract": "“我知道我是对的”变成了“我怎么知道我是对的”。", "chapter": "", "date": "2018-03-04", "star": null}]}, {"id": "22468641", "title": "黄帝思想与中华引擎1", "author": "廖凯原 张少瑜", "cover": "https://cdn.weread.qq.com/weread/cover/69/YueWen_22468641/s_YueWen_22468641.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=71b322907156d82171bb385", "progress": 87, "finished": 0, "hlCount": 12, "ideaCount": 0, "highlights": [{"text": "特别赞颂了黄帝杀蚩尤和商鞅刑太子傅的事迹。", "chapter": "六 分析与评论", "date": "2023-02-10", "color": null}, {"text": "廖先生对先知作用的批驳是他最光辉的思想点之一。", "chapter": "六 分析与评论", "date": "2023-02-10", "color": null}, {"text": "移黄帝道家思想而入新儒家思想的关键人物是董仲舒。", "chapter": "六 分析与评论", "date": "2023-02-10", "color": null}, {"text": "道的科学观", "chapter": "五 道治在中国的历史与未来", "date": "2023-02-10", "color": null}, {"text": "廖以为更积极的版本是：“己所欲，施于人。", "chapter": "四 道治在社会治理中的具体应用", "date": "2023-02-10", "color": null}, {"text": "如美国等。他们是以神治为基础的，易沦为人治。", "chapter": "一 廖凯原先生道治思想的主要内容", "date": "2023-02-10", "color": null}, {"text": "道治就是先予后取的德治", "chapter": "一 廖凯原先生道治思想的主要内容", "date": "2023-02-10", "color": null}, {"text": "元零定律", "chapter": "二 中国梦必须由中华引擎提供动力", "date": "2023-02-10", "color": null}, {"text": "我们之所以将一米定义为1/c秒是因为时间可以和空间互相转化，而空间也可与时间互相转化。", "chapter": "二 中国梦必须由中华引擎提供动力", "date": "2023-02-10", "color": null}, {"text": "一切事物都是比特波[插图]（cte）", "chapter": "二 中国梦必须由中华引擎提供动力", "date": "2023-02-10", "color": null}, {"text": "比特是能量，能量是物质。", "chapter": "二 中国梦必须由中华引擎提供动力", "date": "2023-02-10", "color": null}, {"text": "00 =存在=1", "chapter": "二 中国梦必须由中华引擎提供动力", "date": "2023-02-10", "color": null}], "ideas": []}, {"id": "38552418", "title": "复盘", "author": "虚舟", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/418/38552418/s_38552418.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=7cf32340724c43627cf2a01", "progress": 83, "finished": 0, "hlCount": 12, "ideaCount": 0, "highlights": [{"text": "情绪的背后一定有某个特定的认知，一旦找到这种认知，情绪便很容易得到调整。", "chapter": "第三节 把情绪当作朋友，你需要这些锦囊", "date": "2022-11-25", "color": null}, {"text": "在这样一个随时在线的时代，我们需要能够有勇气做到定期离线。书中指出，如果你没有自由的时间来做白日梦、胡思乱想，那你的创造力一定非常有限。", "chapter": "第一节 慢——以慢为快", "date": "2022-11-24", "color": null}, {"text": "人的思维有一个致命的思维缺陷，就是：自己看自己，永远都是对的。", "chapter": "第三节 好复盘的三个标准", "date": "2022-11-24", "color": null}, {"text": "人有贪嗔痴慢，一旦意识到自己身上有某个值得反省的点，就需要直面自己，不断磨练自己的灵魂和心志，从而让自己得到净化。只有这样，人才能走出小我，拥抱大我，在自我进化的道路上渐行渐远。", "chapter": "第二章：复盘这件小事为什么对你这么重要？", "date": "2022-11-24", "color": null}, {"text": "他认为，在我们的思维模式中，要从说“我是对的”，变成问自己“我怎么知道我是对的？”", "chapter": "第二章：复盘这件小事为什么对你这么重要？", "date": "2022-11-24", "color": null}, {"text": "人才获得了真正的自由。因为考核你的不是某个人，不是某个组织，而是天道，是老天爷。", "chapter": "第二节 人生的第一性原理", "date": "2022-11-24", "color": null}, {"text": "桃李不言下自成蹊，你若盛开，清风与蝴蝶自来。", "chapter": "第二节 人生的第一性原理", "date": "2022-11-24", "color": null}, {"text": "老子告诉我们，天之道，利而不害；圣人之道，为而不争。宇宙本身所做的事情，就是在创造各种条件促进万物的生长和进化，而圣人的法则，也是努力去推动人类的进化，而无需在意得失。", "chapter": "第二节 人生的第一性原理", "date": "2022-11-24", "color": null}, {"text": "为了宇宙的进化、世界的进化、自然的计划、人类的进化贡献自己，这就是个体最根本的生存发展之道。这就是人生的第一性原理。", "chapter": "第二节 人生的第一性原理", "date": "2022-11-24", "color": null}, {"text": "而个体的进化本身，就是宇宙的进化。因为个体和宇宙是一体的，是一不是二，是一个不可分割的整体。由于“看不见的手”的存在，个体进化本身，不管从主观上还是客观上来说，都并非是为了自己，而是为了整体。", "chapter": "第二节 人生的第一性原理", "date": "2022-11-24", "color": null}, {"text": "从个体的角度来看，死亡是残酷的、可怕的，但是从宇宙、大自然的角度来看，死亡再正常不过，不仅正常不过，而且是必须的、必要的，因为它符合进化的需要。", "chapter": "第二节 人生的第一性原理", "date": "2022-11-24", "color": null}, {"text": "对于人来说，这个熵来自于哪里呢？就是来自于小我，无数的小我，让人逐渐处于一种封闭的系统当中无法自拔，除非你不断做功，达到熵减的目标。", "chapter": "第一节 人生的两条曲线：成长的本质是思维通道的改变", "date": "2022-11-24", "color": null}], "ideas": []}, {"id": "24059460", "title": "山海经（全译插图典藏版）", "author": "小岩井译注", "cover": "https://cdn.weread.qq.com/weread/cover/56/YueWen_24059460/s_YueWen_24059460.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=e6232140716f1e44e62da47", "progress": 100, "finished": 1, "hlCount": 12, "ideaCount": 0, "highlights": [{"text": "西南有一个巴国。大皞生了咸鸟，咸鸟生了乘[插图]，乘[插图]生了后照，而后照就是巴国人的祖先。", "chapter": "海内经", "date": "2022-08-25", "color": null}, {"text": "东海之内，北海之隅，有国名曰朝鲜①、天毒②，其人水居，偎③人爱人。", "chapter": "海内经", "date": "2022-08-25", "color": null}, {"text": "应龙在杀了蚩尤以后，又杀了夸父，因他的神力耗尽上不了天，就去南方居住，所以南方的雨水很多。", "chapter": "大荒北经", "date": "2022-08-25", "color": null}, {"text": "颛顼生了老童，老童生了祝融，祝融生了太子长琴，太子长琴住在榣山上，最早开始创作乐曲之风", "chapter": "大荒西经", "date": "2022-08-25", "color": null}, {"text": "有西周之国，姬姓，食谷。有人方耕，名曰叔均。帝俊生后稷，稷降以百谷。稷之弟曰台玺，生叔均。叔均是代其父及稷播百谷，始作耕。有赤国妻氏。有双山。", "chapter": "大荒西经", "date": "2022-08-25", "color": null}, {"text": "西王母梯①几而戴胜②。其南有三青鸟，为西王母取食。在昆仑虚北。", "chapter": "海内西经", "date": "2022-08-25", "color": null}, {"text": "颛顼（zhuān xū）：中国上古的“五帝”之一，姬姓，号高阳氏，黄帝之孙。", "chapter": "海外北经", "date": "2022-08-25", "color": null}, {"text": "夸父①与日逐走，入日。渴欲得饮，饮于河渭，河渭不足，北饮大泽。未至，道渴而死。弃其杖，化为邓林。", "chapter": "海外北经", "date": "2022-08-25", "color": null}, {"text": "共工①之臣曰相柳氏②，九首，以食于九山。相柳之所抵，厥为泽谿。禹杀相柳，其血腥，不可以树五谷种。", "chapter": "海外北经", "date": "2022-08-25", "color": null}, {"text": "有个地方叫沃野，沃野的人民住在那里，那里鸾鸟自在地歌唱，凤鸟自在地舞蹈；凤凰产下的卵，居民可以食用；上天降下的甘露，居民可以饮用，凡是这些人想要的，上天都会满足。人们与各种野兽居住在一起。这个地方在四条大蛇的北边。这个国家的人两只手拿着凤凰蛋吃，有两只鸟在前面引导。", "chapter": "海外西经", "date": "2022-08-25", "color": null}, {"text": "祝融：古代传说中大荒十神之一的火神。", "chapter": "海外南经", "date": "2022-08-25", "color": null}, {"text": "帝之二女居之，是常游于江渊。澧沅之风，交潇湘之渊，是在九江之间，出入必以飘风暴雨。是多怪神，状如人而载蛇，左右手操蛇。多怪鸟。", "chapter": "中次十二经", "date": "2022-08-25", "color": null}], "ideas": []}, {"id": "23444136", "title": "蒋勋说宋词（修订版）", "author": "蒋勋", "cover": "https://cdn.weread.qq.com/weread/cover/69/YueWen_23444136/s_YueWen_23444136.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=2d132c807165baa82d14e2b", "progress": 72, "finished": 0, "hlCount": 12, "ideaCount": 0, "highlights": [{"text": "所谓“至广大”是一种能力，“近精微”也是一种能力。如果说唐朝一直在“至广大”，那么到了宋朝则开始“近精微”了，当然在整个儒家的道统里面，“至广大”和“近精微”必须合在一起才是完整的。", "chapter": "深情存于万事万物", "date": "2022-08-12", "color": null}, {"text": "宋朝是可以静观万物的，静观万物是因为你对自己的生命有信心，可以看到生命来来去去；你有更大的包容，不去做比较和分辨。", "chapter": "包容之美", "date": "2022-08-12", "color": null}, {"text": "在历史上，知识分子常常处于战战兢兢的状况中，要么卑微，要么悲壮，能够有宋朝知识分子那么坦荡的情怀的是少数。我觉得这也是由于宋代继承了后蜀和南唐文人政治的风气。", "chapter": "文人的从容", "date": "2022-08-12", "color": null}, {"text": "中国历史上很少有一个朝代的文人可以在政治上没有恐惧感，可是宋朝的文人有很大的自信和安全感。因为宋朝有所谓的“太祖誓碑”，继位的皇帝都必须遵守，其中一点就是“不杀士大夫”，这是宋朝非常重要的一个制度，是祖宗家法。皇帝再怎么生气，可以把大臣降职、流放，但不能杀他。", "chapter": "文人的从容", "date": "2022-08-12", "color": null}, {"text": "李商隐的“春蚕到死丝方尽”表现出一种极大的热情，而在“日日花前常病酒”中，热情开始冷淡下来了。五代词的内里常常是炙热的火烧过以后冷灰的感觉。“日日花前常病酒”就是那冷灰，它把热烈的情感拿走了。", "chapter": "以一朵花或一枚雪片的姿态体会宇宙自然", "date": "2022-08-12", "color": null}, {"text": "帘外雨潺潺，春意阑珊。罗衾不耐五更寒。梦里不知身是客，一晌贪欢。独自莫凭阑，无限江山，别时容易见时难。流水落花春去也，天上人间。", "chapter": "《浪淘沙》：李后主在美学上的极品", "date": "2022-08-12", "color": null}, {"text": "林花谢了春红，太匆匆。无奈朝来寒雨晚来风。胭脂泪，留人醉，几时重？自是人生长恨水长东。", "chapter": "命运的错置", "date": "2022-08-11", "color": null}, {"text": "沉静", "chapter": "优雅文化的发达", "date": "2022-08-11", "color": null}, {"text": "“雾失楼台，月迷津渡。”", "chapter": "雾失楼台，月迷津渡", "date": "2022-08-11", "color": null}, {"text": "“暗中偷负去，夜半真有力。”这里是用庄子的典故，庄子说：“夫藏舟于壑，藏山于泽，谓之固矣！然而夜半有力者负之而走，昧者不知也！”意思是有人把船藏在山谷当中，可是夜半船忽然不见了，因为有个大力士把船给背走了。庄子的意思是说，把东西带走的是时间，没有什么比时间更厉害，它会把所有东西偷走。这也是苏轼用庄子典故的意义所在。", "chapter": "绵中裹铁", "date": "2022-08-11", "color": null}, {"text": "他感觉到有一天要把生命还给山水。", "chapter": "可以和历史对话的人，已经不在乎活在当下", "date": "2022-08-11", "color": null}, {"text": "修炼其实是为了回来做人，而不是为了告诉别人我多了不起；能告诉别人自己没有那么了不起，才是修行。", "chapter": "融合儒、释、道", "date": "2022-08-11", "color": null}], "ideas": []}, {"id": "29196155", "title": "文明、现代化、价值投资与中国", "author": "李录", "cover": "https://cdn.weread.qq.com/weread/cover/58/yuewen_29196155/s_yuewen_291961551744777228.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=6f5323f071bd7f7b6f521e8", "progress": 100, "finished": 1, "hlCount": 11, "ideaCount": 1, "highlights": [{"text": "现代文明的本质并非政治制度，而是自由市场经济与现代科学技术的结合。", "chapter": "从外国投资人角度看中国经济的未来——2019年1月在国际投资人会议上的主旨演讲", "date": "2022-06-29", "color": null}, {"text": "他们凭着工程师文化和事在人为的精神，持续证明着自己在解决复杂的工程技术难题上的能力，并总是能够比其他大多数人找出更高效、更省钱、更优化的解决方案。这点在制造业中是个优势。", "chapter": "投资是一个发现自己的过程——2013年3月哥伦比亚大学商学院Graham&Doddsville杂志采访精编", "date": "2022-06-29", "color": null}, {"text": "中国在历史上发明了政治上的贤能制，使得中国在农业文明时期的绝大部分时间领先于欧洲。同样，也是地理因素帮助欧洲最先发现了新大陆，并促使西方发明了经济上的贤能制，从而把人类带入了新的现代文明。", "chapter": "从外国投资人角度看中国经济的未来——2019年1月在国际投资人会议上的主旨演讲", "date": "2021-12-12", "color": null}, {"text": "然而，中国政府计划在未来20年内将以每年1%的速度开展城市化进程，这意味着在未来20年内，大约有3亿人成为新的消费者。这正是参与城市化进程的全部意义所在——成为消费者。一旦你真正加入城市生活，有了基本的社会保障，你就会像身边的所有公民一样开始消费，开始赚钱，开始进入到经济循环中去。结果就是可持续的经济增长。", "chapter": "从外国投资人角度看中国经济的未来——2019年1月在国际投资人会议上的主旨演讲", "date": "2021-12-12", "color": null}, {"text": "工程师红利", "chapter": "从外国投资人角度看中国经济的未来——2019年1月在国际投资人会议上的主旨演讲", "date": "2021-12-12", "color": null}, {"text": "中国仍然处于经济发展的黄金时代，对西方发达国家仍然有成本优势，而后面的其他新兴发展中国家（如印度等）还没有形成系统性的竞争优势。今后若干年，中国的工资水平、储蓄水平、投资水平和消费水平还会呈现相互追赶的、螺旋上升的状态，处在一个互相促进的正向循环中，投资机会仍然非常丰富、优异。", "chapter": "从外国投资人角度看中国经济的未来——2019年1月在国际投资人会议上的主旨演讲", "date": "2021-12-12", "color": null}, {"text": "农业文明的基础是光合作用，它把太阳能转化成农作物和可畜养动物，而动植物都依赖土地。这就意味着土地的大小决定了农业产出和所能负担的人口数量。在整个农业文明的历史中，土地的稀缺性是贯穿始终的主题。某个社会一旦拥有更多的土地，就会产生更多的人口，当人口多到一定程度，超过土地大小所能承载的极限，就会陷入马尔萨斯陷阱。战争、瘟疫、饥荒纷至沓来，人口急剧减少，又开始新一轮的循环。农业文明的经济是短缺经济，也即农业经济不足以维持人口的正常增长规模，在到达土地产出极限时，人类的总人口只能减少。", "chapter": "从外国投资人角度看中国经济的未来——2019年1月在国际投资人会议上的主旨演讲", "date": "2021-12-12", "color": null}, {"text": "莫里斯定律（Morris Theorem）：“历史，就是懒惰、贪婪、又充满恐惧的人类，在寻求让生活更容易、安全、有效的方式时创造的，而人类对此毫无意识。", "chapter": "农业文明的诞生", "date": "2021-05-20", "color": null}, {"text": "1776年亚当·斯密的《国富论》的出版、美国《独立宣言》的发表和瓦特蒸汽机的发明这三件互不相干的事件在同一年里发生，成为人类文明史上的分水岭，此后人类社会的现代化进程一发而不可收，从英国开始向全球蔓延。这三件事分别代表了自由市场经济、宪政民主制下的有限政府以及现代科学技术。纵观从工业革命开始持续至今全球最成功、最发达的国家都具备这三个关键的要素。", "chapter": "序二 得道者多助——常劲", "date": "2021-03-15", "color": null}, {"text": "有一次我问诺曼：“你感觉自己多大年龄？”他答：“我永远和与我对话者同龄。”这是我听到的关于年龄的最酷答案！从那以后我就特别关注与我交流的人。", "chapter": "五十述怀", "date": "2021-03-04", "color": null}, {"text": "3.0文明的铁律", "chapter": "从文明史角度看当今中美关系及科技文明时代的东西方关系", "date": "2021-03-03", "color": null}], "ideas": [{"content": "今天实现了！", "abstract": "，3月3日中国开始一年一度的两会。期间，中国政府再次承诺，要在2017年让1000万人民摆脱贫困，并在2020年彻底消除贫困。如果这个目标实现了，将会是中国5000年历史上的首次创举——要知道中国这块土地上生活了将近五分之一的地球人口", "chapter": "", "date": "2021-03-04", "star": null}]}, {"id": "3300061942", "title": "人间清醒2：底层逻辑和顶层认知", "author": "水木然", "cover": "https://cdn.weread.qq.com/weread/cover/88/cpplatform_aq9uukpim68tqjwu4jkb2s/s_cpplatform_aq9uukpim68tqjwu4jkb2s1686815150.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=15532ad0813ab7eb2g01208e", "progress": 99, "finished": 0, "hlCount": 11, "ideaCount": 0, "highlights": [{"text": "如果把金钱和认知放在人面前，人们往往会选择金钱，因为太多人不知道，认知不仅可以换来很多金钱，还能换来幸福，甚至健康。", "chapter": "认知升级", "date": "2026-03-24", "color": 1}, {"text": "说话直的本质是自私，把说话直当成率真则是无知。", "chapter": "深思见真知", "date": "2024-07-18", "color": 1}, {"text": "。痛苦的根源是期待，期待的根源是自己的不圆满。真正的智者，对他人没有期待，只会对自己的圆满有期待，所以他们只爱自己。", "chapter": "爱情与婚姻", "date": "2024-07-18", "color": 1}, {"text": "儒家可以提升我们的执行力，道家可以提升我们认知力，佛家则可以提升我们的心力。", "chapter": "人生成长曲线", "date": "2024-07-18", "color": 1}, {"text": "所谓“高维的我”，不同领域有不同的叫法，心理学称它为“真我”，佛家称它为“阿赖耶识”，道家称它为“元神”，禅宗称它为“明心见性”，阳明心学称它为“良知”，我们称它为“初心”，等等。", "chapter": "人生成长曲线", "date": "2024-07-18", "color": 1}, {"text": "成长的过程，就是克服人性弱点的过程。谁能做到“反人性”，不断地精进和修身，谁才是强者。", "chapter": "认知突围", "date": "2024-07-18", "color": 1}, {"text": "认知有三个层级。第一层：诸葛亮明知城是空的，却可以故作淡定。第二层：司马懿明知诸葛亮使出的是“空城计”，却还故意不捉他。第三层：诸葛亮明知司马懿识破了自己的“空城计”，却还可以继续淡定。", "chapter": "深思见真知", "date": "2024-07-18", "color": 1}, {"text": "所谓“见过大世面”，是你悟到了社会的真相和人性的规律。当你看到真相和人性在你面前徐徐展开的时候，你是淡定且坦然的，因为这些都在你的意料之中。真相，不是用眼睛看到的，而是用心感知到的。看到的是常识，是表象；悟到的才是认知，才是世面。", "chapter": "深思见真知", "date": "2024-07-18", "color": 1}, {"text": "当你觉得需要提升某种技巧的时候，比如写作和演讲，其实是需要提升思想和认知了，因为思想比技能高一个维度。", "chapter": "深思见真知", "date": "2024-07-18", "color": 1}, {"text": "愿你翻越千山，归来仍是少年！", "chapter": "深思见真知", "date": "2024-07-18", "color": 1}, {"text": "真正的“顺其自然”是竭尽所能之后的不强求，而非在困难面前两手一摊的不作为。", "chapter": "认知升级", "date": "2024-07-18", "color": 1}], "ideas": []}, {"id": "23444134", "title": "蒋勋说唐诗（修订版）", "author": "蒋勋", "cover": "https://cdn.weread.qq.com/weread/cover/67/YueWen_23444134/s_YueWen_23444134.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=a1b32c107165baa6a1bc1ca", "progress": 100, "finished": 1, "hlCount": 11, "ideaCount": 0, "highlights": [{"text": "春天有一只鸟那样把春天叫回来。我们不知道在睡着的", "chapter": "此情可待成追忆", "date": "2026-02-16", "color": null}, {"text": "耽溺、感伤。“寻芳不觉醉流霞”，花有一点远，所", "chapter": "更持红烛赏残花", "date": "2026-02-09", "color": null}, {"text": "“……家在虾蟆陵下住。十三学得琵琶成，名属教坊第一部”，十三岁学会了琵琶，列名在皇宫的教坊第一部当中，等于是当时的名妓。“曲罢曾教善才服”，每一次弹完音乐以后，都会让教她的那些老师", "chapter": "《琵琶行》——深情", "date": "2026-01-31", "color": null}, {"text": "的", "chapter": "《琵琶行》——音乐", "date": "2026-01-31", "color": null}, {"text": "到了声音最低最低的时候，一定要“银瓶乍破水浆迸”", "chapter": "《琵琶行》——音乐", "date": "2026-01-31", "color": null}, {"text": "“文以载道”的文学的时候，甚至是反感的，觉得里面有很多八股教条。可是今天却常常会觉得", "chapter": "惟歌生民病，愿得天子知", "date": "2026-01-30", "color": null}, {"text": "判别人，而是批判自己。白居易觉得自己过去写了", "chapter": "惟歌生民病，愿得天子知", "date": "2026-01-30", "color": null}, {"text": "襄阳向洛阳。”这两句诗非常有名，里面用了四个地名，让时间感得到了加强，表现出他想回家的急迫心情。这很像四个蒙太奇画面，充满了速度感。可以看出杜甫惊人的诗歌", "chapter": "离乱与还乡", "date": "2026-01-30", "color": null}, {"text": "写了自己作为难民的经历与心情。杜甫不管怎么说，还是一位官员，还", "chapter": "离乱与还乡", "date": "2026-01-30", "color": null}, {"text": "东坡。虽然一直受到政治上的打击，可是苏东坡知道不", "chapter": "山水中生命的状态", "date": "2026-01-11", "color": null}, {"text": "断续的，很少是断就断、续就续，大部分的情感是在", "chapter": "交响诗乐章", "date": "2026-01-11", "color": null}], "ideas": []}, {"id": "3300054149", "title": "相信", "author": "蔡磊", "cover": "https://cdn.weread.qq.com/weread/cover/71/cpplatform_iheluiy1p49t13lmk5k4mb/s_cpplatform_iheluiy1p49t13lmk5k4mb1680152716.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=cd932fa0813ab7ba6g019df6", "progress": 100, "finished": 1, "hlCount": 11, "ideaCount": 0, "highlights": [{"text": "生活充满了意外，或者说，生活就是由一系列意外构成的——意外的失败、意外的艰难，也有意外的收获、意外的馈赠。我们唯一能决定的就是选择相信什么。", "chapter": "后记", "date": "2023-10-31", "color": 1}, {"text": "我常想，在生命的长度上，自己应该是没什么优势了，那么就尽量活出宽度、厚度来，努力给这个世界、给后人留点儿什么。就像当年“小外星人”在作文里写的那样：“要为人类科学的进步做贡献。”", "chapter": "第五章 疯狂的石头 “这事只有外星人才能做成。”", "date": "2023-10-31", "color": 1}, {"text": "说白了，信则灵。你相信治疗有效，就真的有效。这在医学上并不稀奇，治疗的效果和人的心理预期有密切关系。1955年，哈佛大学医学院教授毕阙(Henry K.Beecher)博士将这种现象命名为“安慰剂效应”。", "chapter": "第四章 见高人，尝百药 “蔡磊，我一定能治好你！”", "date": "2023-10-31", "color": 1}, {"text": "如果我们自己都不努力，还能奢望别人为我们努力吗？", "chapter": "第二章 绝望与希望 “蔡大哥如果是癌症就太好了，祝贺！”", "date": "2023-10-31", "color": 1}, {"text": "楼下一个捡垃圾的流浪汉恰好经过，老朱打住话头，盯着那个身影，眼里全是羡慕。想必我目光的成分跟他并无二致。那个流浪汉能四肢康健地沐浴着阳光，而且，似乎拥有绵延的生命。", "chapter": "第二章 绝望与希望 “蔡大哥如果是癌症就太好了，祝贺！”", "date": "2023-10-31", "color": 1}, {"text": "没有人准备好死亡，更别说刚过40岁、年富力强、家庭和事业蒸蒸日上的我", "chapter": "第一章 不期而遇 “我还得干大事呢！”", "date": "2023-10-30", "color": 1}, {"text": "电梯都不愿意等，现在却只能等死", "chapter": "第一章 不期而遇 “我还得干大事呢！”", "date": "2023-10-30", "color": 1}, {"text": "几秒钟前，那条光影还闪着金边，饱满热烈，现在却一下子变得暗淡无光，了无生气。这世界已经不属于我了。我要死掉了。", "chapter": "第一章 不期而遇 “我还得干大事呢！”", "date": "2023-10-30", "color": 1}, {"text": "如顾城在《一代人》中所写，“黑夜给了我黑色的眼睛，我却用它寻找光明”", "chapter": "尹烨 相信相信的力量", "date": "2023-10-30", "color": 1}, {"text": "人类基本的神性，就是相信相信的力量。", "chapter": "尹烨 相信相信的力量", "date": "2023-10-30", "color": 1}, {"text": "我们确实是到了一个知识大爆炸的时代，所谓的奇点可能真的会在我们这一代到来。", "chapter": "陈天桥 相信自己，相信科技，相信未来", "date": "2023-10-30", "color": 1}], "ideas": []}, {"id": "26406758", "title": "人间值得（畅销200万册纪念版）", "author": "[日]中村恒子 [日]奥田弘美", "cover": "https://cdn.weread.qq.com/weread/cover/32/yuewen_26406758/s_yuewen_264067581720754472.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=0f8325307192ef660f8c2f7", "progress": 100, "finished": 0, "hlCount": 11, "ideaCount": 0, "highlights": [{"text": "表面看上去风光无限的人，其实他们承担的责任更大，立场以及人际关系更复杂。因此，他们遇到的问题和承受的压力，比旁人看到的要多得多。", "chapter": "23 人很难不与他人比较，即便健康有活力的人，未必没有烦恼", "date": "2023-01-16", "color": null}, {"text": "18 痛苦会成为今后重要的经验，所以一次也不要浪费人生总会遇到不愉快的事。有些事能靠自己解决，而有些事我们无能为力。我们的困扰主要来自于后者。", "chapter": "18 痛苦会成为今后重要的经验，所以一次也不要浪费", "date": "2023-01-16", "color": null}, {"text": "当你面对“为了什么而工作”感到迷茫时，你就干脆而果断地告诉自己“工作只是为了赚钱养活自己而已”。这就是人为何要工作的根本。", "chapter": "第1章 工作是为了什么", "date": "2023-01-16", "color": null}, {"text": "因此，在我看来，为了钱而工作，并不是可耻的事情，这是理所当然的事，我认为是非常了不起的。", "chapter": "第1章 工作是为了什么", "date": "2023-01-16", "color": null}, {"text": "然而，从本质上来说，人就是为了生活而工作。这个道理，亘古未变。为了养活自己，为了养活家人而工作，我认为这是工作的首要目的。", "chapter": "第1章 工作是为了什么", "date": "2023-01-16", "color": null}, {"text": "人从出生的时候就是一个人，死亡的时候也是一个人。死亡即生命的终结，至于死后的评价、虚荣以及其他情况，大可不必在意。", "chapter": "31 孤独地死去非常好，担心死亡的方式毫无意义", "date": "2022-12-30", "color": null}, {"text": "一个人安安静静地离开也很美妙。", "chapter": "31 孤独地死去非常好，担心死亡的方式毫无意义", "date": "2022-12-30", "color": null}, {"text": "如果想着“到了晚上先睡觉，第二天早上再思考”，我很快就能入睡。第二天早上，心情就会发生变化，想法也可能与之前不同。", "chapter": "第4章 让心归于平静", "date": "2022-12-30", "color": null}, {"text": "对未来担心也没用，你有忽略眼前的事吗？我只关心眼前的事", "chapter": "第4章 让心归于平静", "date": "2022-12-30", "color": null}, {"text": "总想着得失，那么就会觉得勉强自己，甚至产生心结。与其如此，还不如率性而为，跟随心的决定。", "chapter": "10 机会源于偶然，如果有人助力，就顺势而为", "date": "2022-12-29", "color": null}, {"text": "不需要夸张幸福的价值，欢喜来临时就满心欢喜，如果头脑中出现一些所谓“必须”要做的事，不妨毫不犹豫地说：“不要做”。人生，就是这样周而复始。", "chapter": "第2章 不要期待过多，对生活中的小事心存感激", "date": "2022-12-29", "color": null}], "ideas": []}, {"id": "37188887", "title": "起源：NASA天文学家的万物解答", "author": "巴赫拉姆·莫巴舍尔", "cover": "https://cdn.weread.qq.com/weread/cover/46/YueWen_37188887/s_YueWen_37188887.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=e0632ba072377517e068ce2", "progress": 43, "finished": 0, "hlCount": 11, "ideaCount": 0, "highlights": [{"text": "地球上的生命进化是一个极端复杂的过程。只有那些能够适应它们所处环境的系统才能存活并繁荣。基因突变导致了我们今天观察到的动植物多样化。第一批灵长目的历史可以一直追溯到6 500多万年前，而我们最近的祖先——最初的智人（Homo sapiens）则在15万到10万年前生活在这颗星球上。", "chapter": "Chapter 01 介绍与回顾", "date": "2021-12-18", "color": null}, {"text": "“生命的悲剧就在于，我们老得太快，聪明得太晚。”", "chapter": "前言", "date": "2021-12-18", "color": null}, {"text": "[插图]", "chapter": "Chapter 14 重元素的起源", "date": "2021-05-12", "color": null}, {"text": "物体的质量是对其惯性的度量", "chapter": "Chapter 01 介绍与回顾", "date": "2021-05-11", "color": null}, {"text": "如果一颗恒星足够大，它会作为超新星爆发，把其中生成的重物质散布到星际空间内，用重化学元素丰富这种介质。这就是地球上发现的重元素的来源，也是让生命得以诞生的元素。", "chapter": "Chapter 01 介绍与回顾", "date": "2021-05-11", "color": null}, {"text": "我们在夜空中看到的一切，以及我们在宇宙成分中看到的一切，只占整个宇宙的4%。", "chapter": "Chapter 01 介绍与回顾", "date": "2021-05-11", "color": null}, {"text": "今天，我们对宇宙的成分有着准确的估计：暗物质占22%，暗能量占74%，正常物质占4%——尽管我们对于支配其不同成分的本质还不那么清楚。", "chapter": "Chapter 01 介绍与回顾", "date": "2021-05-11", "color": null}, {"text": "宇宙中最轻的原子核，即氢原子的原子核，是在大爆炸后大约1分钟形成的", "chapter": "Chapter 01 介绍与回顾", "date": "2021-05-11", "color": null}, {"text": "“教育是在人们忘记了自己在学校里学过的东西后仍然存在的东西。”我希望，这本书中的材料会成为你们的教育的一部分。", "chapter": "前言", "date": "2021-05-11", "color": null}, {"text": "这是在无穷无尽的太空中飘浮着的一粒小小尘埃，但它却是70亿人的家园", "chapter": "前言", "date": "2021-05-11", "color": null}, {"text": "发现的最大障碍不是无知，而是自己幻觉中的知识。——丹尼尔·J. 布尔斯廷 （DANIEL J. BOORSTIN）历史学家", "chapter": "献言", "date": "2021-05-11", "color": null}], "ideas": []}, {"id": "26605835", "title": "财富的起源：探讨关税对财富根源的作用", "author": "埃里克·拜因霍克", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/835/26605835/s_26605835.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=d14328d07195f90bd148088", "progress": 100, "finished": 1, "hlCount": 10, "ideaCount": 1, "highlights": [{"text": "令人惊讶的是，研究人员从参与、监督、儿童自主性培养、情感陪伴和认知刺激五个方面进行衡量后发现，父母的教养方式对孩子的影响不如预期的那么重要。真正重要的似乎是父母自身的行为表现，而不是教育技巧本身，", "chapter": "18 公共政策：左右派争论的终结", "date": "2021-04-07", "color": null}, {"text": "人类既不是卢梭笔下纯洁无私的生物，也不是休谟笔下无情自私的生物，而经济学家和道德哲学家亚当·斯密是对的——人类两者兼具。", "chapter": "18 公共政策：左右派争论的终结", "date": "2021-04-07", "color": null}, {"text": "过度乐观的倾向是人类内心深处的欲望之一，我们渴望相信自己的能力。", "chapter": "16 组织：创造“心智社会”，释放个体的创造力", "date": "2021-04-07", "color": null}, {"text": "我们可以将组织视为一个开放的热力学系统，它的内部世界与外部世界有一个明显的区分界限，而且组织的目标驱动着降低组织系统内部与外部环境相关联的熵的活动。", "chapter": "16 组织：创造“心智社会”，释放个体的创造力", "date": "2021-04-07", "color": null}, {"text": "组织是有目标导向、持续边界和社会建构的人类活动系统。", "chapter": "16 组织：创造“心智社会”，释放个体的创造力", "date": "2021-04-07", "color": null}, {"text": "组织是复杂的适应性系统。", "chapter": "16 组织：创造“心智社会”，释放个体的创造力", "date": "2021-04-07", "color": null}, {"text": "经济过程实质上是由高熵向低熵的转变构成的", "chapter": "14 重新定义财富", "date": "2021-04-07", "color": null}, {"text": "要想让社会技术适合，我们必须制定机制来惩罚那些不友善的参与者。", "chapter": "12 力量三：社会技术", "date": "2020-10-01", "color": null}, {"text": "在大约30亿到35亿年前的某个时间点，发生了一场引人注目的意外——能够复制自身的分子被创造出来。", "chapter": "09 视角五：经济是一个进化系统", "date": "2020-10-01", "color": null}, {"text": "进化是一种算法", "chapter": "09 视角五：经济是一个进化系统", "date": "2020-09-25", "color": null}], "ideas": [{"content": "组织是实现低熵的一个工具。", "abstract": "“健康秩序”或财富的工具。", "chapter": "", "date": "2021-04-07", "star": null}]}, {"id": "36213096", "title": "征服市场的人：DeepSeek 创始人梁文锋作序", "author": "格里高利·祖克曼", "cover": "https://cdn.weread.qq.com/weread/cover/84/YueWen_36213096/s_YueWen_36213096.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=57d322107228916857ddb4f", "progress": 93, "finished": 0, "hlCount": 10, "ideaCount": 0, "highlights": [{"text": "从数学意义上说，布朗、默瑟和杰利内克的团队把语音序列视为一个随机过程，每一个当前出现的语音都是随机的，但同时依赖上一步出现的那个语音，这个过程遵循隐马尔可夫模型。", "chapter": "第9章 挖角IBM，招揽最优秀的人才", "date": "2025-02-09", "color": 1}, {"text": "他们认为，语言可以被视为一种概率游戏。在一个句子的任意单词之后出现的单词服从某种概率分布，这种概率分布是由通行的用法或者上下文决定的。", "chapter": "第9章 挖角IBM，招揽最优秀的人才", "date": "2025-02-09", "color": 1}, {"text": "之后的十几年内，这次交易都被认为是史上最伟大的交易，它强有力地展示了智慧和勇气的价值。", "chapter": "第9章 挖角IBM，招揽最优秀的人才", "date": "2025-02-09", "color": 1}, {"text": "“我们实际上是在对人类行为建模，”佩纳维奇解释道，“人类在高压下的行为具有很高的可预测性，他们会本能地表现出恐慌。我们建模的前提是人类会不断重复过去的行为……我们学会了利用这一点。”", "chapter": "第8章 只用单一的交易模型", "date": "2025-02-09", "color": 1}, {"text": "损失厌恶是指，投资者因承受损失而感受到的痛苦是因获利而感受到的满足的两倍；“锚固偏见”是指，先入为主的信息或经验会扭曲当前的判断；“禀赋效应”就是俗话说的“屁股决定脑袋”。", "chapter": "第8章 只用单一的交易模型", "date": "2025-02-09", "color": 1}, {"text": "但西蒙斯和同事们总觉得这种说法有失偏颇，他们觉得投资者有很多认知偏差，正是这些认知偏差导致了恐慌、泡沫、暴涨和崩盘。", "chapter": "第8章 只用单一的交易模型", "date": "2025-02-09", "color": 1}, {"text": "只有系统能决定我们交易什么。”", "chapter": "第6章 神奇公式，在高频交易中盈利", "date": "2025-02-08", "color": 1}, {"text": "我的世界一直在下雪，我想换个环境。", "chapter": "第5章 大奖章诞生，致敬曾经获得的数学奖章", "date": "2025-02-08", "color": 1}, {"text": "“我在赚钱的时候，觉得自己是个天才，”他告诉一个朋友，“在亏损的时候，又觉得自己是个傻瓜。”", "chapter": "第4章 一场投资革命蓄势待发", "date": "2025-02-08", "color": 1}, {"text": "西蒙斯的话：“一定有办法对价格建模。”", "chapter": "推荐序2", "date": "2025-02-08", "color": 1}], "ideas": []}, {"id": "44315941", "title": "长寿：当人类不再衰老", "author": "大卫·辛克莱 马修·拉普兰特", "cover": "https://cdn.weread.qq.com/weread/cover/71/YueWen_44315941/s_YueWen_44315941.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=5fe320b072a435255fe15ab", "progress": 100, "finished": 1, "hlCount": 10, "ideaCount": 0, "highlights": [{"text": "与每周洗1次热水澡的人相比，那些每周蒸7次桑拿的人患心脏病、致命心肌梗死和全因死亡事件的概率减小了2倍。", "chapter": "第二部分 健康跃升，科学给每个人的启示", "date": "2023-11-01", "color": 1}, {"text": "因为事实证明，让你的身体暴露在不太舒适的温度下，是另一个非常有效的开启你的长寿基因的方法。", "chapter": "第二部分 健康跃升，科学给每个人的启示", "date": "2023-11-01", "color": 1}, {"text": "运动越多的人的端粒就越长", "chapter": "第二部分 健康跃升，科学给每个人的启示", "date": "2023-11-01", "color": 1}, {"text": "研究表明，当我们用更多的植物蛋白替代动物蛋白时，全因死亡率显著下降。", "chapter": "第二部分 健康跃升，科学给每个人的启示", "date": "2023-11-01", "color": 1}, {"text": "那些每三天就挨一次饿的老鼠的寿命比每天定时进食的堂兄弟们延长了15%～20%", "chapter": "第二部分 健康跃升，科学给每个人的启示", "date": "2023-11-01", "color": 1}, {"text": "由于幼年缺少食物而生长发育迟缓的雌性老鼠比那些吃得多的老鼠活得更久", "chapter": "第二部分 健康跃升，科学给每个人的启示", "date": "2023-11-01", "color": 1}, {"text": "但是节食让我们的身体处于一种渴望的状态，而不是像大多数人那样在这个物质丰富的世界大快朵颐，节食无疑是有助于我们健康长寿的。", "chapter": "第二部分 健康跃升，科学给每个人的启示", "date": "2023-11-01", "color": 1}, {"text": "总结起来，其实就是“逆境中求生存”——能吃饱，我偏要饿着点儿，能穿暖，我偏要冷着点儿，能舒适，我偏要累着点儿，其统一的机制都是激活人体内最原始的生存回路。", "chapter": "推荐序一 衰老与寿命的进化论", "date": "2023-11-01", "color": 1}, {"text": "人类的细胞分裂次数约为50次，平均每次分裂的周期约为2.4年，那么人类的自然寿命大约就是120岁。", "chapter": "推荐序一 衰老与寿命的进化论", "date": "2023-11-01", "color": 1}, {"text": "再进一步说，为什么生命要有期限？为什么生命不能永恒？因为进化的需要。有生有死才有自然选择，才能实现优胜劣汰，才能完成进化升级，而永生意味着进化的停滞。所以无论能活多久，只要还在进化，死亡就是必需的。那么为什么人类的最大寿命约为120岁？为什么不能是180岁？这个说起来比较复杂。简单来说，这与人体细胞的分裂次数有关，正如薛定谔在其著名的《生命是什么》中所说", "chapter": "推荐序一 衰老与寿命的进化论", "date": "2023-11-01", "color": 1}], "ideas": []}, {"id": "27525171", "title": "让时间陪你慢慢变富", "author": "李笑来", "cover": "https://cdn.weread.qq.com/weread/cover/48/yuewen_27525171/s_yuewen_275251711763435700.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=8ab32c2071a400338ab8bb8", "progress": 99, "finished": 1, "hlCount": 10, "ideaCount": 0, "highlights": [{"text": "投资的本质是什么？投资的本质就是用你的钱去帮你赚钱——而钱这个东西，它是不休息的，它一年365天，每天24小时，在投资正确的前提下，它都在为你工作。", "chapter": "10 定投是普通人必需的选择", "date": "2022-06-06", "color": null}, {"text": "决定一个人富有的三个条件，一是出身，二是运气，三是努力；而这三者之中，努力是最微不足道的。", "chapter": "10 定投是普通人必需的选择", "date": "2022-06-06", "color": null}, {"text": "为自己想做的、正在做的事情拼命赋予伟大的意义。", "chapter": "8 有些人总是身处正确的一侧", "date": "2022-06-06", "color": null}, {"text": "● 投资周期越长，被动的优势越大；● 投资额度越大，被动的优势越大。", "chapter": "6.6 顺应趋势的被动力量究竟有多么强大", "date": "2022-06-06", "color": null}, {"text": "如果，教育就是这个系统想让你变成什么样子，那么，自学，就是你自己想要变成什么样子。", "chapter": "6.6 顺应趋势的被动力量究竟有多么强大", "date": "2022-06-06", "color": null}, {"text": "决定命运的关键性因素常常在主动边界之外。主动边界之外最关键的因素是什么呢？一个词而已：趋势。", "chapter": "6.3 决定命运的因素常常在主动边界之外", "date": "2022-06-06", "color": null}, {"text": "● 交易市场在即时交易过程中的确是零和游戏——看起来对手的盈利来自并恰好等于你的亏损。● 交易市场对那些长期投资者来说却绝对不是零和游戏——因为他们的增长主要来自经济增长，而不是他人短期的亏损。", "chapter": "3 究竟有没有只涨不跌的投资标的", "date": "2022-06-06", "color": null}, {"text": "这世界有没有长期来看只涨不跌的标的？有的！那就是人类的经济发展。", "chapter": "3 究竟有没有只涨不跌的投资标的", "date": "2022-06-06", "color": null}, {"text": "直接选择市场上所有人都最看好的股票。", "chapter": "2 证券交易市场是世界第九大奇迹", "date": "2022-06-06", "color": null}, {"text": "对资产来说，流动性是决定性因素。", "chapter": "1 几乎所有人都有定投的资格和能力", "date": "2022-06-06", "color": null}], "ideas": []}, {"id": "35138325", "title": "冯唐成事心法", "author": "冯唐", "cover": "https://cdn.weread.qq.com/weread/cover/22/YueWen_35138325/s_YueWen_35138325.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=f2e328e072182b15f2e7179", "progress": 48, "finished": 0, "hlCount": 10, "ideaCount": 0, "highlights": [{"text": "我们很谨慎地冒头，很谨慎地成事、多成事、持续多成事，高筑墙，广积粮，缓称王。我们需要避免的，就是卖弄智慧，不要认为油腻是某种智慧，否则我们的失误会更多。", "chapter": "以笨拙为本分，求仁得仁", "date": "2022-06-05", "color": null}, {"text": "如何在现实中修行？珍惜每一个不舒服和难受。在每一个不舒服、难受的时候，跳出自我，把自己的肉身和灵魂，当成人类中的一个，当成另一个他人。你想一想，观察一下，这个人到底怎么了？这个称为“我”的东西，他感受到了什么？他为什么不舒服、为什么难受？我们改变不了基因、原生家庭、环境、教育、遭遇，但我们可以从任何一刻开始觉察“我”这个人到底怎么了。", "chapter": "摒弃“身心灵”，在现实中“修行”", "date": "2022-06-05", "color": null}, {"text": "我每天的习惯很少，只有两个。　　第一个就是每天做一百个仰卧起坐、一百个俯卧撑。我通常能做到，但是有时候也做不到，但先设这个标准。　　第二个特别简单，就是看着Kindle入睡。你可以把Kindle换成纸书，只要不是手机。", "chapter": "选择，不仅只是断舍离", "date": "2022-06-05", "color": null}, {"text": "练就一身本事，能成大事时成大事，不能成大事时继续躲在某处练成事的本事。得志行天下，不得志独善其身，淡定而从容。", "chapter": "有时候“不努力”是种正确战略", "date": "2022-06-05", "color": null}, {"text": "1.你可以不屠龙，但不能不磨剑，你要时刻准备着你的时机到来。你可以把努力集中到去磨剑、长本事上。", "chapter": "有时候“不努力”是种正确战略", "date": "2022-06-05", "color": null}, {"text": "“事功之成否，人力居其三，天命居其七。”", "chapter": "有时候“不努力”是种正确战略", "date": "2022-06-05", "color": null}, {"text": "潜龙勿用是成为一个伟大的成事者必经的步骤，是进阶的修行。", "chapter": "掌控情绪", "date": "2022-06-05", "color": null}, {"text": "天下事只有两种，第一种是关你屁事，第二种是关我屁事”", "chapter": "掌控情绪", "date": "2022-06-05", "color": null}, {"text": "做事，不生气，不着急，闲言碎语，关我屁事。做事越多，成事越多，噪声越多，和噪声不要讲理，要讲“不理”——你能你上，你没上就闭嘴。", "chapter": "掌控情绪", "date": "2022-06-04", "color": null}, {"text": "强", "chapter": "卷首语 管理是一生的日常，成事是一生的修行", "date": "2022-06-04", "color": null}], "ideas": []}, {"id": "628637", "title": "富足：改变人类未来的4大力量", "author": "彼得·戴曼迪斯 史蒂芬·科特勒", "cover": "https://cdn.weread.qq.com/weread/cover/66/YueWen_628637/s_YueWen_628637.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=22132ac059979d221f7304f", "progress": 100, "finished": 0, "hlCount": 10, "ideaCount": 0, "highlights": [{"text": "好奇、恐惧、创造财富的欲望以及追求人生的意义，是人类创新的4大推动力。", "chapter": "17 让创新与突破来得更猛烈些", "date": "2022-03-13", "color": null}, {"text": "幸福并不总是跟收入正相关。在美国，年收入75000美元是幸福的门槛。就全球来说，幸福的门槛是年收入10000美元。跨过这道门槛，幸福跟收入就没什么关系了。", "chapter": "19 下一条路在哪里", "date": "2022-03-03", "color": null}, {"text": "时光流逝并没有冲淡其重要性。在今天，我们仍然可以在", "chapter": "01 人类所面临的最大挑战", "date": "2022-01-16", "color": null}, {"text": "我相信，很多人都拥有自己数字“化身”的日子已经不太远了。", "chapter": "附录2 技术指数型增长的危险", "date": "2021-01-21", "color": null}, {"text": "《奇点临近》还预测，到2023年，价值1000美元的便携式电脑的计算能力将与人脑相同；然后再过25年，它的计算能力将与全人类所有人大脑的计算能力的总和相同。", "chapter": "附录1 各领域参考原始数据", "date": "2021-01-21", "color": null}, {"text": "调查数据表明，一个人在情感上的满足程度随着他的收入上升而提高，但是，这个规律只在一定范围内有效。在收入达到美国人的年平均收入（75000美元）之前，金钱与幸福之间有直接的相关性。而在超过了这个数字之后，这种相关性就不复存在了。", "chapter": "19 下一条路在哪里", "date": "2021-01-20", "color": null}, {"text": "惠普公司在底特律实施了一个智能电网系统，它已经使生产率提高了15%", "chapter": "11 水", "date": "2021-01-20", "color": null}, {"text": "当我们可以在纳米尺度上进行生产，对各种物质的原子进行重新排列时，各种全新的物理性能将不断地涌现出来。", "chapter": "11 水", "date": "2021-01-20", "color": null}, {"text": "网孔只有15纳米宽。在几秒钟之内，它能过滤掉任何东西，这些东西包括细菌、病毒、囊孢、寄生虫、真菌与其他水媒性病原体。", "chapter": "11 水", "date": "2021-01-20", "color": null}, {"text": "未来，风力发电和太阳能发电的成本将足具竞争力；藻类生物燃料的单位种植面积产出，将大大超过玉米；第四代核反应堆的发电成本也将会降低很多。随着能源存储问题的解决和智能电网的普及，人类的能源富足将不是问题。", "chapter": "13 能源", "date": "2021-01-07", "color": null}], "ideas": []}, {"id": "25849521", "title": "人性中的善良天使：暴力为什么会减少", "author": "斯蒂芬·平克", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/521/25849521/s_25849521.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=4b7327e0718a6eb14b77573", "progress": 85, "finished": 0, "hlCount": 10, "ideaCount": 0, "highlights": [{"text": "我们的最终目标应该是让政策和规则成为我们的第二天性，共情则成为非必需品。事实上，共情就像爱，并不是我们所需要的一切。", "chapter": "第9章 善良天使", "date": "2021-04-28", "color": null}, {"text": "首先，当共情与社会的基本原则——公平相抵触的时候，它会危害人类的福祉。", "chapter": "第9章 善良天使", "date": "2021-04-28", "color": null}, {"text": "共情研究已经证明，同情可以推动真正的利他主义，对个体的遭遇换位思考所产生的同情可以扩展至个体所在的群体，这个个体甚至可以只是小说中的虚构人物", "chapter": "第9章 善良天使", "date": "2021-04-28", "color": null}, {"text": "此项实验和其他的研究共同证明，人们自私自利地帮助他人，帮助他人的目的是解除自己看到他人受罪而感到的痛苦。", "chapter": "第9章 善良天使", "date": "2021-04-28", "color": null}, {"text": "利他心理是存在的，动机是同情心。第二个版本的“共情-利他假说”的基础是“投射”和“换位”共情。", "chapter": "第9章 善良天使", "date": "2021-04-28", "color": null}, {"text": "心理利己主义则是指人们只会做给自己带来好处的事情。当然，有人会提出循环论证说，帮助他人可以满足利他情感的需要，这恰好证明了人的行为必定是为了自己的快乐或者对自己有益。", "chapter": "第9章 善良天使", "date": "2021-04-28", "color": null}, {"text": "彼得·辛格有关扩大共情圈（其实是同情圈的）假说。共情圈最内层的核心是我们对儿女的养育", "chapter": "第9章 善良天使", "date": "2021-04-28", "color": null}, {"text": "镜像神经元之于神经科学意义之重大就像DNA之于生物学的意义。[插图]加上报道科研新闻的记者推波助澜，有科学家将镜像神经元吹成是语言、模仿、文化学习、潮流和时尚、球迷、代祷，当然还有共情的生物基础。", "chapter": "第9章 善良天使", "date": "2021-04-28", "color": null}, {"text": "人们为共情一词的各种不同含义争执不休，让共情成为今天的热议话题。用镜像神经元作为悲悯意义上同情的同义词，让对共情理解的混乱固化进入我们的文化基因。里夫金这样写道：“所谓的共情神经元，让人类和其他一些物种能够设身处地地感觉和体验其他实体的境遇。”他得出结论说：“我们从根本上是共情的物种，寻求与我们同胞的亲密参与和伙伴关系。”镜像神经元理论假定，同情（这里的“同情”和“传染”模糊难分）是我们大脑里天生的情感，是我们灵长类动物的传承，我们只需要运用它，或者说，至少不要压抑它，就能为世界迎来一个新时代。里夫金承诺“在不到10年的时间内普及全球共情意识”。很不幸，他的承诺所依据的却是他对神经科学非常有问题的诠释。", "chapter": "第9章 善良天使", "date": "2021-04-28", "color": null}, {"text": "霍布斯陷阱", "chapter": "第4章 人道主义革命", "date": "2021-04-27", "color": null}], "ideas": []}, {"id": "840950", "title": "丝绸之路：一部全新的世界史", "author": "彼得·弗兰科潘", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/950/840950/s_840950.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=b0632e205cd4f6b0654191f", "progress": 6, "finished": 0, "hlCount": 8, "ideaCount": 2, "highlights": [{"text": "我们通常把全球化看作是当代社会独有的现象，但早在2000年前，全球化就已经是事实，它提供着机遇，带来了问题，也推动着技术的进步。", "chapter": "第一章 丝绸之路的诞生", "date": "2020-05-26", "color": null}, {"text": "悬泉置遗址", "chapter": "第一章 丝绸之路的诞生", "date": "2020-05-26", "color": null}, {"text": "玉门关", "chapter": "第一章 丝绸之路的诞生", "date": "2020-05-26", "color": null}, {"text": "“如今你们已离不开中国货了！”一位特使毫不客气地对部落首领说。他认为匈奴的习俗正在发生变化，并且信心十足地预言，中国最终会赢，并征服整个匈奴。", "chapter": "第一章 丝绸之路的诞生", "date": "2020-05-26", "color": null}, {"text": "有一次，一位月氏国首领用马匹换取了一批货物，然后将货物转手卖掉，他的财富一下子多了十倍", "chapter": "第一章 丝绸之路的诞生", "date": "2020-05-26", "color": null}, {"text": "荷马史诗", "chapter": "第一章 丝绸之路的诞生", "date": "2020-05-26", "color": null}, {"text": "塞琉古建立的一座新城——的纪念碑上，刻着来自希腊圣地德尔斐（Delphi）的箴言：童年时，听话；青年时，自律；成年时，正义；老年时，智慧；死去时，安详。【24】", "chapter": "第一章 丝绸之路的诞生", "date": "2020-05-26", "color": null}, {"text": "发现自己已成为从底格里斯河到印度河流域大片疆土的领主。这片疆土如此之大，已经不像是一个王国，而是一个帝国。于是他建立了一个王朝，称塞琉古王朝（Seleucid）", "chapter": "第一章 丝绸之路的诞生", "date": "2020-05-26", "color": null}], "ideas": [{"content": "春风不度玉门关。", "abstract": "玉门关", "chapter": "", "date": "2020-05-26", "star": null}, {"content": "当时匈奴人贪图蝇头小利，没有远大的目光。也只是发生饥饿的时候，才会想到入侵中原。", "abstract": "“如今你们已离不开中国货了！”一位特使毫不客气地对部落首领说。他认为匈奴的习俗正在发生变化，并且信心十足地预言，中国最终会赢，并征服整个匈奴。", "chapter": "", "date": "2020-05-26", "star": null}]}, {"id": "3300072535", "title": "活出生命的意义", "author": "[奥]维克多·弗兰克尔", "cover": "https://cdn.weread.qq.com/weread/cover/73/cpplatform_4uj5m42uyaeybjyxenesic/s_cpplatform_4uj5m42uyaeybjyxenesic1695806902.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=f9b32d30813ab82d5g015c99", "progress": 93, "finished": 0, "hlCount": 7, "ideaCount": 3, "highlights": [{"text": "没有任何理由去怜悯老年人。相反，年轻人应该嫉妒老年人。", "chapter": "为悲剧性的乐观主义辩护", "date": "2025-02-07", "color": 1}, {"text": "那些自杀未遂的人后来都反复跟我讲没有死成对他们来说是多么幸运和幸福。数月或数年后他们会告诉我，他们的问题是有办法解决的，生命还是有意义的。", "chapter": "为悲剧性的乐观主义辩护", "date": "2025-02-07", "color": 1}, {"text": "意义疗法所谓 “矛盾意向法”的技术基础源于以下两方面的事实：一方面，正是恐惧导致了所害怕的事情的出现；另一方面，过度渴望使其所希望的事情变得不可能。", "chapter": "作为一项技术的意义疗法", "date": "2025-02-07", "color": 1}, {"text": "快乐是（而且一直是）一种附加品，如果这种附加品本身成了目的，反而会受到减损。", "chapter": "作为一项技术的意义疗法", "date": "2025-02-07", "color": 1}, {"text": "悲观主义者好比一个恐惧而悲伤地看着墙上的挂历每天都被撕掉一张，挂历越变越薄的人；而积极地应对生活问题的人好比一个每撕掉一张就把它整整齐齐地摞在一起，还要在背面记几行日记的人。", "chapter": "生命之短暂", "date": "2025-02-07", "color": 1}, {"text": "使生命丧失意义的事情，不仅包括痛苦，还包括死亡。我总是不厌其烦地说，生命中真正短暂的是潜力，一旦潜力得到了实现，那么在实现的那一刻它就成为了现实。", "chapter": "生命之短暂", "date": "2025-02-07", "color": 1}, {"text": "遭受不必要的痛苦与其说是英雄行为，不如说是自虐。", "chapter": "苦难之意义", "date": "2025-02-07", "color": 1}], "ideas": [{"content": "及其无身，吾有何患", "abstract": "治疗的要义在于自我超越！", "chapter": "作为一项技术的意义疗法", "date": "2025-02-07", "star": null}, {"content": "臣服", "abstract": "一旦患者停止了和强迫症做斗争，转而以嘲弄的方式去取笑它——运用矛盾意念法——那么恶性循环就会终止，症状开始减轻，最终治愈。", "chapter": "作为一项技术的意义疗法", "date": "2025-02-07", "star": null}, {"content": "自他相换", "abstract": "你看医生，她免除了这样的痛苦，你替代了她的痛苦——当然，代价是你现在还活着，并且陷入了深深的痛苦中", "chapter": "苦难之意义", "date": "2025-02-07", "star": null}]}, {"id": "26261790", "title": "认知红利", "author": "谢春霖", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/790/26261790/s_26261790.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=58632d307190b91e5869c4b", "progress": 100, "finished": 1, "hlCount": 7, "ideaCount": 3, "highlights": [{"text": "迷恋小概率事件", "chapter": "第六模块 解决所有问题", "date": "2020-09-03", "color": null}, {"text": "持续获得确定性的满足+不确定的奖励=上瘾！", "chapter": "16 不会专注，你的忙碌只是在演戏", "date": "2020-09-03", "color": null}, {"text": "你的信念系统（BVR）无法理解眼前这个世界了，才是问题！你的能力无法处理眼前的这件事了，才是原因！", "chapter": "第四模块 解开大脑的封印", "date": "2020-09-02", "color": null}, {"text": "用马斯克自己的话说，这叫作：借助“人类巨灵”的力量，推动行业的变革。", "chapter": "12 你的运气，为什么一直不好", "date": "2020-09-02", "color": null}, {"text": "因此，什么是多维能力就是能把多种能力结合在一起，并且为同一个目标服务，这样就会发挥巨大的价值！", "chapter": "8 你值多少钱", "date": "2020-09-02", "color": null}, {"text": "如果说“能力层”是做解答题的能力，“BVR层”就是做选择题的能力，什么可以做，什么不可以做，什么更重要，什么可以忽略不管。", "chapter": "6 你是第几流人才", "date": "2020-09-02", "color": null}, {"text": "他们明白，任何问题都不是孤立存在的，一定有人曾经遇到过，并且已经有更好的解决办法了，只是我还不知道；我不应该在黑暗中独自前行，去重新发明轮子，也许我的顿悟，只是别人的基本功！我应该要站在巨人的肩膀上，学习更成熟的经验和方法，然后再来解决这个问题。", "chapter": "6 你是第几流人才", "date": "2020-09-02", "color": null}], "ideas": [{"content": "这是一本新的通往财富自由之路，是提升思维能力的套路工具箱，只要你将自己当做一个产品，那么它就是一本人生的产品设计手册。靠信息差赚钱不如认知差赚钱，书中有海量认知的红利。", "abstract": "", "chapter": "", "date": "2020-09-03", "star": 100}, {"content": "感觉说到重点了，好好记下这个笔记。", "abstract": "找到有势能差的地方，然后站在高势能的这边，跟着它一起往低势能处流动。", "chapter": "", "date": "2020-09-02", "star": null}, {"content": "我的人生信条:无我利他", "abstract": "精神层”一定要有“身份层”的支撑，换句话说，如果你在身份层想不清楚自己要成为谁，可以试着来到精神层，想想你能为这个世界做些什么；可以不用那么大，哪怕只是在某一方面，能帮助到为数不多的人。那一方面是什么？", "chapter": "", "date": "2020-09-02", "star": null}]}, {"id": "854928", "title": "枪炮、病菌与钢铁：人类社会的命运（修订版）", "author": "贾雷德·戴蒙德", "cover": "https://cdn.weread.qq.com/weread/cover/44/YueWen_854928/s_YueWen_854928.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=4fc321705d0b904fc822605", "progress": 100, "finished": 1, "hlCount": 5, "ideaCount": 5, "highlights": [{"text": "韩国和朝鲜", "chapter": "附录 2003后记：《枪炮、病菌与钢铁》今日谈", "date": "2020-08-24", "color": null}, {"text": "最优分裂原则”：创新在带有最优中间程度分裂的社会里发展得最快：太过统一的社会处于劣势，太过分裂的社会也不占优。", "chapter": "附录 2003后记：《枪炮、病菌与钢铁》今日谈", "date": "2020-08-24", "color": null}, {"text": "我推断出不同政治实体间的竞争引发了创新在分裂的欧洲大陆的诞生，而此种竞争的缺乏阻滞了创新在统一的中国的诞生", "chapter": "附录 2003后记：《枪炮、病菌与钢铁》今日谈", "date": "2020-08-24", "color": null}, {"text": "引擎科学的长足发展，并非欧洲文明的必然发展，而是在17—18世纪的英国碰巧出现的特定而偶然的际遇所带来的幸运结果。”", "chapter": "附录 2003后记：《枪炮、病菌与钢铁》今日谈", "date": "2020-08-24", "color": null}, {"text": "直到至少15世纪以前，中国在技术上一直走在欧洲前面，在未来也有可能重续辉煌，那样的话，“为什么是欧洲，而非中国？”", "chapter": "附录 2003后记：《枪炮、病菌与钢铁》今日谈", "date": "2020-08-24", "color": null}], "ideas": [{"content": "两边感觉就像故意搞的对比实验", "abstract": "韩国和朝鲜", "chapter": "", "date": "2020-08-24", "star": null}, {"content": "最优分裂原则", "abstract": "最优分裂原则”：创新在带有最优中间程度分裂的社会里发展得最快：太过统一的社会处于劣势，太过分裂的社会也不占优。", "chapter": "", "date": "2020-08-24", "star": null}, {"content": "中国此时社会在大一统的条件下已经经济平衡了，没有创造创新的动力。", "abstract": "我推断出不同政治实体间的竞争引发了创新在分裂的欧洲大陆的诞生，而此种竞争的缺乏阻滞了创新在统一的中国的诞生", "chapter": "", "date": "2020-08-24", "star": null}, {"content": "只能证明欧洲的生存环境不是很好，只能提前递弱代偿。", "abstract": "直到至少15世纪以前，中国在技术上一直走在欧洲前面，在未来也有可能重续辉煌，那样的话，“为什么是欧洲，而非中国？”", "chapter": "", "date": "2020-08-24", "star": null}, {"content": "与人口，人力成本也有关系。", "abstract": "引擎科学的长足发展，并非欧洲文明的必然发展，而是在17—18世纪的英国碰巧出现的特定而偶然的际遇所带来的幸运结果。”", "chapter": "", "date": "2020-08-24", "star": null}]}, {"id": "3300055219", "title": "最优解人生", "author": "比尔·帕金斯", "cover": "https://cdn.weread.qq.com/weread/cover/35/cpplatform_f4wzbjebzrn5yor7gi578h/s_cpplatform_f4wzbjebzrn5yor7gi578h1681367860.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=87b327c0813ab7c11g01944b", "progress": 100, "finished": 1, "hlCount": 9, "ideaCount": 0, "highlights": [{"text": "人生就是不断收集回忆的过程，最终能陪伴我们的也只有回忆了。”", "chapter": "2 投资体验", "date": "2025-02-07", "color": 1}, {"text": "人生就是不断收集回忆的过程”。", "chapter": "9 要大胆，而不是愚蠢", "date": "2025-02-07", "color": 1}, {"text": "相比于浪费人生，人们更加担心钱被花光；你的思维必须倒过来，你最大的恐惧应该是时间与人生被浪费，而不是“到了80岁我还能有多少多少钱”这个问题。", "chapter": "9 要大胆，而不是愚蠢", "date": "2025-02-07", "color": 1}, {"text": "现在就大胆抉择，而不是等到退休后，因为“活力之年”非常短暂。一般来说，“等我退休了就去做某事”这种话整个就大错特错。", "chapter": "9 要大胆，而不是愚蠢", "date": "2025-02-07", "color": 1}, {"text": "你要在真正的黄金年华花更多钱，也就是在身体和财富都还算不错的45—60岁", "chapter": "8 了解你的峰点", "date": "2025-02-07", "color": 1}, {"text": "你的目标不是最大化财富，而是最大化人生体验。对大多数人来说，这都是一个巨大的转变。", "chapter": "8 了解你的峰点", "date": "2025-02-07", "color": 1}, {"text": "无论原因是什么，美国最普遍的退休年龄实际上是62岁，[插图]这是退休年龄中位数，[插图]也是美国人开始领取社会安全福利金的年龄。", "chapter": "8 了解你的峰点", "date": "2025-02-06", "color": 1}, {"text": "生存阈值=0.7×一年生活费×剩余寿命", "chapter": "8 了解你的峰点", "date": "2025-02-06", "color": 1}, {"text": "这种全面的抗拒也就解释了，为何那么多人愿意花钱延长生命，哪怕只是多活几个星期，就算要花好几万，甚至几十万都在所不惜。从这个角度想一想：这么多钱可是他们花了好几年甚至几十年辛苦工作赚来的。他们付出多年健康且充满活力的生命，只为“续费”几个星期的瘫痪病体。如果这都不算“不理性”，那还有什么算得上？", "chapter": "4 如何花钱？（不会真的在死前一分不剩）", "date": "2023-06-23", "color": 5}], "ideas": []}, {"id": "3300022877", "title": "健身营养书：让增肌减脂变简单", "author": "仰望尾迹云 杨昌林", "cover": "https://cdn.weread.qq.com/weread/cover/43/cpplatform_fw3nwgmmjq9wug1eqazg1e/s_cpplatform_fw3nwgmmjq9wug1eqazg1e1727588908.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=4d0326b0813ab6f6fg0174f9", "progress": 93, "finished": 0, "hlCount": 9, "ideaCount": 0, "highlights": [{"text": "如果你有大量规律的有氧运动，那么运动消耗的热量，要按照碳水化合物∶蛋白质=3∶1的比例补上。", "chapter": "8.2　“肌肉拼图”可以吃哪些食物", "date": "2023-11-07", "color": 1}, {"text": "补充肌酸如果用慢速的方法，连续补充12~15周后停3~4周也就足够了。", "chapter": "7.5　肌酸与增肌训练", "date": "2023-11-07", "color": 1}, {"text": "增肌者用橄榄油“促睾”，因为橄榄油的脂肪酸构成，主要是饱和脂肪酸和单不饱和脂肪酸", "chapter": "5.4　橄榄油真的能“促睾”吗", "date": "2023-10-26", "color": 1}, {"text": "额外的有氧运动消耗了800kcal热量，那就要额外补充200g碳水化合物（每克碳水化合物热量为4kcal）", "chapter": "4.6　增肌该怎么吃碳水化合物", "date": "2023-10-26", "color": 1}, {"text": "胰岛素最主要的作用就是降低血糖。我们人体有很多升血糖的激素，但是降血糖的，只有胰岛素一种。", "chapter": "4.4　增肌，胰岛素和睾酮同样重要", "date": "2023-10-26", "color": 1}, {"text": "不要超过30分钟", "chapter": "1.6　跑步到底会不会“丢肌肉”", "date": "2023-10-26", "color": 1}, {"text": "纯减脂者，每天热量缺口建议为500kcal；纯增肌者，每天额外摄入热量建议为500kcal；增肌减脂者，每天热量缺口建议为200~300kcal。理想的纯减脂速度，每周体重降低0.5~1kg；增肌者减脂速度，建议每周不超过0.3kg。", "chapter": "1.3　减脂和增肌的热量管理", "date": "2023-10-26", "color": 1}, {"text": "我们接下来再说增肌者减脂时的热量摄入建议。一般建议，增肌者减脂时，每天制造200~300kcal热量缺口就可以了，不建议太大。", "chapter": "1.3　减脂和增肌的热量管理", "date": "2023-10-26", "color": 1}, {"text": "计算食物热量，一般是按照1g脂肪=9kcal，1g蛋白质=4kcal，1g碳水化合物=4kcal，这个系数叫“阿特沃特系数”。", "chapter": "1.2　健身饮食，你只要做好三件事", "date": "2023-10-26", "color": 1}], "ideas": []}, {"id": "3300027228", "title": "疗愈的饮食与断食：新时代的个人营养学", "author": "杨定一", "cover": "https://cdn.weread.qq.com/weread/cover/83/cpPlatform_2SyxFgJDaCixPXZEigtKZj/s_cpPlatform_2SyxFgJDaCixPXZEigtKZj.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=60a32840813ab7122g018e43", "progress": 94, "finished": 0, "hlCount": 9, "ideaCount": 0, "highlights": [{"text": "虽然膳食纤维也是一种碳水化合物，但基本上不能被人体作为热量使用，不会纳入净碳水化合物来计算。", "chapter": "18 低糖饮食", "date": "2023-11-04", "color": 1}, {"text": "低糖饮食的原则，和前三章所谈的大致相同，以天然、原型的食物为主，唯一的差异是把糖和淀粉减到一天50克以下，大约是1碗饭的分量。", "chapter": "18 低糖饮食", "date": "2023-11-04", "color": 1}, {"text": "物理学家将能够让1毫升的水上升1摄氏度的热能定为1卡。我们一般讲饮食的热量用的单位是“大卡”，1大卡等于1000卡。", "chapter": "10 计算饮食的热量", "date": "2023-11-04", "color": 1}, {"text": "期吃太多肉对代谢是有负担的。", "chapter": "09 新时代的饮食调整，更着重于修正和修复", "date": "2023-11-04", "color": 1}, {"text": "二型糖尿病患者的问题则不是缺少胰岛素这把钥匙，大多数患者的胰岛素分泌正常，甚至偏高，但身体连最需要养分的肌肉细胞，都不再对胰岛素起反应，就像细胞从里面把大门给反锁起来，拿着再多的钥匙也开不了门。", "chapter": "05 胰岛素阻抗：影响代谢和体质的关键", "date": "2023-11-04", "color": 1}, {"text": "当然，受到饥饿素的刺激，自然会感到饿，但前面也提过，饥饿素的作用时间很短，大概1小时左右就会过去，不会让人整天都困在饥饿的感觉里。", "chapter": "51 断食愈久愈好吗？", "date": "2023-11-04", "color": 1}, {"text": "断食18小时，还能刺激生长激素和脑源性营养因子的合成，开始进行身体和脑部的修复工作。", "chapter": "51 断食愈久愈好吗？", "date": "2023-11-04", "color": 1}, {"text": "这种间歇性的高强度运动，一般人简称为HIIT（high-intensity interval training，高强度间歇性训练）。", "chapter": "37 以适合的运动强度，带来健康", "date": "2023-11-04", "color": 1}, {"text": "快走，用躯干和大腿带动身体，是最容易进行的有氧健身运动。有一定的步行速度，让身体稍微流汗，还能够讲话而不气喘，就是理想的运动强度。", "chapter": "37 以适合的运动强度，带来健康", "date": "2023-11-04", "color": 1}], "ideas": []}, {"id": "39889296", "title": "顺着历史学古诗", "author": "蒙曼", "cover": "https://cdn.weread.qq.com/weread/cover/36/YueWen_39889296/s_YueWen_39889296.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=a67322907260a990a67581d", "progress": 100, "finished": 1, "hlCount": 9, "ideaCount": 0, "highlights": [{"text": "《对酒》。不惜千金买宝刀，貂裘（qiú）换酒也堪豪。一腔热血勤珍重，洒去犹能化碧涛。", "chapter": "《对酒》", "date": "2022-07-15", "color": null}, {"text": "九州生气恃（shì）风雷，万马齐喑究可哀。我劝天公重抖擞，不拘一格降人才。", "chapter": "《己亥杂诗》（其一百二十五）", "date": "2022-07-15", "color": null}, {"text": "他们也带回来一大批色目人。所谓色目，并不是说这些人都有彩色的眼睛，而是各色各目的意思，也就是说，这些人的民族、人种都非常复杂。不过，尽管来源复杂，但主体还是中亚、西亚一些信仰伊斯兰教的人。这些人因为归顺较早，比较受蒙古贵族的信任，被编进军队里，到处驻防。他们跟汉人通婚，这才逐渐形成了中国的回族", "chapter": "《上京即事五首》（其三）", "date": "2022-07-15", "color": null}, {"text": "昼出耘田夜绩麻，村庄儿女各当家。童孙未解供耕织，也傍桑阴学种瓜。", "chapter": "《四时田园杂兴》（其三十一）", "date": "2022-07-15", "color": null}, {"text": "谷雨前后，种瓜点豆", "chapter": "《四时田园杂兴》（其三十一）", "date": "2022-07-15", "color": null}, {"text": "所谓四大名鱼，就是松江鲈鱼、长江鲥（shí）鱼、黄河鲤鱼和巢湖银鱼。", "chapter": "《江上渔者》", "date": "2022-07-15", "color": null}, {"text": "他们把晋朝皇室赶到了南方，自己建立了大大小小十几个政权，历史上称为“五胡十六国”，这是中国历史上的一大乱世。后来，在这些少数民族中，鲜卑脱颖而出，建立了北魏，统一了北方。再到后来，北魏分裂成东魏、西魏，东魏、西魏又演化成了北齐和北周。这五个政权都是以鲜卑人为主体建立的，历史上就称之为北朝。跟在江南建国的南朝相对，合称南北朝。", "chapter": "《敕勒歌》", "date": "2022-07-14", "color": null}, {"text": "江南可采莲，莲叶何田田，鱼戏莲叶间。鱼戏莲叶东，鱼戏莲叶西，鱼戏莲叶南，鱼戏莲叶北。", "chapter": "《江南》", "date": "2022-07-14", "color": null}, {"text": "中国古代文学有两大源头，一个是黄河流域的《诗经》，一个是长江流域的《楚辞》。", "chapter": "《大风歌》", "date": "2022-07-14", "color": null}], "ideas": []}, {"id": "38259804", "title": "宏观经济通识课", "author": "韩秀云", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/804/38259804/s_38259804.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=32b32cf07247cc5c32b4f3a", "progress": 100, "finished": 1, "hlCount": 9, "ideaCount": 0, "highlights": [{"text": "借债一定要用到产生效益的地方，否则就会出问题。", "chapter": "第33讲 2010年欧债危机", "date": "2022-07-13", "color": null}, {"text": "央行只能决定贴现率，在中国它叫再贷款利率，在美国它叫联邦基准利率。央行可以用贴现率来给市场降温或给市场加油。", "chapter": "第17讲 货币政策的三大法宝", "date": "2022-07-13", "color": null}, {"text": "贴现率就是商业银行从中央银行借款的利率。", "chapter": "第17讲 货币政策的三大法宝", "date": "2022-07-13", "color": null}, {"text": "我国未来的中央银行必须相对独立，才能够让我国的经济持续健康稳定发展。我国央行的责任也是保持人民币币值的稳定。为了让人民币走向国际化，我国中央银行肩负重任。", "chapter": "第14讲 中央银行的作用", "date": "2022-07-13", "color": null}, {"text": "所谓现代意义的银行是指股份制银行，是由私人投资组成的，它不再受国王的摆布，银行宁愿把钱借给私人也不愿借给政府，这是银行形成过程中的一种巨大的变化。", "chapter": "第12讲 信用是经济运行的基石", "date": "2022-07-13", "color": null}, {"text": "后来，我国政府还提出“假日经济”的概念，为的是让国民在放长假中增加消费。", "chapter": "第9讲 财政政策有哪些？", "date": "2022-07-13", "color": null}, {"text": "我预测，我国未来会推出两个税种：一个是房地产税，一个是遗产税。", "chapter": "第7讲 中国的分税制", "date": "2022-07-13", "color": null}, {"text": "消费+储蓄+政府税收+进口=消费+投资+政府支出+出口", "chapter": "第2讲 经济中的平衡", "date": "2022-07-13", "color": null}, {"text": "但实际上经济学只有两派，一派是新古典主义经济学，即那只“看不见的手”；另一派就是新凯恩斯经济学，即这只“看得见的手”。", "chapter": "第1讲 看得见的手", "date": "2022-07-13", "color": null}], "ideas": []}, {"id": "35666104", "title": "止损：如何克服贪婪和恐惧", "author": "吉姆·保罗 布伦丹·莫伊尼汉", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/104/35666104/s_35666104.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=94732dc0722038b8947e6e8", "progress": 58, "finished": 0, "hlCount": 9, "ideaCount": 0, "highlights": [{"text": "有个市场仓位情绪化的例子是，很多人常常会把赚钱的仓位出清，而赔钱的仓位却死抱不放。这是因为他们把赚钱和赔钱看做是自己智力或自我价值的表现，要是认赔就觉得是自己愚蠢或犯错。这就是混淆了金钱价值和自我价值。", "chapter": "市场亏损转化为内在损失", "date": "2022-05-12", "color": null}, {"text": "市场亏损应该是外部而客观的损失，一旦你把个人情绪带进去，它才会变成主观损失。自我过度涉入，让你用一种负面的方式来看待，这个亏损就成为一项失败，是一个不好的事情，是一个错误", "chapter": "外部损失与内在损失", "date": "2022-05-12", "color": null}, {"text": "不要因为希望或恐惧而做交易，也不要做出情绪性的决策。", "chapter": "中篇 经验教训", "date": "2022-05-12", "color": null}, {"text": "我相信市场反转时最容易赚到钱。大家也都说，想抓顶部和底部最危险，所以应该把握趋势，只取中间那一大段。不过，12年来我常常放过中段，但抓到许多顶部和底部。[16]", "chapter": "顶部和底部的选择", "date": "2022-05-11", "color": null}, {"text": "比方说，他曾提议我们一起买个南美洲的小岛，大概要花200万美元，但是我们实际上只要拿出十万美元，其余可以利用岛上种植的柚木做抵押来贷款，然后把那些柚木做成家具卖掉，大赚一笔，就等于是白赚了一座小岛。格利斯曼就是这么疯狂，不断蹦出一些点子。每个星期都会想到一个可以赚100万美元的新想法。", "chapter": "阿拉伯马的失败", "date": "2022-05-11", "color": null}, {"text": "人各有才，有些事情你很在行，但有些事就是做不来。不过不必为那些你做不来的事情烦心，要是你搞不定，花钱找人处理就好了，没什么好担心的。", "chapter": "你现在已加入陆军", "date": "2022-05-11", "color": null}, {"text": "在我相信赚多少比做什么更重要的同时，也发现高收入的工作需要高学历", "chapter": "短命的少年棒球队生涯", "date": "2022-05-11", "color": null}, {"text": "世界上有两种人：一种是聪明人；另一种是有智慧的人。聪明人会从自己的错误学到教训，而有智慧的人可以从别人的错误学到教训。", "chapter": "上篇 交易员回忆录", "date": "2022-05-11", "color": null}, {"text": "事实上交易成不成功，通常都是因为心理因素，而不是战术问题。吉姆·保罗最后在市场上学到昂贵教训，才明白成功交易绝非来自赚钱秘诀，而是要先搞清楚怎样会导致赔钱。", "chapter": "推荐序", "date": "2022-05-11", "color": null}], "ideas": []}, {"id": "31839322", "title": "新基建", "author": "任泽平 马家进 连一席", "cover": "https://cdn.weread.qq.com/weread/cover/67/YueWen_31839322/s_YueWen_31839322.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=6ee32bb071e5d45a6ee29be", "progress": 100, "finished": 1, "hlCount": 9, "ideaCount": 0, "highlights": [{"text": "新基建经济：兼顾短期扩大需求和长期扩大供给", "chapter": "第三节 总结与反思：在危机后诞生或盛行的经济学流派", "date": "2021-12-25", "color": null}, {"text": "（五）应对：“QE+零利率+财政刺激”迅速发力，缓解流动危机，但饮鸩止渴", "chapter": "第二节 主要的金融危机案例研究", "date": "2021-04-27", "color": null}, {"text": "金融危机是一个永恒的现象。时代在变，但人性像山岳一样古老。人性是健忘的，从贪婪到恐慌，周期背后是人性的轮回。周期在繁荣的顶点之后就会迎来危机。", "chapter": "第一节 金融危机的内在逻辑", "date": "2021-04-27", "color": null}, {"text": "中国有望形成10个以上1 000万级城市和12个以上2 000万级大都市圈", "chapter": "第四节 未来1.9亿新增城镇人口将去向何方", "date": "2021-04-27", "color": null}, {"text": "新增城镇人口的约80%将分布在19个城市群，约60%分布在七大城市群", "chapter": "第四节 未来1.9亿新增城镇人口将去向何方", "date": "2021-04-27", "color": null}, {"text": "5G网络具有低时延、广连接、大带宽三大特点，后续将会促进物联网、车联网、VR、AR等应用场景的不断成熟，推动社会进步和人类生活方式的变革。", "chapter": "第一节 5G时代来临", "date": "2021-04-27", "color": null}, {"text": "“新基建”指发力于科技端的基础设施建设，主要包含5G基建、特高压、城际高速铁路和城际轨道交通、新能源汽车充电桩、大数据中心、人工智能、工业互联网七大领域。", "chapter": "第二节 新基建的内涵与意义", "date": "2021-04-27", "color": null}, {"text": "房地产是周期之母，一旦触发房地产市场风险，则波及范围极广", "chapter": "第三节 疫情全球大流行、经济衰退对中国经济的传导渠道", "date": "2021-04-27", "color": null}, {"text": "美国面临股市泡沫、债务杠杆、金融机构风险、社会撕裂四大危机", "chapter": "第二节 全球流动性危机一度显现", "date": "2021-04-27", "color": null}], "ideas": []}, {"id": "35092698", "title": "终身学习：哈佛毕业后的六堂课", "author": "黄征宇", "cover": "https://cdn.weread.qq.com/weread/cover/42/yuewen_35092698/s_yuewen_350926981696820100.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=07e32e90721778da07e020a", "progress": 100, "finished": 1, "hlCount": 9, "ideaCount": 0, "highlights": [{"text": "他说他一辈子只做两件事：“第一，我只投我知道的公司；第二，市场疯狂的时候我冷静，市场绝望的时候我反而兴奋。”", "chapter": "第3部分 证券投资——质疑和自信的矛盾统一体", "date": "2021-11-15", "color": null}, {"text": "如果我坚信自己的观点，坚信自己的理念，那为什么不坚持做投资？而我本身也是一名投资者，我有我自己的钱，为什么不拿自己的钱来投资？", "chapter": "第3部分 证券投资——质疑和自信的矛盾统一体", "date": "2021-11-15", "color": null}, {"text": "理财专家认为，人们对财富的需求可以分为四个阶段：　　1.财务保底（financial security）；　　2.财务蓬勃（financial vitality）；　　3.财务独立（financial independence）；　　4.财务自由（financial freedom）。", "chapter": "第六章 塑造创富思维比创造财富更重要", "date": "2021-11-15", "color": null}, {"text": "什么是正面思维呢？积极、努力、进取，富有建设性。比如：学习任何知识或技能，无论失败还是成功，都是一种成长。这就是典型的正面思维。相反，我很想把事情做好，但万一失败，别人嘲笑我怎么办？这其实就是负面思维。", "chapter": "第4部分 与命运有约", "date": "2021-11-14", "color": null}, {"text": "懂得利用互惠性原则的人，总会让人感觉他先给别人东西，然后对方就会反馈给他，而且反馈给他的往往是价值更高的东西。", "chapter": "第1部分 直达人心的影响力", "date": "2021-11-13", "color": null}, {"text": "内观禅修提供了一个很好的化解方式，就是当情绪产生的时候，你就去观察它，一观察它也就没了。", "chapter": "第4部分 带有东方神秘色彩的内观禅修", "date": "2021-11-13", "color": null}, {"text": "无论我们有什么样的念头，其实都可以归于两类：一类是欲望，一类是抵触。", "chapter": "第4部分 带有东方神秘色彩的内观禅修", "date": "2021-11-13", "color": null}, {"text": "内观就是如实观察，观察事物真正的面目，然后达到净化自身的目的。", "chapter": "第4部分 带有东方神秘色彩的内观禅修", "date": "2021-11-13", "color": null}, {"text": "我们喜欢赋予每样东西一个故事、一份意义。", "chapter": "第2部分 做一个会讲故事的人", "date": "2021-11-13", "color": null}], "ideas": []}, {"id": "573975", "title": "思考，快与慢", "author": "丹尼尔·卡尼曼", "cover": "https://cdn.weread.qq.com/weread/cover/86/YueWen_573975/s_YueWen_573975.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=af83263058c217af81f8979", "progress": 48, "finished": 0, "hlCount": 9, "ideaCount": 0, "highlights": [{"text": "“增加幸福感的最简单方法是分配好你的时间。你能抽出更多时间做自己喜欢做的事情吗？”", "chapter": "第37章 你有多幸福？", "date": "2021-04-13", "color": null}, {"text": "钱可以买到快乐吗？这是人们最常问的关于幸福的问题。对45万名受试者回应的盖洛普海斯威斯幸福指数分析以及对1000名美国人的每日调查，为我们提供了惊人而又明确的答案。结论是贫穷使人悲惨，富有可能会提升某个人的生活满意度，但总体来说来却不能提高经验自我的幸福感。", "chapter": "第37章 你有多幸福？", "date": "2021-04-13", "color": null}, {"text": "请想象有一架阶梯，每级台阶都标有数字，最低一级是零，最高一级是10。最高的台阶代表你最美好的生活，最低的台阶代表你最糟糕的生活。此时此刻，你认为自己站在哪一级台阶上？", "chapter": "第37章 你有多幸福？", "date": "2021-04-13", "color": null}, {"text": "我们将个人处于不愉快状态的时间比称为U指数。例如，某个人在16个小时醒着的时间内，有4小时处于不愉快状态，其U指数就是25%。U指数并不是基于评定量表，而是基于对时间的客观测评。", "chapter": "第37章 你有多幸福？", "date": "2021-04-13", "color": null}, {"text": "这种全身心投入的状态被米哈里称为心流。心流是艺术家在创作时、人们在被电影和书籍或是填字游戏深深吸引住时的一种状态。", "chapter": "第37章 你有多幸福？", "date": "2021-04-13", "color": null}, {"text": "·峰终定律（peak-end rule）[插图]：整体的回顾性评级可通过将最糟糕时期和最后时刻的疼痛程度的平均加权而评估出来。·过程忽视（duration neglect）：过程的持续对所有疼痛的评估没有任何影响。", "chapter": "第35章 体验效用与决策效用的不一致", "date": "2021-04-13", "color": null}, {"text": "损失厌恶系数指的是两种动机的相对强度：我们想要规避损失的动机要强于获得利益的动机。参照点所关注的是现状，但它还会是将来的目标，即没有实现的目标就是种损失，超过了目标就是种所得。", "chapter": "第28章 公平性——经济交易的参照点", "date": "2021-04-13", "color": null}, {"text": "损失厌恶这一概念绝对是心理学对行为经济学最重要的贡献。", "chapter": "第28章 公平性——经济交易的参照点", "date": "2021-04-13", "color": null}, {"text": "你只是喜欢得到，不喜欢失去——几乎可以肯定地说，你对失去的厌恶程度远大于你对得到的喜欢程度。", "chapter": "第26章 更人性化的前景理论", "date": "2021-04-13", "color": null}], "ideas": []}, {"id": "36954716", "title": "火星人马斯克的地球创业游戏", "author": "一苒 孟路", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/716/36954716/s_36954716.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=8a0327607233e25c8a01348", "progress": 100, "finished": 1, "hlCount": 8, "ideaCount": 1, "highlights": [{"text": "普罗大众在潜意识里非常清楚：成年人的世界里从来没有圣贤和完美，越是精心包装的完美形象，越缺乏可信度。如果韦小宝不好色、令狐冲不痴情、郭靖不呆萌、张无忌不优柔寡断，他们的足智多谋和英雄气概就显得不够率真迷人。", "chapter": "2.推特大V", "date": "2022-02-18", "color": null}, {"text": "品牌卖的不是产品规格、不是你跟对手比有多好，而是价值主张。耐克卖的是鞋，但从来不在广告中提到产品规格，而只推崇伟大的运动员。", "chapter": "1.科技领袖", "date": "2022-02-18", "color": null}, {"text": "2016年公开了第二期战略计划：整合太阳能发电和储能业务；扩充地面交通工具（意思是用特斯拉的产品线推出皮卡、中型SUV等全新车型，提升市场覆盖面）；自动驾驶；汽车共享。", "chapter": "目标格外清晰", "date": "2022-02-17", "color": null}, {"text": "最终，特斯拉应该会停止向私人销售高级自动驾驶汽车，转而像Uber一样直接提供出行服务。", "chapter": "对电动车的灵魂拷问", "date": "2022-02-17", "color": null}, {"text": "民主党的基盘是科技公司、初创新经济、中高产阶级的利益；共和党则代表了军火商、石油公司和钢铁公司、本土中低阶层的利益。", "chapter": "电动车、环保和石油", "date": "2022-02-17", "color": null}, {"text": "是必须连续三年盈利这一项就让它们无缘股票交易市场。", "chapter": "硅谷：创新的摇篮", "date": "2022-02-17", "color": null}, {"text": "特斯拉（智能电动车制造商）、Uber（基于移动互联网的出行服务提供商）和Waymo（全力进军高级自动驾驶技术）", "chapter": "硅谷：创新的摇篮", "date": "2022-02-17", "color": null}, {"text": "在那个年代炒股，比如今买比特币还复杂。", "chapter": "2.马斯克为什么要办学校？", "date": "2021-12-18", "color": null}], "ideas": [{"content": "马斯克是个为梦想而生，意志力、行动力超强，不畏世俗与强权，有大格局，大胸怀的人，是个血有肉的普通人类，但称得上伟大！", "abstract": "", "chapter": "", "date": "2022-02-18", "star": 100}]}, {"id": "850814", "title": "简明美国史", "author": "陈勤", "cover": "https://cdn.weread.qq.com/weread/cover/84/YueWen_850814/s_YueWen_850814.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=9d2324f05cfb7e9d2e0c05b", "progress": 100, "finished": 1, "hlCount": 6, "ideaCount": 3, "highlights": [{"text": "信息时代的精神图腾，创造了苹果公司，改变了世界", "chapter": "第八章 世纪之交的美国", "date": "2019-06-09", "color": null}, {"text": "炉边谈话", "chapter": "两次世界大战之间的美国", "date": "2019-06-08", "color": null}, {"text": "人民的信心", "chapter": "两次世界大战之间的美国", "date": "2019-06-08", "color": null}, {"text": "富兰克林·罗斯福（1882～1945）引领美国走出大萧条，打赢二战，成为超级大国", "chapter": "第七章 光荣与梦想：20世纪的美国", "date": "2019-06-08", "color": null}, {"text": "捍卫持枪权就是在捍卫公民权利免受政府侵犯，相对于持枪本身而言，后者更具有重大意义", "chapter": "吵出来的美国宪法", "date": "2019-06-08", "color": null}, {"text": "称为“半神半人的聚", "chapter": "吵出来的美国宪法", "date": "2019-06-08", "color": null}], "ideas": [{"content": "1929年的经济危机让美国梦第一放破碎了", "abstract": "美国梦第一次破碎了。", "chapter": "", "date": "2019-06-08", "star": null}, {"content": "无私", "abstract": "立国的精神信念。", "chapter": "", "date": "2019-06-08", "star": null}, {"content": "了不起", "abstract": "本来他们都是大奴隶主、大财主、大知识分子，都是既有钱又有名望的人。可就是这些人，义无反顾地签署了《独立宣言》，把自己的退路断了，很了不起。", "chapter": "", "date": "2019-06-08", "star": null}]}, {"id": "237732", "title": "当下的力量（珍藏版）", "author": "埃克哈特·托利", "cover": "https://cdn.weread.qq.com/weread/cover/56/YueWen_237732/s_YueWen_237732.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=402322c053a0a44020d6c2b", "progress": 25, "finished": 0, "hlCount": 1, "ideaCount": 8, "highlights": [{"text": "无念状态", "chapter": "超越你的思维", "date": "2020-09-08", "color": null}], "ideas": [{"content": "小我是有大量的细胞组合而成的。细胞是由大量原子构成的。原子是由电子中子质子构成的。所谓的小我是一个虚假的组合，因为最微小的夸克也是可以再细分的。无限的细分下去，可以洞察世界的本质是空性的。", "abstract": "虚假的自我，也就是小我", "chapter": "", "date": "2020-09-09", "star": null}, {"content": "生命的秘密在于：“在你死亡之前死亡”—并发现原来根本没有死亡。", "abstract": "", "chapter": "", "date": "2020-09-09", "star": null}, {"content": "小我总是徘徊在过去与未来之间，漂浮不定，小我用思维来推导因果得失，常常痛苦不堪，无法自拔，陷入思维的死循环。", "abstract": "对于小我来说，当下时刻几乎不存在，只有过去和未来才是重要的", "chapter": "", "date": "2020-09-08", "star": null}, {"content": "能够进入无我状态，他一定知道自己与万物是一体的，所谓的自我都是可以被粉碎的。过去的我，当下的我，以及未来的我，哪一个才是真正的我呢？我的衣服，我的车子，我的房子，我的妻子，我的儿子。真的是属于我吗？身体只是本体的一个灵魂旅店。", "abstract": "", "chapter": "", "date": "2020-09-08", "star": null}, {"content": "这是一个以万物为一体的本体，它有一双法眼，有一双佛眼，有一双天眼，他在你的上方，你在你的上方，正注视着自己，观察着自己的思维，一言一行。", "abstract": "随着你倾听思维，你会感觉到在这种思维之下或之后的一种有意识的临在", "chapter": "", "date": "2020-09-08", "star": null}, {"content": "用法眼天眼佛，在一个居高临下的上方注视着自己以及自己的思维行为。", "abstract": "随着你倾听思维，你会感觉到在这种思维之下或之后的一种有意识的临在，那就是你更深的自我。", "chapter": "", "date": "2020-09-08", "star": null}, {"content": "我心就是宇宙，宇宙就是我心。我与天地万物同呼吸，共命运。我在思考，我在呼吸，实际上就是宇宙在思考，在呼吸。", "abstract": "在你和你自己之间、你和其他人之间、你和自然之间、你和上帝之间。就是这些思维创造了一种孤立的幻象，你与其他人完全分离的幻象。", "chapter": "", "date": "2020-09-08", "star": null}, {"content": "遇见未知的自己是一本很不错的书。", "abstract": "", "chapter": "", "date": "2020-09-08", "star": null}]}, {"id": "23874306", "title": "我们为什么爱宋朝：重新发现造极之世", "author": "贾冬婷 杨璐", "cover": "https://cdn.weread.qq.com/weread/cover/9/YueWen_23874306/s_YueWen_23874306.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=2d132f90716c4b022d1e66e", "progress": 100, "finished": 1, "hlCount": 8, "ideaCount": 0, "highlights": [{"text": "宋代知识分子无法在政治、军事、外交、经济等众多方面打开局面，才不得不主张反求诸己，内向闭塞，认为“人欲”与“天理”相违背，君子必须“主静、主敬、慎独”。这种拘谨作风，甚至影响了之后中国社会整体的性格，使之趋于保守内向……", "chapter": "尾声 访宋陵", "date": "2022-08-03", "color": null}, {"text": "孔曰成仁，孟曰取义，唯其义尽，所以仁至。读圣贤书，所学何事？而今而后，庶几无愧。", "chapter": "金瓯缺：两宋王朝的真实与想象", "date": "2022-08-03", "color": null}, {"text": "尽管终300年之世，它也没能完成兴复幽燕的伟业、真正成就大一统局面，但托庇于太宗、真宗以降的政治改革和注重文教，两宋得以摆脱此前200年间藩镇林立、武夫当国的困境，成为全球首屈一指的工商业大国、贸易大国和文化中心。", "chapter": "金瓯缺：两宋王朝的真实与想象", "date": "2022-08-03", "color": null}, {"text": "什么是美的表现形式？宋徽宗用自己的艺术创作回答了这个问题。书法、茶、画、收藏、园林，中国文化被津津乐道之美，都在赵佶的日常里", "chapter": "宋徽宗：风流总被雨打风吹去", "date": "2022-08-03", "color": null}, {"text": "朱熹理学强调《大学》，“明明德”“新民”“止于至善”是三纲领，具体实践是格物、致知、诚意、正心、修身、齐家、治国、平天下。", "chapter": "书院：宋人理学传播器", "date": "2022-08-03", "color": null}, {"text": "孟子的“养心莫善于寡欲，其为人也寡欲，虽有不存焉者寡矣。其为人也多欲，虽有存焉者寡矣”。孟子认为人的欲望寡浅才能保持住善良的本性，多欲则会丧失善良的本性。", "chapter": "书院：宋人理学传播器", "date": "2022-08-03", "color": null}, {"text": "宋时，儒释道三教事实上已合流", "chapter": "雅集：理想化归宿", "date": "2022-08-03", "color": null}, {"text": "在宋代所谓“五大名窑”——汝、官、哥、钧、定之中，定窑数量最多，最容易见到完整器，", "chapter": "追寻宋朝：士与器的黄金时代", "date": "2022-08-03", "color": null}], "ideas": []}, {"id": "921043", "title": "生活的哲学", "author": "朱尔斯·埃文斯", "cover": "https://cdn.weread.qq.com/weread/cover/51/YueWen_921043/s_YueWen_921043.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=63032ce05e0dd3630e81a3e", "progress": 41, "finished": 0, "hlCount": 8, "ideaCount": 0, "highlights": [{"text": "如卡尔·萨根所说：“……有1000亿个星系，它们每一个都包含大约1000亿个星星。想想如此广阔、惊人的宇宙中会有多少种生命。", "chapter": "神秘主义者与怀疑论者", "date": "2022-06-27", "color": null}, {"text": "赫拉克利特相信，我们可以通过培养我们的理性、控制我们的激情、清除酗酒和贪吃等坏习惯来获得宇宙视角，坏习惯会使我们的意识之火变暗，把我们从宇宙视角往下拉。当我们屈服于“内心的欲望”，我们就会使我们的意识变得暗淡。如果我们过理性和节制的生活，那么我们就会使我们的灵魂变得干燥，让意识之火燃得更亮，它就能够理解和照亮逻各斯，使自己跟逻各斯和谐一致。", "chapter": "神秘主义者与怀疑论者", "date": "2022-06-27", "color": null}, {"text": "我们需要使我们的意识超越我们狭隘、自私的关切，获得法国学者和神秘主义者皮埃尔·阿多所说的“宇宙意识”。", "chapter": "神秘主义者与怀疑论者", "date": "2022-06-27", "color": null}, {"text": "三昧，指的是看到相互分离的事物，但是感觉它们是一个整体，伴有狂喜之情。", "chapter": "神秘主义者与怀疑论者", "date": "2022-06-27", "color": null}, {"text": "卢克莱修坚持认为：“死亡对我们来说什么都不是。”在我们死后，我们不会存在。非存在没什么可害怕的。所以那就享受生活吧，明智地追求快乐，避免去想财富、宗教或性爱（卢克莱修小心翼翼地避免去爱上谁，他认为爱情带来的痛苦多过快乐）。", "chapter": "哲学的盛筵", "date": "2022-06-27", "color": null}, {"text": "为了实现更加连续不断的平静，理性的享乐主义者学习去限制自己的欲望，限制到容易实现的程度。“使自己习惯于简单、便宜的饮食，满足健康所需，使自己不惧命运。”伊壁鸠鲁写道。", "chapter": "哲学的盛筵", "date": "2022-06-27", "color": null}, {"text": "真正的快乐对物质的依赖十分有限", "chapter": "哲学的盛筵", "date": "2022-06-27", "color": null}, {"text": "如果过于乐观的期待是愤怒的主要原因，那么解决方法是降低我们的期待，努力让他们符合现实，这样我们就不会一直觉得世界失信于我们。", "chapter": "04 接受和适应人生中的不完美", "date": "2022-06-27", "color": null}], "ideas": []}, {"id": "823535", "title": "血酬定律：中国历史中的生存游戏", "author": "吴思", "cover": "https://cdn.weread.qq.com/weread/cover/22/YueWen_823535/s_YueWen_823535.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=8d4328f05c90ef8d48685a7", "progress": 90, "finished": 0, "hlCount": 8, "ideaCount": 0, "highlights": [{"text": "至少从道义的角度，我看不出这种城乡分割政策与种族隔离政策和种姓歧视政策有什么本质上的区别", "chapter": "第41章 雁户：基本故事和变型故事", "date": "2022-06-08", "color": null}, {"text": "西方男人的幻想可以集中在巨大的财富上，但中国的财富很缺乏自卫能力，不那么值得幻想。在一个缺乏安全和秩序的社会里，对获利能力的幻想，不如对加害能力的幻想那么具有根本性，那么肆无忌惮所向披靡。这就是说，对加害能力和自卫能力的热切幻想，对公平和正义的热切幻想，反映了我们社会的缺陷。", "chapter": "第36章 金庸给我们编了什么梦", "date": "2022-06-08", "color": null}, {"text": "金庸对武侠的想象色彩缤纷，但是最核心的一点，就是拥有一种超常的能力，可以保护自己不受暴力的侵犯和伤害，自己却有能力随心所欲地伤害别人。", "chapter": "第36章 金庸给我们编了什么梦", "date": "2022-06-08", "color": null}, {"text": "潜规则在是暗中运行的，而白规却以曝光相威胁，这正是抓住了潜规则体系的致命弱点的一击。", "chapter": "第31章 我认出了一个小物种", "date": "2022-06-08", "color": null}, {"text": "在自然界的拟态关系中，模拟者是占了便宜的。它们无须自己制造毒素，节省了资源，又获得了近似毒物的安全度。在人类社会中，模拟者要占这个便宜，就必须分肥。铺户和钱庄老板每年要拿出部分利润，从不好惹的人手里买一身不好惹的装扮。", "chapter": "第23章 硬伙企业(1)", "date": "2022-06-08", "color": null}, {"text": "血酬是对暴力的酬报，就好比工资是对劳动的酬报、利息是对资本的酬报、地租是对土地的酬报。", "chapter": "第3章 匪变：血酬定律及其推想(1)", "date": "2022-06-08", "color": null}, {"text": "在与上级官府的关系方面，主要是缴纳赋税，输送人才。在与百姓关系方面，则是从汉朝就确定的老四项：一、宣传倡导道德法令，二、维持社会治安，三、养老扶贫，四、听讼断狱。", "chapter": "第14章 县官的隐身份(1)", "date": "2022-06-07", "color": null}, {"text": "当然，从来就没有什么救世主，也不能靠神仙皇帝。人民的生存权，与牛羊猪鸡的生存权一样，说到底，还是自己用肉蛋奶和皮毛换来的，具体到某个品种的生存权和发展权，则是靠比较高的生产力水平竞争来的。", "chapter": "第6章 命价考略(2)", "date": "2022-06-07", "color": null}], "ideas": []}, {"id": "31531099", "title": "扛住就是本事", "author": "冯仑", "cover": "https://cdn.weread.qq.com/weread/cover/19/YueWen_31531099/s_YueWen_31531099.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=2cc3254071e1205b2cc2a08", "progress": 100, "finished": 1, "hlCount": 8, "ideaCount": 0, "highlights": [{"text": "它总是要和其他动物进行生死较量，“你死我才能活”。而大象是“大家都活，只是我比你勤奋”。所以这两种生活态度和生活哲学是不一样的。", "chapter": "44 大象哲学与“象牙女王”", "date": "2022-05-18", "color": null}, {"text": "人生其实就是这样。如果你斤斤计较，一笔一笔非要算清楚，目光短浅，那不能成大事。有的人不计较眼前的利益，往往能收获更大的成功。这也就是我经常讲的，心离钱越远，钱离口袋越近。", "chapter": "43 年轻人要比起点，比机会", "date": "2022-05-18", "color": null}, {"text": "我认为主要有四点——自信、我愿意、学习能力、眼界。", "chapter": "42 年轻人该有怎样的创业心态", "date": "2022-05-18", "color": null}, {"text": "洛克菲勒家族的这种做法看似很小气，甚至有意将孩子和财富隔绝开，实际上这说明他们对所谓的富豪生活是警惕的。就像老约翰在给他儿子的信中说的，天下没有白吃的午餐，更不可能一直维持现状。在洛克菲勒家族看来，限制奢靡生活，拒绝让孩子不劳而获，就是在鼓励孩子们自己去真实的社会上冒险。", "chapter": "31 家族企业的财富传承", "date": "2022-05-18", "color": null}, {"text": "第一句话，当很多事情诱惑你的时候，一定要提醒自己减少决策。　　第二句话，市场的鼻子很长，我们应该眼观六路，耳听八方。用心倾听，朝相反方向做，为人所不为，也用时间来证明你。", "chapter": "25 少做决策才是上策", "date": "2022-05-18", "color": null}, {"text": "静比动好，少比多好，精细比粗放好，耐心是赢取财富最主要的法宝。", "chapter": "25 少做决策才是上策", "date": "2022-05-18", "color": null}, {"text": "企业家是一个为别人的需求去追求梦想、不断满足市场需求的责任承担者。一个创业者如果想变成企业家、好的领导者，就得是一个风险承担者，也是最后兜底的埋单者。", "chapter": "07 大哥姿势：领导者指道、扛事、埋单", "date": "2022-05-18", "color": null}, {"text": "经历了一些新的事，遇到了一些有趣的人，看到了不同的风景，品尝了跟过去不同的人生滋味。", "chapter": "第1章 序言：要有看世界的智慧", "date": "2022-05-18", "color": null}], "ideas": []}, {"id": "23876675", "title": "习书有法", "author": "崔树强", "cover": "https://cdn.weread.qq.com/weread/cover/90/YueWen_23876675/s_YueWen_23876675.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=f7832f00716c5443f78b261", "progress": 12, "finished": 0, "hlCount": 8, "ideaCount": 0, "highlights": [{"text": "书法一方面表现了自然万象之美，另一方面表现了人的心灵节奏之美。换句话说，书法同时传达了自然的美和精神的美。", "chapter": "五、书法：立象以尽意", "date": "2022-04-03", "color": null}, {"text": "书法是无声之音，所谓“象八音之迭起”，因为书法有音乐般的节奏与和谐。实际上，一切艺术发展到极精微的境界，都逼近于音乐，都直指人心。", "chapter": "四、中得心源：书为心画", "date": "2022-04-03", "color": null}, {"text": "我们不能从一幅书法中识别一个人道德品质的高下和政治立场的正确与否，而是可以从线条和笔墨中感知到一个人的胸襟、气度、脾气和性格。", "chapter": "四、中得心源：书为心画", "date": "2022-04-03", "color": null}, {"text": "只要汉字还存在，只要人们对于美的追求还存在，书法将会存在下去，并成为一朵独立的花朵，立于艺术的百花园中。", "chapter": "二、实用与艺术的分野", "date": "2022-04-03", "color": null}, {"text": "书法史的发展，实际上是一个实用性不断削弱、艺术性不断增强的过程。", "chapter": "二、实用与艺术的分野", "date": "2022-04-03", "color": null}, {"text": "书法之所以能成为一种艺术，绝不是因为它是一种工整的书写，写得像印刷出来一样合乎规范，而是中国人在黑与白、点和线的千变万化中，完成了人的精神创造和情感宣泄。", "chapter": "二、实用与艺术的分野", "date": "2022-04-03", "color": null}, {"text": "我们反复练字，实际上也就是练习一种能够把自我生命融入点画的能力。", "chapter": "一、书写用品——文房四宝", "date": "2022-04-03", "color": null}, {"text": "书法的练习，就是通过笔墨的技巧，达到精神活力的呈现。", "chapter": "前言", "date": "2022-04-03", "color": null}], "ideas": []}, {"id": "39888467", "title": "后疫情时代的中国经济（套装共21册）", "author": "吴晓波 王德培 管清友 秦朔等", "cover": "https://cdn.weread.qq.com/weread/cover/75/YueWen_39888467/s_YueWen_39888467.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=943329407260a653943ae3c", "progress": 82, "finished": 0, "hlCount": 8, "ideaCount": 0, "highlights": [{"text": "第一，全球化能够带来繁荣，却不能带来公平，世界贸易这块压舱石愈是厚重，国家、阶层之间的平衡就愈难维持。", "chapter": "第三章 贸易全球化何去何从", "date": "2022-03-20", "color": null}, {"text": "三是去物质化。这是高质量的发展方式，极简的消费模式将大行其道", "chapter": "第一章 大疫情，大变局", "date": "2022-03-20", "color": null}, {"text": "未来学家丹尼尔·平克认为，未来的人有6种技能很重要：设计感、讲故事的能力、整合事物的能力、共情能力、玩的能力、找到人生意义感。", "chapter": "第十七章 教育回归初心", "date": "2022-03-20", "color": null}, {"text": "互联网时代的发展不在于拥有多少资源，而在于能连接多少资源、调动多少资源。商业的本质是交易，连接是交易的基础设施，使得在错综复杂连接的土壤上结出“商业结构”的果子。", "chapter": "第二章 “脱钩”与互联，谁代表未来", "date": "2022-03-20", "color": null}, {"text": "中国通过“一带一路”倡议将开创中国主导的全球化模式。不管是第一次全球化浪潮时期的殖民模式，还是第二次全球化浪潮时期以资本为中心的市场经济模式，或是第三次全球化浪潮时期的数字经济模式，都和中国推动的“一带一路”倡议下的全球化模式有着很大的区别。", "chapter": "第二节 中国企业的全球化机会", "date": "2022-03-19", "color": null}, {"text": "如今的贫富分化与20世纪存在显著差异：穷人与失业者获得更多生活保障；中产阶级纳税高、负债高，真实财富受到挤压；高收入阶层受益于资产泡沫，财富规模暴增", "chapter": "第九章 金融“末日大洪水”", "date": "2022-03-19", "color": null}, {"text": "一方面失业率飙升，另一方面政府拼命花钱支撑需求", "chapter": "第九章 金融“末日大洪水”", "date": "2022-03-19", "color": null}, {"text": "100年前的西班牙流感在国际政治格局上产生了两个后果：一个是助推了人类现代史上集权经济、计划经济国家苏联出现，其在“二战”前后一跃成为超级大国，将全世界卷入一场近半个世纪的美苏争霸纷争中；一个是工业革命以来的日不落帝国英国在那一场流感和相关动乱以后的30年里，从世界老大的位置上退了下来，美国取而代之成为世界头号强国。", "chapter": "第五章 中国成为世界经济安全岛", "date": "2022-03-15", "color": null}], "ideas": []}, {"id": "739613", "title": "幸福的方法", "author": "泰勒·本-沙哈尔", "cover": "https://cdn.weread.qq.com/weread/cover/99/YueWen_739613/s_YueWen_739613.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=e52321a05b491de52ec3a43", "progress": 100, "finished": 1, "hlCount": 8, "ideaCount": 0, "highlights": [{"text": "17世纪哲学家弗朗西斯·培根曾说过，亲密关系可以“将我们的快乐加倍，将我们的痛苦减半”。亚里士多德也说“没有友谊就没有幸福”。", "chapter": "第8章 经营幸福的亲密关系", "date": "2021-02-04", "color": null}, {"text": "寻找使命感", "chapter": "第7章 幸福工作法", "date": "2021-02-04", "color": null}, {"text": "幸福面前人人平等", "chapter": "第6章 幸福学习法", "date": "2021-02-04", "color": null}, {"text": "我们应该教给所有的孩子：生命中真正的幸福和成就感必须依靠自己的付出与努力，而不是借助旁人的帮助”", "chapter": "第6章 幸福学习法", "date": "2021-02-04", "color": null}, {"text": "幸福感才是人生的最高目标。", "chapter": "第4章 幸福才是人生的终极财富", "date": "2021-02-04", "color": null}, {"text": "灵性被称为“真切地感受到事情的意义”。", "chapter": "第3章 幸福的意义", "date": "2021-02-04", "color": null}, {"text": "我认为，幸福的定义应该是“快乐与意义的结合”。真正快乐的人，能够在自己觉得有意义的生活方式里享受它的点点滴滴。这种解释绝不仅限于生命里的某些时刻，而是人生的全过程。", "chapter": "第3章 幸福的意义", "date": "2021-02-04", "color": null}, {"text": "西方科学家喜欢很透彻地研究物体，包括把它们解剖、分解、不断放大来仔细地研究；而东方科学家则是把事物联系起来，从整体的角度出发，缩小并退后一步来系统地观察。", "chapter": "致中国读者", "date": "2021-02-03", "color": null}], "ideas": []}, {"id": "33306093", "title": "项塔兰", "author": "格里高利·大卫·罗伯兹", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/93/33306093/s_33306093.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=1b83262071fc35ed1b8ac70", "progress": 100, "finished": 1, "hlCount": 8, "ideaCount": 0, "highlights": [{"text": "，人的快乐和所住屋子的大小正好成反比。”", "chapter": "第十二章", "date": "2020-08-26", "color": null}, {"text": "的激情之中，就有了生命的所有目的、过程与意义。真相就是我们，我们每个人，每个原子，每个银河，宇宙中每个微不足道的东西，全都在朝上帝移动。”", "chapter": "第九章", "date": "2020-08-26", "color": null}, {"text": "对光子而言是一个开阔空间的宇宙，而整个宇宙只是一粒小尘埃。我们称为世界的东西，其实只是个观念，而且是不怎么理想的观念。从光的角度来看，赋予世界生命力的光子，我们所认知的宇宙，其实并非真实存在的。没有一样东西真实存在。懂了吗？”", "chapter": "第九章", "date": "2020-08-26", "color": null}, {"text": "他们的世界温柔而彻底地将我的人生拥入其梦境，犹如上涨的潮水漫过海", "chapter": "第八章", "date": "2020-08-26", "color": null}, {"text": "人在睡觉时是全世界人的朋友。”", "chapter": "第八章", "date": "2020-08-26", "color": null}, {"text": "项塔兰为我的名字，意为和平之人或天赐平和的男子。妇女团也同意。", "chapter": "第六章", "date": "2020-08-26", "color": null}, {"text": "凡来自大地的，最终都回归大地；凡兴盛茁壮的，都渐渐消失以再度滋长。", "chapter": "第六章", "date": "2020-08-26", "color": null}, {"text": "凡快乐必有其苦恼，凡财富必有其代价，凡生命必迟早要经受彻底的悲伤和死亡。", "chapter": "第六章", "date": "2020-08-26", "color": null}], "ideas": []}, {"id": "30060855", "title": "公司制的黄昏：区块链思维与数字化激励", "author": "龚焱 李磊 于洪钧", "cover": "https://cdn.weread.qq.com/weread/cover/79/YueWen_30060855/s_YueWen_30060855.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=7193284071cab1377190a13", "progress": 100, "finished": 1, "hlCount": 7, "ideaCount": 1, "highlights": [{"text": "转移的触发因素是互联网。互联网的诞生，使得卖方和买方之间的信息不对称被填平了，定价权的天平又一次不可逆转地从卖方逐步转移到了买方手中，用户有了前所未有的定价权。", "chapter": "用户第一", "date": "2022-12-16", "color": null}, {"text": "市场机制的运行是有成本的，制度的使用也是有成本的。因此，当交易中需要付出的代价太多，人们可能要考虑交易费用较低的替代方案，甚至干脆放弃交易。", "chapter": "一场经典辩论，一个经典定理", "date": "2021-12-31", "color": null}, {"text": "与其产生时代的工业主义相结合，层级制把组织内部变成了一架非人格化的庞大机器，所有的行为都是为了保障组织最大限度地获取经济效益。", "chapter": "组织形态变了", "date": "2021-12-31", "color": null}, {"text": "复式记账都是一种结果记账法，并非过程记账法。", "chapter": "当信任的构建者失信", "date": "2020-11-18", "color": null}, {"text": "1494", "chapter": "第一节 复式记账的故事", "date": "2020-11-18", "color": null}, {"text": "科斯认为，公司之所以存在，是因为它可以节约交易成本。交易成本包括交易过程中出现的寻找交易伙伴、谈判交易条件的成本，还包括签订合同及执行合同的成本，以及违约后进行处罚的成本。", "chapter": "存在的意义与边界", "date": "2020-11-18", "color": null}, {"text": "从1494年作为一种学科理论被意大利人卢卡·帕乔利提出。复式记账存世至今已有500多年的时间", "chapter": "序言一 是时候，从账本1.0迈向账本2.0", "date": "2020-05-04", "color": null}], "ideas": [{"content": "我们发现复式记账面临一个很大的挑战。\\n \\n这个账本上记录了三个东西：资产、现金流、营收和利润。所以，复式记账是一种结果记账法。", "abstract": "从1494年作为一种学科理论被意大利人卢卡·帕乔利提出。复式记账存世至今已有500多年的时间", "chapter": "", "date": "2020-05-04", "star": null}]}, {"id": "23433948", "title": "爱弥儿", "author": "[法]卢梭", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/948/23433948/s_23433948.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=bf632640716592dcbf67c89", "progress": 100, "finished": 1, "hlCount": 7, "ideaCount": 1, "highlights": [{"text": "“这个方法轻松简单，即在结婚后，像情人那样生活。", "chapter": "结合", "date": "2020-11-27", "color": null}, {"text": "在人生当中，一切都会结束，一切都是暂时的。", "chapter": "情欲", "date": "2020-11-27", "color": null}, {"text": "人们之所以有许多痛苦，就是因为不知节制地追求欲望；我们忘记了真实的环境，臆想出虚幻的环境，从幻境走回现实时，就会觉得自己生活不幸福。", "chapter": "情欲", "date": "2020-11-27", "color": null}, {"text": "在与人交往中，男人的礼仪表现在乐于助人上，而女人的礼仪则表现在细心体贴上。", "chapter": "艺术发展", "date": "2020-11-27", "color": null}, {"text": "一个女人可以通过化妆来让自己独领风骚，但是想让别人喜欢上她，还是要靠人品的。", "chapter": "两性教育的不同", "date": "2020-11-27", "color": null}, {"text": "明智的人首先关心的是所有人的利益，然后才会关心自己的利益；因为人类是每一种利益的总体拥有者，而不是其中的某个个人。", "chapter": "情感的升华", "date": "2020-11-27", "color": null}, {"text": "你必须知道，不能是你来告诉他要学习什么东西，而是让他自己决定想要学习什么和研究什么。你的任务就是想方设法地让他去了解那些事物，让他产生学习的意愿，想办法帮助他实现他的愿望。", "chapter": "用提问的方法引导孩子学习", "date": "2020-11-26", "color": null}], "ideas": [{"content": "有舍才有得", "abstract": "你会发现，就算失去了拥有的东西，你也会得到极大的快乐，而不会惊慌失措。你拥有东西，而不是东西拥有你。你会意识到，对于人们来说，一切身外之物都会有消失的那一天，所以要舍得放弃，才能享受快乐。", "chapter": "", "date": "2020-11-27", "star": null}]}, {"id": "437152", "title": "刘慈欣谈科幻", "author": "刘慈欣", "cover": "https://cdn.weread.qq.com/weread/cover/62/yuewen_437152/t6_yuewen_4371521703698657.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=49132e3056aba0491ccdf81", "progress": 20, "finished": 0, "hlCount": 0, "ideaCount": 8, "highlights": [], "ideas": [{"content": "反商", "abstract": "减小自身尺度就等于扩张了生存空间，我们把这称为文明的“反向扩张”。", "chapter": "", "date": "2018-04-24", "star": null}, {"content": "角度就是不一样", "abstract": "外星人对热情伸出双手的人类视而不见，却去和蚂蚁拥抱交谈。这就生出了一个我们以前从未认真考虑过的问题：\r\n谁是地球的户主？", "chapter": "", "date": "2018-04-24", "star": null}, {"content": "哈哈", "abstract": "多活一年就多一点机遇，差一步差万步，不要死在距永生阶梯只有一步之遥的地方哦。", "chapter": "", "date": "2018-04-24", "star": null}, {"content": "人与神的差异", "abstract": "人类在死亡面前的不平等却是人与神间的差异，这", "chapter": "", "date": "2018-04-24", "star": null}, {"content": "技术奇点", "abstract": "技术奇点的含意是：技术的进步可能由量变产生突然的质变，在极短的时间里彻底改变人类世界的状态。", "chapter": "", "date": "2018-04-24", "star": null}, {"content": "真的吗？？？", "abstract": "设想我们能将宇宙飞船的速度再提高二三百倍（相当不少了！），达到光速的百分之一，那么我们到达最近的恒星再返回需要1000年，如果飞船从宋朝出发，现在就快回来了", "chapter": "", "date": "2018-04-24", "star": null}, {"content": "格局", "abstract": "现在，我们看到了这样一个事实：人类放弃了太空中的10万个地球，只打算在这一个地球上生存下去，而他们生存的手段是环保，", "chapter": "", "date": "2018-04-24", "star": null}, {"content": "又开脑洞了", "abstract": "我们现在所关心的，是每个基本粒子是否是一个充满着亿万星系的宇宙，或者我们的宇宙是不是一个基本粒子。", "chapter": "", "date": "2018-04-24", "star": null}]}, {"id": "3300084200", "title": "悲欣交集：弘一法师李叔同全传（不论在俗还是出家，他的一生都卓尔不群）", "author": "金梅 著 丰子恺 绘", "cover": "https://cdn.weread.qq.com/weread/cover/33/cpplatform_ebntsqsmheosxcobbg96zt/s_cpplatform_ebntsqsmheosxcobbg96zt1705300512.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=41a32ce0813ab8764g010ea8", "progress": 83, "finished": 0, "hlCount": 7, "ideaCount": 0, "highlights": [{"text": "平一日始入大慈山，断食十七日[插图]，身心灵化，欢乐康", "chapter": "第六章 出家前后", "date": "2026-02-22", "color": null}, {"text": "诗，填词，写字，治金石，演剧。他对于艺术，差不多全般皆能，而且每种都很出色。专门一种的艺术家大都不及他，要向他学习。……他的教授图画音乐，有许多其他修养作背景，所以我们不得不崇敬他。借夏丏尊先生的话来讲：他做教师，有人格作背景，好比佛菩萨的有“后光”。所以他从不威胁学生", "chapter": "第五章 为人师表", "date": "2026-02-22", "color": null}, {"text": "后，听到李先生正在门口满面和气地叫他回去。这位同学不得不回到李先生身边，李先生又叫他回到教室里。进了教室，李先生才用轻而严肃的声音，和气地对他说", "chapter": "第五章 为人师表", "date": "2026-02-22", "color": null}, {"text": "歌曲配谱，又能作必要的改动。如同样选用J.D.奥德威的《梦见家和母亲》的曲子，为自己的歌词配曲，李叔同的《送别》一歌，由于删去了原曲中每四小节出现一次的", "chapter": "第五章 为人师表", "date": "2026-02-22", "color": null}, {"text": "的《行路难》、李商隐的《隋宫》、辛弃疾的《菩萨", "chapter": "第五章 为人师表", "date": "2026-02-22", "color": null}, {"text": "面。他的歌词善于借景抒情，句式基本上采用的是中国古典律诗或长短句的结构。如《春游》：春风吹面薄于纱，春人妆束淡于画。游春人在画中行，万花飞舞春人下。梨花淡白菜花黄，柳花委地芥花香。莺啼陌上人归去，花外疏钟送夕阳。这是李叔同作曲乐歌的代表作。李“在", "chapter": "第五章 为人师表", "date": "2026-02-22", "color": null}, {"text": "简单一些，却完全是根据西洋风俗的。当然和普通的改成日本风的有些不同。会话的中国语，又和法语有相像的地方。因此，愈使人感得痛快。尤其是李君的优美婉丽，决", "chapter": "第三章 留学东瀛", "date": "2026-02-22", "color": null}], "ideas": []}, {"id": "3300121812", "title": "奇点更近：未来20年的人工智能神预测", "author": "[美]雷·库兹韦尔", "cover": "https://cdn.weread.qq.com/weread/cover/13/cpplatform_czc2p6hy2gz2zzbchune6q/s_cpplatform_czc2p6hy2gz2zzbchune6q1732096406.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=30932ba0813ab9615g012cce", "progress": 74, "finished": 0, "hlCount": 7, "ideaCount": 0, "highlights": [{"text": "到2030年左右，最勤奋、最有见识的人将达到“长寿逃逸速度”。这是一个临界点，自此每过一年，我们的剩余预期寿命就会增加一年。", "chapter": "勤奋的人将在2030年左右实现长寿逃逸速度", "date": "2026-03-11", "color": 1}, {"text": "未来20年的进步将与过去20年大致相似，但这忽略了这一过程的指数性质，即进步的速度将是指数级的，而不是线性的。", "chapter": "勤奋的人将在2030年左右实现长寿逃逸速度", "date": "2026-03-11", "color": 1}, {"text": "只有2％的人回答正确：贫困人口减少了50％。越来越多的社会科学研究证实了公众认知与现实之间存在差异，依据的是无数的社会和经济指标。", "chapter": "第4章 生活正在指数级变得更好", "date": "2026-03-11", "color": 1}, {"text": "我们现在正处于接近这些指数曲线陡然升高的阶段。", "chapter": "第4章 生活正在指数级变得更好", "date": "2026-03-11", "color": 1}, {"text": "我同样计划打造一个属于我的AI副本。", "chapter": "来生：制造出令人信服的仿生人", "date": "2026-03-11", "color": 1}, {"text": "从所有可检测的证据来看，复制人会同被复制人一样真实。如果你认为身份的本质在于信息、记忆与性格，那么复制人就是那个人", "chapter": "来生：制造出令人信服的仿生人", "date": "2026-03-11", "color": 1}, {"text": "随着技术的飞速发展，不管是复制人还是我们这些仍然活着的人，都将能够选择不同的身体和体型。最终，复制人甚至有可能被安置进通过本体的DNA培育并通过赛博技术增强的生物体体内，前提是能找到这些DNA。", "chapter": "来生：制造出令人信服的仿生人", "date": "2026-03-11", "color": 1}], "ideas": []}, {"id": "26720043", "title": "手工咖啡：咖啡爱好者的完美冲煮指南", "author": "[美]杰茜卡·伊斯托 安德烈亚斯·威尔霍夫", "cover": "https://cdn.weread.qq.com/weread/cover/54/YueWen_26720043/s_YueWen_26720043.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=f3432fc07197b72bf340aa5", "progress": 79, "finished": 0, "hlCount": 7, "ideaCount": 0, "highlights": [{"text": "理解口感的一种方法是将其分解为醇厚度、油脂和涩感。", "chapter": "口感", "date": "2026-01-01", "color": 1}, {"text": "咖啡豆不应在烘焙后立刻使用，因为它需要时间排出一定量的二氧化碳，否则喝起来会很苦。", "chapter": "破译咖啡包装袋上的标签", "date": "2026-01-01", "color": 1}, {"text": "有一些特定的品种，例如波旁、瑰夏、SL34，这些字眼代表着高品质。", "chapter": "破译咖啡包装袋上的标签", "date": "2026-01-01", "color": 1}, {"text": "巴拿马以瑰夏闻名的翡翠庄园", "chapter": "破译咖啡包装袋上的标签", "date": "2026-01-01", "color": 1}, {"text": "整整1分钟后，水温只下降了一两度。1分30秒后，大约降到97.2℃，2分钟后，大约降到95℃。整整3分钟后，水温平均下降了7℃。此时大多数测试的记录为93℃，仍然在冲煮的理想温度范围内。", "chapter": "温度", "date": "2025-11-15", "color": 1}, {"text": "咖啡冲煮的理想温度通常是90.5℃~96℃", "chapter": "温度", "date": "2025-11-15", "color": 1}, {"text": "在第六章里，我会为每一种注水法提供一个标准水流时间。如果流速超过了标准时间，就证明你的粉太细；如果没达到标准时间就完成冲煮，证明粉太粗。", "chapter": "研磨度和冲煮时间", "date": "2025-11-15", "color": 1}], "ideas": []}, {"id": "812443", "title": "白鹿原", "author": "陈忠实", "cover": "https://cdn.weread.qq.com/weread/cover/78/YueWen_812443/s_YueWen_812443.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=47532ac05c659b47554a825", "progress": 100, "finished": 1, "hlCount": 7, "ideaCount": 0, "highlights": [{"text": "钻笼套强。先躲过眼下的风头再说，说不定风头过了也就没事了，说不定田总乡约调走了也就好办了。你嘛，你", "chapter": "第十五章", "date": "2025-12-29", "color": null}, {"text": "一个音就是土著。”黑娃又瞪着眼问：“我只知道你是白狼。", "chapter": "第十二章", "date": "2025-12-29", "color": null}, {"text": "木头泥屐绑上脚就出了街门。街巷里的泥浆埋没了泥屐的木腿，他小心地走过去，背着手，走到", "chapter": "第八章", "date": "2025-12-29", "color": null}, {"text": "辙印深陷的土路，迈着不慌不急的步子，在田地和村庄之间", "chapter": "第八章", "date": "2025-12-29", "color": null}, {"text": "中的大门，这样严峻的事，使他不再非议不大顺眼的", "chapter": "第八章", "date": "2025-12-29", "color": null}, {"text": "庭，一般人即使听到“溜溜溜”的叫声，也不会与狗的", "chapter": "第八章", "date": "2025-12-29", "color": null}, {"text": "房子砸锅碗负责任。你明白了吗？快把麻绳装到褡", "chapter": "第七章", "date": "2025-12-29", "color": null}], "ideas": []}, {"id": "3300026070", "title": "营养圣经", "author": "帕特里克•霍尔福德", "cover": "https://cdn.weread.qq.com/weread/cover/74/cpPlatform_7QvhMr1iwbZJ96JxBJGPWv/s_cpPlatform_7QvhMr1iwbZJ96JxBJGPWv.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=7b032730813ab70afg0109a6", "progress": 99, "finished": 0, "hlCount": 7, "ideaCount": 0, "highlights": [{"text": "沙丁鱼是一个非常好的选择，它体型很小，相比那些体型相对更大的鱼，其体内的毒素积累要少一些。", "chapter": "第8章 有关蛋白质的问题", "date": "2023-11-12", "color": 1}, {"text": "膳食纤维理想的摄入量是每天不少于35克。膳食纤维的作用是非常多的，其中一种作用是可以吸收消化道里的水分，使食物的体积膨大，使其更容易地穿过消化道。", "chapter": "第7章 最佳膳食方向", "date": "2023-11-12", "color": 1}, {"text": "纤维的最佳摄入量是每天不低于35克", "chapter": "第60章 食物真相档案", "date": "2023-11-12", "color": 1}, {"text": "一份理想的膳食中，脂肪所提供的能量不超过总能量的20%，", "chapter": "第60章 食物真相档案", "date": "2023-11-12", "color": 1}, {"text": "补充益生菌对治疗伴有炎症的肠道失调症如节段性回肠炎和溃疡性结肠炎有良好的效果。", "chapter": "第22章 改善你的消化功能", "date": "2023-11-09", "color": 1}, {"text": "补充卵磷脂的颗粒或胶囊可以促进乳化作用，并且对脂肪耐受性很低的人有所帮助，例如那些因手术切除了胆囊而不能储存胆汁的人。", "chapter": "第22章 改善你的消化功能", "date": "2023-11-09", "color": 1}, {"text": "鲭鱼、鲱鱼、湖红点鲑鱼、三文鱼、金枪鱼、沙丁鱼、枪鱼和白鱼的Omega-3脂肪含量是最高的，而且其含量的多少基本也是按照这个顺序从多到少排列的。鲭鱼的EPA和DHA的含量大约是枪鱼和白鱼的10倍，100克的鲭鱼可以为你提供共2.5克的EPA和DHA。", "chapter": "第9章 生命的脂肪", "date": "2023-11-09", "color": 1}], "ideas": []}, {"id": "31144168", "title": "投资至简：从原点出发构建价值投资体系", "author": "静逸投资", "cover": "https://cdn.weread.qq.com/weread/cover/32/YueWen_31144168/s_YueWen_31144168.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=c0632ff071db38e8c06c716", "progress": 96, "finished": 0, "hlCount": 7, "ideaCount": 0, "highlights": [{"text": "能力圈的唯一衡量标准就是能否判断出一家企业5~10年的未来，没有其他标准了。无论一家企业处在什么样的行业，", "chapter": "第三节 构建价值投资体系", "date": "2023-03-16", "color": 1}, {"text": "机会成本看似是一个非常简单的概念，但很多人无法理解。例如，用自家商铺开餐馆的人会认为自己没有租金成本（假定周边同样商铺月租金5万元），月毛利润4万元也认为自己是盈利的。", "chapter": "第三节 构建价值投资体系", "date": "2023-03-16", "color": 1}, {"text": "我们做投资时，需要知道自己的时间维度。如果看中质量一般的公司静态的低估，价格回归合理后就应该卖出；如果买入了质量很高的公司，就应该伴随其尽可能长的经营时间。早", "chapter": "第三节 构建价值投资体系", "date": "2023-03-16", "color": 1}, {"text": "格雷厄姆喜欢静态的安全边际，对动态的安全边际持保留态度。而巴菲特修正了格雷厄姆的看法，巴菲特在2007年股东大会上说过这样一段话：“尽管我们希望花四毛钱买一元钱的东西，但是真碰上伟大的生意，我们愿意出接近一元钱的价格买下来。”", "chapter": "第三节 构建价值投资体系", "date": "2023-03-16", "color": 1}, {"text": "股权成为长期收益最高资产的第一个原因是经济的持续增长，即“总的蛋糕越做越大”。经济持续的增长，其实是人类总体生产、交换和消费越来越多商品和服务的表现。", "chapter": "第一章 构建投资的大厦", "date": "2023-03-15", "color": 1}, {"text": "根据股价的变动而进行的这种反思没有任何意义，但大部分的反思都是根据股价做出的。", "chapter": "第三节 我们应该怎样对待投资中的错误", "date": "2023-03-15", "color": 1}, {"text": "投资要先易后难，循序渐进，可以先投资指数基金，然后采用格雷厄姆的低市盈率、分散投资的方法，再慢慢过渡到巴菲特的深度分析、集中投资的方法。", "chapter": "第四节 大道甚夷，而人好径：《道德经》中的投资智慧", "date": "2023-03-15", "color": 1}], "ideas": []}, {"id": "22791651", "title": "《金刚经》说什么", "author": "南怀瑾", "cover": "https://cdn.weread.qq.com/weread/cover/87/YueWen_22791651/s_YueWen_22791651.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=e5832360715bc5e3e581083", "progress": 84, "finished": 0, "hlCount": 7, "ideaCount": 0, "highlights": [{"text": "一般学佛的人观念错误，认为学佛可以偷懒，可以躲避，以为在学佛，万事不管。这完全是错误的态度，不但不够小乘，就是基本做人的行为都算错误的。", "chapter": "第二十八品 不受不贪分", "date": "2022-08-19", "color": null}, {"text": "须菩提。于意云何。汝等勿谓如来作是念。我当度众生。须菩提。莫作是念。何以故。实无有众生如来度者。若有众生如来度者。如来即有我人众生寿者。须菩提。如来说有我者。即非有我。而凡夫之人。以为有我。须菩提。凡夫者。如来说即非凡夫。是名凡夫。", "chapter": "第二十五品 化无所化分", "date": "2022-08-19", "color": null}, {"text": "虚空之体却是不增不减的；所以一切众生，不要被变化不实的现象所骗。", "chapter": "第十八品 一体同观分", "date": "2022-08-18", "color": null}, {"text": "法眼又是什么眼呢？慧眼观空。而能够真正认识自性空、空性的体，就是法眼。法眼观一切众生平等，非空非有。只落在空，还是小乘果的一边，要能够真正观空里的妙有才行。在凡夫的境界来说，是性空缘起；在悟道智慧境界里来说，是真空起妙有，这是法眼的道理，是平等而观。", "chapter": "第十八品 一体同观分", "date": "2022-08-18", "color": null}, {"text": "自求多福，自助而后天助，自助而后人助。", "chapter": "第二品 善现启请分", "date": "2022-06-26", "color": null}, {"text": "花落水流红，闲愁万种，无语怨东风。", "chapter": "第二品 善现启请分", "date": "2022-06-26", "color": null}, {"text": "百年三万六千日，不在愁中即病中。”", "chapter": "出版说明", "date": "2022-06-26", "color": null}], "ideas": []}, {"id": "857847", "title": "岁月台湾：1900年以来的台湾大事记（第四版）", "author": "秦风编著", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/847/857847/s_857847.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=265320f05d16f7265362f82", "progress": 98, "finished": 1, "hlCount": 7, "ideaCount": 0, "highlights": [{"text": "2008年3月22日，台湾政治史上第二次和平政党轮替出现，国民党“正副总统”候选人马英九、萧万长以七百六十五万多票对五百四十四万多票、约两百二十万的悬殊比例，击败了民进党候选人谢长廷、苏贞昌。选举结果震撼了岛内外，民进党大败，结束八年执政，国民党则重新上台，开创了中国人政党和平下台又和平上台的历史纪录。", "chapter": "2000-2008 在纷扰中前行的台湾", "date": "2022-08-06", "color": null}, {"text": "在1970年代，台湾青年心目中最想当的风云人物是台塑董事长王永庆，在1980年代是宏碁董事长施振荣，那么到了1990年代末期，学子心目中排行第一的人物无疑是台湾集成电路公司董事长张忠谋。", "chapter": "1999 高科技产业崛起", "date": "2022-08-06", "color": null}, {"text": "但是，把这个胜利和暂时利用金马把敌人套在绞索上，把占领金马和占领台湾统一来解决的长远利益比较起来，则不如让金马暂缓占领，仍由蒋军占领似乎较为有利。", "chapter": "1958 金门炮战", "date": "2022-08-05", "color": null}, {"text": "不过8日，当台美混合舰队又到金门卸货时，解放军接获指示集中炮击国民党军军舰，此时美舰不仅未予护航，反而迅速驶离。此时双方均清楚了彼此避免正面交战的战略底线，不过解放军仍然维持着“打而不登，封而不死”的策略，似乎有意让国民党军继续留守金门，并维持某种内战的形式。", "chapter": "1958 金门炮战", "date": "2022-08-05", "color": null}, {"text": "由于身为“外来者”，内在牵绊较少，“耕者有其田”的政纲反而容易贯彻", "chapter": "1953 耕者有其田", "date": "2022-08-05", "color": null}, {"text": "艾奇逊指称，美国承认在中国发生的事是一场真正的革命，蒋介石政府不是为军事优势所击败，而是为中国人民所抛弃。", "chapter": "1950 美国第七舰队进入台湾海峡", "date": "2022-08-05", "color": null}, {"text": "1995年正逢甲午战争一百年、台湾光复五十年以及雾社事件六十五周年，经过各界的努力，莫那·鲁道的铜像终于竖立在雾社", "chapter": "1930-1944 莫那·鲁道与雾社事件", "date": "2022-08-05", "color": null}], "ideas": []}, {"id": "27480167", "title": "简明世界经济史：金钱推动下的人类进程4000年", "author": "宫崎正胜", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/167/27480167/s_27480167.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=8ed32a8071a350678edfa04", "progress": 100, "finished": 1, "hlCount": 7, "ideaCount": 0, "highlights": [{"text": "赌场资本主义的道路", "chapter": "4 美国工厂向亚洲的转移与亚洲金融风暴", "date": "2022-05-18", "color": null}, {"text": "美元作为唯一能和黄金直接交换的货币的固定汇率制只持续了短短25年。美国经济失去了绝对优势。1971年之后，美元与黄金的交换停止了，世界经济因美国经济的衰弱再度陷入动荡。", "chapter": "第10章 美元实力下降，亚洲经济势头强劲", "date": "2022-05-18", "color": null}, {"text": "1889", "chapter": "4 电能的登场与电灯、电影、电器产品", "date": "2022-05-18", "color": null}, {"text": "1895年，日本赢得了甲午战争的胜利，与清朝签订《马关条约》，获得了巨额赔款2.3亿两白银。日本用这些白银于1897年确立了金本位制，", "chapter": "3 被鸦片击溃的清朝经济", "date": "2022-05-17", "color": null}, {"text": "两千多倍", "chapter": "3 罗斯柴尔德家族的崛起与金融时代的开始", "date": "2022-05-17", "color": null}, {"text": "资本主义经济是以土地和劳动力的商品化为基础，“利用货币提高最大利润，使货币自我增殖的组织架构”。", "chapter": "第2章 大航海时代欧洲经济的蓬勃发展", "date": "2022-05-17", "color": null}, {"text": "其实，数式中运用的等号（＝），本身也是商人在买卖中所使用的符号，用来表示天平的两端保持平衡的状态。", "chapter": "2 伊斯兰经济的大规模化及十进制、复式记账法的登场", "date": "2022-05-17", "color": null}], "ideas": []}, {"id": "29371437", "title": "第三次全球化浪潮", "author": "王世渝", "cover": "https://cdn.weread.qq.com/weread/cover/34/YueWen_29371437/s_YueWen_29371437.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=2b03237071c02c2d2b0cda0", "progress": 100, "finished": 1, "hlCount": 7, "ideaCount": 0, "highlights": [{"text": "如果第一次全球化浪潮时期，从东方去西方需要几个月的时间，第二次全球化浪潮时期，这个时间缩短到十几个小时，那么第三次全球化浪潮，这个时间将缩短为几个小时，甚至零。", "chapter": "三次全球化浪潮的时空关系", "date": "2022-03-19", "color": null}, {"text": "第一次全球化浪潮需要英国逐步去扩大其殖民地范围，占有殖民地之后还要去经营，而且距离遥远，效率极低；第二次全球化浪潮是通过公司、资本、货币来发展的，时空距离都大大缩短；而第三次全球化浪潮把资本淡化了，依靠虚拟世界的连接，全球时空同步。", "chapter": "为什么是华为？", "date": "2022-03-19", "color": null}, {"text": "金岩石", "chapter": "为什么是华为？", "date": "2022-03-19", "color": null}, {"text": "这个链条将会把全球所有组织、家庭、个人链接起来，组成没有国界、没有延时、没有种族、不分男女、不分宗教信仰、没有语言障碍的虚拟关系。", "chapter": "第三次全球化浪潮的特征", "date": "2022-03-19", "color": null}, {"text": "一个全球化的虚拟世界信息链很快成立，更加智能的信息链通过区块链的方式，把全球主要人群按照不同的区块主题构造为无数个独立又关联的链条。", "chapter": "第三次全球化浪潮的特征", "date": "2022-03-19", "color": null}, {"text": "5G时代的到来会大大加快第三次全球化浪潮的步伐，但完全没有想到，第三次全球化浪潮刚刚掀起就已经波澜壮阔、剑拔弩张。", "chapter": "浪潮始于何时？", "date": "2022-03-19", "color": null}, {"text": "当全球化体系输入中国的时候，可能会被中国修改和重构，然后再贴上中国的标签，带着中国文明的符号走向世界。", "chapter": "全球化与逆全球化", "date": "2022-03-19", "color": null}], "ideas": []}, {"id": "33641196", "title": "洞见：从科学到哲学，打开人类的认知真相", "author": "罗伯特·赖特", "cover": "https://cdn.weread.qq.com/weread/cover/11/YueWen_33641196/s_YueWen_33641196.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=b5d328f0720152ecb5d53f2", "progress": 98, "finished": 0, "hlCount": 7, "ideaCount": 0, "highlights": [{"text": "自然选择植入我们大脑的道德设备中，有一块就是正义感——一种本能，认为善事应该得到奖赏，恶行应该受到惩罚。因此，看到为恶者食恶果会给我们一种正义得以伸张的满足感。而且，做坏事的一般都是我们的敌人和对手；当我们的朋友和盟友做了坏事时，他们很可能就是受环境所困，因此不应受到严厉的惩罚。除非他们对我们做了坏事，这样他们也就将会被移出我们的“朋友和盟友”分类。", "chapter": "第十二章 没有杂草的世界", "date": "2021-12-10", "color": null}, {"text": "从自然选择的角度来看，感知的目的就是处理与生物体进化论利益相关的信息，也就是获得基因传播的机会。而我们的生命体给感知的信息贴上正面或负面的价值标签，以此标定相关性。我们天生就要去评判事物，并将这些判断编码到情感中。", "chapter": "第十一章 “空”积极的一面", "date": "2021-12-10", "color": null}, {"text": "关键点在于，声音本身是被动的，并非主动的，既没有令人愉悦，也没有令人不悦。从某种意义上讲，如果声音令人不悦，肯定就是你对它做了加工。", "chapter": "第十章 存在与内涵", "date": "2021-12-10", "color": null}, {"text": "理性的作用并非直接抑制一种感觉，而是强化能够抑制这种感觉的另外一种感觉。", "chapter": "第九章 “自我”控制", "date": "2021-12-09", "color": null}, {"text": "在人类进化过程中，思考对行动的作用越来越大，但是思考的起点和终点一直都是感觉。", "chapter": "第九章 “自我”控制", "date": "2021-12-09", "color": null}, {"text": "二百五十年前，休谟跟上了佛学的步伐，如今科学终于跟上了休谟的步伐。", "chapter": "第九章 “自我”控制", "date": "2021-12-09", "color": null}, {"text": "审视想法是怎样的感受葛斯汀说，有一种方法就是“想象大脑中涌起的每一种想法都是身边人的”。那么你又将如何与这些想法联系起来呢？他认为，你不必与这些想法有任何联系。“想法出现和消失，就像声音一样，但与之建立的联系是我们强加上去的。”", "chapter": "第八章 想法如何自我思考", "date": "2021-12-09", "color": null}], "ideas": []}, {"id": "920800", "title": "爆裂：未来社会的9大生存原则", "author": "伊藤穰一 杰夫·豪", "cover": "https://cdn.weread.qq.com/weread/cover/21/YueWen_920800/s_YueWen_920800.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=bde32b105e0ce0bde56eff6", "progress": 82, "finished": 0, "hlCount": 7, "ideaCount": 0, "highlights": [{"text": "未来不一定会出现类似于终结者的智能，由它们来决定人类是不好的存在，必须消灭。未来社会将是人类和机器合作，相互启迪，让集体智能不断扩大。", "chapter": "总结", "date": "2021-06-07", "color": null}, {"text": "孩子，钢铁不强，血肉之躯更强！", "chapter": "8 韧性优于力量", "date": "2021-06-07", "color": null}, {"text": "“实践”优于“理论”意味着，人们要意识到，在节奏快变成新常态的未来，等待和计划的成本要比先实践后随机应对更高。", "chapter": "6 实践优于理论", "date": "2021-06-07", "color": null}, {"text": "没有人是靠别人告诉他怎么做而赢得诺贝尔奖的", "chapter": "附言：有良知的违抗", "date": "2021-06-07", "color": null}, {"text": "我们的工作则是违抗。计算机安全得不到改善，如果没有计算机网络黑客；我们无法生存，如果没有肠道微生物——有益的微生物和有害的微生物，尽管大多数显然处于两者之间。49", "chapter": "5 违抗优于服从", "date": "2021-06-07", "color": null}, {"text": "内在奖励比外在奖励更能激励人们取得更好的表现。", "chapter": "2 拉力优于推力", "date": "2021-06-07", "color": null}, {"text": "比特币和区块链的重要性在于其架构，简单来说，该架构记录了每一笔发生在公共总账中的比特币交易。该构架基于一种认知，即网络会将所需的资源“拉”进组织，整合和维护，而无须中心进行协调，中心会把这些资源集中“推”给组织。", "chapter": "2 拉力优于推力", "date": "2021-06-07", "color": null}], "ideas": []}, {"id": "609080", "title": "世界上最神奇的24堂课", "author": "哈奈尔", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/80/609080/s_609080.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=1cb32a40594b381cbcdf850", "progress": 100, "finished": 1, "hlCount": 7, "ideaCount": 0, "highlights": [{"text": "思想就是能量，能量就是思想", "chapter": "第5章 你可以成为任何一类人", "date": "2021-05-20", "color": null}, {"text": "尽可能地放松你的每一块肌肉和每一根神经，直到你感到宁静从容，与自身和世界相和谐为止。太阳丛就要开始运作了，结果将会让你称奇不已，你会感觉自己的能力在一点一滴地增强。", "chapter": "第4章 无须向外界求助，自己才是最强大的", "date": "2021-05-20", "color": null}, {"text": "潜意识会对我们的显意识意愿作出响应，这意味着宇宙精神无限的创造性能量在人类个体的显意识的掌控之中。", "chapter": "第4章 无须向外界求助，自己才是最强大的", "date": "2021-05-20", "color": null}, {"text": "从显意识到潜意识的转变，其实就是从刻意到自觉再到习惯的改变。", "chapter": "第4章 无须向外界求助，自己才是最强大的", "date": "2021-05-20", "color": null}, {"text": "从心灵的层面上讲，潜意识是理想、抱负和想象的源泉，能够激发出我们的内在力量。可以说，潜意识是连接人类心灵与宇宙间无限智慧的一座桥梁。", "chapter": "第3章 习惯的策源地——潜意识", "date": "2021-05-20", "color": null}, {"text": "我最迫切想做的事就是教你识别机遇，加强你的推理能力；坚定你的意志，赋予你抉择的智慧，理性的同情，拥有主动进取、坚韧不拔的精神，并且教你如何尽情地享受高质量的生活。", "chapter": "第1章 作者序言", "date": "2021-05-20", "color": null}, {"text": "当我们全心全意只想自己的时候我们就会感到恐惧，如果我们能够把注意力转移到别人身上，恐惧就消失了。总而言之，恐惧是一种过分的自我关注。", "chapter": "第20章 知识战胜恐惧", "date": "2021-05-20", "color": null}], "ideas": []}, {"id": "27211035", "title": "窗边的小豆豆", "author": "黑柳彻子", "cover": "https://cdn.weread.qq.com/weread/cover/35/27211035/s_27211035.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=81232c10719f351b812f401", "progress": 100, "finished": 1, "hlCount": 7, "ideaCount": 0, "highlights": [{"text": "“不要把孩子们束缚在老师的计划中，要让他们到大自然中去。孩子们的梦想，要比老师的计划大得多。”", "chapter": "后记", "date": "2021-04-22", "color": null}, {"text": "大荣君连中学也没有读完，但他丝毫不觉得有什么难为情的，自己研究，自己开拓，从事着自己真正喜爱的工作，这一切令我非常感动。", "chapter": "后记", "date": "2021-04-22", "color": null}, {"text": "先生不仅仅看到眼前的事情，还考虑到几十年之后的事，并据此来培育我们。先生经常对我说“你真是一个好孩子”，同样，他也一直对高桥君说一句话：“你绝对能做到。”这句话无疑深深影响着高桥君的一生。", "chapter": "后记", "date": "2021-04-22", "color": null}, {"text": "“无论哪个孩子，当他出世的时候，都具有优良的品质。在他成长的过程中，会受到很多影响，有来自周围环境的影响，也有来自成年人的影响，这些优良的品质可能会受到损害。所以，我们要早早地发现这些优良的品质，并让它们发扬光大，把孩子们培养成富有个性的人。”", "chapter": "后记", "date": "2021-04-22", "color": null}, {"text": "每当校长先生看到小豆豆，就会说：“你真是一个好孩子。”这时候，小豆豆就高兴地笑，蹦蹦跳跳地说：“是啊，我是一个好孩子。”于是，小豆豆也觉得自己的确是一个好孩子。", "chapter": "“真是一个好孩子！”", "date": "2021-04-22", "color": null}, {"text": "世界上最可怕的事情，莫过于有眼睛却发现不了美，有耳朵却不会欣赏音乐，有心灵却无法理解什么是真。不会感动，也不会充满激情……", "chapter": "韵律操", "date": "2021-04-22", "color": null}, {"text": "校长先生对我做的事没有生气，很信任我，把我当作一位很有人格的人来尊重”", "chapter": "放回原处", "date": "2021-04-22", "color": null}], "ideas": []}, {"id": "914501", "title": "认知突围：做复杂时代的明白人", "author": "蔡垒磊", "cover": "https://cdn.weread.qq.com/weread/cover/82/YueWen_914501/s_YueWen_914501.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=e2432d405df445e24a4de6a", "progress": 100, "finished": 1, "hlCount": 6, "ideaCount": 1, "highlights": [{"text": "怎样才算没有虚度人生", "chapter": "人生的消费和投资", "date": "2024-12-19", "color": 1}, {"text": "自利是人的最终目的，本质就是满足需要——物质需要和精神需要——消费就是一个满足需要的过程，而投资则是一个延迟满足需要的过程。", "chapter": "人生的消费和投资", "date": "2024-12-19", "color": 1}, {"text": "丰富自己的时间经历", "chapter": "丰富自己的时间经历", "date": "2024-12-19", "color": 1}, {"text": "每个机会其实都是靠一个个碎片拼出来的，没有前面积累的碎片，你就难以拼出下一个图形，而没有下一个图形当中的一块碎片，你自然也无法拼出下下个。", "chapter": "没机会真的怪不了运气", "date": "2024-12-19", "color": 1}, {"text": "幸福只源于跟他人和自己的比较。如果你想获得幸福感，不需要自欺欺人，只要摆正自己对幸福的认知即可，自欺欺人本身就代表并没有从本质上将认知扭转过来。无论是调整比较对象，还是克服状态惰性，这都是大脑能完成的任务。所以幸福这件事，实在是取决于你自身，而不是你的客观状态。", "chapter": "幸福人人都能拥有", "date": "2021-11-16", "color": null}, {"text": "有些人的小一些。", "chapter": "格局，决定你的世界", "date": "2021-11-16", "color": null}], "ideas": [{"content": "管窥效应", "abstract": "有些人的小一些。", "chapter": "", "date": "2021-11-16", "star": null}]}, {"id": "827159", "title": "心智探奇：人类心智的起源与进化", "author": "[美]史蒂芬·平克 郝耀伟译", "cover": "https://cdn.weread.qq.com/weread/cover/8/YueWen_827159/s_YueWen_827159.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=c7c32fe05c9f17c7c7af081", "progress": 77, "finished": 0, "hlCount": 6, "ideaCount": 1, "highlights": [{"text": "对一个由自然选择而设计的有机体而言，留下后代是其存在的理由，也是所有辛劳和奋斗的目标", "chapter": "父母与孩子", "date": "2023-05-10", "color": 1}, {"text": "因为我们不会相信一个人，直到我们亲眼看到在哪种情形下他会冒汗为止。", "chapter": "末日机器", "date": "2023-05-09", "color": 1}, {"text": "这种混淆是由于将人的基因当作他们真实的自我，把基因的动机当作人最深刻、最真实的无意识动机造成的。这样就很容易得出愤世嫉俗且不正确的道德观，认为所有的爱都是虚伪的。这混淆了人的真实动机和基因的隐喻化动机", "chapter": "利他", "date": "2023-05-08", "color": 1}, {"text": "有数据显示，快乐的人并不是那些富有的、有特权的、强壮的或相貌好看的，而是那些有配偶、有朋友、有宗教信仰和有一份具有挑战性且有意义的工作的。", "chapter": "幸福跑步机", "date": "2023-05-07", "color": 1}, {"text": "心智是一个器官，一个生物小装置。我们具有心智是因为上新-更新世的非洲灵长类动物，它们复杂设计得到的结果收益大于成本。要理解我们自身，我们需要知道历史上这段场景的有关过程、原因、地点和时间。这些就是本章的内容。", "chapter": "03 自然选择理论", "date": "2023-05-07", "color": 1}, {"text": "心智进化的最终目的是为了复制最大数量的基因，而正是基因创造了心智。", "chapter": "第一部分　心智理论的前世今生", "date": "2023-05-07", "color": 1}], "ideas": [{"content": "这是人类之间的信任机制，是基于对方是一个普通的正常的人。以上是生物机制，未来会有新的算法机制", "abstract": "因为我们不会相信一个人，直到我们亲眼看到在哪种情形下他会冒汗为止。", "chapter": "末日机器", "date": "2023-05-09", "star": null}]}, {"id": "842421", "title": "后物欲时代的来临", "author": "郑也夫", "cover": "https://cdn.weread.qq.com/weread/cover/65/yuewen_842421/s_yuewen_8424211732529400.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=1bb320f05cdab51bb976fed", "progress": 100, "finished": 1, "hlCount": 6, "ideaCount": 1, "highlights": [{"text": "这意味着，如果我们展望未来，经济问题并不是“人类的永恒问题”。", "chapter": "三 生产的解决，工作的终结", "date": "2020-09-29", "color": null}, {"text": "人类遭遇了百万年未有之巨变，即温饱的全面解决，它将导致一系列的变化。收入与幸福感的脱节便是这一门槛的函数。", "chapter": "一 门槛前后的收入与幸福", "date": "2020-09-29", "color": null}, {"text": "你吃饱了，但是为了他的就业，社会劝告你再吃一些。这不荒诞吗？", "chapter": "五 对消费的辩护与批判", "date": "2020-09-29", "color": null}, {"text": "非物质化", "chapter": "五 对消费的辩护与批判", "date": "2020-09-29", "color": null}, {"text": "当温饱彻底解决，物质上的炫耀越来越失去魅力后，人类将进入艺术的时代。", "chapter": "五 对消费的辩护与批判", "date": "2020-09-29", "color": null}, {"text": "消费主义极有可能成为资本主义的掘墓人。", "chapter": "五 对消费的辩护与批判", "date": "2020-09-29", "color": null}], "ideas": [{"content": "当温饱彻底解决，物质上的炫耀越来越失去魅力后，人类将进入艺术的时代。人们将通过艺术，而不是物质，来寻求区分。", "abstract": "当温饱彻底解决，物质上的炫耀越来越失去魅力后，人类将进入艺术的时代。", "chapter": "", "date": "2020-09-29", "star": null}]}, {"id": "3300198717", "title": "金瓶梅（文白对照绣像图文版）", "author": "[明]兰陵笑笑生", "cover": "https://cdn.weread.qq.com/weread/cover/74/cpplatform_2aubq5zqsjqb6xzw2fnjct/s_cpplatform_2aubq5zqsjqb6xzw2fnjct1773820912.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=0a332270813abb41fg01773d", "progress": 100, "finished": 1, "hlCount": 6, "ideaCount": 0, "highlights": [{"text": "芥子纳须弥", "chapter": "第一百回 韩爱姐路遇二捣鬼 普静师幻度孝哥儿", "date": "2026-04-16", "color": 1}, {"text": "汝当各托生，再勿将冤结。[插图]楞严耶？法华耶？大悲耶？亦复如此观。读此书而以为淫者、秽者，无目者也。", "chapter": "第一百回 韩爱姐路遇二捣鬼 普静师幻度孝哥儿", "date": "2026-04-16", "color": 1}, {"text": "凭谁话尽兴亡事，一衲闲云两袖风。", "chapter": "第一百回 韩爱姐路遇二捣鬼 普静师幻度孝哥儿", "date": "2026-04-16", "color": 1}, {"text": "三寸气在千般用，一日无常万事休", "chapter": "第一回 西门庆热结十弟兄 武二郎冷遇亲哥嫂", "date": "2026-04-16", "color": 1}, {"text": "内中又有几个斗宠争强，迎奸卖俏的，起先好不妖娆妩媚，到后来也免不得屍横灯影，血染空房", "chapter": "第一回 西门庆热结十弟兄 武二郎冷遇亲哥嫂", "date": "2026-04-16", "color": 1}, {"text": "繇（yóu）着你铜山金谷的奢华，正好时却又要冰消雪散。", "chapter": "第一回 西门庆热结十弟兄 武二郎冷遇亲哥嫂", "date": "2026-04-16", "color": 1}], "ideas": []}, {"id": "25695472", "title": "致命冒险", "author": "闪米特", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/472/25695472/s_25695472.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=64532030718814f0645d813", "progress": 100, "finished": 1, "hlCount": 6, "ideaCount": 0, "highlights": [{"text": "其实，无论遇到多少次生命危险，我当时想的东西都是一样的，就是如何活下去。因为生死之外，再无大事。", "chapter": "野狐峡求生（下）", "date": "2025-07-21", "color": 1}, {"text": "只有以这样激烈的方式，我才能获知生命的真相。", "chapter": "生死博弈（下）", "date": "2025-07-21", "color": 1}, {"text": "。在激流的间隙里，我还在想着如何改良闪氏火锅的配方。", "chapter": "生死博弈（下）", "date": "2025-07-21", "color": 1}, {"text": "朗，我不想等下去了，等待会消磨我的勇气。", "chapter": "生死博弈（上）", "date": "2025-07-21", "color": 1}, {"text": "我义无反顾地选择了他，不正是因为他敢于面对一切的勇气、永远不可压垮的坚韧、浑身散发的自信味道吗？如果他变了，不再是以前的那个他，那我能够像以前那样爱他吗？", "chapter": "爱他就陪他一起疯", "date": "2025-07-21", "color": 1}, {"text": "只要有一口干净的水喝，有清洁的空气呼吸，能在美丽的大自然中自由行走，对于我来说，就已经是完美的人生了。", "chapter": "自序——一个人的致命冒险", "date": "2025-07-21", "color": 1}], "ideas": []}, {"id": "39128586", "title": "你是你吃出来的（套装共2册）", "author": "夏萌", "cover": "https://cdn.weread.qq.com/weread/cover/34/yuewen_39128586/s_yuewen_391285861678700081.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=ebd322f072550e0aebd4ff9", "progress": 58, "finished": 0, "hlCount": 6, "ideaCount": 0, "highlights": [{"text": "包裹在脂类外面的一层蛋白质我们称为载脂蛋白，载脂蛋白+磷脂+胆固醇+甘油三酯叫作脂蛋白，比如，高密度脂蛋白(HDL)、低密度脂蛋白(LDL)都是这样的复合体。低密度脂蛋白从肝脏出发，驶向周围组织；而高密度脂蛋白从周围组织驶向肝脏。", "chapter": "血脂、体脂和食物脂肪，一一分清楚", "date": "2023-11-05", "color": 1}, {"text": "《中国居民膳食指南(2016)》指出，每个健康的中国人应该保证每天摄入200～350克新鲜水果，而且强调果汁不能代替鲜果。", "chapter": "水果：吃得实在太少了", "date": "2023-11-05", "color": 1}, {"text": "运动后可以吃鸡蛋+牛奶+蔬菜+坚果+水果，也可以把牛奶换成牛肉或者三文鱼。", "chapter": "选对食物是一门技术活儿", "date": "2023-11-05", "color": 1}, {"text": "缺乏维生素B族最常见的症状是上火，表现为眼结膜充血，烦躁，口腔溃疡。熬夜加班之后也容易出现类似症状", "chapter": "维生素平衡：极容易缺乏，很难过量", "date": "2023-11-04", "color": 1}, {"text": "磷脂的功能很重要，它可以维持新陈代谢，保证荷尔蒙的均衡分泌，促进智力发育，防止痴呆和血栓形成", "chapter": "脂类平衡：每日摄入量不能低于总能量的30%", "date": "2023-11-04", "color": 1}, {"text": "脂类包括脂肪和类脂，脂肪是甘油三酯，又称中性脂肪；类脂包括磷脂、胆固醇和糖脂。", "chapter": "脂类平衡：每日摄入量不能低于总能量的30%", "date": "2023-11-04", "color": 1}], "ideas": []}, {"id": "38259822", "title": "金融的逻辑（套装全两册）", "author": "陈志武", "cover": "https://cdn.weread.qq.com/weread/cover/7/YueWen_38259822/s_YueWen_38259822.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=8c132c807247cc6e8c1fcf9", "progress": 99, "finished": 0, "hlCount": 6, "ideaCount": 0, "highlights": [{"text": "前面谈到，现在基于主权货币的国际体系有其内在风险，需要改革，但这需要时间。我们不要去主动快速推翻美元体系，因为在出现世界政府、超主权货币之前，推翻美元体系对中国经济会是破坏性的，中国经济还继续需要美元的稳定。", "chapter": "第19章 金融“阴谋论”可以休矣", "date": "2022-07-14", "color": null}, {"text": "战争所依赖的是强盗逻辑、暴力逻辑、炮舰逻辑，而金融市场靠的是真本事，靠的是自由选择的逻辑。", "chapter": "第19章 金融“阴谋论”可以休矣", "date": "2022-07-14", "color": null}, {"text": "货币化，让“东西”成为商品，能在市场上自由买卖，货币化的过程就是增加劳动者、生产者自由的过程。", "chapter": "第2章 货币化与自由", "date": "2022-07-14", "color": null}, {"text": "人的本性是追求自我利益的最大化，包括物质、权力、地位、名誉，以及各类机会等。但问题是，资源是有限的。", "chapter": "第2章 货币化与自由", "date": "2022-07-13", "color": null}, {"text": "工业化、城市化、公司化不断把生产从“家”的功能中剥离出来，改由市场里的公司来承担。", "chapter": "第1章 市场通往自由，金融解放个人", "date": "2022-07-13", "color": null}, {"text": "实际上，中国的经济增长现在也要从投资驱动型的模式向消费驱动型的模式转型。", "chapter": "第15章 美国消费驱动型模式不会改变", "date": "2022-07-13", "color": null}], "ideas": []}, {"id": "38937440", "title": "有本事", "author": "冯唐", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/440/38937440/s_38937440.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=7923237072522360792b5fd", "progress": 100, "finished": 0, "hlCount": 6, "ideaCount": 0, "highlights": [{"text": "恒河沙就是数据，无尽的数据就是大千世界，对无尽数据的有效分析就是道。以后类似我们苹果公司这类伟大的公司就是佛一样的存在。”", "chapter": "应云何住，云何降伏其心", "date": "2022-06-05", "color": null}, {"text": "因为人只有疯到认为自己可以改变世界才是最终改变世界的人", "chapter": "应云何住，云何降伏其心", "date": "2022-06-05", "color": null}, {"text": "所谓一个人的成功不也是一样的吗？所谓秘诀无非就是，知道自己是块什么材料，爱做什么事儿，能做什么事儿，然后不急不慢地做一辈子。", "chapter": "不急不慢地做一辈子", "date": "2022-06-05", "color": null}, {"text": "第十三，同理心。己所不欲，勿施于人。己欲达而达人。老吾老以及人之老，幼吾幼以及人之幼。第十四，专注。一时一事，心无旁骛。第十五，努力。尽心尽力，尽职尽责。坚持，再坚持，第三次坚持之后还不行，放弃。第十六，倾听。如果有选择，多倾听，而不是多唠叨。第十七，干净。而不是脏。第十八，惜物。节制，节制，节制，哪怕你有资源可以浪费。第十九，助人为乐。乐于分享，乐于帮忙，能为了别人放下自己。第二十，抗糟蹋，抗噪声，抗失败，抗挫折。第二十一，感知力。静听松涛如海，静观星光如灯。第二十二，爱。能爱，能投入，能忘记自己，哪怕是暂时的，哪怕自己会受伤。", "chapter": "最希望孩子们具备的二十二个能力和特质", "date": "2022-06-05", "color": null}, {"text": "第二，慢速长跑能让你独处，效果类似参加静修。跑了一阵之后，就不想说话了，天高地迥，就想放下心里的一切，一步一步活着到终点。", "chapter": "人生苦短，马拉松很长", "date": "2022-06-05", "color": null}, {"text": "人的幸福是由两件事儿构成的，第一是做自己擅长而且喜欢的事儿，第二是和自己喜欢而且喜欢自己的人在一起。", "chapter": "得志则996，不得志则悠然南山", "date": "2022-06-05", "color": null}], "ideas": []}, {"id": "573962", "title": "增长的极限", "author": "德内拉·梅多斯 乔根·兰德斯 丹尼斯·梅多斯", "cover": "https://cdn.weread.qq.com/weread/cover/52/YueWen_573962/s_YueWen_573962.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=f1b32cf058c20af1b2b41b1", "progress": 100, "finished": 1, "hlCount": 6, "ideaCount": 0, "highlights": [{"text": "从系统的观点来说，可持续社会是一个具备足够的信息机制、社会机制和制度机制来抑制导致指数型人口增长和资本增长的正反馈循环的社会。", "chapter": "■可持续社会", "date": "2022-03-15", "color": null}, {"text": "一旦人口与经济超越了地球的物理极限，那么只有两条路可以返回去：通过日益升级的短缺与危机而导致的非自愿崩溃，或者通过精心的社会选择而带来的生态足迹有控制的缩减。", "chapter": "■总结", "date": "2022-03-15", "color": null}, {"text": "地球上大多数居民的持续贫困和少数居民的过度消费是环境恶化的两个主要原因。", "chapter": "■靠资本而不是收入来生活", "date": "2022-03-15", "color": null}, {"text": "由于1吨谷物相当于1000吨水，进口谷物就成了最有效的进口水的方式……", "chapter": "■可再生资源", "date": "2022-03-15", "color": null}, {"text": "人越多越穷，越穷人越多", "chapter": "■人越多越穷，越穷人越多", "date": "2022-03-15", "color": null}, {"text": "在人类社会中，人口和生产资本是指数型增长的发动机。", "chapter": "■呈指数型增长的事物", "date": "2022-03-15", "color": null}], "ideas": []}, {"id": "33577958", "title": "价值", "author": "张磊", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/958/33577958/s_33577958.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=5be32a3072005be65bef195", "progress": 100, "finished": 1, "hlCount": 6, "ideaCount": 0, "highlights": [{"text": "价值投资不必依靠天才，只需依靠正确的思维模式，并控制自己的情绪。", "chapter": "第5章 价值投资者的自我修养", "date": "2021-12-12", "color": null}, {"text": "前面说过我的“三把火”理论，就是说人生中只有火烧不掉的东西才重要，即一个人的知识、能力和价值观，而支撑这三个方面的，是一个人理性的好奇、诚实与独立，这三点构成对价值投资者的基本要求。", "chapter": "第5章 价值投资者的自我修养", "date": "2021-05-26", "color": null}, {"text": "通过海量的跨学科阅读，掌握各个学科最重要的智慧，构建属于自己的思维体系。", "chapter": "第1章 价值的底色", "date": "2021-04-23", "color": null}, {"text": "无法烧掉的东西才重要，总结起来有三样，那就是一个人的知识、能力和价值观，这也是深藏于内心并真正属于自己的“三把火”。", "chapter": "第1章 价值的底色", "date": "2021-04-23", "color": null}, {"text": "真正的投资，有且只有一条标准，那就是是否在创造真正的价值，这个价值是否有益于社会的整体繁荣。", "chapter": "自序 这是一条长期主义之路", "date": "2021-04-23", "color": null}, {"text": "世界上只有一条护城河，就是企业家们不断创新，不断地疯狂地创造长期价值。", "chapter": "第4章 价值投资方法与哲学", "date": "2021-04-23", "color": null}], "ideas": []}, {"id": "635942", "title": "反脆弱：从不确定性中获益", "author": "纳西姆·尼古拉斯·塔勒布", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/942/635942/s_635942.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=0633241059b4260632af2bf", "progress": 100, "finished": 1, "hlCount": 6, "ideaCount": 0, "highlights": [{"text": "能生存下来的事物必然是满足了一些（通常是隐性的）目的，时间能够看到这些目的，但我们的眼睛和逻辑思维能力却无法捕捉它们。", "chapter": "第20章 时间与脆弱性", "date": "2021-05-20", "color": null}, {"text": "我们之所以需要将重点放在行动上，避开言词，还有另一个因素要考虑：依赖于外部的认可有损健康。人们在给予认可时是残忍和不公平的，所以最好跳出这种游戏。在别人的态度面前保持强韧性。", "chapter": "第9章 胖子托尼与脆弱推手", "date": "2021-05-20", "color": null}, {"text": "正如斯多葛主义是关乎情绪的驯化而非消除，杠铃策略也力求驯化而非消除不确定性。", "chapter": "第11章 千万别嫁给摇滚明星", "date": "2021-05-20", "color": null}, {"text": "事实上，乔治·西姆农，这位20世纪最多产的作家之一，一年只有60天的时间用来写作，其余300天则“什么都不做”。但是，他出版的小说超过200本。", "chapter": "第11章 千万别嫁给摇滚明星", "date": "2021-05-20", "color": null}, {"text": "如果我不得不上班的话，我认为最可取的（痛苦也较少的）就是高强度地工作一段非常短的时间，然后什么都不做（假设什么都不做，就是真正意义上的什么都不做），直到我完全恢复，并期待重来一次，而不是像日本人那样从事那种低强度、无休止、缺乏睡眠保证的、乏味的工作。主菜和甜点还是需要分开的。", "chapter": "第11章 千万别嫁给摇滚明星", "date": "2021-05-20", "color": null}, {"text": "如果潜在收益大于潜在损失，那么你对波动源就具有反脆弱性", "chapter": "第10章 塞内加的不利因素和有利因素", "date": "2021-05-20", "color": null}], "ideas": []}, {"id": "726463", "title": "时间管理：如何充分利用你的24小时（漫画版） (简单有趣的个人管理丛书)", "author": "吉姆兰德尔", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/463/726463/s_726463.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=6f0321005b15bf6f06284be", "progress": 100, "finished": 1, "hlCount": 6, "ideaCount": 0, "highlights": [{"text": "高效能人士的七个习惯", "chapter": "第二部分 让你所拥有的时间发挥最大效用", "date": "2021-05-02", "color": null}, {"text": "制作任务清单实际上可以是很有趣的。姑且把它当成创作一部微型小说，其中主要人物就是你自己。", "chapter": "第二部分 让你所拥有的时间发挥最大效用", "date": "2021-05-02", "color": null}, {"text": "你的内心越平静，你的工作效率就越高。", "chapter": "第二部分 让你所拥有的时间发挥最大效用", "date": "2021-05-02", "color": null}, {"text": "你每天至少应该花10分钟时间，来规划你这一天该如何度过。", "chapter": "第二部分 让你所拥有的时间发挥最大效用", "date": "2021-05-02", "color": null}, {"text": "很多作家往往使用10个字来表达5个字就能说明白的事情。要学会只读那5个字。", "chapter": "第二部分 让你所拥有的时间发挥最大效用", "date": "2021-05-02", "color": null}, {"text": "有效的时间管理不仅仅是寻找一天中的额外时间，还要将你的有效时间和你的有效精力匹配起来。", "chapter": "第二部分 让你所拥有的时间发挥最大效用", "date": "2021-05-02", "color": null}], "ideas": []}, {"id": "750479", "title": "指数型组织：打造独角兽公司的11个最强属性", "author": "萨利姆·伊斯梅尔 迈克尔·马隆 尤里·范吉斯特", "cover": "https://cdn.weread.qq.com/weread/cover/80/yuewen_750479/s_yuewen_7504791693972514.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=bf7321c05b738fbf790ea69", "progress": 0, "finished": 0, "hlCount": 6, "ideaCount": 0, "highlights": [{"text": "彼得·戴曼迪斯和史蒂芬·科特勒在《富足》中指出，随着技术的发展，我们将走进一个富足的世界，在那里，使用权将胜过所有权。相比之下，供应或资源的稀缺往往会让成本居高不下，并更多地刺激拥有而非使用。", "chapter": "06 指数型组织形成的9大驱动因素", "date": "2020-05-10", "color": null}, {"text": "数字化（Digitized）、欺骗性（Deceptive）、颠覆性（Disruptive）、去物质化（Dematerialize）、去货币化（Demonetize）和大众化（Democratize）的概念，我称其为6D框架。", "chapter": "前言 制胜未来的指数型组织", "date": "2020-05-10", "color": null}, {"text": "我们在无人机、DNA测序、3D打印、传感器、机器人和比特币等领域看到了这样的变革。", "chapter": "06 指数型组织形成的9大驱动因素", "date": "2020-05-10", "color": null}, {"text": "当今的商业、政府或者非营利企业，以其目前的配置来看，全都无法跟上这6D所构筑的高速发展节奏。", "chapter": "前言 制胜未来的指数型组织", "date": "2020-05-10", "color": null}, {"text": "去货币化", "chapter": "06 指数型组织形成的9大驱动因素", "date": "2020-05-10", "color": null}, {"text": "互联网在过去10年里最重要、却最不为人所知的一大成就就是，它将市场营销和销售的边际成本降到了近乎为零的地步。", "chapter": "06 指数型组织形成的9大驱动因素", "date": "2020-05-10", "color": null}], "ideas": []}, {"id": "918310", "title": "颠覆者：周鸿祎自传", "author": "周鸿祎 范海涛", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/310/918310/s_918310.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=41532d205e0326415bf4719", "progress": 100, "finished": 1, "hlCount": 5, "ideaCount": 1, "highlights": [{"text": "通过研究腾讯过往的经历，我想找出QQ软件的软肋，做一款让用户爱不释手的软", "chapter": "“360扣扣保镖”和“出逃香港”", "date": "2025-02-18", "color": 1}, {"text": "我早就说过，做互联网的人，一定会遇到三个无法回避的问题：生、死、腾讯。腾讯就像一个天花板，你怎么长都要碰上它。它发现你长个儿了，就会自动往下沉，压缩你的生存空间，再把你压回小个子。", "chapter": "春节中的偷袭——腾讯来了怎么办？", "date": "2025-02-18", "color": 1}, {"text": "我对免费的认识很朴素，只要是人人都需要的，就应该是免费的。", "chapter": "360杀毒为什么走向免费", "date": "2025-02-18", "color": 1}, {"text": "人生最后的高度可能都是一样的，就是一张病床的高度", "chapter": "逆转——360慢慢渗透进安全市场，大获成功", "date": "2025-02-18", "color": 1}, {"text": "我经常讲欲望是永远无止境的，你不能控制自己的欲望就会永远痛苦。", "chapter": "雅虎总结——在不同的欲望之间取舍", "date": "2025-02-18", "color": 1}], "ideas": [{"content": "回顾历史展望未来，纳米ai搜索又会有什么故事呢？", "abstract": "", "chapter": "", "date": "2025-02-18", "star": 100}]}, {"id": "3300010746", "title": "大话中国艺术史", "author": "意公子", "cover": "https://cdn.weread.qq.com/weread/cover/46/3300010746/s_3300010746.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=1d5323a0813ab6ab2g0169eb", "progress": 66, "finished": 0, "hlCount": 5, "ideaCount": 1, "highlights": [{"text": "隶书在篆书之上做了一次“减法”，化圆为方，化弧为直，宽扁的字体，横画长而直画短，讲究的是“蚕头燕尾”“一波三折”。", "chapter": "第三章 秦汉艺术 让世界记住我！——青春期的第一次成熟", "date": "2022-08-10", "color": null}, {"text": "既然生命是平等的，那蝼蚁也应该与天地一样伟大。", "chapter": "4.1 竹林七贤 第一支文人大V天团，出道！", "date": "2022-03-30", "color": null}, {"text": "我们看见了在公元366年的一个黄昏，一个叫乐尊的僧人来到敦煌，凿下了第一座洞窟。", "chapter": "第四章 魏晋南北朝 兵家不幸诗家幸——青春期的第一次失落", "date": "2022-03-30", "color": null}, {"text": "从公元189年东汉名存实亡，经历过英雄辈出的三国年代，到西晋短暂50年、如昙花一现的统一，再到五胡入华、十六国混战、南北朝对峙，一直到589年隋朝实现大一统，中国一共分裂了400年。", "chapter": "第四章 魏晋南北朝 兵家不幸诗家幸——青春期的第一次失落", "date": "2022-03-30", "color": null}, {"text": "王小波说：“一个人只拥有此生此世是不够的，他还应该拥有诗意的世界。”", "chapter": "中国艺术史 最熟悉的陌生人", "date": "2022-03-30", "color": null}], "ideas": [{"content": "手机也是", "abstract": "用一句话总结，青铜器既是吃饭、听歌的家伙，还是打架的家伙。", "chapter": "", "date": "2022-03-30", "star": null}]}, {"id": "33628204", "title": "认知觉醒：开启自我改变的原动力", "author": "周岭", "cover": "https://cdn.weread.qq.com/weread/cover/86/YueWen_33628204/s_YueWen_33628204.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=6a732ce07201202c6a7b30a", "progress": 100, "finished": 1, "hlCount": 5, "ideaCount": 1, "highlights": [{"text": "飞行员的注意力会被巨大的危险所俘获，心智带宽降低", "chapter": "第七章 情绪力——情绪是多角度看问题的智慧", "date": "2021-10-21", "color": null}, {"text": "身体感受永远是进入当下状态的最好媒介，而感受事物消失的过程更是一种很好的专注力训练。它提示我们，身心合一的要领不仅是专注于当下，更是享受当下，而这种享受必将使我们更从容，不慌张。", "chapter": "第四章 专注力——情绪和智慧的交叉地带", "date": "2021-08-27", "color": null}, {"text": "们必须用觉知力和自控力去约束天性", "chapter": "第四章 专注力——情绪和智慧的交叉地带", "date": "2021-08-27", "color": null}, {"text": "小事听从你的脑，大事听从你的心。", "chapter": "第二章 潜意识——生命留给我们的彩蛋", "date": "2021-08-27", "color": null}, {"text": "做总比不做强！", "chapter": "第一章 大脑——一切问题的起源", "date": "2021-08-26", "color": null}], "ideas": [{"content": "管窥效应", "abstract": "飞行员的注意力会被巨大的危险所俘获，心智带宽降低", "chapter": "", "date": "2021-10-21", "star": null}]}, {"id": "25568730", "title": "未来学校：重新定义教育", "author": "朱永新", "cover": "https://cdn.weread.qq.com/weread/cover/48/YueWen_25568730/s_YueWen_25568730.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=0f632cf0718625da0f6a5c5", "progress": 82, "finished": 0, "hlCount": 5, "ideaCount": 1, "highlights": [{"text": "与此同时，家庭开始自觉地、心甘情愿地把本来属于它的教育权全部拱手相让给学校。家庭的教育“领地”就这样一点点“失守”。人们甚至认为，教育就是学校的事情。", "chapter": "家庭会成为未来学习中心吗？", "date": "2020-08-21", "color": null}, {"text": "从世界各地的探索来看，游戏完全可以成为未来学习的一支生力军。尽管人们对网游或者数字游戏有着不同的看法，但是，对于游戏蕴含的追求自由与创造、勇于挑战与闯关、遵守规则与约定、享受愉悦与幸福等特有的功能是没有异议的，这就是游戏精神的本质。", "chapter": "未来的学习方式有什么不同？", "date": "2020-08-20", "color": null}, {"text": "究竟什么知识最有价值？这曾经是教育家关注的头等重要的问题。1859年，英国学者斯宾塞提出了一个著名命题：“什么知识最有价值？", "chapter": "学习内容，跟我们今天的课程体系一样吗？", "date": "2020-08-20", "color": null}, {"text": "教学不是冷冰冰地把知识从一个脑袋装进另一个脑袋里，而是师生之间无时不在的情感交流。", "chapter": "未来教师会不会失业？", "date": "2020-08-20", "color": null}, {"text": "学习共同体", "chapter": "互联网时代的教育变革", "date": "2020-08-20", "color": null}], "ideas": [{"content": "所以是有温度的，在学校里面学到的都只是一种技能，但是一种心理习惯或者性格是需要与人的互动中才能成型的，好的老师肯定是一个心理学家。", "abstract": "教学不是冷冰冰地把知识从一个脑袋装进另一个脑袋里，而是师生之间无时不在的情感交流。", "chapter": "", "date": "2020-08-20", "star": null}]}, {"id": "189509", "title": "科技想要什么", "author": "凯文·凯利", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/509/189509/s_189509.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=f4f3209052e445f4fbd794f", "progress": 100, "finished": 1, "hlCount": 4, "ideaCount": 2, "highlights": [{"text": "到距今1万年前时，地球上超过80％的大型哺乳动物完全消失。", "chapter": "第一部分 起源", "date": "2021-02-03", "color": null}, {"text": "未来某天我们将造出其他大脑，它们会让我们震撼，它们会思考我们绝不可能想象的事物。", "chapter": "第十四章 无限博弈", "date": "2020-09-24", "color": null}, {"text": "卡尔·萨根（Carl Sagan）对此作了令人印象深刻的阐释：“我们是思考星空的星尘。”", "chapter": "第十四章 无限博弈", "date": "2020-09-24", "color": null}, {"text": "上帝，请赐我宁静，去接受我不能改变的一切；赐我勇气，去改变我所能改变的一切；并赐我智慧去认清这两者之间的分别。", "chapter": "第四部分 方向", "date": "2020-09-24", "color": null}], "ideas": [{"content": "我们是思考天空的星尘", "abstract": "", "chapter": "", "date": "2020-09-24", "star": null}, {"content": "用生物演化学的角度来考虑科技的发展路径。从用碳基智能到硅基文明，科技的发展越来越快，科技有自己的发展方向，人类只是他的子宫，通过人类这个子宫，将来会孕育出怎样的科技生命体呢？", "abstract": "", "chapter": "", "date": "2020-09-24", "star": 100}]}, {"id": "MP_WXS_2393320173", "title": "财经天下周刊", "author": "公众号", "cover": "http://wx.qlogo.cn/mmhead/Q3auHgzwzM7Mg3IHVXLDvCwicLzib3TGcKY60DaZ4HsTyn10LAZicaicqw/0", "link": "https://weread.qq.com/book-detail?type=1&v=4f54297224d505f5758535f32333933333230313733b93", "progress": 0, "finished": 1, "hlCount": 0, "ideaCount": 6, "highlights": [], "ideas": [{"content": "是啊，太科幻了", "abstract": "你说一个手机里面包含了多少东西？电话、录音机、电唱机、摄像机、游戏机。在1980年代，这些东西要拿个小车推的，现在浓缩到这么点东西里面，这就是科幻。", "chapter": "", "date": "2018-10-01", "star": null}, {"content": "可遇不可求", "abstract": "创意越来越难了。", "chapter": "", "date": "2018-10-01", "star": null}, {"content": "创意最有价值", "abstract": "的小说是以创意为核心的，", "chapter": "", "date": "2018-10-01", "star": null}, {"content": "强👍", "abstract": "他认为中国科幻最大的缺憾就是没有创造自己的想象世界，而满足于在别人已经创造的世界中演绎自己的故事，“世界都是熟悉的，只剩下故事了”", "chapter": "", "date": "2018-10-01", "star": null}, {"content": "每一步都算数", "abstract": "有心的读者或许不难从那个模拟软件中读出“黑暗森林”的雏形。", "chapter": "", "date": "2018-10-01", "star": null}, {"content": "1990年，可能吗？", "abstract": "1990年代，为了打发时间，他常常编些自觉有趣的软件，其中一个是模拟宇宙点状文明体系总体状态的。在他看来，极度遥远的距离，使宇宙间的各个文明（如果存在的话）点状化了，“就像在体育场的最后一排看足球，球员本身的复杂技术动作已经被距离隐去，球场上出现的只是由23个点（他将球也算了进去）构成的不断变化的矩阵”。", "chapter": "", "date": "2018-10-01", "star": null}]}, {"id": "3300192100", "title": "这世界既残酷也温柔", "author": "孙宇晨", "cover": "https://cdn.weread.qq.com/weread/cover/79/cpplatform_2wvsxia1hxypvbsqmbwbt4/s_cpplatform_2wvsxia1hxypvbsqmbwbt41768382257.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=c7f32200813abb18ag0101be", "progress": 100, "finished": 1, "hlCount": 5, "ideaCount": 0, "highlights": [{"text": "在互联网时代，在高度竞争的市场经济社会中，学历和家庭背景都不是成功的必要因素。只有敏锐的商业嗅觉才是真正实现财富自由的核心价值", "chapter": "危机与机会并存的互联网时代", "date": "2026-04-12", "color": 1}, {"text": "读书只是一种个人选择，不意味着赚钱更多、社会地位更高。在市场经济浪潮逐渐汹涌的今天，已经不存在只要寒窗苦读就能改变命运的事情了。读书不应该被赋予改变命运、获得金钱的期待，读书仅仅是一种个人选择。", "chapter": "不独立，没人替你坚强", "date": "2026-04-12", "color": 1}, {"text": "贫贱不能移，孟子讲的意思是气度要大。就算睡出租屋，也不堕青云志。贫困不是对自己的伤害，妄自菲薄才是。", "chapter": "心里有火光，就愿意向上", "date": "2026-04-12", "color": 1}, {"text": "但老虎日后注定成为老虎，注定是百兽之王，这就是企业格局对于企业的核心影响。", "chapter": "心里有火光，就愿意向上", "date": "2026-04-12", "color": 1}, {"text": "学校的考试分数其实考察的是死记硬背的能力、短暂理解的能力以及自控力。社会不一样，社会还会考察一个人的想象力、情商、交际能力、工作态度等等，方方面面的能力和特质都会纳入考量。", "chapter": "“三观”碎了怎么办", "date": "2026-04-12", "color": 1}], "ideas": []}, {"id": "3300142877", "title": "我看见的世界：李飞飞自传", "author": "[美]李飞飞", "cover": "https://cdn.weread.qq.com/weread/cover/28/cpplatform_kg3xhzvscqeh1fgafdx7m1/s_cpplatform_kg3xhzvscqeh1fgafdx7m11745725507.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=76c32a50813ab9e4fg01737b", "progress": 95, "finished": 0, "hlCount": 5, "ideaCount": 0, "highlights": [{"text": "风险投资的术语让我在自己的领域里感觉像个局", "chapter": "11 无人可控", "date": "2026-03-31", "color": null}, {"text": "AlexNet展示了大规模数据集、高速图形处理器和深度分层神经网络三者近乎神奇的组合。", "chapter": "09 万物以外是什么", "date": "2026-03-31", "color": null}, {"text": "历史刚被创造出来，而世界上只有少数人知道。", "chapter": "08 实验验证", "date": "2026-03-31", "color": null}, {"text": "之间却存在着偏差。尽管神经网络的潜力显而易见", "chapter": "04 心智探索", "date": "2026-03-31", "color": null}, {"text": "但他从不像别人那样把我一语否定。他对我采取了激", "chapter": "03 鸿沟渐窄", "date": "2026-03-31", "color": null}], "ideas": []}, {"id": "920702", "title": "机器崛起前传：自我意识与人类智慧的开端", "author": "蔡恒进 蔡天琪 张文蔚 汪恺", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/702/920702/s_920702.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=d9a32dd05e0c7ed9a7fa180", "progress": 98, "finished": 0, "hlCount": 5, "ideaCount": 0, "highlights": [{"text": "人类思维三大定律是：元直觉定律、跃迁性定律和自我肯定性定律。", "chapter": "跋", "date": "2025-07-24", "color": 1}, {"text": "自我意识可以说是一种幻觉。对人类而言，“自我”一开始的确就是各种感觉的综合。因为这种剖分是所有逻辑的起点，所以正是在人有了原意识、能够剖分出“自我”与“外界”时候，人类认识世界才成了可能", "chapter": "第十三章 自我意识与高级智能", "date": "2025-07-22", "color": 1}, {"text": "在人类进化过程中，我们还没有发现比“进化论”更合理的解释。", "chapter": "第十三章 自我意识与高级智能", "date": "2025-07-22", "color": 1}, {"text": "这就是牟宗三先生讲的系统相的限制之处。", "chapter": "Preface 人类与机器人的共存共荣（推荐序三）", "date": "2025-07-22", "color": 1}, {"text": "物者，心之物也。心者，物之心也", "chapter": "Preface 默契道妙 开物天工（推荐序二）", "date": "2025-07-22", "color": 1}], "ideas": []}, {"id": "856170", "title": "富兰克林自传（经典译林）", "author": "本杰明·富兰克林", "cover": "https://cdn.weread.qq.com/weread/cover/85/YueWen_856170/s_YueWen_856170.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=d1c32df05d106ad1cef92c8", "progress": 64, "finished": 0, "hlCount": 5, "ideaCount": 0, "highlights": [{"text": "谁若一次施恩与你，必将二次施恩与你，其乐意之情为受恩于你者所不及也。这也表明冤仇宜解不宜结，冤冤相报弊无穷。", "chapter": "〔第三部〕", "date": "2024-12-11", "color": 1}, {"text": "人的幸福，因撞到千载难逢的大运而得者为数寥寥，由日积月累的小惠而生者比比皆是。", "chapter": "译者导言", "date": "2024-12-09", "color": 1}, {"text": "这门亲事像谈一笔生意，富兰克林要求女方陪嫁一百英镑替他还债，对方拿不出钱来就拉倒了。", "chapter": "译者导言", "date": "2024-12-09", "color": 1}, {"text": "我将它作为又一个例证，说明维持一个人的生命和健康需要的收入微乎其微。”", "chapter": "译者导言", "date": "2024-12-09", "color": 1}, {"text": "英国哲学家洛克1690年发表的《政府论》否定了“君权神授”的观念，提出了有名的“社会契约”论。", "chapter": "译者导言", "date": "2024-12-08", "color": 1}], "ideas": []}, {"id": "23437994", "title": "把时间当作朋友（第3版）", "author": "李笑来", "cover": "https://cdn.weread.qq.com/weread/cover/93/YueWen_23437994/s_YueWen_23437994.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=38c327807165a2aa38c3323", "progress": 98, "finished": 0, "hlCount": 5, "ideaCount": 0, "highlights": [{"text": "当好运气发生在自己身上时，我们应该非常开心；而当坏运气降", "chapter": "5 运气", "date": "2023-06-08", "color": null}, {"text": "“运用心智获得解放”。", "chapter": "1 孰主孰仆", "date": "2023-06-07", "color": 1}, {"text": "换一种方法来表述，那就是：经过长期思考，弗兰克终于意识到自己其实可以控制自己的大脑，而不是", "chapter": "1 孰主孰仆", "date": "2023-06-07", "color": 1}, {"text": "用自己的精神战胜了自己的精神病”的人。换言之，纳什通过挣扎学会了控制自己的大脑，不再被自己大脑中的幻觉所控制。", "chapter": "1 孰主孰仆", "date": "2023-06-07", "color": 1}, {"text": "用下图来描述“无意识地受大脑控制”与“有意识地控制大脑”之间的区别。", "chapter": "1 孰主孰仆", "date": "2023-06-07", "color": 1}], "ideas": []}, {"id": "34615967", "title": "红楼梦（人民文学版）", "author": "曹雪芹著 无名氏续 程伟元 高鹗整理", "cover": "https://cdn.weread.qq.com/weread/cover/45/YueWen_34615967/s_YueWen_34615967.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=0da329707210329f0da4d39", "progress": 7, "finished": 0, "hlCount": 5, "ideaCount": 0, "highlights": [{"text": "凡心偶炽", "chapter": "第一回 甄士隐梦幻识通灵 贾雨村风尘怀闺秀", "date": "2023-01-28", "color": null}, {"text": "今之人，贫者日为衣食所累，富者又怀不足之心，纵一时稍闲，又有贪淫恋色、好货寻愁之事，那里去有工夫看那理治之书？所以我这一段故事，也不愿世人称奇道妙，也不定要世人喜悦检读，只愿他们当那醉淫饱卧[25]之时，或避事[26]去愁之际，把此一玩，岂不省了些寿命筋力？", "chapter": "第一回 甄士隐梦幻识通灵 贾雨村风尘怀闺秀", "date": "2023-01-21", "color": null}, {"text": "无材可去补苍天，枉入红尘若许年。　此系身前身后事，倩谁[17]记去作奇传？", "chapter": "第一回 甄士隐梦幻识通灵 贾雨村风尘怀闺秀", "date": "2023-01-21", "color": null}, {"text": "便袖了这石，同那道人飘然而去，竟不知投奔何方何舍", "chapter": "第一回 甄士隐梦幻识通灵 贾雨村风尘怀闺秀", "date": "2023-01-21", "color": null}, {"text": "那红尘中有却有些乐事，但不能永远依恃；况又有‘美中不足，好事多魔’八个字紧相连属，瞬息间则又乐极悲生，人非物换，究竟是到头一梦，万境归空，倒不如不去的好。", "chapter": "第一回 甄士隐梦幻识通灵 贾雨村风尘怀闺秀", "date": "2023-01-21", "color": null}], "ideas": []}, {"id": "32492018", "title": "跟着诗词去旅行", "author": "郝娟菡", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/18/32492018/s_32492018.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=1bb3212071efc9f21bb1e3b", "progress": 99, "finished": 1, "hlCount": 5, "ideaCount": 0, "highlights": [{"text": "苏州有林园计二百余处，最盛名的有四处：拙政园、留园、狮子林、沧浪亭。", "chapter": "Suzhou苏州 画桥烟波动绮罗", "date": "2022-08-15", "color": null}, {"text": "掬一捧阳光，闲坐小窗，展卷书香，淡淡的情怀，淡淡的向往。", "chapter": "专题笔走春秋：一首诗，一个世界", "date": "2022-08-15", "color": null}, {"text": "生而千年不死，死而千年不倒，倒而千年不朽", "chapter": "Talimu huyanglin塔里木胡杨林 岁月的样子，撼人心魄", "date": "2022-08-15", "color": null}, {"text": "美食有百味，人生亦有百味。", "chapter": "专题文中饕影：就一盘诗菜，尽酌百味", "date": "2022-08-15", "color": null}, {"text": "青青翠色入壶中，山盘水碟放未空。人生难得佳趣两，半入行囊半味中。", "chapter": "专题文中饕影：就一盘诗菜，尽酌百味", "date": "2022-08-15", "color": null}], "ideas": []}, {"id": "30985916", "title": "学好数学并不难：代数+几何（套装共2册）", "author": "孙亮朝", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/916/30985916/s_30985916.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=5c13272071d8cebc5c1b4f4", "progress": 13, "finished": 0, "hlCount": 5, "ideaCount": 0, "highlights": [{"text": "在一个稳定成熟的市场上，商人之间比拼的不仅是谁手中的现金多，更是谁的信用更好，信用多的人就能够赊欠更多的货款，生意就能做得更大．", "chapter": "赚钱的数字：负数的存在", "date": "2022-07-31", "color": null}, {"text": "前面通过轨道方程求解发射距离用到的知识属于代数；反过来，现在这种通过几组数据来求得轨道方程的方法就叫作解析几何．", "chapter": "想要打仗，需要你懂几何、代数和解析几何", "date": "2022-07-31", "color": null}, {"text": "人类从不相同的事物发现共同点的这种能力叫作抽象能力．抽象能力是我们认知世界的基础，如果没有这种抽象能力，人类不但不会发现数学，也不会发展出语言、音乐、文字、绘画等一切人类文明．", "chapter": "人类的抽象能力：1＋1到底等于几", "date": "2022-07-31", "color": null}, {"text": "而在这些方面，人和人之间基本没有差别，所以从这个角度来看，在数学方面考100分的同学比考50分的同学也就只是聪明了一点点而已．", "chapter": "数学考100分的同学比考50分的同学聪明多少倍", "date": "2022-07-31", "color": null}, {"text": "既然人活着就只能承受这样的苦难，就让我用数学的快乐，在人生的苦酒里加一点糖吧．", "chapter": "一 一旦你了解数学，你一定会爱上它", "date": "2022-07-31", "color": null}], "ideas": []}, {"id": "23769306", "title": "罗素思想小品", "author": "[英]罗素", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/306/23769306/s_23769306.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=a2332ff0716ab0daa232ae2", "progress": 29, "finished": 0, "hlCount": 5, "ideaCount": 0, "highlights": [{"text": "无所事事是不可能令人感到幸福的，可是如果要做的事过于繁重或令人反感，也毫无快乐可言。要做的事若有明显、中意的目标，又不与本能冲突，它便令人愉快。", "chapter": "通向幸福之路", "date": "2022-06-05", "color": null}, {"text": "但最大部分，还须归功于一天天的少关心自己。像旁的受过清教徒教育的人一样，我惯对自己的罪过、愚忘和失败作种种的冥想。我觉得自己是——当然是准确地——一个可怜的标本。慢慢地，我学会了对自己和自己的缺陷不再耿耿于怀；而对外界的事物，却一天天地集中我的注意：譬如世界现状，知识的各部门，以及我抱有好感的个人等。", "chapter": "谈什么使人不快乐", "date": "2022-06-05", "color": null}, {"text": "康德在18世纪写的名文《一个世界公民观点之下的普遍历史观念》，曾给罗素以深刻影响，世界公民便成为他魂牵梦萦的理想，而这又与他的人文主义取向相一致。正因为此，他急切地呼吁要建立一个世界政府。可", "chapter": "序言", "date": "2022-06-05", "color": null}, {"text": "卢梭的文化符号是忏悔孤独，叔本华的文化符号是生存虚幻，尼采的文化符号是上帝死了，培根的文化符号是知识格言，汤因比的文化符号是宏大叙事，梭罗的文化符号是恬静落寞，杜威的文化符号是实用主义……", "chapter": "序言", "date": "2022-06-05", "color": null}, {"text": "人要遭到反对就用权威压人，即使反对者是你自己家人；而应努力以理服人，因为靠权威取得的胜利是虚幻的。不要随声附和，而比之更觉得愉悦的是理智地表示不同意见，因为如果你珍视理应如此的智慧，后者比前者意味着更大程度的赞同。", "chapter": "文前", "date": "2022-06-05", "color": null}], "ideas": []}, {"id": "837379", "title": "菩提树下的微笑：《金刚经》解密", "author": "蔡志忠", "cover": "https://cdn.weread.qq.com/weread/cover/13/YueWen_837379/s_YueWen_837379.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=b32328205cc703b3221e727", "progress": 95, "finished": 0, "hlCount": 5, "ideaCount": 0, "highlights": [{"text": "没有困境，便没有顿悟。没有烦恼，便没有觉悟。没有觉悟便不能灭除烦恼！迷时佛度众生，悟时众生自度成佛。", "chapter": "5 学佛的目的是什么？", "date": "2022-03-21", "color": null}, {"text": "佛在灵山莫远求，灵山就在汝心头。", "chapter": "5 学佛的目的是什么？", "date": "2022-03-21", "color": null}, {"text": "学佛修行的目的是为了在生时能活出天堂，而非死后能去西方净土。", "chapter": "5 学佛的目的是什么？", "date": "2022-03-21", "color": null}, {"text": "六祖慧能回答说：“道由心悟，岂在坐卧？”", "chapter": "3 禅是什么？", "date": "2022-03-21", "color": null}, {"text": "（八风就是红尘世间的：利、衰、毁、誉、称、讥、苦、乐。）", "chapter": "3 禅是什么？", "date": "2022-03-21", "color": null}], "ideas": []}, {"id": "737451", "title": "拿破仑传", "author": "[德]路德维希", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/451/737451/s_737451.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=841321905b40ab841daf8b6", "progress": 38, "finished": 0, "hlCount": 5, "ideaCount": 0, "highlights": [{"text": "世界上只有两种力量：智慧和剑。而从长远看，剑总是被智慧所战胜。", "chapter": "江", "date": "2022-03-09", "color": null}, {"text": "巴黎就像一座军营，没有前线，没有战役，各武装政党你方唱罢我登场，旧秩序与新理想争辩不休，激进思想的光芒照亮天空，希望落空的迷惘与称霸天下的野心令人无所适从，这一切仿佛一场由自由、平等与欺骗交杂而成的闹宴——在这一切之上，从云端向下观望的是卢梭与伏尔泰的灵魂，卢梭目光中流露出厌恶，伏尔泰嘴角带着冷笑，而恰恰是他们的着作引发了这一切。", "chapter": "江", "date": "2022-03-09", "color": null}, {"text": "很久以后，他又回忆说：“直到洛迪那个晚上，我才觉得自己是个不同一般的人，产生了干一番大事业的雄心。而在此之前，这些大事业在我脑海里只是一些虚无缥缈的幻想。”", "chapter": "溪", "date": "2022-03-08", "color": null}, {"text": "“展望未来，我只看到光明。即使没有光明，人也得生活在现实里。勇敢者蔑视未来。”", "chapter": "岛", "date": "2022-03-08", "color": null}, {"text": "这个贫穷的中尉却坐在陋室里，凭着坚定的直觉研读并且只研读那些将来对他有用的东西：炮兵的原理和历史，攻坚战的法则，柏拉图的理想国，波斯、雅典和斯巴达人的宪法，英国历史，腓特烈大帝的征战，法国的财政，鞑靼人和土耳其人的国家与风俗，埃及和迦太基的历史，印度概况，英国人关于当代法国的报告，米拉波、布丰和马基雅维利，瑞士的历史与宪法，中国、印度和印加帝国的历史与宪法，贵族的历史，贵族的罪行，天文、地理和气象学，繁殖规律，死亡率统计。", "chapter": "岛", "date": "2022-03-08", "color": null}], "ideas": []}, {"id": "861023", "title": "任正非传", "author": "孙力科", "cover": "https://cdn.weread.qq.com/weread/cover/38/YueWen_861023/s_YueWen_861023.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=b3c32e505d235fb3caefcfe", "progress": 100, "finished": 0, "hlCount": 5, "ideaCount": 0, "highlights": [{"text": "《黄石公三略》中说：“纯刚纯强，其国必亡。”经营企业同治理国家一样，需要讲求“刚柔并济”。", "chapter": "6 从“狼性”到“人性”", "date": "2021-11-30", "color": null}, {"text": "任何一个民族，任何一个组织，只要没有新陈代谢，生命就会停止。如果我们顾全每位功臣的历史，那么就会葬送公司的前途。如果没有市场部集体大辞职带来的对华为公司文化的影响，任何先进的管理、先进的体系在华为都无法生根。”", "chapter": "3 “炒干部”", "date": "2021-11-30", "color": null}, {"text": "在高度发达的信息社会中，知识资产使得金融资产苍白无力。按劳分配要看你劳动中的知识含量，按资分配正在转向按知识分配。", "chapter": "第八章 “华为精神”", "date": "2021-11-30", "color": null}, {"text": "“私有协议”，即是“在国际标准组织实现网络互联互通而制定标准和规范之前，某家公司产品先进入市场而形成的标准”。", "chapter": "5 华为的“统一战线”", "date": "2021-11-29", "color": null}, {"text": "我们是在竞争中学会了竞争的规则、学会了如何赢得竞争。”", "chapter": "3 改变自我，改变历史", "date": "2021-11-29", "color": null}], "ideas": []}, {"id": "32640270", "title": "永生之后", "author": "梁建章", "cover": "https://cdn.weread.qq.com/weread/cover/76/YueWen_32640270/s_YueWen_32640270.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=7533246071f20d0e7531dae", "progress": 100, "finished": 1, "hlCount": 5, "ideaCount": 0, "highlights": [{"text": "诗明回答道：“不是啊。我是要为家里生很多子女。”杰德先是一愣，随后笑着感叹道：“好样的！”", "chapter": "尾声", "date": "2021-06-12", "color": null}, {"text": "比如多子女家庭可以享受教育和医疗费用全免的政策，还可以获得各项税收优惠，包括购房减免土地税。", "chapter": "奔向未来", "date": "2021-06-12", "color": null}, {"text": "在经过几天几夜的思考之后，丈夫贝拉说出了心中的忧虑，他担心这是外星球专门针对地球的一个阴谋。至于阴谋的核心内容，就是用所谓的“延生药”，改变人类的生育观念，最终达到限制地球发展的目的。", "chapter": "破局", "date": "2021-06-12", "color": null}, {"text": "如果说永生意味着基因在某一个载体内持续存活，那么生育就是让基因不断在各种新载体之间得到传承。", "chapter": "寻找父亲", "date": "2021-06-12", "color": null}, {"text": "真正的幸福，应当是让整个人类通过繁衍来不断探索和传播文明。”", "chapter": "生死之辩", "date": "2021-06-12", "color": null}], "ideas": []}, {"id": "815728", "title": "硅谷钢铁侠：埃隆·马斯克的冒险人生", "author": "阿什利·万斯", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/728/815728/s_815728.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=bc8328d05c7270bc82b6cb2", "progress": 100, "finished": 1, "hlCount": 5, "ideaCount": 0, "highlights": [{"text": "但我更加确信，马斯克是有情有义之人，他以一种史诗般的方式呈现喜怒哀乐，他感受最深刻的是自己改变人类命运的使命，因而难以意识到他人的强烈情绪，以致他富有人情味的一面被掩盖，令他显得冷酷无情，没有顾及个体的想法和需求。而很可能正是这种人，才能将太空网络的奇思妙想变成现实。", "chapter": "后记", "date": "2021-05-17", "color": null}, {"text": "当马斯克在2014年宣布特斯拉将公开其所有专利时，分析师们试图确定他是不是在作秀或者其中是否隐藏了不明动机或者圈套。但马斯克的决定就是这么坦率，他希望人们制造并购买电动汽车。马斯克认为，人类的未来取决于此。如果公开特斯拉的专利意味着其他公司能够更容易地制造出电动汽车，那么这对人类来说是有利的，这些理念应该是免费的。愤世嫉俗的人一定会嘲笑他的观点，但马斯克已经计划好这么做，他在解释自己的想法时是真诚的，而且极为真诚。", "chapter": "第十一章 埃隆·马斯克的统一场理论：下一个10年", "date": "2021-05-17", "color": null}, {"text": "公司打算售出成千上万辆Model 3，让电动汽车成为真正的主流产品。", "chapter": "第十一章 埃隆·马斯克的统一场理论：下一个10年", "date": "2021-05-17", "color": null}, {"text": "马斯克对一个风险投资人说过类似的话，他说，“我具有武士精神。我宁愿切腹，也不要失败。”", "chapter": "第四章 第一次创业：征服网络世界", "date": "2021-05-17", "color": null}, {"text": "马斯克关于人类需要拯救的信念不断加强。但是他从一开始就不单单只考虑南非的迫切需求，而是将全人类看作一个整体。在一些陈词滥调的熏陶下，他将美国看作充满机遇和梦想成真的土地。这就是为什么一个孤僻而笨拙的南非男孩儿，怀着最大的诚意去追寻人类的“集体启蒙”，最后却成为美国最具冒险精神的实业家。", "chapter": "第二章 出生地非洲：冒险无极限的基因", "date": "2021-05-17", "color": null}], "ideas": []}, {"id": "22719593", "title": "你有多自律，就有多自由", "author": "卡西", "cover": "https://cdn.weread.qq.com/weread/cover/84/yuewen_22719593/s_yuewen_227195931688619300.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=219322b0715aac69219b459", "progress": 100, "finished": 1, "hlCount": 5, "ideaCount": 0, "highlights": [{"text": "温和，是一个女人应有的修养，也是一个家庭最需要的营养。", "chapter": "一个女人的温和，在婚姻里到底有多重要", "date": "2021-04-21", "color": null}, {"text": "人一旦有了牵绊，就容易死于安乐，躲在舒适区里，享受安逸的假象。总结起来一句话：世界那么大，你快去看看，攒钱是为了梦想，不是买房。", "chapter": "我攒了三十万，要不要买房子", "date": "2021-04-21", "color": null}, {"text": "三毛说：“心之何如，有似万丈迷津，遥亘千里，其中并无舟子可以度人，除了自度，他人爱莫能助。”", "chapter": "你的状态，取决于你的心态", "date": "2021-04-21", "color": null}, {"text": "没有发生的事情，不值得你忧虑和恐惧，如果它终究要来，你为何要提前失去快乐？", "chapter": "与世界和解，是人生的必修课", "date": "2021-04-21", "color": null}, {"text": "到2040年，人必须将学习贯穿终生，不断升级，才能不出局。因此，我们必须培养孩子持续学习的能力，那我们应该教给孩子们什么？我的建议是，应该专注韧性和情商的培育。”", "chapter": "你在原来的领域风生水起，换个战场，还行吗", "date": "2021-04-21", "color": null}], "ideas": []}, {"id": "934465", "title": "思维简史：从丛林到宇宙", "author": "伦纳德·蒙洛迪诺", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/465/934465/s_934465.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=8c8327205e42418c80c6a20", "progress": 100, "finished": 1, "hlCount": 5, "ideaCount": 0, "highlights": [{"text": "我们的大脑只占身体重量的2%，却要消耗身体摄入能量的20%。", "chapter": "2.好奇心", "date": "2021-02-10", "color": null}, {"text": "人类之所以高贵，是因为我们有求知的动力。", "chapter": "1.我们求知的动力", "date": "2021-02-10", "color": null}, {"text": "那时我就意识到求知欲乃是人类所有欲望中最重要的，尽管我们身处的环境不同，但驱使我认识世界的热情和父亲是一样的。", "chapter": "1.我们求知的动力", "date": "2021-02-10", "color": null}, {"text": "补写", "chapter": "6.新的推理方式", "date": "2021-02-10", "color": null}, {"text": "惯性定律", "chapter": "6.新的推理方式", "date": "2021-02-10", "color": null}], "ideas": []}, {"id": "674048", "title": "邓小平时代", "author": "傅高义", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/48/674048/s_674048.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=00f325d05a490000f72bda9", "progress": 100, "finished": 1, "hlCount": 5, "ideaCount": 0, "highlights": [{"text": "世行报告建议中国要更加注重利用价格，从价格入手促进更有效的投资决策，推进更灵活的对外贸易。它还建议让国内人口更加自由地流动，使劳动力的使用变得更有效率。但是它也主张价格变动和其他改革都不宜操之过急。这个团队不主张全面迅速的市场自由化或私有化。对于中方人员来说，参与这项研究，使他们有机会了解具有全球发展经验的经济学专业人士的视野，并学习用新的眼光重新审视自身的体制。", "chapter": "第16章 加快经济发展和开放步伐，1982—1989", "date": "2021-01-25", "color": null}, {"text": "邓小平建议党的干部学习三种知识：经济学、科学技术和管理。", "chapter": "第7章 三个转折点，1978", "date": "2021-01-25", "color": null}, {"text": "如果不能比资本主义国家发展得更快，就无法证明我们的制度的优越性。”", "chapter": "第7章 三个转折点，1978", "date": "2021-01-25", "color": null}, {"text": "世界上正在进行一场科技革命，出现了一些全新的领域，高分子、核能、电子计算机、半导体、航天和激光等等。", "chapter": "第6章 复出，1977—1978", "date": "2021-01-25", "color": null}, {"text": "反修防修", "chapter": "第3章 整顿，1974—1975", "date": "2021-01-24", "color": null}], "ideas": []}, {"id": "861002", "title": "人生的智慧", "author": "叔本华", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/2/861002/s_861002.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=4ec322505d234a4ecf640ab", "progress": 94, "finished": 1, "hlCount": 5, "ideaCount": 0, "highlights": [{"text": "笛卡尔的一生", "chapter": "人是什么", "date": "2021-01-22", "color": null}, {"text": "对生活稍有了解就能明白：痛苦和无聊是人类幸福最大的敌人，我对这一点进行以下补充：当我们感到快乐的时候，也就是远离第一个敌人的时候，离第二个敌人也就近了，反过来也是一样。因此，我们的生活实际上就在这两种状态之间时强时弱地左右摇摆。", "chapter": "人是什么", "date": "2021-01-21", "color": null}, {"text": "健康永远都要排在第一位。", "chapter": "人是什么", "date": "2021-01-21", "color": null}, {"text": "对过去的悔恨和对将来的担忧，让我们将现在的美好时光拒之门外，或者糟蹋了它，这是非常愚蠢的", "chapter": "建议和格言", "date": "2021-01-10", "color": null}, {"text": "如果一个人想要让自己的观点获得别人的信任，就应该冷静地、语气平和地表达出自己的观点。因为一切激烈的情绪都是从意欲中产生的，所以如果情绪激烈地表达自己的观点，这一观点就会被人们看作意欲的产物，而非认识的结果，因为认识拥有冷静的本质。", "chapter": "建议和格言", "date": "2021-01-10", "color": null}], "ideas": []}, {"id": "651366", "title": "乡土中国", "author": "费孝通", "cover": "https://cdn.weread.qq.com/weread/cover/89/yuewen_651366/s_yuewen_6513661742315957.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=22e32b3059f06622e6e5c85", "progress": 100, "finished": 1, "hlCount": 5, "ideaCount": 0, "highlights": [{"text": "我初学社会学时，并没有从理论入手去钻研社会究竟是什么的根本问题。我早年自己提出的学习要求是了解中国人是怎样生活的，了解的目的是在改善中国人的生活。", "chapter": "附录", "date": "2020-07-23", "color": null}, {"text": "这在差序社会里可以不觉得是矛盾；因为在这种社会中，一切普遍的标准并不发生作用，一定要问清了，对象是谁，和自己是什么关系之后，才能决定拿出什么标准来。", "chapter": "维系着私人的道德", "date": "2020-07-23", "color": null}, {"text": "为什么我们这个最基本的社会单位的名词会这样不清不楚呢？在我看来却表示了我们的社会结构本身和西洋的格局是不相同的，我们的格局不是一捆一捆扎清楚的柴，而是好像把一块石头丢在水面上所发生的一圈圈推出去的波纹。每个人都是他社会影响所推出去的圈子的中心。被圈子的波纹所推及的就发生联系。每个人在某一时间某一地点所动用的圈子是不一定相同的。", "chapter": "差序格局", "date": "2020-07-23", "color": null}, {"text": "我们儒家最考究的是人伦，伦是什么呢？我的解释就是从自己推出去的和自己发生社会关系的那一群人里所发生的一轮轮波纹的差序", "chapter": "差序格局", "date": "2020-07-23", "color": null}, {"text": "自我主义并不限于拔一毛而利天下不为的杨朱，连儒家都该包括在内。", "chapter": "差序格局", "date": "2020-07-23", "color": null}], "ideas": []}, {"id": "29348688", "title": "历史的终结与最后的人", "author": "弗朗西斯·福山", "cover": "https://cdn.weread.qq.com/weread/cover/86/YueWen_29348688/s_YueWen_29348688.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=c7d3253071bfd350c7d3739", "progress": 18, "finished": 0, "hlCount": 5, "ideaCount": 0, "highlights": [{"text": "如果人们只有欲望和理性，那他们就会满足于市场导向的威权国家，比如佛朗哥的西班牙，以及军人统治下的韩国或巴西。可是，他们对于自身的自我价值有一种充满激情的自豪，正是这种充满激情的自豪促使他们向往民主，因为民主政府待他们如成人而非孩童，并且承认他们作为自由个体的自主权。在我们时代，共产主义之所以为自由民主所取代，原因就在于共产主义所提供的承认形式有重大缺陷。", "chapter": "代序", "date": "2020-05-11", "color": null}, {"text": "对黑格尔来说，这个终结就是自由国家，而在马克思那里，则是共产主义社会。", "chapter": "代序", "date": "2020-05-11", "color": null}, {"text": "左派厌恶“自由”所驱动的不平等，而右派厌恶“民主”所要求的平等权利。如果一个制度只有“自由”，它可能迟早内爆于人们对“平等”的渴望；如果一个制度只有“民主”，那么它也可能很快由于“多数暴政”而活力衰竭。", "chapter": "导读 历史漫长的终结", "date": "2020-05-11", "color": null}, {"text": "之所以不构成根本矛盾，是因为自由民主制作为一个具有内部纠错功能的机制，能够在制度内部解决这些“问题”，无需诉诸制度更替本身。比如，二十世纪福利制度的兴起，即是自", "chapter": "导读 历史漫长的终结", "date": "2020-05-11", "color": null}, {"text": "自由民主制是否真的能带来平等的、相互的和有意义的“承认”？", "chapter": "导读 历史漫长的终结", "date": "2020-05-11", "color": null}], "ideas": []}, {"id": "277540", "title": "中信国学大典·六祖坛经", "author": "净因法师导读及译注", "cover": "https://cdn.weread.qq.com/weread/cover/47/YueWen_277540/s_YueWen_277540.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=81832a90543c24818557178", "progress": 84, "finished": 0, "hlCount": 5, "ideaCount": 0, "highlights": [{"text": "六祖惠能说：的确如玄策所说，只要你的心如虚空，不执着空见，应用自在无碍，或动或静都不分别思量；忘却凡圣的差别，泯灭能、所的对待；如此性相一如，自然无时不在定中。", "chapter": "机缘品第七", "date": "2019-10-23", "color": null}, {"text": "一如，五蕴和合，其性本空，六尘也不", "chapter": "机缘品第七", "date": "2019-10-23", "color": null}, {"text": "世间的人不是向外迷惑执着诸相，就是心内迷惑执着于空，如果能够于相远离相执，于空远离空执，这就是内外都不执迷。", "chapter": "机缘品第七", "date": "2019-10-22", "color": null}, {"text": "三无思想（无念、无相、无住）是惠能禅修思想的精髓。就内心修炼而言，“无念”不是断一切念，而是不对已过去和未到来的事起执着妄念，以便专注于当下这一念；就对客观事物的认识而言，“无相”不是否定万物存在的虚无主义，而是“于相而离相”，觉悟万物空无自性的本质；就修行用功的方法而言，“无住”心念明明白白地认识一切法，但不执一法，念念无住，随缘而住，正念不断，直觉悟般若空性，圆证佛果。", "chapter": "定慧品第四", "date": "2019-10-22", "color": null}, {"text": "惠能针对这一执着指出往生净土的要诀，“迷人念佛求生于彼，悟人自净其心”。修学净土应从自心入手，逐步去除心中的烦恼。烦恼减一分，清净增一分，智慧长一分。等到心中十万八千种烦恼尽除，清净的心显现，如实观照宇宙、人生真相，随缘而行，当下就是净土。", "chapter": "《六祖坛经》导读", "date": "2019-10-22", "color": null}], "ideas": []}, {"id": "25615383", "title": "涛动周期论：经济周期决定人生财富命运", "author": "周金涛等编著", "cover": "https://cdn.weread.qq.com/weread/cover/71/YueWen_25615383/s_YueWen_25615383.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=9c8326707186dc179c84e6a", "progress": 100, "finished": 1, "hlCount": 4, "ideaCount": 1, "highlights": [{"text": "当萧条来临后，资产只能做到相对保值，而不是绝对保值，所以，此时的最佳配置就是现金加黄金。它们可能是跌得最少的，同时你可以有充足的流动性在低位购买资产。", "chapter": "18 周金涛采访实录合集", "date": "2023-03-08", "color": 1}, {"text": "2012年房地产周期的B浪反弹大概率在2019年之前就要结束，即在2017—2019年大概率进入C浪下跌。本轮房价的大底可能在2020年之后出现，亦即在2020至2025年之间见底。", "chapter": "13 康波中的房地产周期研究", "date": "2023-03-08", "color": 1}, {"text": "启动于1995年（康波繁荣期）的本轮房地产周期可能要到2020—2025年才会触及大底，历时25—30年。这个低点与商品产能周期的低点（2030年）是接近的。", "chapter": "13 康波中的房地产周期研究", "date": "2023-03-08", "color": 1}, {"text": "其中，1892—1995年，房地产周期的平均时长约为26年。1920—1995年，房地产周期的平均时长为25年左右。这意味着一个房地产周期的平均时长约为25年，即一个康波周期可能存在着两个房地产周期。其中，房地产周期的上行期平均长度为8.5年左右，下行期平均长度为17年左右，表明上行期要明显短于下行期", "chapter": "13 康波中的房地产周期研究", "date": "2023-03-08", "color": 1}], "ideas": [{"content": "等2025年再看看房价", "abstract": "启动于1995年（康波繁荣期）的本轮房地产周期可能要到2020—2025年才会触及大底，历时25—30年。这个低点与商品产能周期的低点（2030年）是接近的。", "chapter": "13 康波中的房地产周期研究", "date": "2023-03-08", "star": null}]}, {"id": "848549", "title": "大转型：开放社会秩序的生成逻辑", "author": "何显明 吴兴智", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/549/848549/s_848549.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=28332ef05cf2a528309ce82", "progress": 3, "finished": 0, "hlCount": 3, "ideaCount": 2, "highlights": [{"text": "终极价值信仰的崩溃，导致虚无主义、享受主义成为个体唯一可能的价值信念，从而极大地加剧了社会失范的深刻性与普遍性。", "chapter": "第一章 大转型：社会管理创新的时代背景", "date": "2020-08-22", "color": null}, {"text": "尼采的宣言：“上帝死了，你们天天进的教堂是上帝的坟墓！”", "chapter": "第一章 大转型：社会管理创新的时代背景", "date": "2020-08-22", "color": null}, {"text": "社会分工决定了人们要满足自己的需求只能通过交换实现，于是商品交换具有了普遍性、全面性，人的社会联系由此不再直接表现为生产者个人之间的相互关系，而是表现为物与物之间的关系，作为交换媒介的货币因此成为“万能之物”，成为“最高的善”。人", "chapter": "第一章 大转型：社会管理创新的时代背景", "date": "2020-08-22", "color": null}], "ideas": [{"content": "现代社会已用人文主义取代", "abstract": "终极价值信仰的崩溃，导致虚无主义、享受主义成为个体唯一可能的价值信念，从而极大地加剧了社会失范的深刻性与普遍性。", "chapter": "", "date": "2020-08-22", "star": null}, {"content": "商品社会什么时候消失？", "abstract": "社会分工决定了人们要满足自己的需求只能通过交换实现，于是商品交换具有了普遍性、全面性，人的社会联系由此不再直接表现为生产者个人之间的相互关系，而是表现为物与物之间的关系，作为交换媒介的货币因此成为“万能之物”，成为“最高的善”。", "chapter": "", "date": "2020-08-22", "star": null}]}, {"id": "927152", "title": "财商养成第一课 (原名: 最富足的投资)", "author": "[美]吉姆·罗杰斯", "cover": "https://cdn.weread.qq.com/weread/cover/24/yuewen_927152/s_yuewen_9271521710313653.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=6b132e105e25b06b1e3b3f0", "progress": 100, "finished": 1, "hlCount": 3, "ideaCount": 2, "highlights": [{"text": "骑摩托车的投资者", "chapter": "假如看到未来的报纸，人人都能成为百万富翁", "date": "2019-02-04", "color": null}, {"text": "我行我素，勇敢自信，独出心裁。亦趋亦步之人永远也不会成为杰出的成功者。", "chapter": "我行我素，勇敢自信，独出心裁", "date": "2019-02-03", "color": null}, {"text": "关键是，你自己要先想明白什么对你最重要，什么是你所希望的，然后再向其他人征询意见。", "chapter": "依靠你们自己的才能智慧", "date": "2019-02-03", "color": null}], "ideas": [{"content": "懂各国历史的人才能说出的话", "abstract": "然而，21世纪属于中国。中国目前正在发展，就在我们的眼前。中国曾多次呈现辉煌时期。埃及曾经辉煌过一次，罗马曾经辉煌过一次，大英帝国曾经辉煌过一次。中国在历史上数次辉煌，又数次平安渡过巨大灾难。今天，中国再度崛起。", "chapter": "", "date": "2019-02-04", "star": null}, {"content": "精神自由后，才更有可能财务自由", "abstract": "在更早些时候，如果我能够负担得起，我一定会免费工作。追寻自己的激情与热情的人们根本不是“去上班”。", "chapter": "", "date": "2019-02-03", "star": null}]}, {"id": "921826", "title": "心流：最优体验心理学", "author": "米哈里·契克森米哈赖", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/826/921826/s_921826.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=65e328b05e10e265eb76e03", "progress": 50, "finished": 0, "hlCount": 2, "ideaCount": 3, "highlights": [{"text": "但当一切都变得自动自发，自我就消失不见了。", "chapter": "第三章 心流的构成要素", "date": "2020-09-27", "color": null}, {"text": "好像我的记忆输入完全关闭，我只记得30秒钟以前的事，往后想，我也只能考虑到未来的5分钟。", "chapter": "第三章 心流的构成要素", "date": "2020-09-27", "color": null}], "ideas": [{"content": "忘我的同时，也忘记了个人的利益得失，忘记了的烦恼忧患，获得了最优的心理体验，这是一种禅的境界。但实际上最好的方法还是佛教里面所讲的，发菩提心，做一个有远大格局的人，格局大的人，个利益得失就会看淡很多。儒家文化的核心是差序格局，佛提倡众生平等，心学所讲的是将人的心跟宇宙的格局融合为一体，我心就是宇宙，当你与万物融为一体的时候，就会获得一种更高层次的忘我体验。", "abstract": "但当一切都变得自动自发，自我就消失不见了。", "chapter": "", "date": "2020-09-27", "star": null}, {"content": "现实是复杂的，需要考虑的因素更多，归根结底，人的一切烦恼根源是人际关系，个人独处很容易控制一切，但当参与集体活动的时候，你就必须考虑人跟人之间的关系，在几百万年的狩猎采集生活中，人类，已经是群体性动物，现代的分工与合作，依然摆脱不了人与人之间的问题。", "abstract": "诸如此类以下棋为题材的故事并不算异想天开，很多棋界天才，包括美国第一任棋王保罗·墨菲和最近一任棋王费舍在内，都因太习惯条理分明的棋局世界，毅然弃绝了现实世界的纷扰混乱。", "chapter": "", "date": "2020-09-27", "star": null}, {"content": "攀岩是活在当下的运动，而从中可以引伸出，不仅仅是攀岩，一切活动只要高度控制，只关注当下，那么也可以获得较好的体验。", "abstract": "好像我的记忆输入完全关闭，我只记得30秒钟以前的事，往后想，我也只能考虑到未来的5分钟。", "chapter": "", "date": "2020-09-27", "star": null}]}, {"id": "830765", "title": "区块链：定义未来金融与经济新格局", "author": "火币网 张健", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/765/830765/s_830765.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=bb5322005cad2dbb59d0bf8", "progress": 11, "finished": 0, "hlCount": 1, "ideaCount": 4, "highlights": [{"text": "香农为人类引入了一个新的单词——比特（bit）。牛顿量化了力，建立起经典物理学的大厦；香农量化了信息，打下了人类进入信息时代的基础。如今比特作为衡量信息多少的单位，已经与米、千克、分钟一样，成为人类生活中最基本的量纲之一。", "chapter": "信息的演化", "date": "2018-10-06", "color": null}], "ideas": [{"content": "所以有的神话是：神派出一头羊传递旨意。得多慢啊！", "abstract": "你无法想象在原始部落使用移动支付，也同样无法想象在现代社会使用贝壳消费。", "chapter": "", "date": "2018-10-06", "star": null}, {"content": "什么叫比特币？", "abstract": "比特币是一个可以点对点进行支付、不依赖任何第三方的电子现金系统。", "chapter": "", "date": "2018-10-06", "star": null}, {"content": "香农", "abstract": "香农为人类引入了一个新的单词——比特（bit）。牛顿量化了力，建立起经典物理学的大厦；香农量化了信息，打下了人类进入信息时代的基础。如今比特作为衡量信息多少的单位，已经与米、千克、分钟一样，成为人类生活中最基本的量纲之一。", "chapter": "", "date": "2018-10-06", "star": null}, {"content": "文字与货币是人类最大的共识。共识程度越高是不是生产力更高", "abstract": "文字作为一种人际交流的手段，承载的是信息；而货币作为一种价值传输的载体，承载的是信用。自这两者诞生以来，人类信息传播和价值交换的手段也一直没有停止迭代和进化", "chapter": "", "date": "2018-10-04", "star": null}]}, {"id": "3300195418", "title": "太平年（已更新第三册|同名电视剧原著）", "author": "老克", "cover": "https://cdn.weread.qq.com/weread/cover/63/cpplatform_kyklogckarjwrvruceepoz/s_cpplatform_kyklogckarjwrvruceepoz1770898202.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=da832bf0813abb2d5g018848", "progress": 98, "finished": 0, "hlCount": 4, "ideaCount": 0, "highlights": [{"text": "指着皇后怀中的七皇子重睿，喘息着道：七……七郎……拜……拜……令公……皇后李", "chapter": "第五章 北望惊澜", "date": "2026-02-18", "color": null}, {"text": "林学士范质一路走来，脚步匆匆。赵匡胤瞪大了眼", "chapter": "第五章 北望惊澜", "date": "2026-02-18", "color": null}, {"text": "窗看了一眼刑室之内的光景。程昭悦微微点了点头：言念君子，温其如玉！何承训叹息了一声：身上的肉打烂了，将养好要七八日；再打烂再将养；也有个五六番了，只是不肯开口说话，", "chapter": "第四章 血色投名", "date": "2026-02-18", "color": null}, {"text": "盏吃茶。亲卫第二都指挥使闫通急匆匆走了进来", "chapter": "第三章 新王困局", "date": "2026-02-18", "color": null}], "ideas": []}, {"id": "3300042461", "title": "财富之眼：用经济思维看清世界", "author": "汤山老王", "cover": "https://cdn.weread.qq.com/weread/cover/6/cpPlatform_t6MVd2NveB2FM9XwEa5YnT/s_cpPlatform_t6MVd2NveB2FM9XwEa5YnT.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=bf932530813ab7716g011e2d", "progress": 91, "finished": 0, "hlCount": 4, "ideaCount": 0, "highlights": [{"text": "截至2022年1月，美联储所持有的国债在美国政府总债务中的比例已超过40%[插图]。", "chapter": "第02讲 不能明说的“现代货币理论”", "date": "2025-11-28", "color": 1}, {"text": "土地出让收入是地方政府债务的重要还款来源，在偿债压力下，地方政府就会有维持高房价、", "chapter": "第28讲 债务的本质：从“基建狂魔”说起", "date": "2023-09-02", "color": 1}, {"text": "数据将是未来商业领域最重要的资产", "chapter": "第27讲 时代为什么选择了新能源汽车", "date": "2023-09-02", "color": 1}, {"text": "2022年2月1日，美国国债首次突破30万亿美元大关，创下历史新高。如此高昂的本金，利率每增加一个基点，美国政府增加支出的利息都是天文数字", "chapter": "第02讲 不能明说的“现代货币理论”", "date": "2023-09-02", "color": 1}], "ideas": []}, {"id": "3300012239", "title": "安阳(博雅双语名家名作)(英汉对照)", "author": "李济", "cover": "https://cdn.weread.qq.com/weread/cover/39/3300012239/s_3300012239.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=fd432020813ab6b47g01961e", "progress": 90, "finished": 0, "hlCount": 4, "ideaCount": 0, "highlights": [{"text": "一是长子继位制的确立和兄终弟及制的废除，这消除了家族纠纷的一大根源。王国维认为，长子继位制的确立有助于平息由家族和家庭纠纷造成的社会混乱状态，稳定古代中国的政治制度。", "chapter": "拾叁．谱系、贞人和亲族关系", "date": "2025-03-03", "color": 1}, {"text": "令人称奇的是，在地下埋藏了三千多年且完全不为学术界所知的甲骨文在19世纪末被发现后，证实了司马迁所记载的商代先公先王的名单惊人地准确。", "chapter": "拾叁．谱系、贞人和亲族关系", "date": "2025-03-03", "color": 1}, {"text": "换句话说，完成一轮对祖先的“彡”祭要用110天，完成一轮“翌”祭需要再用110天，而剩下的祭、[插图]、[插图]三种仪式可交叠进行，共用130天。完成五种仪式共用350天或约一历法年。", "chapter": "拾肆．祖先及神灵崇拜", "date": "2025-03-03", "color": 1}, {"text": "王亥是商室最早的近祖先公上甲微的父亲，", "chapter": "拾肆．祖先及神灵崇拜", "date": "2025-03-03", "color": 1}], "ideas": []}, {"id": "41355404", "title": "要钱还是要生活", "author": "维姬·罗宾 乔·多明格斯", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/404/41355404/s_41355404.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=50932c207277088c5095c38", "progress": 98, "finished": 0, "hlCount": 4, "ideaCount": 0, "highlights": [{"text": "找一个人跟你相互讲一讲在过去6个月里买了哪一样并不真正需要的东西。", "chapter": "后记 “金钱观”", "date": "2025-02-07", "color": 1}, {"text": "既然你知道了金钱是你的生命能量，把它浪费在你不喜欢也从不使用的物品上就显得很不明智了。", "chapter": "第六章 享受节俭生活", "date": "2025-02-07", "color": 1}, {"text": "所谓节俭，就是享受我们所拥有的", "chapter": "第六章 享受节俭生活", "date": "2025-02-07", "color": 1}, {"text": "财务自由，就是不用再为钱而工作", "chapter": "新版前言", "date": "2025-02-07", "color": 1}], "ideas": []}, {"id": "915291", "title": "如何投资数字货币", "author": "王博 周朝晖主编", "cover": "https://cdn.weread.qq.com/weread/cover/69/YueWen_915291/s_YueWen_915291.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=d0a32ca05df75bd0a7e4a19", "progress": 100, "finished": 1, "hlCount": 4, "ideaCount": 0, "highlights": [{"text": "所以，笔者一直怀疑：比特币可能是美国政府的阴谋，动机就是拯救美国。", "chapter": "第5篇 百家争鸣篇", "date": "2025-01-13", "color": 1}, {"text": "那种因为比特币先入为主将长期称王，而藐视一切竞争币的思想是狭隘的。", "chapter": "第2章 认清比特币与竞争币的互补共存性", "date": "2025-01-13", "color": 1}, {"text": "最终把比特币变成美国人的金融强权工具。", "chapter": "第2章 认清比特币与竞争币的互补共存性", "date": "2025-01-13", "color": 1}, {"text": "中国狗狗币协会江恩", "chapter": "第2章 认清比特币与竞争币的互补共存性", "date": "2025-01-13", "color": 1}], "ideas": []}, {"id": "3300038765", "title": "学习中医很简单：我的《四圣心源》习悟记", "author": "陈喜生", "cover": "https://cdn.weread.qq.com/weread/cover/63/cpPlatform_hRAJJrzzZ6DzmN49gPRBsK/s_cpPlatform_hRAJJrzzZ6DzmN49gPRBsK.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=19232e40813ab75a4g015bae", "progress": 10, "finished": 0, "hlCount": 4, "ideaCount": 0, "highlights": [{"text": "用现代语言来说，中医就是一个研究物质和能量之间关系的学科。试问，这样的学科怎么会不科学呢？", "chapter": "阴阳", "date": "2023-07-06", "color": 1}, {"text": "人体之阴就有这样一个储存和释放能量的作用，但阴绝不只是脂肪，人体中一切承载阳气的物质都为阴。", "chapter": "阴阳", "date": "2023-07-06", "color": 1}, {"text": "阳得阴而能藏，", "chapter": "阴阳", "date": "2023-07-06", "color": 1}, {"text": "而这个宇宙中所有能够接收能量的物质都称为阴。阴能储存阳，使能量稳定存在。", "chapter": "阴阳", "date": "2023-07-06", "color": 1}], "ideas": []}, {"id": "851256", "title": "图解舌诊：伸伸舌头百病消", "author": "罗大伦", "cover": "https://cdn.weread.qq.com/weread/cover/35/YueWen_851256/s_YueWen_851256.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=6e4327d05cfd386e477a002", "progress": 100, "finished": 1, "hlCount": 4, "ideaCount": 0, "highlights": [{"text": "肝气不舒确实是会影响到心脏功能的，因为肝属木，心属火，木生火，所以，肝火旺的人心火也会越来越大，心火越来越大以后，心脏就受不了，就会出问题。所以，好多人肝气不舒是以心悸，或者胸闷、心脏异常跳动等症状去医院检查的。", "chapter": "2 肝气不舒的人身体有哪些表现", "date": "2023-06-28", "color": 5}, {"text": "阳虚症状最明显的是老人，好多老人晚上小便五六次，就是因为肾阳不足，肾的滤水功能很弱，所以白天喝了很多水，但肾脏没有在白天把这些水代谢出去。", "chapter": "4 阳虚体质之人的保养方", "date": "2023-06-28", "color": 5}, {"text": "熬夜会导致阴虚，那些天天半夜12点以后睡觉的人，慢慢就会变成阴虚体质，为什么呢？津液给耗没了。", "chapter": "1 什么原因会导致人阴虚", "date": "2023-06-28", "color": 5}, {"text": "什么是阴？就是体内濡润的、主静的物质，包括津液、血液都是阴，它们主要用来滋润我们身体里面静的这些东西", "chapter": "1 如何看舌质", "date": "2023-06-28", "color": 5}], "ideas": []}, {"id": "30478460", "title": "说文解字（精装）", "author": "[汉]许慎", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/460/30478460/s_30478460.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=cfb32ab071d1107ccfb5bc9", "progress": 9, "finished": 0, "hlCount": 4, "ideaCount": 0, "highlights": [{"text": "赤”是个会意字。甲骨文的上部是个“大”，下部是“火”，大火的颜色为红色。", "chapter": "C", "date": "2023-05-14", "color": 1}, {"text": "楷书是在小篆的基础上形成的。", "chapter": "C", "date": "2023-05-14", "color": 1}, {"text": "它的本义就是奴隶", "chapter": "C", "date": "2023-05-14", "color": 1}, {"text": "“保”的本义为负子于背，即把孩子背在背上。引申指养育、抚育、抚养。", "chapter": "B", "date": "2023-05-14", "color": 1}], "ideas": []}, {"id": "3300011076", "title": "投资中国：泉果基金创始人王国斌先生唯一著作", "author": "王国斌", "cover": "https://cdn.weread.qq.com/weread/cover/76/3300011076/s_3300011076.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=26d32de0813ab6ad3g0168de", "progress": 11, "finished": 0, "hlCount": 4, "ideaCount": 0, "highlights": [{"text": "推动人类社会发展的三个核心驱动力——全球化、城市化、科技进步，中国在这三个方面都有非常巨大的潜力，同时也有强大的执行力。", "chapter": "03 “刷新”后的中国，投资豁然开朗", "date": "2023-05-07", "color": 1}, {"text": "挖掘机的出现，让很多人失业了。但你愿意回到没有挖掘机，只能用铲子挖土的时代吗？我们的产业转移出去那么多，该如何解决失业问题？只能充分发挥想象力。但是我认为，我们国家一定有条件让这些人不会更差，这是我走过很多地方以后得出的结论。", "chapter": "第一部分 “刷新”后的中国，投资豁然开朗", "date": "2022-08-20", "color": null}, {"text": "“推动人类社会发展的三个核心驱动力分别是城市化、全球化和科技进步。”", "chapter": "第一部分 “刷新”后的中国，投资豁然开朗", "date": "2022-08-20", "color": null}, {"text": "此后，多年投资经验告诉我，管理好自己的心性是投资成功的一半。", "chapter": "序言 看好中国，看好资产管理", "date": "2022-08-20", "color": null}], "ideas": []}, {"id": "936231", "title": "正觉之道·佛子行广释", "author": "根让仁波切", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/231/936231/s_936231.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=f9e324405e4927f9e811b4b", "progress": 42, "finished": 0, "hlCount": 4, "ideaCount": 0, "highlights": [{"text": "要消除烦恼，彻底断除贪嗔痴，最殊胜的方法就是修空性。", "chapter": "第一章 前行的趋入方法", "date": "2023-04-15", "color": 1}, {"text": "六祖惠能大师曾说过：“佛法在世间，不离世间觉，离世觅菩提，有如觅兔角。”", "chapter": "第一章 前行的趋入方法", "date": "2023-02-14", "color": null}, {"text": "唯识派认为阿赖耶识是积业的基础。", "chapter": "第二章 正行宣说三士道", "date": "2022-03-24", "color": null}, {"text": "学佛引人向善，但这并不表示信佛、学佛的人就不会投生到三恶道，一定会去三善道，果报并不由宗教信仰来决定，而是由自己的发心与善恶行为所决定，因此，有情众生都无一例外要受因果规律的支配。", "chapter": "第二章 正行宣说三士道", "date": "2022-03-24", "color": null}], "ideas": []}, {"id": "3300053312", "title": "你值得过更好的生活（独家首发｜全新修订本）", "author": "罗伯特·沙因费尔德", "cover": "https://cdn.weread.qq.com/weread/cover/43/cpplatform_gmpxvbdjh8x2d2cn7xmyzv/s_cpplatform_gmpxvbdjh8x2d2cn7xmyzv1679490024.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=10132b00813ab7b53g012328", "progress": 100, "finished": 1, "hlCount": 4, "ideaCount": 0, "highlights": [{"text": "哇！这简直棒极了。我创造了这间咖啡店、这部浓缩咖啡机、这些咖啡豆、牛奶、奶泡器、糖浆和杯子。我创造了店员以及和我一起出现在咖啡店里的这些人。", "chapter": "第九章 自己做主", "date": "2023-03-25", "color": 1}, {"text": "你从不知道你的意识就是创造者，它创造了你所体验到的一切，而且你对这个创造过程孰视无睹。", "chapter": "第八章 百年寻宝", "date": "2023-03-25", "color": 1}, {"text": "你的特殊目标是以独特的无限存有的身份，用你所选择的独特方式，进行这场人性游戏。", "chapter": "第二章 三个闹心的问题", "date": "2023-03-25", "color": 1}, {"text": "。从金钱游戏中彻底解脱，为自己创造一个新游戏，选择自己的规则，永久改变自己跟金钱的关系。", "chapter": "第一章 金钱游戏规则", "date": "2023-03-25", "color": 1}], "ideas": []}, {"id": "585339", "title": "资本，让你看懂世界格局", "author": "西瓜子", "cover": "https://cdn.weread.qq.com/weread/cover/3/YueWen_585339/s_YueWen_585339.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=f0e3298058ee7bf0ec63194", "progress": 99, "finished": 1, "hlCount": 4, "ideaCount": 0, "highlights": [{"text": "换言之，世界经济的最大矛盾，从前是，现在是，未来还是——“产品生产出来，找不到买主”。不是人们不需要产品，而是需要产品的人没有足够的支付能力——换言之，就是没有钱。", "chapter": "一地鸡毛——伪“需求不足”", "date": "2022-12-28", "color": null}, {"text": "全球金融危机的根源在于，强大的实物生产能力的对面，是有限的消费能力；而此前世界经济飞速增长的背后，是欧美民众通过透支未来的“虚假购买力”支撑起来的。", "chapter": "一地鸡毛——伪“需求不足”", "date": "2022-12-28", "color": null}, {"text": "在资本大战中存活下来的所有经济体和个人，不是因为通过阴谋而操纵了资本，而是顺应了资本的本性。在资本的体系中，人、国家、经济体只是资本的奴隶和支配对象，只有资本才是主人。这一点，我们一定要搞清楚。", "chapter": "美国人的选择", "date": "2022-12-28", "color": null}, {"text": "先尽力帮助其将房价推高，继而在泡沫最疯狂之时，给出一个理由，令资金大规模流出中国，从而一举戳破房地产泡沫，待房地产崩盘将中国经济和金融拖入破产之际，他们便可以手拉手儿，手拿账簿来接收一切了。", "chapter": "中国的“软肋”", "date": "2022-12-28", "color": null}], "ideas": []}, {"id": "3300039044", "title": "风险投资史", "author": "塞巴斯蒂安·马拉比", "cover": "https://cdn.weread.qq.com/weread/cover/17/cpPlatform_8XBcdJxGVyJuGnRCzBZjBd/s_cpPlatform_8XBcdJxGVyJuGnRCzBZjBd.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=c3e32420813ab75c0g0148cf", "progress": 84, "finished": 0, "hlCount": 4, "ideaCount": 0, "highlights": [{"text": "当时作为思科的董事，孙正义清楚地认识到中国的零售业已经开始起飞，互联网的普及也已经箭在弦上，所以对于任何试图以此盈利的项目的投资都是合理的。而林夏如投的那些初创企业正好给了孙正义亲身入场的机会。", "chapter": "第10章 到中国去，在那里掀起资本新浪潮", "date": "2022-12-18", "color": null}, {"text": "立刻", "chapter": "第10章 到中国去，在那里掀起资本新浪潮", "date": "2022-12-18", "color": null}, {"text": "比如在2000年向太空发射一千克质量物体的成本竟然与1970年相同。他们设想，也许太空探索技术公司可以利用科学进步来开启这个领域？其次，公司实验中的火箭虽然爆炸了，但工程师们明白爆炸的原因。而如果你能从中吸取教训，那么失败就反而是一种额外的收获。最后，马斯克本人就是典型的傲慢的天才。如果创始人基金相信自己的理论，那么马斯克嘲笑自己撞毁了未投保赛车的事实就应该足以让他们支持他。", "chapter": "第9章 反传统的风险投资模式不断涌现", "date": "2022-12-18", "color": null}, {"text": "敢于冒风险的“短钱”是很常见的，股市的炒家大抵如此，而敢于冒风险的“长钱”则是稀缺的。这本书讲的便是放眼长期的风险投资人的故事。", "chapter": "各方赞誉", "date": "2022-12-17", "color": null}], "ideas": []}, {"id": "3300028878", "title": "作个闲人：苏东坡的治愈主义", "author": "费勇", "cover": "https://cdn.weread.qq.com/weread/cover/31/cpPlatform_m3faLt9onDKm8R3cfBzDYB/s_cpPlatform_m3faLt9onDKm8R3cfBzDYB.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=83c326f0813ab71c7g018fe5", "progress": 46, "finished": 0, "hlCount": 4, "ideaCount": 0, "highlights": [{"text": "“穷则独善其身，达则兼济天下”", "chapter": "01 何时忘却营营？", "date": "2022-10-14", "color": null}, {"text": "他徒步去松风亭，快步走了一段路，感觉很累，想在树林间休息。他一抬头，望到松风亭还在树梢的上面，还有很远的距离。怎么能够走到那儿呢？山一样的压力挥之不去，犹豫之间，苏东坡突然转了一个念头：这里到处都是可以休息的地方，到处都是可以看风景的地方，为什么非要累死累活爬到松风亭呢？一转念，就解脱了。", "chapter": "09 此间有什么歇不得处？", "date": "2022-10-14", "color": null}, {"text": "1057年，22岁的苏东坡参加欧阳修主持的礼部考", "chapter": "04 天涯流落俱可念", "date": "2022-10-14", "color": null}, {"text": "1084年，苏东坡即将离开黄州，写过一首《海棠》：东风袅袅泛崇光，香雾空蒙月转廊。只恐夜深花睡去，故烧高烛照红妆。", "chapter": "04 天涯流落俱可念", "date": "2022-10-14", "color": null}], "ideas": []}, {"id": "36685887", "title": "最好的养育是不焦虑", "author": "橙子", "cover": "https://cdn.weread.qq.com/weread/cover/71/YueWen_36685887/s_YueWen_36685887.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=c6b32f10722fc83fc6bde78", "progress": 43, "finished": 0, "hlCount": 4, "ideaCount": 0, "highlights": [{"text": "单词背不下来”或者“容易拼错”这种事，是英语学习中最不重要的事情。", "chapter": "不死记硬背单词，孩子也能学好英语吗？", "date": "2022-08-28", "color": null}, {"text": "学习英语，想要不那么痛苦，就应该向学习母语的方式靠拢，先去学习口语，最好能做到听懂，会说很多内容，学一些自然拼读规则，然后就尽快开始应用，大量阅读和写作，快速地认识和使用更多词汇，让英语学习变得更有意义也更有趣，从而有利于坚持学习。", "chapter": "不死记硬背单词，孩子也能学好英语吗？", "date": "2022-08-28", "color": null}, {"text": "用实际行动告诉孩子，你这样的行为是不对的，是不被人类社会接受的，孩子才会在各种碰壁中慢慢摸索到界限，知道在这个世界上混下去的基础规则。", "chapter": "管教熊孩子，只靠“讲道理”是无效的", "date": "2022-08-27", "color": null}, {"text": "只有那些有尊严、受尊重的孩子才可能拥有自控能力。", "chapter": "怎样让孩子在享受快乐的同时，又拥有自控力？", "date": "2022-08-27", "color": null}], "ideas": []}, {"id": "34539930", "title": "什么是最好的父母", "author": "河合隼雄", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/930/34539930/s_34539930.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=6cd32790720f099a6cda5c7", "progress": 95, "finished": 0, "hlCount": 4, "ideaCount": 0, "highlights": [{"text": "如果自己的孩子比一般孩子晚上学三年，那假设其他孩子活到八十岁，自己的孩子能活到八十三岁，那不就扯平了嘛！用这样的心情去对待就行了。", "chapter": "26 孩子不去上学，到底是怎么了？", "date": "2022-08-20", "color": null}, {"text": "我们该做的并不是严加管制，而是要培养既珍惜自由，又不会被诱惑所吞噬的人。创造一个能够培养出抵制诱惑的人的社会，确实很重要。", "chapter": "06 对孩子来说，现在的不良诱惑太多了。我该怎么应对呀？", "date": "2022-08-19", "color": null}, {"text": "最重要的是培养能抵制诱惑的人。", "chapter": "06 对孩子来说，现在的不良诱惑太多了。我该怎么应对呀？", "date": "2022-08-19", "color": null}, {"text": "用自己喜欢的方式去养育就好。”", "chapter": "03 我能顺利地把孩子养好吗？一想到这个问题就十分不安，怎么办？", "date": "2022-08-19", "color": null}], "ideas": []}, {"id": "3300014120", "title": "经济学：第18版（翻译版）", "author": "〔美〕保罗·萨缪尔森 威廉·诺德豪斯著", "cover": "https://cdn.weread.qq.com/weread/cover/20/3300014120/s_3300014120.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=38e32a80813ab6c04g010d5e", "progress": 8, "finished": 0, "hlCount": 4, "ideaCount": 0, "highlights": [{"text": "许多经济活动都涉及到放弃现时消费以增加资本。我们每次进行投资——新建一座工厂或修筑一条道路，增加受教育年限或提高教育质量，增加知识技术积累——都在提高经济的未来的生产率，进而增加我们未来的消费。", "chapter": "第一编 基本概念", "date": "2022-05-08", "color": null}, {"text": "1.生产什么商品和劳务取决于消费者的货币选票", "chapter": "第一编 基本概念", "date": "2022-05-08", "color": null}, {"text": "在没有集中的智慧或计算的情况下，它能解决涉及到亿万个未知变量或相关关系的生产和分配的问题，对此连当今最快的超级计算机也都望尘莫及。", "chapter": "第一编 基本概念", "date": "2022-05-08", "color": null}, {"text": "他们在商品充裕、价格低廉的时期买进，而在商品紧俏、价格高昂的时期卖出。", "chapter": "A.风险和不确定性经济学", "date": "2022-05-08", "color": null}], "ideas": []}, {"id": "28394088", "title": "世说新语（全集）", "author": "[南朝宋]刘义庆", "cover": "https://cdn.weread.qq.com/weread/cover/96/yuewen_28394088/s_yuewen_283940881678700083.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=645328e071b1426864542b5", "progress": 8, "finished": 0, "hlCount": 4, "ideaCount": 0, "highlights": [{"text": "西晋之所以会亡国，跟这些标榜个性、清谈误国的名士有脱不开的关系。为政者，不脚踏实地做事，整天放浪形骸，喝酒清谈，搞小圈子，这样的上位者不把国家搞砸才怪。他们只学到了阮籍、嵇康的外在，却没搞明白真名士心中的境界。", "chapter": "德行第一", "date": "2022-03-30", "color": null}, {"text": "儒家认为所有感情都不应该过分，悲痛过度以致损害身心健康反而不值得肯定。所以说，凡事过犹不及。", "chapter": "德行第一", "date": "2022-03-30", "color": null}, {"text": "316年，西晋灭亡，北方从此进入十六国时期。", "chapter": "《世说新语》历史背景及特有名词介绍", "date": "2022-03-30", "color": null}, {"text": "“魏晋风度”之所以千年以来被中国文人津津乐道，正是因为它的本质其实是：当现实充满无奈与悲观之时，文人们依然可以选择一种老庄式的超然洒脱，追求自我，崇尚自由，保留一种清隽高洁的风骨，以形式上的傲然物外，来表达内心的不妥协。", "chapter": "译者序 风流总被，雨打风吹去", "date": "2022-03-27", "color": null}], "ideas": []}, {"id": "24282914", "title": "活在此时此刻", "author": "[法]一行禅师", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/914/24282914/s_24282914.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=e283207071728722e28cb43", "progress": 100, "finished": 0, "hlCount": 4, "ideaCount": 0, "highlights": [{"text": "整个宇宙凝聚到一起，才有你的出现。", "chapter": "寻找家", "date": "2021-11-18", "color": null}, {"text": "央成了快乐行走的广场。在八名警官前面，还有一辆", "chapter": "自由地行走", "date": "2021-11-18", "color": null}, {"text": "我们就会感到自己真真正正地存在于此时此地。我们将释放身体", "chapter": "钟", "date": "2021-11-17", "color": null}, {"text": "只要心存正念的力量，日常生活的每一个行为都可以充满快乐。", "chapter": "关门", "date": "2021-10-27", "color": null}], "ideas": []}, {"id": "855722", "title": "灰犀牛：如何应对大概率危机", "author": "米歇尔·渥克", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/722/855722/s_855722.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=044324f05d0eaa04421f3d9", "progress": 41, "finished": 0, "hlCount": 4, "ideaCount": 0, "highlights": [{"text": "避险基金公司的传奇对冲基金经理人迈克尔·巴里", "chapter": "第一章 遭遇灰犀牛", "date": "2021-11-16", "color": null}, {"text": "人们宁愿和大家一起犯错，也不愿成为唯一正确的那个人。", "chapter": "第一章 遭遇灰犀牛", "date": "2021-11-16", "color": null}, {"text": "灰犀牛思维的重要理论之一就是要在迎战即将到来的危机的过程中，发现能给自己盈利的机会。", "chapter": "第一章 遭遇灰犀牛", "date": "2021-11-16", "color": null}, {"text": "黑天鹅事件是我们无法预知的事件。灰犀牛事件是我们本来应该看到但却没看到的危险，又或者是我们有意忽视了的危险。", "chapter": "第一章 遭遇灰犀牛", "date": "2021-11-16", "color": null}], "ideas": []}, {"id": "25872053", "title": "达摩教养法：了解孩子的大脑让孩子更快乐、健康，更有成就感", "author": "罗伯特·基思·华莱士 弗雷德里克·特拉维斯", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/53/25872053/s_25872053.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=ae932e70718ac6b5ae91bd2", "progress": 100, "finished": 1, "hlCount": 4, "ideaCount": 0, "highlights": [{"text": "我们提供三条简单的建议：安静的环境、多抱婴儿、大量玩耍。这三点看起来没什么了不起，却能促进每个孩子的大脑发育", "chapter": "第二部分 达摩教养法的四个主要年龄段", "date": "2021-05-02", "color": null}, {"text": "大脑深处的海马体对新鲜的感官信息非常敏感。如果海马体探测到非常新的刺激，就会指导全部注意力集中到新刺激上。南希可以应用这个知识，轻轻地、慢慢地跟儿子说话。大声尖叫的儿子很快就会停下来问：“你说什么？”妈妈的轻言慢语和儿子的大声尖叫形成巨大反差时，杰登的海马体会判断妈妈的话比他发脾气更重要，从而指导杰登去关注妈妈说了什么。", "chapter": "第二部分 达摩教养法的四个主要年龄段", "date": "2021-05-02", "color": null}, {"text": "超觉冥想", "chapter": "在各种情况下如何运用这些方法", "date": "2021-05-02", "color": null}, {"text": "冲动反应", "chapter": "达摩教养法简介", "date": "2021-05-02", "color": null}], "ideas": []}, {"id": "24051770", "title": "品格的力量：坚毅、好奇心、乐观精神与孩子的未来", "author": "[美]保罗·图赫", "cover": "https://cdn.weread.qq.com/weread/cover/14/yuewen_24051770/s_yuewen_240517701729073102.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=e3132770716f003ae31a7e5", "progress": 32, "finished": 0, "hlCount": 4, "ideaCount": 0, "highlights": [{"text": "在婴儿期具有安全依恋倾向的孩子更自信，更有好奇心[插图]，而且更善于应对挫折。", "chapter": "11 你帮孩子储备自信了吗？", "date": "2020-09-04", "color": null}, {"text": "安全依恋型孩子", "chapter": "10 别担心“宠坏”孩子", "date": "2020-09-04", "color": null}, {"text": "在出生后的第一年里，如果父母总是习惯于以最快的速度而且毫无选择地对婴儿的哭闹做出回应，那么，这样的孩子往往比那些经常被父母置之不理的孩子更加独立，而且在品格上往往表现得更加勇敢、刚毅。", "chapter": "10 别担心“宠坏”孩子", "date": "2020-09-04", "color": null}, {"text": "运用情感领域或认知领域的自控能力对改善学习状况和顺利完成学业都是至关重要的。", "chapter": "6 生命不能承受之压", "date": "2020-09-04", "color": null}], "ideas": []}, {"id": "453352", "title": "教育漫话", "author": "[英]洛克", "cover": "https://cdn.weread.qq.com/weread/cover/26/YueWen_453352/s_YueWen_453352.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=af7323b056eae8af7ef830b", "progress": 80, "finished": 0, "hlCount": 4, "ideaCount": 0, "highlights": [{"text": "一个人在有能力对一些话题表达见解之前，先去对其了解一下是有必要的。否则就这样让他去谈论，就像是让一个盲人去谈色彩或是让一个失聪的人去谈音乐一样，是愚蠢的。", "chapter": "孩子的学习教育", "date": "2020-05-11", "color": null}, {"text": "学习语言要重在应用", "chapter": "孩子的学习教育", "date": "2020-05-11", "color": null}, {"text": "如果一点水果也不让他们接触到，一旦管得稍微松了些或是通过贿赂仆人得到了水果，恐怕他们会连果皮果核都吞个一干二净，吃得过量的。", "chapter": "孩子的家庭教育", "date": "2020-05-10", "color": null}, {"text": "我认为水果应该在饭前或两餐之间吃，儿童还应当在早餐时吃水果。", "chapter": "孩子的家庭教育", "date": "2020-05-10", "color": null}], "ideas": []}, {"id": "26278269", "title": "苏轼传", "author": "王水照 崔铭", "cover": "https://cdn.weread.qq.com/weread/cover/94/YueWen_26278269/s_YueWen_26278269.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=ec332f707190f97dec3e09f", "progress": 99, "finished": 0, "hlCount": 3, "ideaCount": 1, "highlights": [{"text": "李白的天马行空、脱略羁绊，固然使人倾倒，但不免太高太远，难以企及；杜甫忠悃诚笃，感时伤世，人们不能无动于衷，但学起来又太苦太累，而苏轼则是现世性与超越性水乳交融在一起的一位智者。他总是拥有一代又一代的众多读者，永远令人怀想，永远给人启迪。", "chapter": "结束语 浩瀚渊深赞“苏海”，流风余韵遗人间", "date": "2022-08-26", "color": null}, {"text": "在长达四十多年的创作生涯中，苏轼为我们留下了二千七百多首诗、三百多首词和四千二百多篇散文作品。", "chapter": "结束语 浩瀚渊深赞“苏海”，流风余韵遗人间", "date": "2022-08-26", "color": null}, {"text": "大患缘有身，无身则无疾。", "chapter": "四方震悼，山河同悲", "date": "2022-08-26", "color": null}], "ideas": [{"content": "僧死壁坏，雪泥鸿爪", "abstract": "人生到处知何似？应似飞鸿踏雪泥：泥上偶然留指爪，鸿飞那复计东西。老僧已死成新塔，坏壁无由见旧题。往日崎岖还记否：路长人困蹇驴嘶。", "chapter": "", "date": "2022-08-26", "star": null}]}, {"id": "34868118", "title": "中国书法史", "author": "朱天曙", "cover": "https://cdn.weread.qq.com/weread/cover/7/YueWen_34868118/s_YueWen_34868118.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=a8532a9072140b96a8536c3", "progress": 41, "finished": 0, "hlCount": 3, "ideaCount": 1, "highlights": [{"text": "魏晋文人在充分认识自然之美的同时，意识到自然是人性美与艺术美的和谐，是对整个宇宙、人生的感受和领悟。", "chapter": "四、魏晋书法精神", "date": "2022-03-30", "color": null}, {"text": "以毛笔进行书写的书迹与带有工艺性质的甲骨文、金文、石刻书迹有着鲜明的不同，也是后世所说“书卷气”与“金石气”的分野。", "chapter": "四、隶变", "date": "2022-03-29", "color": null}, {"text": "簋", "chapter": "三、多采的书风", "date": "2022-03-29", "color": null}], "ideas": [{"content": "簋，汉字，读作：guǐ。簋，是古代中国用于盛放煮熟饭食的器皿，也用作礼器，圆口，双耳。流行于商朝至东周，是中国青铜器时代标志性青铜器具之一。", "abstract": "簋", "chapter": "", "date": "2022-03-29", "star": null}]}, {"id": "908170", "title": "文明是副产品", "author": "郑也夫", "cover": "https://cdn.weread.qq.com/weread/cover/33/yuewen_908170/s_yuewen_9081701733220300.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=47232dc05ddb8a472a3e8f7", "progress": 95, "finished": 0, "hlCount": 3, "ideaCount": 1, "highlights": [{"text": "达尔文的进化论思想中，真的没有“目的”。", "chapter": "三 目的论与副产品", "date": "2020-09-29", "color": null}, {"text": "宏观而论，虽然可以说基因交换的方式很多，但战争带来了基因的大交换，它是在漫长的远古时代人类没有被分裂成若干亚种的重要原因。", "chapter": "六 外婚制解释之一：抢婚", "date": "2019-11-30", "color": null}, {"text": "与长臂猿等灵长目动物不同，人类偏偏将家置于群体之中。家庭内外的所有女性都对成家与未成家的男子构成极大的诱惑。以包含二态性之肉身居于群体中，人类的一夫一妻制怎么可能是纯粹、牢固而稳定的。故历史上权势者的多妻，现当代越来越多的离婚，构成人类一夫一妻制的补充物和安全阀。", "chapter": "五 置身族群中的一夫一妻家庭", "date": "2019-11-30", "color": null}], "ideas": [{"content": "是因为被农作物反向塑造。人与古物之间是相互影响的关系。", "abstract": "凡此种种，都令后人不解：祖先因何选择了农业。很可能这样发问本身是颇成问题的，那全然不是理性的选择。我们只好转问：那又是怎么发生的，如何走上了这条不归之路？", "chapter": "", "date": "2020-09-04", "star": null}]}, {"id": "3300082609", "title": "这就是ChatGPT", "author": "斯蒂芬·沃尔弗拉姆", "cover": "https://cdn.weread.qq.com/weread/cover/24/cpplatform_4cn8w4tmgzntjobg9ffeny/s_cpplatform_4cn8w4tmgzntjobg9ffeny1703648785.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=74332a90813ab86c4g019d98", "progress": 49, "finished": 0, "hlCount": 2, "ideaCount": 2, "highlights": [{"text": "人类可贵的，是有内在驱动力和内在体验，能够内在地定义目标或者意义，从而最终定义未来。", "chapter": "奇书", "date": "2025-02-02", "color": 1}, {"text": "但沃尔弗拉姆认为自然界是用编程语言（而且是非常简单的编程语言）书写的。”而且这些现象或者系统，比如人类大脑的工作和气象系统的演化，在计算方面是等效的，具有相同的复杂度，这称为“计算等价原理”。", "chapter": "奇人", "date": "2025-02-02", "color": 1}], "ideas": [{"content": "2025年1月，深度求索deepseek 出来了", "abstract": "即使在已经发明和发现一切之后，仍有收获惊喜的可能。", "chapter": "前言", "date": "2025-02-02", "star": null}, {"content": "硅幕降临", "abstract": "最终，AI也会逐步发展出自己的世界。这是一种新的生态，可能有自己的宪章，人类需要适应，与之共存共荣。", "chapter": "奇书", "date": "2025-02-02", "star": null}]}, {"id": "25731006", "title": "自私的基因（40周年增订精装版）", "author": "理查德·道金斯", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/6/25731006/s_25731006.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=67f323e071889fbe67ff2f1", "progress": 40, "finished": 0, "hlCount": 2, "ideaCount": 2, "highlights": [{"text": "如果其中有什么寓意深刻的地方可供人类借鉴，那就是我们必须把利他主义的美德灌输到我们子女的头脑中去，因为我们不能指望他们的本性里有利他主义的成分。", "chapter": "第8章 代际之战", "date": "2020-09-23", "color": null}, {"text": "我们可以把动物看作赌徒。对一个赌徒来说，有时最好的策略不是穷凶极恶地主动出击，而是坐等良机。", "chapter": "第7章 计划生育", "date": "2020-09-23", "color": null}], "ideas": [{"content": "用这种方法做实验太巧妙了。", "abstract": "给一些欧椋鸟个体分别放送两种录音，一种再现了欧椋鸟稠密聚集的栖息地且鸣叫声非常洪亮，另一种再现了欧椋鸟不太稠密的栖息地且鸣叫声比较小。两相比较，前面一种欧椋鸟的产蛋量要少些。", "chapter": "", "date": "2020-09-23", "star": null}, {"content": "人可以没有领地，但不能没有钱", "abstract": "我们可以把动物看作赌徒。对一个赌徒来说，有时最好的策略不是穷凶极恶地主动出击，而是坐等良机。", "chapter": "", "date": "2020-09-23", "star": null}]}, {"id": "3300121506", "title": "胖东来 于东来 大器必成胖东来的美好企业之路", "author": "黄伟芳", "cover": "https://cdn.weread.qq.com/weread/cover/51/cpplatform_s8mjcybwikjhyum1jzxmmc/s_cpplatform_s8mjcybwikjhyum1jzxmmc1773126211.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=e1d321b0813ab95f6g016bb1", "progress": 100, "finished": 1, "hlCount": 3, "ideaCount": 0, "highlights": [{"text": "DL百科包括专业知识、实操标准、客服标准、规章制度、考核方案等多个分类，一共有20950个词条，由1534人进行了155954次编辑，堪称超市经营全能指南。", "chapter": "胖东来的属性是学校", "date": "2026-03-14", "color": 1}, {"text": "爱自己就是“让自己轻松、自由，心里面要开心而不是纠结”，就是要“追求人性的美好，让自己活得健康、活得舒心、活得美丽、活得悠然、活得浪漫、活得富有情怀、活得有价值，让自己都觉得自己的生命是那么美好”。", "chapter": "以爱为桨，重新启航", "date": "2026-03-14", "color": 1}, {"text": "我们的生命需要悠闲、需要享受、需要健康，忘记我们要快乐、我们要真诚、我们要友善，", "chapter": "以爱为桨，重新启航", "date": "2026-03-14", "color": 1}], "ideas": []}, {"id": "3300022946", "title": "精品咖啡学·实务篇", "author": "韩怀宗", "cover": "https://cdn.weread.qq.com/weread/cover/46/3300022946/s_3300022946.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=8c932c10813ab6f76g016ea5", "progress": 35, "finished": 0, "hlCount": 3, "ideaCount": 0, "highlights": [{"text": "这些在室温下未与热水接触即可气化的成分由鼻子吸入，呈现的气化味谱叫作“干香”。", "chapter": "Chapter 1 第一章 从喝一杯咖啡开始：尽享千香万味", "date": "2025-12-30", "color": 1}, {"text": "一杯黑咖啡至少含有1,000种成分，实验室从咖啡中分离出来的化合物，至今已超850种，其中1/3属于芳香物，丰富度远胜红酒、香草、巧克力和杏仁，堪称人类最香醇的饮品。", "chapter": "Chapter 1 第一章 从喝一杯咖啡开始：尽享千香万味", "date": "2025-12-30", "color": 1}, {"text": "最令我惊艳的是产自海南白沙黎族自治县陨石坑的罗布斯塔，干净度（clean cup）极佳，喝得到奶油与巧克力香气，风味比驰名世界的印度皇家罗布斯塔更为干净丰富。", "chapter": "新版自序", "date": "2025-12-30", "color": 1}], "ideas": []}, {"id": "3300037234", "title": "重返狼群背后的故事", "author": "李微漪 红娟 著", "cover": "https://cdn.weread.qq.com/weread/cover/71/cpplatform_5equcpdrzq54esze2ahdcb/s_cpplatform_5equcpdrzq54esze2ahdcb1768555392.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=34032ce0813ab750bg0142a3", "progress": 90, "finished": 0, "hlCount": 3, "ideaCount": 0, "highlights": [{"text": "心动不如行动，有人干脆计划移民去澳洲开兔子餐馆。但仔细想想还是算了吧，移民需要很多很多钱，老祖宗早就告诉我们了，贫贱不能移。", "chapter": "第十三章 微漪笔下的草原新故事", "date": "2026-01-20", "color": 1}, {"text": "鵟", "chapter": "第十三章 微漪笔下的草原新故事", "date": "2026-01-20", "color": 1}, {"text": "从此，微漪专心致志当起了野生动物画家。晴空净如拭的若尔盖草原，旷达着她的眼睛和心灵，果然秀色始天然，人世乃清安。从此鸥飞渺渺不知倦，翠岚融冶苍穹间。", "chapter": "第五章 天干饿不死手艺人", "date": "2026-01-20", "color": 1}], "ideas": []}, {"id": "23303646", "title": "绿山墙的安妮", "author": "[加]蒙哥马利", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/646/23303646/s_23303646.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=b21324e0716395deb21aecf", "progress": 99, "finished": 0, "hlCount": 3, "ideaCount": 0, "highlights": [{"text": "“亲爱的世界，”她低声说，“你很可爱，我能生活在你的怀抱里，非常高兴。”", "chapter": "第三十八章 峰回路转", "date": "2025-12-23", "color": 1}, {"text": "当我们所喜爱的某一个人再也不能在这里与我们同享欢乐时，我们仍然觉得有些事情使我们很高兴，每次想到这一点心里总有点内疚，而当我们发现自己重新对生活发生兴趣时，我们感到好像我们背叛了我们的悲哀似的。", "chapter": "第三十七章 收获者的名字叫死亡", "date": "2025-12-23", "color": 1}, {"text": "“你不过是绿山墙农舍的安妮，”她认真地说，“每当我竭力想象自己是科迪莉娅小姐时，都发现你不过是现在这副样子。可是，做绿山墙农舍的安妮比做其他任何地方的安妮都要好上一百万倍，是不是呢？”", "chapter": "第八章 对安妮的培养开始了", "date": "2025-12-22", "color": 1}], "ideas": []}, {"id": "831446", "title": "自卑与超越", "author": "阿尔弗雷德·阿德勒", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/446/831446/s_831446.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=d55329905cafd6d5525c389", "progress": 61, "finished": 0, "hlCount": 3, "ideaCount": 0, "highlights": [{"text": "她们都认为子女是自己所完成的一件作品。我们可以这样认为：母亲认为自己就是创造生命的上帝。其实，追求母道就是追求一种优越感，就像对神的地位的追求。", "chapter": "第六章 家庭的影响", "date": "2025-11-16", "color": 1}, {"text": "自卑能毁灭你，也能成就你。超越自卑，你将成为内心强大的自己！", "chapter": "献辞", "date": "2025-11-16", "color": 1}, {"text": "现代人生活在这样一种错觉之下：他似乎很明白自己的追求，但事实上他追求的，不过是别人期望他去追求的东西罢了。", "chapter": "第一章 生活的意义", "date": "2020-08-22", "color": null}], "ideas": []}, {"id": "522205", "title": "人性的弱点（果麦经典）", "author": "卡耐基", "cover": "https://cdn.weread.qq.com/weread/cover/94/YueWen_522205/s_YueWen_522205.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=a233272057f7dda23713095", "progress": 99, "finished": 0, "hlCount": 3, "ideaCount": 0, "highlights": [{"text": "和人打交道时，请牢记这一点——人并非理性生物。他们由情感驱使，被偏见支配，傲慢与虚荣是他们的动力之源。", "chapter": "Chapter 01 人际关系的基本技巧", "date": "2025-08-28", "color": 1}, {"text": "批评、指责和抱怨是蠢材与生俱来的“才能”；理解和宽容却是对人品和自律的极大考验。", "chapter": "Chapter 01 人际关系的基本技巧", "date": "2025-08-28", "color": 1}, {"text": "那些刻薄伤人、极尽侮辱之能事的话语往往来自我们的家人。这一真相令人震惊，然而事实的确如此。”", "chapter": "Chapter 06 幸福家庭生活的七个法则", "date": "2025-08-26", "color": 1}], "ideas": []}, {"id": "3300003224", "title": "长安的荔枝（同名影视原著）", "author": "马伯庸", "cover": "https://cdn.weread.qq.com/weread/cover/75/cpPlatform_dbb14284a55f1e733b60202b0777255d/s_cpPlatform_dbb14284a55f1e733b60202b0777255d.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=cc932860813ab67c2g014597", "progress": 100, "finished": 1, "hlCount": 3, "ideaCount": 0, "highlights": [{"text": "说就好，何必打个哑谜？而且干吗要去招福寺？李善", "chapter": "第四章", "date": "2024-12-17", "color": null}, {"text": "远远的廊下何履光抱臂站着，朝这边冷笑。这北人笨得像只清远鸡，还妄想把经略府拖进鲜荔枝这摊浑水里？", "chapter": "第二章", "date": "2023-01-12", "color": null}, {"text": "二月春风，柳色初青。每到这个时节，长安以东的大片郊野便会被一大片碧色所浸染，一条条绿绦在官道两旁依依垂下，积枝成行，有若十里步障。唯有灞桥附近，是个例外。", "chapter": "第二章", "date": "2023-01-12", "color": null}], "ideas": []}, {"id": "40133507", "title": "基层女性（探讨关于爱、金钱与精神世界的建立）", "author": "王慧玲", "cover": "https://cdn.weread.qq.com/weread/cover/95/YueWen_40133507/s_YueWen_40133507.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=d3c3209072646383d3ce031", "progress": 99, "finished": 1, "hlCount": 3, "ideaCount": 0, "highlights": [{"text": "阅读是这个世界上成本最低、收获最大的投资行为。", "chapter": "克服思想上的贫穷", "date": "2024-12-28", "color": 1}, {"text": "我在某一天坚定了我想要的生活，理解了幸福就是身体的无病痛和内心的无困扰之后，那些我曾经认为重要的东西，那些试图绑架我的人和观念，突然就对我没有任何力量了。", "chapter": "去过不被绑架的人生", "date": "2024-12-28", "color": 1}, {"text": "你的责任是对你自己的生命负责，成为一个健康快乐的人。", "chapter": "你永远是有选择的", "date": "2024-12-28", "color": 1}], "ideas": []}, {"id": "713363", "title": "正义之心：为什么人们总是坚持“我对你错”", "author": "乔纳森·海特", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/363/713363/s_713363.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=ef9326505ae293ef96cb658", "progress": 17, "finished": 0, "hlCount": 3, "ideaCount": 0, "highlights": [{"text": "世间的一切都是计算。因此要小心行动，手中掌握平衡。在天平的一端放上事物带来的快感，在另一端放上随之而来的痛苦，然后看天平向哪边倾斜。", "chapter": "第一部分 道德心理学第一原则 直觉在先，策略性推理在后", "date": "2024-04-29", "color": 1}, {"text": "即儿童有了与伤害相关的经验，在此基础上自我构建出道德。孩子们痛恨自己受到伤害，因而知道伤害是错的，由此也渐渐明白了伤害他人是错的，而这又令他们理解了公平，终至于正义。", "chapter": "第一部分 道德心理学第一原则 直觉在先，策略性推理在后", "date": "2024-04-29", "color": 1}, {"text": "拜托不要强迫他们遵从上帝、老师，或者你。这只会将他们固结在社会惯例的层次。", "chapter": "第一部分 道德心理学第一原则 直觉在先，策略性推理在后", "date": "2024-04-29", "color": 1}], "ideas": []}, {"id": "837932", "title": "穷查理宝典：查理·芒格智慧箴言录（全新增订本）", "author": "彼得·考夫曼", "cover": "https://cdn.weread.qq.com/weread/cover/48/YueWen_837932/s_YueWen_837932.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=2e0320e05cc92c2e0796c5a", "progress": 92, "finished": 0, "hlCount": 3, "ideaCount": 0, "highlights": [{"text": "相同的政治观点之后，我曾多次暗中以为，我提倡这种政治制", "chapter": "歌颂长者：芒格论晚年", "date": "2023-12-07", "color": null}, {"text": "牛奶车的马那样蒙上了“眼罩”。我估计现在哈佛大学法学院", "chapter": "第十一讲 人类误判心理学", "date": "2023-12-07", "color": null}, {"text": "“能力会让你到达巅峰，但只有品德才能让你留在那里。”", "chapter": "查理论诚实：在2004年西科年会上的讲话", "date": "2021-12-12", "color": null}], "ideas": []}, {"id": "3300042127", "title": "伤寒六病讲稿.第三册", "author": "林盛进", "cover": "https://cdn.weread.qq.com/weread/cover/56/cpPlatform_gM2Q36bDzY4SN5jLGnaKV1/s_cpPlatform_gM2Q36bDzY4SN5jLGnaKV1.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=db732350813ab76f4g0178d8", "progress": 82, "finished": 0, "hlCount": 3, "ideaCount": 0, "highlights": [{"text": "厚朴40克，生姜40克，半夏40克，人参5克，炙甘草10克。", "chapter": "第五十八讲 虚寒腹胀", "date": "2023-07-01", "color": 1}, {"text": "用桂枝汤发汗之后，表郁已解，但胃肠虚寒这个原始的病因并没有解除，所以，还有胃肠寒腹胀满的病理和症状，简单点说，就是表解而里未和。", "chapter": "第五十八讲 虚寒腹胀", "date": "2023-07-01", "color": 1}, {"text": "厚朴生姜半夏甘草人参汤证的病理是胃肠虚寒腹胀。", "chapter": "第五十八讲 虚寒腹胀", "date": "2023-07-01", "color": 1}], "ideas": []}, {"id": "906972", "title": "我决定活得有趣", "author": "[新加坡]蔡澜", "cover": "https://cdn.weread.qq.com/weread/cover/41/yuewen_906972/s_yuewen_9069721751249667.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=4b0327105dd6dc4b003bbc5", "progress": 84, "finished": 0, "hlCount": 3, "ideaCount": 0, "highlights": [{"text": "当成玩的，什么事都可以做", "chapter": "当成玩的，什么事都可以做", "date": "2023-04-06", "color": 1}, {"text": "有一天如果那个鬼制度被打破，儿童到学校去只是认识新朋友，大家一起唱歌游戏，那才是他们真正的幸福。", "chapter": "我们这辈人最幸福的事", "date": "2023-04-06", "color": 1}, {"text": "骨灰撒在维多利亚海港，每晚看到灿烂", "chapter": "活得有趣，才能活得精彩", "date": "2023-04-06", "color": 1}], "ideas": []}, {"id": "3300039393", "title": "零极限：创造健康、平静与财富的夏威夷疗法（全新修订本）", "author": "乔·维泰利", "cover": "https://cdn.weread.qq.com/weread/cover/14/cpPlatform_iC6hyeK7maDrAWod6hQZPS/s_cpPlatform_iC6hyeK7maDrAWod6hQZPS.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=da532e20813ab75e3g013f94", "progress": 99, "finished": 1, "hlCount": 3, "ideaCount": 0, "highlights": [{"text": "臣服才是关键。", "chapter": "附录一 零极限基本原则", "date": "2023-03-26", "color": 1}, {"text": "你可以用自己的意识，去选择你要的体验", "chapter": "附录一 零极限基本原则", "date": "2023-03-26", "color": 1}, {"text": "你意识到对于生命你可以选择却不能控制，你还意识到自己所能做的最妙的事，就是接受每个当下。", "chapter": "尾声 觉醒的三个阶段", "date": "2023-03-26", "color": 1}], "ideas": []}, {"id": "43348095", "title": "65种微习惯：轻松掌控你的行为、思维和情绪", "author": "古川武士", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/95/43348095/s_43348095.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=45132a707295707f4512f84", "progress": 69, "finished": 0, "hlCount": 3, "ideaCount": 0, "highlights": [{"text": "如果你把100%的精力都放在眼前的一件事情上，那么哪怕每天都很忙碌，精神压力也是很小的。", "chapter": "方法46 投入的情绪：感受你的心流", "date": "2022-12-21", "color": null}, {"text": "精神压力来自对过去的不甘和对未来的不安。", "chapter": "方法46 投入的情绪：感受你的心流", "date": "2022-12-19", "color": null}, {"text": "3.自发活动（占50%）：能否按照自己的心愿生活当我们被周围", "chapter": "90%的幸福都来自习惯", "date": "2022-12-18", "color": null}], "ideas": []}, {"id": "714302", "title": "斯坦福极简经济学", "author": "蒂莫西·泰勒", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/302/714302/s_714302.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=f7f327705ae63ef7f54c98b", "progress": 65, "finished": 0, "hlCount": 3, "ideaCount": 0, "highlights": [{"text": "一个月内的通胀率达到20%，甚至40%以上，称作恶性通胀", "chapter": "22 通胀率走高会使市场运作不顺畅", "date": "2022-12-21", "color": null}, {"text": "通胀不是洪水猛兽", "chapter": "22 通胀率走高会使市场运作不顺畅", "date": "2022-12-21", "color": null}, {"text": "尼克松总统觉得有必要实施全国性的工资和价格管制，结果成效不如预期，导致了生产短缺以及反对价格管制的论战。到了1974年，工资和价格管制取消，通胀率急升，1974年是11%，70年代晚期再度达到两位数。", "chapter": "22 通胀率走高会使市场运作不顺畅", "date": "2022-12-21", "color": null}], "ideas": []}, {"id": "3300013547", "title": "算法的力量：人类如何共同生存？", "author": "杰米·萨斯坎德", "cover": "https://cdn.weread.qq.com/weread/cover/47/3300013547/s_3300013547.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=7a032660813ab6bcag017e13", "progress": 62, "finished": 0, "hlCount": 3, "ideaCount": 0, "highlights": [{"text": "放眼全球，我们可以看到五种不同的民主制度，每一种都是通过数字技术实现的：协商民主、直接民主、维基民主、数据民主和人工智能民主。", "chapter": "第十二章 民主的梦想", "date": "2022-12-18", "color": null}, {"text": "区块链的社会意义在于它可以在陌生人之间实现安全交易，而无须可信的第三方中介，如银行、信用卡公司或国家。它意图解决计算机科学（和政治学）中长期存在的问题：在没有通常所说的“人际关系”的人与人之间，如何建立起“信任”之类的东西。", "chapter": "第二章 日益综合的技术", "date": "2022-12-18", "color": null}, {"text": "，一个通过自动无人机网络投递货物的邮政系统，或者将一支陆基、水基和空基自动交通工具团队作为公共交通系统，你不一定希望这些“公用事业”是私有或是私人运营的。如果它们拒绝为农村地区服务怎么办？如果它们把价格定得太高，把穷人排除在外，我们又怎么办", "chapter": "第十八章 财富的旋风", "date": "2022-12-18", "color": null}], "ideas": []}, {"id": "3300026288", "title": "了不起", "author": "冯唐", "cover": "https://cdn.weread.qq.com/weread/cover/93/cpPlatform_wkPtCw5gapNyTopt23q9vD/s_cpPlatform_wkPtCw5gapNyTopt23q9vD.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=28c32440813ab70c4g018057", "progress": 100, "finished": 1, "hlCount": 3, "ideaCount": 0, "highlights": [{"text": "禅是需要自己在日常生活的一点一滴、一言一行、一食一饭中去慢慢琢磨的。", "chapter": "在点滴日常中渐悟", "date": "2022-08-26", "color": null}, {"text": "儒家教我们拿得起，道家教我们放得下，佛家教我们想得开。", "chapter": "在点滴日常中渐悟", "date": "2022-08-26", "color": null}, {"text": "树立“不二观”，欲望可以有，但是迎着欲望当头一棒，看清欲望的本质。欲望是虚幻的，所谓好的物质都是现代社会创造出来的，让你觉得好而已，其实没有太大区别。", "chapter": "生而为人，欲望满身", "date": "2022-08-26", "color": null}], "ideas": []}, {"id": "33639323", "title": "人生无意读庄子", "author": "陈可抒", "cover": "https://cdn.weread.qq.com/weread/cover/20/YueWen_33639323/s_YueWen_33639323.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=4c732bd072014b9b4c798aa", "progress": 30, "finished": 0, "hlCount": 3, "ideaCount": 0, "highlights": [{"text": "人们对于事物尚还没有定见，却偏偏热衷于进行辩论，仅仅是为了争胜而已。", "chapter": "人亦有不芒者乎？", "date": "2022-08-14", "color": null}, {"text": "世间种种讲谈不也正是如此吗？夸夸其谈，故作高深，自以为是云蒸霞蔚的气象，其实不过是天地间微不足道而又毫无正见的朝菌罢了。", "chapter": "乐出虚，蒸成菌", "date": "2022-08-14", "color": null}, {"text": "音乐是人类的作品，风声是自然的作品，而人类与自然却都是上天的作品；音乐和风声是人籁和地籁，人类与自然的呈现，便是天籁。", "chapter": "人籁、地籁、天籁", "date": "2022-08-14", "color": null}], "ideas": []}, {"id": "614313", "title": "一切都是最好的安排", "author": "加措", "cover": "https://cdn.weread.qq.com/weread/cover/32/YueWen_614313/s_YueWen_614313.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=0fb32b10595fa90fb385a97", "progress": 0, "finished": 0, "hlCount": 3, "ideaCount": 0, "highlights": [{"text": "幸福是用来感觉的，而不是用来比较的；生活是用来经营的，而不是用来计较的；感情是用来维系的，而不是用来考验的；爱人是用来疼爱的，而不是用来伤害的。幸福的人总在营造好心情，快乐的人总在找寻好心情，智慧的人总是在传播好心情，觉悟的人总是在制造好心情。生命的价值在于你怎样勇敢地活着！", "chapter": "第4章 快乐是一种能力", "date": "2022-06-01", "color": null}, {"text": "一个人越成功，    他所经历的磨难就越多。", "chapter": "第10章 信念是菩提", "date": "2022-06-01", "color": null}, {"text": "挫折就像是一块石头，    对于弱者，它是绊脚石，    对于强者，它是垫脚石。", "chapter": "第10章 信念是菩提", "date": "2022-06-01", "color": null}], "ideas": []}, {"id": "837388", "title": "田园的微笑：《菜根谭》解密", "author": "蔡志忠", "cover": "https://cdn.weread.qq.com/weread/cover/43/YueWen_837388/s_YueWen_837388.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=d18327f05cc70cd18453bf1", "progress": 91, "finished": 0, "hlCount": 3, "ideaCount": 0, "highlights": [{"text": "现在的人想达到心中无念，但总是做不到。其实只要不追悔过去，不企盼将来，随缘当下。能做到这点，自然就会进入无我境界。", "chapter": "5 道家老庄思想", "date": "2022-03-24", "color": null}, {"text": "老子说：“失道而后德，失德而后仁，失仁而后义，失义而后礼。”", "chapter": "5 道家老庄思想", "date": "2022-03-24", "color": null}, {"text": "儒家鼓励大家邦有道时，出来做事，邦无道时，隐居以避免遭受祸害。道家刚好相反，主张“道存则隐，道废则现”。", "chapter": "5 道家老庄思想", "date": "2022-03-24", "color": null}], "ideas": []}, {"id": "677785", "title": "半导体芯片制造技术", "author": "杜中一主编", "cover": "https://cdn.weread.qq.com/weread/cover/46/YueWen_677785/s_YueWen_677785.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=337329905a5799337a7d802", "progress": 85, "finished": 0, "hlCount": 3, "ideaCount": 0, "highlights": [{"text": "最常见的可移动离子污染物是钠。钠离子同时也是在硅中移动性最强的物质，因此，对钠的控制成为硅片生产的首要目标。", "chapter": "1.3 半导体生产污染控制", "date": "2022-02-24", "color": null}, {"text": "晶体缺陷按缺陷的几何尺寸可分为点缺陷，如空位、间隙原子等；线缺陷，如位错等；面缺陷，如晶粒间界和堆垛层错等。", "chapter": "1.2 半导体材料基础", "date": "2022-02-24", "color": null}, {"text": "砷化镓具有电子迁移率高（是硅的5～6倍）、禁带宽度大（砷化镓为1.43eV，硅为1.1eV）、本征载流子浓度低、光电特性好以及耐热、抗辐射性能好和对磁场敏感等优良特性，因此用砷化镓材料制作的器件频率响应好，速度快，工作温度高，能满足集成光电子的需要。砷化镓是目前最重要的光电子材料，也是继硅材料之后最重要的微电子材料，它适合于制造高频、高速的器件和电路。", "chapter": "1.2 半导体材料基础", "date": "2022-02-24", "color": null}], "ideas": []}, {"id": "841402", "title": "悉达多", "author": "[德]赫尔曼·黑塞", "cover": "https://cdn.weread.qq.com/weread/cover/25/YueWen_841402/s_YueWen_841402.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=a22322405cd6baa2214af0a", "progress": 99, "finished": 0, "hlCount": 3, "ideaCount": 0, "highlights": [{"text": "这是一块石头。一段时间之后，它也许会化为泥土，它又会由泥土变成植物、动物或者人，从前我一定会说，这块石头仅仅是一块石头而已，它没有价值，它属于玛耶的世界，不过也许由于处在变化的循环里，它也能变成人和神灵，因此我也认为是重要的。这是从前我一定会想到的。可是现在我是这样想的，这块石头是一块石头，它也是动物、神和佛。我尊敬它和爱它，不是因为它以后会从原来的东西变成另外一种东西，而是因为很久以来它一直就是每一样东西，并且永远是每一样东西。", "chapter": "歌文达", "date": "2022-02-01", "color": null}, {"text": "“歌文达，这个世界不是不完美的，也不是在沿着一条漫长的途径逐渐向着完美发展。不，每个瞬间世界都是完美的，每一个罪恶都已经在它之中携含了恩赦，所有的孩童都是潜在的老人，所有的婴儿在身上都带着死亡，所有垂死的人必获得永恒的生命。", "chapter": "歌文达", "date": "2022-02-01", "color": null}, {"text": "每一样东西，没有以前，没有以后，只有现在和现在的实在。", "chapter": "摆渡人", "date": "2022-02-01", "color": null}], "ideas": []}, {"id": "34527944", "title": "分析与思考：黄奇帆的复旦经济课", "author": "黄奇帆", "cover": "https://cdn.weread.qq.com/weread/cover/96/YueWen_34527944/s_YueWen_34527944.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=6d432b40720edac86d477b1", "progress": 0, "finished": 1, "hlCount": 3, "ideaCount": 0, "highlights": [{"text": "第一，股票市场的总市值与GDP的比值。从海外资本市场发展来看，国民经济证券化率达到100%是资本市场成熟的标志。目前我国股票市场的总市值与GDP比值大概在60%，还远未达到100%程度，说明资本市场还有较大的发展空间。", "chapter": "面向未来的人民币发行制度", "date": "2021-12-26", "color": null}, {"text": "从2008年年底至2014年10月，美联储先后出台三轮量化宽松政策，总共购买资产约3.9万亿美元。美联储持有的资产规模占国内生产总值的比例从2007年年底的6.1%大幅升至2014年年底的25.3%，资产负债表扩张到前所未有的水平。", "chapter": "货币的“锚”及发行制度分析", "date": "2021-12-26", "color": null}, {"text": "第二，我国实行结汇制，即我国的商业银行、企业，基本上不能保存外汇，必须将收到的外汇卖给央行。因此，由于我国的货币发行的基础是外汇，而美元在我国的外汇占款、一篮子货币中占比较高，因此可以说人民币是间接锚定美元发行的。", "chapter": "货币的“锚”及发行制度分析", "date": "2021-12-26", "color": null}], "ideas": []}, {"id": "860293", "title": "神秘的量子生命", "author": "吉姆·艾尔－哈利利  约翰乔·麦克法登", "cover": "https://cdn.weread.qq.com/weread/cover/86/YueWen_860293/s_YueWen_860293.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=b30329905d2085b30d0f056", "progress": 29, "finished": 0, "hlCount": 3, "ideaCount": 0, "highlights": [{"text": "线粒体几乎肯定是从一种共生菌类进化而来的，数亿年前该菌寄生在动物和植物祖先的细胞中，后来失去了独自生存的能力。", "chapter": "生死攸关的酶", "date": "2021-12-16", "color": null}, {"text": "随机分子运动会干扰精心排列的量子系统，这种现象被称为“退相干”（decoherence）。正是这种现象快速地抵消掉了宏观非生命物体奇特的量子效应。", "chapter": "神奇的生命", "date": "2021-12-16", "color": null}, {"text": "生命就像一台复杂的分子机器。生命有序性的自我维持需要依靠酶、色素、DNA、RNA和其他生化分子的协同合作，而这些生化分子的性质则多数建立在诸如隧穿、相干性和纠缠态等量子现象上。", "chapter": "量子生物学的新发现", "date": "2020-04-08", "color": null}], "ideas": []}, {"id": "788370", "title": "奇点临近", "author": "雷·库兹韦尔", "cover": "https://cdn.weread.qq.com/weread/cover/65/YueWen_788370/s_YueWen_788370.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=85d326e05c079285d02a273", "progress": 76, "finished": 0, "hlCount": 3, "ideaCount": 0, "highlights": [{"text": "劳埃德展示了一千克物质潜在的计算容量是如何等于Pi倍的能源除以普朗克常数的。由于能源是如此大的一个数值，而普朗克常数却非常小，这个等式就产生了一个非常大的数字：约每秒5×1050次操作。", "chapter": "第3章 达到人脑的计算能力", "date": "2021-11-30", "color": null}, {"text": "随着望远镜的发明，人类可以看到数百万光年以外的其他星系。反之，如果使用显微镜，他们还可以看到细胞的结构。今天，通过不断发展的现代技术，人类的观察范围远至130亿光年外的距离，近到量子边缘的亚原子粒子。", "chapter": "第2章 技术进化理论：加速回归定律", "date": "2021-11-30", "color": null}, {"text": "微机器人是纳米机器人，它是一种血细胞大小的机器人。这些机器人会自动连接起来，形成任意的物理结构。此外，他们能够以一种引导视觉和听觉的信息方式，把虚拟现实中的东西转换到真实的现实中[插图]。", "chapter": "第1章 六大纪元", "date": "2021-11-30", "color": null}], "ideas": []}, {"id": "25622031", "title": "怎么过一天，就怎么过一生：掌控自己的生活（套装8册）", "author": "褚明宇 李尚龙等", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/31/25622031/s_25622031.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=5a3328907186f60f5a36c76", "progress": 4, "finished": 1, "hlCount": 3, "ideaCount": 0, "highlights": [{"text": "葆春老师的话说：一眼看到火葬场。李老师说这话本来没有贬义，他是", "chapter": "第一章 人生的凹凸面——面对岔路的时候我们该如何抉择", "date": "2021-11-07", "color": null}, {"text": "一帮很铁的哥们儿，有个水平不怎么样但是很拉风的乐队，有热恋中的女朋友、暗恋中的小美女，还有一拨对我有不切实际幻想的仰慕", "chapter": "第一章 人生的凹凸面——面对岔路的时候我们该如何抉择", "date": "2021-11-07", "color": null}, {"text": "答问题的人知道这个最优选择；三、这个最优选择适用于包括你在", "chapter": "第一章 人生的凹凸面——面对岔路的时候我们该如何抉择", "date": "2021-11-07", "color": null}], "ideas": []}, {"id": "37665432", "title": "五种时间：重建人生秩序", "author": "王潇", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/432/37665432/s_37665432.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=c4e32e00723eba98c4edac3", "progress": 100, "finished": 1, "hlCount": 3, "ideaCount": 0, "highlights": [{"text": "想要的究竟都有什么。其实很多世俗意义上的成功，都原本是", "chapter": "想要一切", "date": "2021-11-04", "color": null}, {"text": "金榜题名、升职加薪、结婚生子、买房买车，这些愿望都被描述得非常具体和确定，占据整个饼状图的99%。", "chapter": "拥挤的许愿池", "date": "2021-11-04", "color": null}, {"text": "做某事”，包括阅读、看电影、旅行、运动、唱歌、玩游戏、学乐器", "chapter": "拥挤的许愿池", "date": "2021-11-04", "color": null}], "ideas": []}, {"id": "910157", "title": "重塑幸福：如何活成你想要的模样", "author": "马克·曼森", "cover": "https://cdn.weread.qq.com/weread/cover/35/YueWen_910157/s_YueWen_910157.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=d6f32ea05de34dd6fdf3a65", "progress": 66, "finished": 0, "hlCount": 3, "ideaCount": 0, "highlights": [{"text": "不在乎就是去蔑视生活中那些最可怕和最艰难的挑战而仍去采取行动。不在乎就是去无视那些与我们的生活无关的无聊琐事并且笔直向前。", "chapter": "不在乎的生活艺术", "date": "2021-05-25", "color": null}, {"text": "人脑是用来储存意义的机器。我们所理解的“意义”是由大脑在两个或两个以上的体验之间进行联系生成的。", "chapter": "我们的大脑有时是不可靠的", "date": "2021-05-25", "color": null}, {"text": "强迫症是一种可怕的神经性和遗传性疾病。这种病无法治愈，能做到可控就已经很不错了。我们知道，控制这类疾病实际上就是调整人的价值观。", "chapter": "打好命运给你的烂牌", "date": "2021-05-25", "color": null}], "ideas": []}, {"id": "334185", "title": "如何说孩子才会听，怎么听孩子才肯说（大全集）", "author": "静涛 凤莲编著", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/185/334185/s_334185.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=61832f00551969618439aab", "progress": 92, "finished": 0, "hlCount": 3, "ideaCount": 0, "highlights": [{"text": "孩子们都很钦佩那些勇于探索、敢于迎接挑战的人，并乐意效仿他们。然而，大多数时候，我们却教孩子们循规蹈矩，不要冒险。．", "chapter": "发掘孩子的天赋潜能", "date": "2021-05-02", "color": null}, {"text": "其实6～12岁这一时期是培养孩子兴趣的好时期。因为这一时期孩子的神经系统发育迅速，能适应和接受一些技巧、技能的训练，其性格也已初具雏形，兴趣相对稳定，并且具有一定的自控能力，还有较为充裕的学习时间。", "chapter": "发掘孩子的天赋潜能", "date": "2021-05-02", "color": null}, {"text": "只有纵情发展孩子们的天性，才能培养出大胆创新、勇敢质疑的头脑。如果一心一意要培养顺从听话的‘乖’宝宝，就不要梦想培育出智慧如天马行空的优秀人才。”", "chapter": "发掘孩子的天赋潜能", "date": "2021-05-02", "color": null}], "ideas": []}, {"id": "569761", "title": "技术元素", "author": "凯文·凯利", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/761/569761/s_569761.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=ce5321a058b1a1ce5bb99f5", "progress": 0, "finished": 0, "hlCount": 3, "ideaCount": 0, "highlights": [{"text": "其实我们人类正是宇宙最强大力量的产物。我们就是技术——自我制造的咬尾蛇。", "chapter": "技术元素", "date": "2021-04-13", "color": null}, {"text": "第一个有持久活力的星球孕育出生命，生命提升自己以创造心智，心智又提升自己以创造技术，技术再自我提升来创造更高水平的外熵。", "chapter": "技术元素", "date": "2021-04-13", "color": null}, {"text": "技术不仅是世上最强大的力量，它可能是整个宇宙最强大的力量。", "chapter": "技术元素", "date": "2021-04-13", "color": null}], "ideas": []}, {"id": "22622910", "title": "账户：新经济与新金融之路", "author": "周子衡", "cover": "https://cdn.weread.qq.com/weread/cover/50/YueWen_22622910/s_YueWen_22622910.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=62f32320715932be62f4faf", "progress": 85, "finished": 0, "hlCount": 3, "ideaCount": 0, "highlights": [{"text": "人类社会经济体系应致力于建立一个“任何交易主体之间可在任何时间，于任何地点，交易任何商品或服务”的、现实的市场体系。", "chapter": "大萧条的启示——须实现“交易大爆炸”", "date": "2021-04-12", "color": null}, {"text": "当前以线下货币兑换上线为主的这一局面，将发生颠覆性的改变，纯粹网络货币将蓬勃发展，直至发行法定数字货币。", "chapter": "网络货币的问题——需求是根本", "date": "2021-04-12", "color": null}, {"text": "《大学》有云：苟日新，日日新，又日新。", "chapter": "引论 新经济与新金融的“进化史”", "date": "2021-04-10", "color": null}], "ideas": []}, {"id": "622127", "title": "活出最乐观的自己", "author": "[美]塞利格曼", "cover": "https://cdn.weread.qq.com/weread/cover/84/YueWen_622127/s_YueWen_622127.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=47632c80597e2f476b5050a", "progress": 8, "finished": 0, "hlCount": 3, "ideaCount": 0, "highlights": [{"text": "当我们高估了自己的无助感时，其他力量就会左右我们孩子的前途。", "chapter": "第1章 悲观者与乐观者的画像", "date": "2020-09-04", "color": null}, {"text": "那就是保持一个积极健康的心态对于我们的事业和成长都极为重要，而塞利格曼的著作恰恰能帮助我们做到这一点。", "chapter": "幸福可以学来，幸福可以到永远", "date": "2020-09-04", "color": null}, {"text": "他一针见血地点破了当代心理学发展的弊病，指出心理学不应该只研究人类的弱点和问题，而应该同时关注人类的美德和优势。", "chapter": "幸福可以学来，幸福可以到永远", "date": "2020-09-04", "color": null}], "ideas": []}, {"id": "809766", "title": "易中天中华史：奠基者", "author": "易中天", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/766/809766/s_809766.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=17132e405c5b261714cafd4", "progress": 100, "finished": 1, "hlCount": 3, "ideaCount": 0, "highlights": [{"text": "周人创立了四大制度——井田、封建、宗法、礼乐。井田是经济制度，封建是政治制度，宗法是社会制度，礼乐是文化制度。井田顾民生，封建从民意，宗法敦民俗，礼乐安民心。", "chapter": "重新安装系统", "date": "2020-03-08", "color": null}, {"text": "如此复杂的系统工程，当然一言难尽，但线索是清晰的——因为“君权天授”，所以要“以人为本”；因为以人为本，所以要“以德治国”；因为以德治国，所以要以礼维持秩序，以乐保证和谐，即“以礼立序，以乐致和”。天授是旗帜，人本是纲领，德治是“一个中心”，礼乐是“两个基本点”，这就是周公的思想体系。", "chapter": "重新安装系统", "date": "2020-03-08", "color": null}, {"text": "从甲骨文和金文的字形看，礼就是礼器，即祭礼；乐就是乐器，即乐舞。这就是本来意义上的礼乐。", "chapter": "重新安装系统", "date": "2020-03-08", "color": null}], "ideas": []}, {"id": "32351714", "title": "人体简史", "author": "[英]比尔·布莱森", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/714/32351714/s_32351714.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=698326e071eda5e269837c3", "progress": 2, "finished": 0, "hlCount": 2, "ideaCount": 1, "highlights": [{"text": "宇宙中最超凡的东西，就在你的头颅里面。哪怕你穿梭于外太空的每一寸，说不定都找不到任何东西比你两耳之间这两斤半软乎乎如海绵般的物事更神奇、更复杂、功能更强劲的了。", "chapter": "第四章 大脑：你的大脑80%都是水", "date": "2022-10-21", "color": null}, {"text": "构建一个人需要59种元素。其中6种——碳、氧、氢、氮、钙和磷——占了我们身体的99.1％", "chapter": "第一章 制造一个人要花多少钱", "date": "2020-09-19", "color": null}], "ideas": [{"content": "人就是各种元素在宇宙的这锅汤里面的一种涌现。", "abstract": "构建一个人需要59种元素。其中6种——碳、氧、氢、氮、钙和磷——占了我们身体的99.1％", "chapter": "", "date": "2020-09-19", "star": null}]}, {"id": "26392839", "title": "戴维斯王朝", "author": "约翰·罗斯柴尔德", "cover": "https://cdn.weread.qq.com/weread/cover/50/YueWen_26392839/s_YueWen_26392839.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=a09322407192b907a091b95", "progress": 100, "finished": 1, "hlCount": 2, "ideaCount": 1, "highlights": [{"text": "狂野比尔做出了一个头脑清晰的论断：“世界的未来不会躺在地毯上。", "chapter": "岳父离世", "date": "2020-09-09", "color": null}, {"text": "股票不会去理会报纸上的那些评论，或那些骇人的头条。", "chapter": "股市升跌与经济好坏并非完全同步", "date": "2020-09-09", "color": null}], "ideas": [{"content": "有眼光", "abstract": "狂野比尔做出了一个头脑清晰的论断：“世界的未来不会躺在地毯上。", "chapter": "", "date": "2020-09-09", "star": null}]}, {"id": "921459", "title": "理想国", "author": "[古希腊]柏拉图", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/459/921459/s_921459.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=810324b05e0f7381080a72e", "progress": 23, "finished": 0, "hlCount": 2, "ideaCount": 1, "highlights": [{"text": "当一个人对肉体上的享受越来越少时，那他对精神上的畅谈也就要求越多。", "chapter": "第2章 财产 正义 节制", "date": "2020-05-25", "color": null}, {"text": "到了老年时代，对于情爱一事已没了兴趣，但能使人清心寡欲，体会到另一番自由随性的快乐感受，这种境界不仅是像从一个暴君手里脱离苦海，更是从无数暴君那里脱离苦海。", "chapter": "第2章 财产 正义 节制", "date": "2020-05-25", "color": null}], "ideas": [{"content": "少了一份爱恨情仇。找了一份对爱的执着。", "abstract": "到了老年时代，对于情爱一事已没了兴趣，但能使人清心寡欲，体会到另一番自由随性的快乐感受，这种境界不仅是像从一个暴君手里脱离苦海，更是从无数暴君那里脱离苦海。", "chapter": "", "date": "2020-05-25", "star": null}]}, {"id": "920939", "title": "资本论（超值白金版）", "author": "马克思", "cover": "https://cdn.weread.qq.com/weread/cover/84/YueWen_920939/s_YueWen_920939.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=f1c32f005e0d6bf1c506c79", "progress": 32, "finished": 0, "hlCount": 1, "ideaCount": 2, "highlights": [{"text": "实际上，机器是生产剩余价值的手段", "chapter": "第十三章 机器和大工业", "date": "2019-04-05", "color": null}], "ideas": [{"content": "重点", "abstract": "如果工人每天生活资料的价值代表6个物化劳动小时的话，那么平均每天劳动6小时就不是为资本家劳动，而是独立地为自己劳动。", "chapter": "", "date": "2019-04-05", "star": null}, {"content": "意义重大", "abstract": "1776年瓦特制造的蒸汽机点燃了“工业革命”的导火线。改进后的蒸汽机广泛应用于各种生产领域。1814年，英国人史蒂芬将瓦特的蒸汽机装在火车上，从而开创了陆路运输的新时代，这些庞然大物改变了当时的社会与人们的生活。", "chapter": "", "date": "2019-04-05", "star": null}]}, {"id": "3300160037", "title": "庄子（文白对照）", "author": "[战国]庄周", "cover": "https://cdn.weread.qq.com/weread/cover/9/cpplatform_talyhjz759nxpwavdard7s/s_cpplatform_talyhjz759nxpwavdard7s1755855910.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=42b32030813aba503g01794e", "progress": 100, "finished": 1, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "我于形骸之外，不亦过乎！”子产蹴然改容更貌曰：“子无乃称！”", "chapter": "德充符", "date": "2026-04-09", "color": null}, {"text": "他站立时不施教，坐着时不议论，弟子们空着手去，", "chapter": "德充符", "date": "2026-04-09", "color": null}], "ideas": []}, {"id": "3300146060", "title": "肉蒲团（白话版）", "author": "[明末清初]李渔 简读编辑组", "cover": "https://cdn.weread.qq.com/weread/cover/28/cpplatform_rhjvvqwug9jgb3zn2b1nbc/s_cpplatform_rhjvvqwug9jgb3zn2b1nbc1748330412.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=bd2328b0813ab9f8eg01091b", "progress": 100, "finished": 1, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "人，更像在宣判，锋利却不见血。赛昆仑一贯自负，性子倔得像山石，平时听不得别人一句劝，可这一回，竟是哑了口，低头沉", "chapter": "第二十回 宿业已偿 心火归寂", "date": "2026-01-28", "color": null}, {"text": "传之后世。若侥幸高中进士，便入仕为国；若文运不", "chapter": "第二回 问道山中 尘外得真", "date": "2026-01-27", "color": null}], "ideas": []}, {"id": "25081177", "title": "大圆满前行（全三册）", "author": "嘎玛仁波切", "cover": "https://cdn.weread.qq.com/weread/cover/35/YueWen_25081177/s_YueWen_25081177.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=c5632530717eb559c560ae0", "progress": 14, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "练", "chapter": "第三章 起修", "date": "2025-12-12", "color": null}, {"text": "妄念", "chapter": "第一章 关于大圆满前行", "date": "2025-12-09", "color": null}], "ideas": []}, {"id": "3300046907", "title": "幸福的方法", "author": "泰勒·本·沙哈尔", "cover": "https://cdn.weread.qq.com/weread/cover/48/cpplatform_3t4c7h4z7txnsyhgbiuyzm/s_cpplatform_3t4c7h4z7txnsyhgbiuyzm1674095975.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=e2e329a0813ab78d2g017d32", "progress": 12, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "在习惯被固定下来之前，不要试图养成新习惯。就像托尼·施瓦茨说的，“微小的进步，好过野心勃勃却遭遇失败……不要着急，成功自然会像雪球一样越滚越大”。", "chapter": "从幸福到更幸福", "date": "2025-09-12", "color": 1}, {"text": "西方科学家喜欢很透彻地研究物体，包括把它们解剖、分解、不断放大以仔细研究；东方科学家则把事物联系起来，从整体的角度出发，缩小并退后一步，系统观察。", "chapter": "致中国读者", "date": "2025-09-12", "color": 1}], "ideas": []}, {"id": "3300151174", "title": "2049：未来10000天的可能", "author": "[美]凯文·凯利 吴晨", "cover": "https://cdn.weread.qq.com/weread/cover/69/cpplatform_ftvzmdf1yxwhfrpnjrrvnj/s_cpplatform_ftvzmdf1yxwhfrpnjrrvnj1751445133.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=bdd325d0813aba18dg0142a8", "progress": 73, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "中国将成为未来汽车制造的主导者，全球最棒的电动车制造商也许会在中国出现，它将远远超过特斯拉。", "chapter": "自动驾驶的渐进式发展", "date": "2025-09-03", "color": 1}, {"text": "“上载”大脑，马斯克所渴望的人机合体，甚至将人的意识上载到云端，实现永生，仍将是科幻小说里才有的情节，距离实现恐怕至少要100年的时间。", "chapter": "从昆虫大脑到分布式智能", "date": "2025-09-03", "color": 1}], "ideas": []}, {"id": "814415", "title": "人间词话", "author": "[清]王国维", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/415/814415/s_814415.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=97f32cc05c6d4f97f65e89c", "progress": 37, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "形象鲜艳，视觉开阔，达到了平淡的境界。", "chapter": "二十二", "date": "2025-09-01", "color": 1}, {"text": "枝头红杏本来是视觉范围的，而“闹”则属于听觉的范围，巧妙运用通感的手法，将无声静止的画面写得生机勃勃、充满动态，浓郁的春色在喧闹的枝头被活灵活现地表现出来", "chapter": "七", "date": "2025-09-01", "color": 1}], "ideas": []}, {"id": "3300145722", "title": "花凋（轻经典）", "author": "张爱玲", "cover": "https://cdn.weread.qq.com/weread/cover/43/cpplatform_eh78v2gszwvou1b2vymgzs/s_cpplatform_eh78v2gszwvou1b2vymgzs1752237732.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=3b932cf0813ab9f6cg012c8c", "progress": 95, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "开了。她在枕上别过脸去，合上眼睛，面白如纸，但", "chapter": "花凋", "date": "2025-06-03", "color": null}, {"text": "能接受。可是真遇着了一身病痛的人，他们止睁大", "chapter": "花凋", "date": "2025-06-03", "color": null}], "ideas": []}, {"id": "3300142056", "title": "目标中国：华盛顿的“屠龙”战略", "author": "[美]威廉·恩道尔", "cover": "https://cdn.weread.qq.com/weread/cover/27/cpplatform_kjemgaxambyvammclqo2mw/s_cpplatform_kjemgaxambyvammclqo2mw1745311995.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=b1432810813ab9dfdg016c1f", "progress": 96, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "2010年的汽车保有量高达1990年的90倍，有人甚至预测在2030年之前就会超过美国。", "chapter": "命系石油", "date": "2025-05-06", "color": 1}, {"text": "2014年3月，中情局策划的独立广场政变强迫基辅脱离俄罗斯，迫使乌克兰合法选举的总统维克托·亚努科维奇流亡俄罗斯", "chapter": "总序 现代世界地缘政治简史", "date": "2025-05-02", "color": 1}], "ideas": []}, {"id": "3300139132", "title": "智能涌现： AI时代的思考与探索", "author": "张亚勤", "cover": "https://cdn.weread.qq.com/weread/cover/40/cpplatform_txtzwqvyhcukxklkh4m8s7/s_cpplatform_txtzwqvyhcukxklkh4m8s71743390035.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=69b32970813ab9cd9g012928", "progress": 67, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "在诸多计算与通信相关的定律中，有三则定律可以视作迄今为止计算与通信范式的根本——香农定律、冯·诺依曼架构和摩尔定律。", "chapter": "第2章 人工智能是第四次工业革命的技术引擎", "date": "2025-05-04", "color": 1}, {"text": "在深度学习技术探索的早期，递归神经网络(RNN)、卷积神经网络(CNN)、长短期记忆人工神经网络(LSTM)是主要的代表性算法。", "chapter": "第2章 人工智能是第四次工业革命的技术引擎", "date": "2025-05-04", "color": 1}], "ideas": []}, {"id": "3300034297", "title": "西蒙学习法：如何在短时间内快速学会新知识", "author": "友荣方略　著", "cover": "https://cdn.weread.qq.com/weread/cover/62/cpPlatform_qz1HZEsKKgjd3PZEUTUyPG/s_cpPlatform_qz1HZEsKKgjd3PZEUTUyPG.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=a7f32050813ab73e5g017342", "progress": 12, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "因为读书学习本身就是西蒙的兴趣，就是他喜欢的。", "chapter": "1.4 源于热爱：西蒙的学习成长有何启示", "date": "2024-12-28", "color": 1}, {"text": "学习和记忆1个组块大约需要1.5分钟，5万个组块则大约需要7.5万分钟，大约是1250个小时。假设每天学习8个小时，大约需要156天，大约是5.2个月。", "chapter": "前言", "date": "2024-12-28", "color": 1}], "ideas": []}, {"id": "3300072108", "title": "货币金字塔：从黄金、美元到比特币和央行数字货币（凹阅读）【有料、有趣、有意涵的金融科普书。彻底了解货币的必读书目!】", "author": "[美]尼克·巴蒂亚", "cover": "https://cdn.weread.qq.com/weread/cover/26/cpplatform_kagjpbtpeu7nyz85r7w6ba/s_cpplatform_kagjpbtpeu7nyz85r7w6ba1695693984.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=f29324a0813ab82aag018ac6", "progress": 91, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "比特币将可能取代黄金成为最受欢迎的中立货币，并在总市值上超过黄金。", "chapter": "第十章 货币面额的自由", "date": "2024-11-21", "color": 1}, {"text": "世界各国政府和企业将购买BTC并将其作为现金储备持有，因为它减少了对当前美元体系的依赖，这表明全球美元计价的时代正在向加密货币的方向迈进，而不是像人民币或欧元等任何其他政府货币过渡。", "chapter": "第十章 货币面额的自由", "date": "2024-11-21", "color": 1}], "ideas": []}, {"id": "37477534", "title": "早起的奇迹", "author": "哈尔·埃尔罗德", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/534/37477534/s_37477534.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=e9c32220723bdc9ee9ca9c7", "progress": 17, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "“你的成功水平很少能超过自己的个人发展水平，因为你是什么水平，就会创造什么水平的成功。”", "chapter": "用2级能力怎么创造10级成功？", "date": "2023-11-02", "color": 1}, {"text": "“你最大的冒险， 就是过梦想中的生活。”", "chapter": "从“负分人生”到“满分人生”的小秘诀", "date": "2023-11-02", "color": 1}], "ideas": []}, {"id": "43180429", "title": "万物原理", "author": "弗兰克·维尔切克", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/429/43180429/s_43180429.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=d5932b607292e18dd59c7b9", "progress": 33, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "“时间就是阻止所有事情同时发生的东西。”", "chapter": "02. 丰富的时间", "date": "2023-08-03", "color": 1}, {"text": "时空决定了物质如何运动，物质决定了时空如何弯曲。", "chapter": "04. 极少的定律", "date": "2023-08-03", "color": 1}], "ideas": []}, {"id": "41598972", "title": "工作、消费主义和新穷人", "author": "齐格蒙特·鲍曼", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/972/41598972/s_41598972.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=c9d327e0727abffcc9d74ab", "progress": 100, "finished": 1, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "工作伦理本质上是对自由的摒弃。", "chapter": "第一章 工作的意义：创造工作伦理", "date": "2023-06-26", "color": 5}, {"text": "如果认为标价牌是区分工作与非工作、努力与懒惰的标准，那是对人类本性的贬低；如果认为没有收益，人们宁愿闲着，让自己的技能和想象力腐烂生锈，那是对人类本性的肢解。", "chapter": "第六章 新穷人的前景", "date": "2021-12-25", "color": null}], "ideas": []}, {"id": "3300045422", "title": "中医基础理论（全国中医药行业高等教育“十四五”规划教材）", "author": "郑洪新 杨柱", "cover": "https://cdn.weread.qq.com/weread/cover/19/cpplatform_fcjvinvsndgobwy3xjf1lk/s_cpplatform_fcjvinvsndgobwy3xjf1lk1673405925.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=c9b323a0813ab783eg012fc1", "progress": 24, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "以五行相克理论说明五脏之间的制约关系：水克火，以应肾水上济于心，防止心火之亢盛；火克金，以应心火之阳热，制约肺气清肃太过；金克木，以应肺气清肃下降，抑制肝气升发太过；木克土，以应肝气条达舒畅，疏泄脾气之壅滞；土克水，以应脾之运化水液，堤防肾水失常泛滥。", "chapter": "第三节 五行学说", "date": "2023-06-25", "color": 5}, {"text": "精气血津液是构成人体和维持生命活动的基本物质。其中，气属阳，精血津液属阴", "chapter": "第二节 阴阳学说", "date": "2023-06-25", "color": 5}], "ideas": []}, {"id": "566431", "title": "从0到1：开启商业与未来的秘密", "author": "彼得·蒂尔 布莱克·马斯特斯", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/431/566431/s_566431.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=3973284058a49f39706f0c0", "progress": 98, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "需求方面的差别更大。不像工业化国家的人，计算机不渴望奢华大餐，不追求法国卡普费拉的海景别墅；它们需要的只是微不足道的电量，它们甚至不够聪明来提出要求。", "chapter": "全球化vs.科技", "date": "2023-06-20", "color": 1}, {"text": "。要保持公司的正常运转，员工的外貌和国籍并不重要，但他们必须同我们一样痴迷于数字货币。", "chapter": "每个员工都与众不同", "date": "2023-06-20", "color": 1}], "ideas": []}, {"id": "42557162", "title": "进化的力量", "author": "刘润", "cover": "https://cdn.weread.qq.com/weread/cover/12/YueWen_42557162/s_YueWen_42557162.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=b4132f6072895eeab41b898", "progress": 99, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "教育智能硬件为什么会火？因为智能硬件（产品）相对于教育培训（服务）来说可能是一个更大的赛道。每一场培训都需要占用一个教师的交付时间，边际成本很高。而硬件的好处是完全不占用教师的时间，如果需求抓得准，可以达到巨大的量。", "chapter": "第8章 疯狂生长", "date": "2023-05-19", "color": 1}, {"text": "一是要积累足够多的本金，a要尽量足够大。这是为了能在后面放大自己的收益。二是等待时间窗口。机会没来，静静等待；机会来了，不要手软。", "chapter": "找到增长飞轮，实现指数级增长", "date": "2023-05-19", "color": 1}], "ideas": []}, {"id": "3300018231", "title": "AI未来进行式（豆包的情感陪伴、机器人的情绪价值、宇树科技……AI未来全部预言）", "author": "李开复 陈楸帆", "cover": "https://cdn.weread.qq.com/weread/cover/31/3300018231/s_3300018231.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=0bc32b20813ab6d9fg0114c1", "progress": 100, "finished": 1, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "奇点时代将在2045年到来，距离2042年不远。", "chapter": "丰饶时代之后，会是奇点时代吗", "date": "2023-06-19", "color": 1}, {"text": "这就是电子游戏，只不过游戏的名字叫‘工作’……", "chapter": "开复导读", "date": "2023-06-19", "color": 1}], "ideas": []}, {"id": "3300042720", "title": "开启你的高维智慧", "author": "刘丰", "cover": "https://cdn.weread.qq.com/weread/cover/89/cpPlatform_be99f6vVfCxNcD8G8MEcoP/s_cpPlatform_be99f6vVfCxNcD8G8MEcoP.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=07c321b0813ab7730g010b98", "progress": 12, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "这个空间的任意质点都具足宇宙中的所有信息和它们的相互关系，这叫宇宙全息律。也就是我们这个空间中的任意质点都具足宇宙中的所有智慧。", "chapter": "第一部分 多元文化系统集成与交响的现实意义", "date": "2023-04-04", "color": 1}, {"text": "起心N维在无穷，存在至简正弦涌，一切呈现投影重，零维全息万有中。", "chapter": "导言", "date": "2023-04-03", "color": 1}], "ideas": []}, {"id": "22791699", "title": "庄子諵譁", "author": "南怀瑾", "cover": "https://cdn.weread.qq.com/weread/cover/19/YueWen_22791699/s_YueWen_22791699.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=69a324a0715bc61369affcc", "progress": 90, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "拔一毛以利天下不为也", "chapter": "为人为己之争", "date": "2023-01-31", "color": null}, {"text": "一个非常重要的中心点，大家不要忽略，就是人如果懂了这个道，虽然在自然变化之中，自己却能够做宇宙之主，主宰自己的生命；这就是生命的升华，这种人叫做真", "chapter": "顺自然 逆自然", "date": "2022-12-23", "color": null}], "ideas": []}, {"id": "134933", "title": "世界上最伟大的投资书", "author": "邢群麟 王巧", "cover": "https://cdn.weread.qq.com/weread/cover/19/YueWen_134933/s_YueWen_134933.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=de332200520f15de306d96e", "progress": 34, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "公认的投资大师、美国富达麦哲伦基金管理人彼得·林奇的投资方法其实很简单，就是人人皆知的“双10%”守则：即在目标股从底部上涨10%时买入，在从顶部下跌10%时卖出，结果其收益总是大大高于整天用各种技术分析方法去发掘买卖点的人。这就是对耐心的回报。", "chapter": "《股票作手回忆录》 ", "date": "2022-12-26", "color": null}, {"text": "端正心态，做到“不急、不怕、不贪、不悔”，只有这样，我们才能享受到投资的乐趣而不是投机的心酸。", "chapter": "《漫步华尔街》 ", "date": "2022-12-26", "color": null}], "ideas": []}, {"id": "36540956", "title": "樊登讲论语（套装全2册）", "author": "樊登", "cover": "https://cdn.weread.qq.com/weread/cover/84/yuewen_36540956/s_yuewen_365409561678700081.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=d1132290722d921cd11fabb", "progress": 4, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "这句话合起来，就是你要去关注内在的美，而不要过于看重外在的东西。", "chapter": "贤贤易色：别沉迷于外在的美好", "date": "2022-12-18", "color": null}, {"text": "无论外在的世界如何，我只要努力做好自己能够掌控的部分就够了。", "chapter": "自序 《论语》塑造了我", "date": "2022-12-18", "color": null}], "ideas": []}, {"id": "3300026099", "title": "人类之旅：财富与不平等的起源", "author": "奥戴德·盖勒", "cover": "https://cdn.weread.qq.com/weread/cover/28/cpPlatform_sfJ7PmCdtwbzTB7CXZPive/s_cpPlatform_sfJ7PmCdtwbzTB7CXZPive.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=d9032430813ab70b1g01997e", "progress": 66, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "英国政治经济学家亚当·斯密和大卫·李嘉图就强调过专业分工与贸易对促进经济繁荣的重要性", "chapter": "第8章 制度的指纹", "date": "2022-12-18", "color": null}, {"text": "部分原因在于大脑有两个主要弱点。第一，我们的大脑消耗的能量太多，它只占人体重量的2%，耗能却高达20%。", "chapter": "第一篇 人类的奥德赛之旅", "date": "2022-12-18", "color": null}], "ideas": []}, {"id": "832038", "title": "道德经：百万读者，过万好评（全注全译典藏版）", "author": "[春秋]老子 李若水译评", "cover": "https://cdn.weread.qq.com/weread/cover/50/YueWen_832038/s_YueWen_832038.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=d81323305cb226d8152b3d7", "progress": 78, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "福因祸而生，人遭祸而能悔过责己，修道行养，则祸去福来。祸伏匿于福中，人得福而为骄恣，则福去祸来。祸福更相生，谁能知其穷极时？", "chapter": "第五十八章 祸兮福倚，福兮祸伏", "date": "2022-12-02", "color": null}, {"text": "人的个性天生，需要保持，也改变不了。但人毕竟活在社会中，所以个性必须融于共性之中，做到和光同尘", "chapter": "第五十八章 祸兮福倚，福兮祸伏", "date": "2022-12-02", "color": null}], "ideas": []}, {"id": "32880010", "title": "在故宫寻找苏东坡", "author": "祝勇", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/10/32880010/s_32880010.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=bcc3289071f5b58abccf05c", "progress": 100, "finished": 1, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "苏东坡说，自己就像是小蚂蚁不慎跌入一小片水洼，以为落入大海，于是慌慌张张爬上草叶，心慌意乱，不知道会漂向何方。但用不了多久，水洼干涸，小蚂蚁就会生还。从人类的眼光来看，小蚂蚁很可笑，同样，从天地的视角里，他自己的个人悲哀也同样可笑。", "chapter": "七", "date": "2022-08-26", "color": null}, {"text": "读诗与写诗，其实都是一个选定自我的过程。一个人，喜欢什么样的诗，他自己就是一个什么样的人。", "chapter": "五", "date": "2022-08-26", "color": null}], "ideas": []}, {"id": "27416208", "title": "象与骑象人", "author": "乔纳森·海特 ", "cover": "https://cdn.weread.qq.com/weread/cover/58/YueWen_27416208/s_YueWen_27416208.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=34132b0071a256903410e86", "progress": 38, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "人类是一种悬浮在自己所编织的意义之网中的动物。", "chapter": "如何寻得完满之道", "date": "2022-08-19", "color": null}, {"text": "我们每个人都很虚伪，当我们蔑视别人虚伪之时，更显得自己加倍虚伪。", "chapter": "是什么让我们虚伪", "date": "2022-08-19", "color": null}], "ideas": []}, {"id": "934365", "title": "西方哲学史：从古希腊到当下", "author": "奎纳尔·希尔贝克 尼尔斯·吉列尔", "cover": "https://cdn.weread.qq.com/weread/cover/92/YueWen_934365/s_YueWen_934365.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=5aa32d705e41dd5aaf9ea31", "progress": 94, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "。与萨特一样，德·波伏娃不要孩子，以此来选择使这种“自然的强制”减小到最低程度。", "chapter": "第八节 认同和承认——西蒙·德·波伏娃与女性主义哲学", "date": "2022-06-29", "color": null}, {"text": "在存在主义中，具有核心意义的是认同（identity）问题：我到底是谁？萨特认为，在界定我们的认同这一点上，原则上我们是自由的。我们扮演的角色是没有任何脚本的！不存在什么“本质”可以告诉我们是谁、我们应当是什么。我们都是自由的，我们都承担着为这存在之谜寻找答案——编造答案——的责任。", "chapter": "第七节 现象学和存在主义——胡塞尔和萨特", "date": "2022-06-29", "color": null}], "ideas": []}, {"id": "23768926", "title": "物联网之芯：传感器件与通信芯片设计", "author": "曾凡太 边栋 徐胜朋", "cover": "https://cdn.weread.qq.com/weread/cover/17/yuewen_23768926/s_yuewen_237689261735184701.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=f5d32ee0716aaf5ef5d0680", "progress": 0, "finished": 1, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "材料型传感器，就是利用某些功能材料本身所具有的内在特性及物理效应（力敏效应、光电效应、压电效应和热电效应等）来感知被测量，并转换成可用电信号的传感器。", "chapter": "3.2 材料型传感器", "date": "2022-06-22", "color": null}, {"text": "物联网芯片产业主要包括RFID芯片、移动芯片、M2M芯片、微控制器芯片、无线传感器芯片、安全芯片、移动支付芯片、通信射频芯片和身份识别类芯片等。", "chapter": "序言 “芯”随“物”动，“物”依“芯”联", "date": "2022-06-22", "color": null}], "ideas": []}, {"id": "40055543", "title": "置身事内：中国政府与经济发展", "author": "兰小欢", "cover": "https://cdn.weread.qq.com/weread/cover/52/YueWen_40055543/s_YueWen_40055543.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=2a332d10726332f72a34943", "progress": 74, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "中国人财富的压舱石是房子，美国人财富的压舱石是金融资产。这个重大差别可以帮助理解两国的一些基本政策，比如中国对房市的重视以及美国对股市的重视。", "chapter": "第一节 房价与居民债务", "date": "2022-05-19", "color": null}, {"text": "从时间点上看，大规模的土地财政收入始于21世纪初。2001年所得税改革后，中央财政进一步集权，拿走了企业所得税的六成。从那以后，地方政府发展经济的方式就从之前的“工业化”变成了“工业化与城市化”两手抓：一方面继续低价供应大量工业用地，招商引资；另一方面限制商住用地供给，从不断攀升的地价中赚取土地垄断收益。这些年出让的城市土地中，工业用地面积约占一半，但出让价格极低：2000年每平方米是444元，2018年是820元，只涨了85%。而商业用地价格增长了4.6倍，住宅用地价格更是猛增了7.4倍（图2-5）。", "chapter": "第二节 土地财政", "date": "2022-05-19", "color": null}], "ideas": []}, {"id": "35177933", "title": "财富的逻辑（套装全两册）", "author": "陈志武", "cover": "https://cdn.weread.qq.com/weread/cover/10/YueWen_35177933/s_YueWen_35177933.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=a2e327507218c5cda2eff51", "progress": 68, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "人为管理的投资基金无法长久打败股市大盘指数。", "chapter": "第13章 社保基金应采用指数投资法", "date": "2022-05-19", "color": null}, {"text": "西方国家今天集中精力于产业链最前端和最后端的发展，最前端包括理念的创新、最新技术的发明、知识产权的维护、企业融资、资本市场等，最后端也就是营销，这两部分是经济增加值最多的阶段。", "chapter": "第23章 全球化下的中国选择", "date": "2022-05-19", "color": null}], "ideas": []}, {"id": "924187", "title": "说文解字全鉴（珍藏版）", "author": "[汉]许慎", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/187/924187/s_924187.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=c8832a205e1a1bc88c499b8", "progress": 0, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "汉字字形的演变大体经历了甲骨文—金文—大篆—小篆—隶书—草书—楷书—行书等几个阶段。", "chapter": "前言", "date": "2022-03-29", "color": null}, {"text": "《说文解字》是中国第一部系统地分析汉字字形和考究字源的字书，也是文字学方面最具权威的古典著作，是我们研究中国汉字、了解中国文化的必备工具书。", "chapter": "内容提要", "date": "2022-03-29", "color": null}], "ideas": []}, {"id": "851633", "title": "沙丘", "author": "弗兰克·赫伯特", "cover": "https://cdn.weread.qq.com/weread/cover/50/yuewen_851633/s_yuewen_8516331708661306.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=56332f105cfeb1563f0721e", "progress": 100, "finished": 1, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "最不同寻常的人类，是贝尼·杰瑟里特姐妹会的女士，她们可以拥有共同的记忆——这一概念主要是基于卡尔·古斯塔夫·荣格的学说，他认为存在一种“集体潜意识”，是人类先天就具有的一种共同的“内容和行为模式”。", "chapter": "后记", "date": "2022-03-28", "color": null}, {"text": "有留必有去；有爱必有恨；有和平，也会有战争。", "chapter": "21", "date": "2022-03-27", "color": null}], "ideas": []}, {"id": "26843101", "title": "从工业化到城市化：未来30年经济增长的可行路径", "author": "徐远", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/101/26843101/s_26843101.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=a3432920719997dda341447", "progress": 99, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "展望未来，我国改革开放的历史过程和未来方向可以归纳为“从工业化到城市化”。", "chapter": "第十五章 从工业化到城市化：中国改革开放的一个观察视角", "date": "2022-02-10", "color": null}, {"text": "乡土社会的解体，是工业化、城市化的必然结果。", "chapter": "第六篇 结语", "date": "2022-02-10", "color": null}], "ideas": []}, {"id": "933885", "title": "人口创新力：大国崛起的机会与陷阱", "author": "梁建章 黄文政", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/885/933885/s_933885.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=20b32b505e3ffd20b73b97e", "progress": 98, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "唯一有机会与美国竞争的国家只剩下了中国和印度。", "chapter": "后记 人口、创新和文明的竞争", "date": "2022-02-07", "color": null}, {"text": "到2050年，非洲人口将占世界人口的25%（目前只有14%）。到2100年，非洲的人口将占世界人口的40%，超过40亿。", "chapter": "第一章 全球人口发展趋势", "date": "2022-02-05", "color": null}], "ideas": []}, {"id": "839177", "title": "易中天中华史·第二部：秦汉魏晋南北朝（套装共6册）", "author": "易中天", "cover": "https://cdn.weread.qq.com/weread/cover/71/YueWen_839177/s_YueWen_839177.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=f1e327d05cce09f1eb6a815", "progress": 98, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "乱世出英雄，也出思想。事实上，正如有春秋战国的礼坏乐崩，才有百家争鸣；有汉末以后的腐朽溃烂，也才有魏晋风度。", "chapter": "魏之亡", "date": "2022-02-03", "color": null}, {"text": "这一年，司马睿在建康（今南京）即位，是为东晋元帝。", "chapter": "魏之亡", "date": "2022-02-03", "color": null}], "ideas": []}, {"id": "858434", "title": "我不过低配的人生", "author": "雾满拦江", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/434/858434/s_858434.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=c80323b05d1942c806177d7", "progress": 88, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "人的智商，与其内心深处的恐惧成反比，恐惧越大，智商越低。当恐惧大到足够程度，智商飙降为零——最大的恐惧，会让人大脑一片空白，甚至丧失反应能力。这种情况，就是恐惧导致智商消失的最常见情形。", "chapter": "你要相信生活会改变", "date": "2022-01-24", "color": null}, {"text": "等杀光了政敌，赵高感觉，李斯这货，已经没什么利用价值了，就向秦二世说：陛下，你有没有发现，丞", "chapter": "你要相信生活会改变", "date": "2021-11-02", "color": null}], "ideas": []}, {"id": "856239", "title": "非暴力沟通", "author": "马歇尔·卢森堡", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/239/856239/s_856239.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=684323505d10af6849e6c12", "progress": 89, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "如果以苛刻的态度对人对己，我们的心情也好不到哪里去。通过运用非暴力沟通，我们不再试图分析自己或他人有什么毛病，而是用心去了解我们的需要，这样，我们的内心就会逐渐变得平和。", "chapter": "心灵环保", "date": "2022-01-12", "color": null}, {"text": "愤怒是我们的思维方式造成的。它的核心是尚未满足的需要。如果我们能够借助它来提醒自己——我们有需要没有得到满足", "chapter": "“合理的愤怒”？", "date": "2022-01-12", "color": null}], "ideas": []}, {"id": "35449548", "title": "第一性原理", "author": "李善友", "cover": "https://cdn.weread.qq.com/weread/cover/82/YueWen_35449548/s_YueWen_35449548.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=e8032c10721ceacce804ae9", "progress": 0, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "正是因为有了“主体性认知”和“群体信念”的存在，所以在破除隐含假设的逻辑之前，必须先破除两件事：一是“我错了”；二是“我们错了”。把“我”“我们”和“我的思想”“我们的思想”之间密不可分的结打开，我认为这是批判性思维最重要的预备性的工作。简单来说，我们要勇于承认两件事情：一是“我错了”；二是“我们错了”。", "chapter": "批判性思维", "date": "2021-12-11", "color": null}, {"text": "主体性认同作为一种在人类基因中天然存在的认知与行动倾向，在现实中经常会为我们带来很多不必要的麻烦。", "chapter": "群体信念", "date": "2021-12-11", "color": null}], "ideas": []}, {"id": "917692", "title": "终极算法：机器学习和人工智能如何重塑世界", "author": "佩德罗·多明戈斯", "cover": "https://cdn.weread.qq.com/weread/cover/96/YueWen_917692/s_YueWen_917692.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=a38329305e00bca3852990b", "progress": 89, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "，你的数据公司可以对一切加密，让你来保管钥匙（如今你甚至", "chapter": "性、谎言和机器学习", "date": "2021-12-01", "color": null}, {"text": "保险公司）承保。时下有许多公司提出要加强你在云盘某处的数", "chapter": "性、谎言和机器学习", "date": "2021-12-01", "color": null}], "ideas": []}, {"id": "41439366", "title": "自洽：在不确定的日子里向内看", "author": "史欣悦", "cover": "https://cdn.weread.qq.com/weread/cover/2/YueWen_41439366/s_YueWen_41439366.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=9ec32fe0727850869ec8200", "progress": 100, "finished": 1, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "考试就不会学习，恐怕也是我们学校教育需要反思的地方。如果想转行做律师，要考司法考试，或者出国读法学院，要考LSAT（法学院入学考试），那就把这件事当主修，是没有问题的。", "chapter": "做自己的博士生导师", "date": "2021-11-25", "color": null}, {"text": "自己情况的教学方案。大多数人应该都会考虑以下几个方面。一是选题，相当于你想报考哪个方向的“博士”。人总有许多兴趣，既然是自己安排，就这个也想学点，那个也想学点。选题不能太杂，一段时间有一个重点，最多两个，也就足够了。一两个重点最好也能保持一年左右的时间，不要频繁改变；如果有两个重点，也要明确主次，哪个是主修的，哪个是辅修的。比如，我想更加深入地了解一下普通法系的运作方式，那我可以先查资料，给自己开个书单，找到一些知名学者的讲座，然后分解到一年的时间里，每周读多少、写多少，写得好的可以分享在哪里，等等。这就是一个自己带着自己做出来的学习计划。假设我工作中还需要学一些管理学的知识，那就把读些管理学图书当作辅修，争取和普通法学习同时进行。等到普通法的一年计划差不多完成了，如果还想把管理", "chapter": "做自己的博士生导师", "date": "2021-11-25", "color": null}], "ideas": []}, {"id": "33874507", "title": "60分钟高效阅读：超实用的快速读书法", "author": "镜晓娴", "cover": "https://cdn.weread.qq.com/weread/cover/87/YueWen_33874507/s_YueWen_33874507.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=83a32c907204e24b83a365f", "progress": 99, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "我们很多人不是没有能力，而是被人性弱点束缚住了手脚和思想，被限制了能力和发展。如果我们想突破自己，可以从书中找到一", "chapter": "第五节 提升财商能力的一份书单", "date": "2021-11-16", "color": null}, {"text": "幸福就是跟所有关系建立的一种被需要的连接。", "chapter": "第四节 阅读的意义，是找到你生命中最重要的东西", "date": "2021-11-13", "color": null}], "ideas": []}, {"id": "31595333", "title": "4点起床：最养生和高效的时间管理", "author": "中岛孝志", "cover": "https://cdn.weread.qq.com/weread/cover/52/YueWen_31595333/s_YueWen_31595333.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=dc0324a071e21b45dc0c570", "progress": 22, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "睡眠的质量不应该用“时间”标准去衡量，而是应该根据“熟睡了多久，醒的时候是否神清气爽”来判断。质比量重要，模拟比数字重要，关键是自己舒不舒服。体内生物钟比闹钟更靠谱。", "chapter": "这样睡不用睡足八小时", "date": "2021-10-21", "color": null}, {"text": "所以，从生理学的角度看，人应该晚上八点多睡觉，早上四点起来——这才是对身心最理想的生活节奏。", "chapter": "早上荷尔蒙分泌更旺盛", "date": "2021-10-21", "color": null}], "ideas": []}, {"id": "23691350", "title": "人类存在的意义", "author": "爱德华·威尔逊", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/350/23691350/s_23691350.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=56132a90716980565615349", "progress": 97, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "一言以蔽之，个体选择会使我们的“罪恶”增殖，群体选择则会让我们的“美德”增殖。最终结果就是，除了遭受精神疾病折磨的人之外，我们每个人都要面对内心的煎熬与挣扎。", "chapter": "15 在宇宙中孤独并自由着", "date": "2021-10-21", "color": null}, {"text": "就个人层面的选择来说，自私自利的行为可以给种群和其他种群的竞争带来益处，但通常来说，这种行为会对整个物种带来危害。", "chapter": "15 在宇宙中孤独并自由着", "date": "2021-10-21", "color": null}], "ideas": []}, {"id": "834464", "title": "活着", "author": "余华", "cover": "https://cdn.weread.qq.com/weread/cover/1/yuewen_834464/s_yuewen_8344641758521403.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=33332bf05cbba0333b1efb4", "progress": 100, "finished": 1, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "当这部沉重的小说结束时，活着的意志，是福贵身上唯一不能被剥夺走的东西。", "chapter": "英文版自序", "date": "2021-06-27", "color": null}, {"text": "牛是通人性的，我拉着它往回走时，它知道是我救了它的命，身体老往我身上靠，亲热得很，我对它说：“你呀，先别这么高兴，我拉你回去是要你干活，不是把你当爹来养着的。”", "chapter": "五", "date": "2021-06-27", "color": null}], "ideas": []}, {"id": "629424", "title": "思考致富", "author": "拿破仑·希尔", "cover": "https://cdn.weread.qq.com/weread/cover/1/YueWen_629424/s_YueWen_629424.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=0cc32c40599ab00cc3b986f", "progress": 100, "finished": 1, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "1. 成就最卓著的男士是那些性欲极强，即熟练掌握性转换艺术的人。2. 积累巨额财富以及在文学、艺术、工业、建筑业和其他行业取得广泛赞誉的人，背后都少不了某个女性的影响和激励。", "chapter": "第十一章 性转换的奥秘（通往致富之路的第十步）", "date": "2021-06-30", "color": null}, {"text": "毅力是一种精神状态，因此可以培养。像所有精神状态一样，培养毅力要有明确的动因，包括以下几种：1. 明确的目的。知道自己想要什么，这是培养毅力的第一步，可能也是最重要的一步。强烈的动机能激励你战胜许多困难。2. 欲望。若追求强烈渴望的某个目标，那么在追求过程中，获得并保持毅力相对容易。3. 自立。相信自己有能力贯彻某项计划，这种信任会激励你坚持不懈地将计划贯彻到底（通过第4章“自我暗示”中描述的原则可培养自立）。4. 明确的计划。严密的计划即便有很多缺点甚至根本不切实际，也能鼓舞人的毅力。5. 准确认识自己。根据积累的经验和日常观察，知道自己的计划很可靠，这样的认识能鼓舞毅力；相反，“主观臆断”而非“真知灼见”，只能破坏毅力的培养。6. 合作。与别人的共鸣、对别人的理解与合作，往往也有助于毅力的培养。7. 意志力。集中精力为实现某个具体目标而拟订计划，这种习惯会使人产生毅力。8. 习惯。毅力是习惯的直接产物。我们每天向大脑输入什么样的日常经历，大脑就会记住这些经历，并成为其中的一部分。强迫自己重复勇敢行为，能够有效治愈恐惧，战胜这个最大的天敌。每个亲赴战场的人都知道这一点。", "chapter": "第九章 毅力：催生信念的持久努力（通往致富之路的第八步）", "date": "2021-06-30", "color": null}], "ideas": []}, {"id": "23027232", "title": "韭菜的自我修养", "author": "李笑来", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/232/23027232/s_23027232.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=c4732230715f5e20c47838a", "progress": 100, "finished": 1, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "“直接花钱买币是最划算的”——“因为，在金融的世界里，没有什么人的体力和智力比资本更牛×，所以，拼体力、拼智力都是错的！", "chapter": "附录", "date": "2021-05-25", "color": null}, {"text": "无论什么样的工作，只要想做到极致，就很难，然而，只要做到了，就一定有成长，有新的境界。生活工作之外，还要有学习，现代人最幸福的地方就是可以无生活压力地学习，而学习的目的，不是为了更高的工资、更好的社会地位，只是为了满足自己的好奇心，为了自己的大脑继续成长……", "chapter": "21 生活之外还必须有工作和学习", "date": "2021-05-25", "color": null}], "ideas": []}, {"id": "713324", "title": "多元智能新视野", "author": "霍华德·加德纳", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/324/713324/s_713324.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=2d9327e05ae26c2d94dc979", "progress": 100, "finished": 1, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "除了存在智能和精神信仰智能以外，我思考得最多的就是幽默智能和道德智能。", "chapter": "第一部分 多元智能理论", "date": "2021-05-04", "color": null}, {"text": "承认每个人都是具有多种能力组合的个体，而不是只拥有单一的、用纸和笔可以测试出来的解答问题能力的生命个体，显得十分重要。", "chapter": "第一部分 多元智能理论", "date": "2021-05-04", "color": null}], "ideas": []}, {"id": "736986", "title": "色彩心理学", "author": "鲁芳", "cover": "https://cdn.weread.qq.com/weread/cover/29/YueWen_736986/s_YueWen_736986.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=f6e326a05b3edaf6ee63eda", "progress": 37, "finished": 1, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "给予孩子发泄情绪的权利和空间。情绪每个人都有，孩子也不例外，当他（她）出现急躁、不安等情绪，甚至是大发脾气时，家长应当允许，因为这是他们发泄情绪的一种方式。事后可以正确引导，帮助他们放慢节奏，引导他们在做决定时要平静。", "chapter": "五彩缤纷色——儿童世界里的色彩心理学", "date": "2021-04-28", "color": null}, {"text": "偏好红色的孩子。在性格特征方面，儿童可能会不断地向大人提出要求，为大人找事做，而他们自己似乎也不会闲着；性情倔强、难以被说服，除非是自己想通了；他们往往有自己的主见，做事大胆，有领袖风范。", "chapter": "五彩缤纷色——儿童世界里的色彩心理学", "date": "2021-04-28", "color": null}], "ideas": []}, {"id": "813166", "title": "傲慢与偏见", "author": "简·奥斯丁", "cover": "https://cdn.weread.qq.com/weread/cover/51/YueWen_813166/s_YueWen_813166.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=2fd32cc05c686e2fd39e264", "progress": 12, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "一个女人不能出类拔萃，就不能真正算是多才多艺。一个女人必须精通音乐、唱歌、绘画、舞蹈以及现代语言，才当得起这个称号。除此之外，她的仪表步态、嗓音语调、谈吐表情，都必须具备一种特质，否则她只能获得一半的资格。", "chapter": "8", "date": "2021-04-25", "color": null}, {"text": "一个人可以骄傲而不虚荣。骄傲多指我们对自己的看法，虚荣多指我们想要别人对我们抱有什么看法。”", "chapter": "5", "date": "2021-04-24", "color": null}], "ideas": []}, {"id": "814575", "title": "战争：从类人猿到机器人，文明的冲突和演变（第二版）", "author": "[美]莫里斯 栾力夫译", "cover": "https://cdn.weread.qq.com/weread/cover/52/yuewen_814575/s_yuewen_8145751717583989.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=cd632f105c6defcd6d0263d", "progress": 100, "finished": 1, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "美国统治下的和平”将让位于“技术统治下的和平”［这个词语来自于未来学家阿耶沙（Ayesha）和帕拉格·卡纳（Parag Khanna）］，我们将不再需要“世界警察”。", "chapter": "第二章 将怪兽放入囚笼 建设性战争", "date": "2021-04-25", "color": null}, {"text": "第一点是，通过战争，人类创造出更庞大、组织更完善的社会，而这样的社会减少了社会成员死于暴力的风险。", "chapter": "为我们时代的和平", "date": "2021-04-24", "color": null}], "ideas": []}, {"id": "36816805", "title": "哈佛长时记忆法", "author": "川崎康彦", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/805/36816805/s_36816805.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=072320d07231c7a50723f76", "progress": 73, "finished": 1, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "请欣然接受并感谢曾经历过的消极的事情，这样你过去的记忆就会被改写，“臆想细胞”就会变成“幸福细胞”。这样的话，你就会从恶性循环中解脱出来。这真是一件不可思议的事。", "chapter": "Chapter 02 哈佛最强记忆法", "date": "2021-04-08", "color": null}, {"text": "最有效的锻炼工作记忆能力的方法是什么呢？答案是“有氧运动+外语学习+独自旅行”。", "chapter": "有效提高大脑灵敏度", "date": "2021-04-08", "color": null}], "ideas": []}, {"id": "792709", "title": "金台答问录", "author": "湛若水", "cover": "https://cdn.weread.qq.com/weread/cover/12/yuewen_792709/s_yuewen_7927091679652299.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=c4a325e05c1885c4a7ea137", "progress": 20, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "惟有「朝闻道夕死可矣」之言，「死而不亡」之说，为可信耳。", "chapter": "", "date": "2021-04-05", "color": null}, {"text": "隆窃意太虚中气如大洋海水，人于其中禀受此气，如取水于海，或以瓢、或以盂、或以缶，大小不同，各随其分量领受得去。", "chapter": "", "date": "2021-04-05", "color": null}], "ideas": []}, {"id": "860221", "title": "孟子", "author": "[战国]孟子", "cover": "https://cdn.weread.qq.com/weread/cover/67/YueWen_860221/s_YueWen_860221.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=2fa32a805d203d2fa987255", "progress": 15, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "在这个问题上，孔孟至少有两大不同：一、孔孟虽然都讲“仁政”，也都讲君臣父子的伦常关系，即“礼”，但当二者发生矛盾时，孔子常犯糊涂，拘于“礼”而不顾“仁”；孟子思想更明确，认为“仁”才是“礼”的核心，君臣之“礼”如果违反了“仁”，要他何用呢？所以孟子反复讲，“民贵君轻”，国君不称职，可以废了另立，如果天子是暴君，可以杀，不叫“弑”。显然，孟子的思想比孔子先进。", "chapter": "一", "date": "2021-03-25", "color": null}, {"text": "孟子认为，齐宣王“好货”（喜欢财物）、“好色”都不是毛病，而是人的正常需求。但齐王应该认识到老百姓同样“好货”“好色”，他们的正当需求也应该得到尊重和满足，因此齐王应“与百姓同之”，这才能算是实行“王政”。", "chapter": "一", "date": "2021-03-25", "color": null}], "ideas": []}, {"id": "573318", "title": "论人类不平等的起源和基础（果麦经典）", "author": "[法]卢梭", "cover": "https://cdn.weread.qq.com/weread/cover/37/YueWen_573318/s_YueWen_573318.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=f963287058bf86f96cbb7c4", "progress": 100, "finished": 1, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "正是这一体系进一步印证了应该将人类排除在食肉动物之外，而将其纳入在食果动物行列的观点。", "chapter": "第7章 注释", "date": "2020-11-26", "color": null}, {"text": "自然既然给予人类眼泪，那就表示，它曾给予人类一颗最仁慈的心。”", "chapter": "4", "date": "2020-11-25", "color": null}], "ideas": []}, {"id": "916887", "title": "社会学原来这么有趣：颠覆传统教学的18堂社会学课", "author": "仲英涛", "cover": "https://cdn.weread.qq.com/weread/cover/1/YueWen_916887/s_YueWen_916887.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=78f322b05dfd9778f9c89cb", "progress": 71, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "历史唯物主义", "chapter": "马克思社会哲学方法论的实质", "date": "2020-10-08", "color": null}, {"text": "人的价值不断丧失，物的价值不断上升，这是资本主义社会出现的两个奇怪现象。", "chapter": "马克思社会哲学的主题", "date": "2020-10-08", "color": null}], "ideas": []}, {"id": "25561846", "title": "一九八四（译文经典）", "author": "乔治·奥威尔", "cover": "https://cdn.weread.qq.com/weread/cover/9/YueWen_25561846/s_YueWen_25561846.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=dde328c071860af6dde328f", "progress": 0, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "在这时候，在我看来，没有出息倒是唯一的美德。", "chapter": "译本序", "date": "2020-05-28", "color": null}, {"text": "因此，在黎斯看来，奥威尔首先是一个社会主义者，其次是一个反极权主义者，而他的“反极权主义的斗争是他的社会主义信念的必然结果。他相信，只有击败极权主义，社会主义才有可能胜利”", "chapter": "译本序", "date": "2020-05-28", "color": null}], "ideas": []}, {"id": "30243983", "title": "企业、市场与法律", "author": "罗纳德·哈里·科斯", "cover": "https://cdn.weread.qq.com/weread/cover/36/YueWen_30243983/s_YueWen_30243983.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=a7d323c071cd7c8fa7d590e", "progress": 0, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "斯密定理”：“分工受市场范围的限制。", "chapter": "译者的话", "date": "2020-05-11", "color": null}, {"text": "“科斯定理”：若交易费用为零，无论权利如何界定，都可通过市场交易达到资源的最佳配置。", "chapter": "译者的话", "date": "2020-05-11", "color": null}], "ideas": []}, {"id": "815124", "title": "了凡四训（典藏本）", "author": "[明]袁了凡 木暮评注", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/124/815124/s_815124.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=048321705c7014048d919f2", "progress": 50, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "，所行善恶，纤悉必记。夜则设桌于庭，效②赵阅道焚香告帝。", "chapter": "第一篇 立命之学", "date": "2020-05-09", "color": null}, {"text": "行为决定结果、志向决定收获", "chapter": "前言", "date": "2020-05-08", "color": null}], "ideas": []}, {"id": "573938", "title": "这次不一样：八百年金融危机史", "author": "卡门 M.莱因哈特 肯尼斯 S.罗格夫", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/938/573938/s_573938.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=a2832bc058c1f2a288322fd", "progress": 78, "finished": 0, "hlCount": 2, "ideaCount": 0, "highlights": [{"text": "早期关于第二次世界大战后汇率制度分类研究在内的很多研究，都将年通货膨胀率40%或更高作为严重通货膨胀危机发生的标志。", "chapter": "第1章 危机的类型和标识", "date": "2020-03-24", "color": null}, {"text": "金德尔伯格30多年前出版的《疯狂、惊恐和崩溃：金融危机史》", "chapter": "译者序", "date": "2020-03-24", "color": null}], "ideas": []}, {"id": "925055", "title": "知乎大神安森垚经典套装（全两册）", "author": "安森垚", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/55/925055/s_925055.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=4a7320005e1d7f4a7c295c2", "progress": 14, "finished": 0, "hlCount": 1, "ideaCount": 1, "highlights": [{"text": "北京猿人在我们的祖先晚期智人还没有走出非洲的时候，就已经灭绝了。", "chapter": "一、万物灵长——从1.0版到10.0版的人类进阶史", "date": "2021-03-09", "color": null}], "ideas": [{"content": "按照现代生物学的研究，北京猿人在我们的祖先晚期智人还没有走出非洲的时候，就已经灭绝了。", "abstract": "北京猿人在我们的祖先晚期智人还没有走出非洲的时候，就已经灭绝了。", "chapter": "", "date": "2021-03-09", "star": null}]}, {"id": "34627725", "title": "第二座山", "author": "戴维·布鲁克斯", "cover": "https://cdn.weread.qq.com/weread/cover/0/YueWen_34627725/s_YueWen_34627725.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=fcb325907210608dfcb3b28", "progress": 10, "finished": 0, "hlCount": 1, "ideaCount": 1, "highlights": [{"text": "当整个社会就是以自我为中心建立起来的时候，其成员就会变得彼此分离和疏远。", "chapter": "引言", "date": "2021-02-04", "color": null}], "ideas": [{"content": "记住一点：人是社会性动物。", "abstract": "当整个社会就是以自我为中心建立起来的时候，其成员就会变得彼此分离和疏远。", "chapter": "", "date": "2021-02-04", "star": null}]}, {"id": "851343", "title": "罗辑思维：我懂你的知识焦虑", "author": "罗振宇等", "cover": "https://cdn.weread.qq.com/weread/cover/62/YueWen_851343/s_YueWen_851343.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=5bf328405cfd8f5bf26b4f3", "progress": 100, "finished": 1, "hlCount": 1, "ideaCount": 1, "highlights": [{"text": "1666年，这是世界科学史上第一个奇迹之年，因为牛顿在老家避难的这段时间，在他妈妈的农场里，几乎做出了他一生所有重要的科学贡献。", "chapter": "02 现代世界的诞生", "date": "2020-09-27", "color": null}], "ideas": [{"content": "观念地层PK思想通道。", "abstract": "为什么牛顿能够构建出观念地层？", "chapter": "", "date": "2020-09-27", "star": null}]}, {"id": "26454163", "title": "这里是中国", "author": "星球研究所 中国青藏高原研究会", "cover": "https://cdn.weread.qq.com/weread/cover/95/YueWen_26454163/s_YueWen_26454163.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=084324d07193a89308476c4", "progress": 97, "finished": 0, "hlCount": 1, "ideaCount": 1, "highlights": [{"text": "甘肃的未来在哪里？我想是“一带一路”的大机遇。因为历史已经证明，愈向西愈美丽，愈开放愈美丽，愈多元愈美丽。", "chapter": "甘肃：愈多元愈美丽", "date": "2020-09-04", "color": null}], "ideas": [{"content": "怎么样复活楼兰盛世", "abstract": "", "chapter": "", "date": "2020-09-04", "star": null}]}, {"id": "3300203177", "title": "好的家庭教育", "author": "李笑来", "cover": "https://cdn.weread.qq.com/weread/cover/75/cpplatform_pv9fzoe8gwmdtbvo2wbjka/s_cpplatform_pv9fzoe8gwmdtbvo2wbjka1777281364.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=1e432b80813abb5ddg017b40", "progress": 0, "finished": 1, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "所谓的体面，就是做到“不是我的，我不要”。", "chapter": "1.1 尊重产权", "date": "2026-06-28", "color": 1}], "ideas": []}, {"id": "3300177660", "title": "专注的真相", "author": "李笑来", "cover": "https://cdn.weread.qq.com/weread/cover/4/cpplatform_v6rotsdw578bplfggz32pk/s_cpplatform_v6rotsdw578bplfggz32pk1763434329.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=59b324d0813ababe6g010489", "progress": 70, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "普通人也有类似的体验，比如一辆车开上一段时间，那方向盘就会被大脑“内化”为你的一个器官，操控起来得心应手。", "chapter": "3 更便宜更隐蔽更普及的毒", "date": "2026-06-28", "color": 1}], "ideas": []}, {"id": "40792926", "title": "华严经", "author": "佛陀跋陀罗  [唐]实叉难陀", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/926/40792926/s_40792926.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=76b32300726e735e76ba964", "progress": 0, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "观一切法无常、一切法苦、一切法空、一切法无我、一切法无作、一切法无味、一切法不如名、一切法无处所、一切法离分别、一切法无坚实。", "chapter": "十住品第十五", "date": "2026-02-23", "color": 1}], "ideas": []}, {"id": "25736032", "title": "霍去病（中华传奇人物故事汇）【中宣部2022年主题出版重点出版物】", "author": "胡辉", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/32/25736032/s_25736032.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=2c0329e07188b3602c060f7", "progress": 99, "finished": 1, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "与霍去病前往长安外的少华山、太白山、骊山、终南山等地练习翻山越岭、野外求生的技能。", "chapter": "幼鹰展翅", "date": "2026-02-15", "color": 1}], "ideas": []}, {"id": "244004", "title": "冬牧场", "author": "李娟", "cover": "https://cdn.weread.qq.com/weread/cover/22/yuewen_244004/s_yuewen_2440041690201500.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=d1d32fa053b924d1d0ac0a5", "progress": 16, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "过去，那三大袋土全都用完了。而加玛一有空则拾起小笤帚打扫地窝子门外的空地。所谓扫地，也就是把沙地上乱七八糟的脚印抹去，再扫出整齐顺眼、丝缕有序的痕迹。来注射疫苗的兽医离开时，嫂子托他将一大包我们平时舍不得吃的好东西捎到春秋定居点的家中", "chapter": "五 地下的家", "date": "2026-02-16", "color": null}], "ideas": []}, {"id": "26447797", "title": "丰乳肥臀【中国诺奖得主代表作】", "author": "莫言", "cover": "https://cdn.weread.qq.com/weread/cover/82/yuewen_26447797/s_yuewen_264477971701748559.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=ea532d2071938fb5ea51430", "progress": 0, "finished": 1, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "村庄的宁静，顿时霞光满天，五彩缤纷，仿佛有仙女站在云端，让鲜艳的花瓣纷纷扬扬。上官吕氏心情激动。她是铁匠的妻子，但实际上她打铁的技术比丈夫强许多，只要是看到铁与火，就血热。热血沸腾，冲刷血管子。肌肉暴突，一根根，宛如出鞘的牛鞭，黑铁砸红铁，花朵四射，汗流浃背，在奶沟里汇成溪，铁血腥味弥漫在天地之间。她看到司马亭在高高的塔台上蹦了一下。清晨的潮湿空气里，弥漫", "chapter": "第一章", "date": "2026-01-30", "color": null}], "ideas": []}, {"id": "3300139656", "title": "引领时代的工业高科技：一读就懂的新质生产力", "author": "王雷", "cover": "https://cdn.weread.qq.com/weread/cover/29/cpplatform_948k1x26qga7naptdbbffn/s_cpplatform_948k1x26qga7naptdbbffn1743567928.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=86732760813ab9d0dg016b48", "progress": 94, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "固态锂电池不会出现传统锂电池让人头疼的锂枝晶问题。", "chapter": "3.7 固态电池", "date": "2026-01-19", "color": 1}], "ideas": []}, {"id": "3300128635", "title": "不抱怨的世界", "author": "[美]威尔·鲍温", "cover": "https://cdn.weread.qq.com/weread/cover/81/cpplatform_5ejnvkteknj5ydzpkcyke4/s_cpplatform_5ejnvkteknj5ydzpkcyke41735619977.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=b6432090813ab98bfg0155f3", "progress": 93, "finished": 1, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "唯一能够让你避免成为一个爱抱怨的人的方法是学会感恩。", "chapter": "第一部分 无意识的无能", "date": "2025-11-23", "color": 1}], "ideas": []}, {"id": "35942747", "title": "奇怪的知识增加了", "author": "马库斯·乔恩", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/747/35942747/s_35942747.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=51432e607224715b5144cf4", "progress": 95, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "实际上，你体内所有细胞大概每七年就会全部更换一次。难怪大家都说“七年之痒”。你看着自己的身边人，不禁想到，“这好像不是当初我下定决心要在一起的那个人了”。", "chapter": "4 七年之痒", "date": "2025-11-11", "color": 1}], "ideas": []}, {"id": "3300071185", "title": "床，沙发，我的人生", "author": "罗曼·莫内里", "cover": "https://cdn.weread.qq.com/weread/cover/25/cpplatform_5gdjt3yi8zrazby6yipvbq/s_cpplatform_5gdjt3yi8zrazby6yipvbq1694761915.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=41632490813ab824eg015667", "progress": 36, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "我心知自己就像一根掉进了汤里的头发——不合时宜。", "chapter": "4", "date": "2025-07-25", "color": 1}], "ideas": []}, {"id": "25469764", "title": "世界尽头的咖啡馆", "author": "约翰·史崔勒基", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/764/25469764/s_25469764.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=62932c607184a344629996d", "progress": 34, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "为了实现存在的意义，做你想做的任何事。", "chapter": "09", "date": "2025-08-05", "color": 1}], "ideas": []}, {"id": "3300083741", "title": "信念 : 人生每一步都算数（珍藏版）", "author": "雷殿生", "cover": "https://cdn.weread.qq.com/weread/cover/85/cpplatform_kbttvc9usqoqzr1j5bti3f/s_cpplatform_kbttvc9usqoqzr1j5bti3f1704785877.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=9e1326b0813ab8736g0119ec", "progress": 99, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "撒下爱的种子，一定会收获善良和美好。", "chapter": "柯家四兄妹：用努力转变命运", "date": "2025-06-15", "color": 1}], "ideas": []}, {"id": "29499625", "title": "汪曾祺全集（全12册）", "author": "汪曾祺", "cover": "https://cdn.weread.qq.com/weread/cover/4/yuewen_29499625/s_yuewen_294996251676539569.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=685327d071c220e9685fc42", "progress": 1, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "旅行人跨出乡土一步，便背上一份沉重的寂寞，每个人知道浮在水上的梦，不会流到亲人的枕边，所以他们都不睡觉，且不惜自己的言语，为了自己，也为了别人，话着故乡风物，船上是不容有一分拘执的。", "chapter": "猎猎", "date": "2025-07-17", "color": 1}], "ideas": []}, {"id": "3300142620", "title": "慢慢变富2：普通人的成功投资", "author": "闲来一坐s话投资", "cover": "https://cdn.weread.qq.com/weread/cover/60/cpplatform_cd9xqbius7whcusxjjhhdx/s_cpplatform_cd9xqbius7whcusxjjhhdx1745561370.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=30e32e00813ab9e36g01035e", "progress": 100, "finished": 1, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "美国道琼斯工业平均指数从1932年的41点，上升到2024年年底的42544.22点，总体趋势就是不断向上攀升，不断创出历史新高。", "chapter": "股市投资要有“历史观”", "date": "2025-05-02", "color": 1}], "ideas": []}, {"id": "3300093919", "title": "大道无形：段永平", "author": "刘若愚", "cover": "https://cdn.weread.qq.com/weread/cover/12/cpplatform_3x53mm7hfm53bjgiilgk8c/s_cpplatform_3x53mm7hfm53bjgiilgk8c1783327742.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=3dd323e0813ab8b2fg0196ef", "progress": 5, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "巴菲特“投资投的是生意”的说法是真实不虚的。", "chapter": "1 买股票就是买公司", "date": "2025-02-19", "color": 1}], "ideas": []}, {"id": "3300072295", "title": "太白金星有点烦", "author": "马伯庸", "cover": "https://cdn.weread.qq.com/weread/cover/72/cpplatform_huhykqamxcvke1jfkpqxiv/s_cpplatform_huhykqamxcvke1jfkpqxiv1695711014.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=23e32130813ab82bdg015cd2", "progress": 100, "finished": 1, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "奇怪要求没见过，也不争辩，匆匆下凡忙活起来。", "chapter": "第一章", "date": "2025-05-05", "color": null}], "ideas": []}, {"id": "3300079356", "title": "长城汽车魏建军 品类创新：从乡镇小厂到明星车企的突围解密", "author": "温雅卿", "cover": "https://cdn.weread.qq.com/weread/cover/10/cpplatform_uvtfxxym2dos9k8tkcawsm/s_cpplatform_uvtfxxym2dos9k8tkcawsm1700732022.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=9c532b40813ab857fg016c8d", "progress": 100, "finished": 1, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "魏建军几乎考察了国内所有品牌的发动机，排除了种种不可靠因素之后，最终锁定了一家专业生产发动机的制造供应商的产品，即四川省绵阳新华内燃机股份有限公司的汽油发动机。", "chapter": "“卡脖子”逼出自主研发", "date": "2025-04-24", "color": 1}], "ideas": []}, {"id": "3300119145", "title": "智人之上 ——从石器时代到 AI 时代的信息网络简史", "author": "[以]尤瓦尔·赫拉利", "cover": "https://cdn.weread.qq.com/weread/cover/79/cpplatform_nnjdppmxmsy3wfh16rjq2j/s_cpplatform_nnjdppmxmsy3wfh16rjq2j1730345368.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=a24329f0813ab950ag015395", "progress": 92, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "少数几个能够收集全球数据的企业或政府，就有能力把全球其他地区变成自己的数据殖民地，它们不是依靠公开的军事武力，而是通过信息来控制这些领土。", "chapter": "第十一章 硅幕：全球帝国还是全球分裂？", "date": "2025-01-26", "color": 1}], "ideas": []}, {"id": "3300128993", "title": "黄仁勋:英伟达之芯", "author": "[美]斯蒂芬·威特", "cover": "https://cdn.weread.qq.com/weread/cover/17/cpplatform_tbvb88uy6cwrq2lzpcsshr/s_cpplatform_tbvb88uy6cwrq2lzpcsshr1735874725.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=47a32050813ab98e3g013257", "progress": 21, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "算力就是生产力。算力的富足将我们带入计算时代。算力重新锚定了科技创新的坐标，在这个坐标系中，我们将摆脱算力贫瘠的假定，站到人类发展进程中的下一个真问题面前：那么，计算什么。", "chapter": "推荐序 从摩尔定律到黄氏定律", "date": "2025-01-12", "color": 1}], "ideas": []}, {"id": "30243991", "title": "中国：增长放缓之谜", "author": "周天勇 王元地", "cover": "https://cdn.weread.qq.com/weread/cover/65/YueWen_30243991/s_YueWen_30243991.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=1a3325e071cd7c971a3b96a", "progress": 14, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "改革开放之前，中国城市化水平几乎停滞不前；而改革开放打破城乡二元结构以来，全国城市化水平增长加快，1978—2007年，中国的城市化水平从17.9%推进到了44.94%", "chapter": "1.2 中国经济高速增长的成因", "date": "2025-01-05", "color": 1}], "ideas": []}, {"id": "915642", "title": "终身成长（全新修订版）", "author": "卡罗尔·德韦克", "cover": "https://cdn.weread.qq.com/weread/cover/59/YueWen_915642/s_YueWen_915642.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=b0e327605df8bab0e873984", "progress": 3, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "人类在经过多年的热情、辛苦奋斗以及训练后能够取得什么样的成就，是无法预知的。", "chapter": "两种思维模式对你意味着什么", "date": "2025-01-05", "color": 1}], "ideas": []}, {"id": "3300120749", "title": "不被大风吹倒（莫言陪女儿高考也这样！ ）", "author": "莫言", "cover": "https://cdn.weread.qq.com/weread/cover/60/cpplatform_n3ezmfhymkjcbuuszk8bgy/s_cpplatform_n3ezmfhymkjcbuuszk8bgy1731488438.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=2c032e80813ab95aag019524", "progress": 6, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "书中写了一个残酷无情的刽子手，但在生活中，我是个善良懦弱的人，我看到杀鸡的场面，腿肚子", "chapter": "我保持年轻的秘诀", "date": "2024-12-15", "color": null}], "ideas": []}, {"id": "32436082", "title": "李书福：守正出奇", "author": "魏江 刘洋", "cover": "https://cdn.weread.qq.com/weread/cover/38/YueWen_32436082/s_YueWen_32436082.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=364321f071eeef7236494e6", "progress": 14, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "1996年，李书福去美国做了一次考察，他惊奇地发现，美国大街上跑的都是汽车，而不是摩托车", "chapter": "为什么进入汽车行业", "date": "2024-12-15", "color": 1}], "ideas": []}, {"id": "804033", "title": "富爸爸点石成金", "author": "罗伯特·清崎 唐纳德·特朗普", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/33/804033/s_804033.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=d9a320505c44c1d9af1c0bb", "progress": 16, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "值得注意的是，学校并不是企业家的摇篮，而是企业员工的培训机构。", "chapter": "序言 与众不同的企业家", "date": "2024-11-26", "color": 1}], "ideas": []}, {"id": "34631845", "title": "西游记（人民文学版）", "author": "[明]吴承恩", "cover": "https://cdn.weread.qq.com/weread/cover/22/yuewen_34631845/s_yuewen_346318451676961764.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=64032210721070a5640294f", "progress": 10, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "损一毫。那大力鬼王与众启奏道：“万岁，这大圣不知是何处学得这护身之法，臣等用刀砍斧剁，", "chapter": "第七回 八卦炉中逃大圣 五行山下定心猿", "date": "2024-11-21", "color": null}], "ideas": []}, {"id": "25982880", "title": "人生没什么不可放下：弘一法师的人生智慧", "author": "宋默", "cover": "https://cdn.weread.qq.com/weread/cover/8/YueWen_25982880/s_YueWen_25982880.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=96432640718c77a0964ad49", "progress": 41, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "就算每天赚100万也不觉得得意，每天赚10元也不觉得失意，该吃饭吃饭，该睡觉睡觉，不要逼迫自己，", "chapter": "1 恬淡是养心的第一法", "date": "2024-06-04", "color": 1}], "ideas": []}, {"id": "3300058955", "title": "活着：中小企业的55个生存策略", "author": "菲利普·泽梅尔洛特", "cover": "https://cdn.weread.qq.com/weread/cover/56/cpplatform_offruxnpdogu5degyq22s6/s_cpplatform_offruxnpdogu5degyq22s61684294195.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=cfc32000813ab7d87g015fc9", "progress": 100, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "投入工作。实践经验要给新员工安排一个舒适的工位。听起来很容易，但是很多企业家都忽略了这一点。你是否在员工入职前，为他提前安排好工位，并且在那里准备好了电脑、电话、名片或者工装？许多公司觉得员工不需要名片，他们错了，名片可以让员工有归属", "chapter": "生存策略38 重视员工入职手册的作用", "date": "2024-08-01", "color": null}], "ideas": []}, {"id": "35990194", "title": "朝花夕拾", "author": "鲁迅", "cover": "https://cdn.weread.qq.com/weread/cover/10/YueWen_35990194/s_YueWen_35990194.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=e7332a1072252ab2e732536", "progress": 93, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "“你看，你将这条血管移了一点位置了。——自然，这样", "chapter": "藤野先生", "date": "2024-11-13", "color": null}], "ideas": []}, {"id": "44406251", "title": "金钱的灵魂：让你从内在真正富起来", "author": "特威斯特 巴克", "cover": "https://cdn.weread.qq.com/weread/cover/4/yuewen_44406251/s_yuewen_444062511703749800.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=1f332f9072a595eb1f3a8e1", "progress": 39, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "改变世界观意味着改变自己对‘什么才是真实的’的看法……改变自己的价值观——自己更看重哪些事物；改变生活方式——运用时间与金钱的方式；改变谋生的方式——赚取金钱的方式。”", "chapter": "第十二章 逆转潮流", "date": "2024-03-30", "color": 1}], "ideas": []}, {"id": "3300027648", "title": "宗庆后：有一种人生叫大器晚成", "author": "吴玲", "cover": "https://cdn.weread.qq.com/weread/cover/20/cpPlatform_3ik1yrCuTD8vdbGjxtvDiN/s_cpPlatform_3ik1yrCuTD8vdbGjxtvDiN.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=e58321f0813ab714cg01819f", "progress": 100, "finished": 1, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "一旦看书学习成为一个人的习惯，那么这个人就拥有比其他人更为广阔的视野和前程。他站在更高端的位置上，思索着世事变化，琢磨着自己的下一步该往哪走，又该怎么走", "chapter": "1 年轻时代，苦大于甜", "date": "2024-03-09", "color": 1}], "ideas": []}, {"id": "3300028322", "title": "千脑智能", "author": "杰夫·霍金斯", "cover": "https://cdn.weread.qq.com/weread/cover/42/cpPlatform_gC7uHgW2L4FiooYPCnGF4g/s_cpPlatform_gC7uHgW2L4FiooYPCnGF4g.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=45a329e0813ab7190g012b04", "progress": 97, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "这就是探索的本质：你不知道你会学到什么，但你一定会学到某些东西。", "chapter": "第16章 阻止人类灭绝的3种方法", "date": "2024-02-23", "color": 1}], "ideas": []}, {"id": "3300046707", "title": "人生只有一件事", "author": "金惟纯", "cover": "https://cdn.weread.qq.com/weread/cover/10/cpplatform_9jmnaaecwrxf8p3bfrc7yh/s_cpplatform_9jmnaaecwrxf8p3bfrc7yh1674023485.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=1d932fb0813ab78beg017bc3", "progress": 21, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "一位老友跟我分享，前一阵子他和老婆有点小摩擦，他对老婆说：“你刚才那么说，我真的很受伤，现在我很生气，我没办法不生气。请你给我五分钟，让我静一下，只要五分钟，我就回来，保证不再生气。”我朋友能够这样说话，真是令人佩服！", "chapter": "第2章 可以不一样", "date": "2023-12-05", "color": 1}], "ideas": []}, {"id": "814697", "title": "观呼吸：平静的第一堂课", "author": "德宝法师", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/697/814697/s_814697.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=05c323205c6e6905c51b25b", "progress": 99, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "贪念涵盖一切与欲望有关的事物，从渴求物质享受，到希望被别人尊重皆是；嗔心则从小怨到暴怒；痴念则涵盖从白日梦到严重幻想的各种事情。布施对治贪，慈悲则对治嗔。", "chapter": "第十一章 处理分心（上）", "date": "2023-11-20", "color": 1}], "ideas": []}, {"id": "3300072508", "title": "非药而愈：吃出健康的秘密", "author": "徐嘉", "cover": "https://cdn.weread.qq.com/weread/cover/94/cpplatform_57np68e3avug13qemu2qof/s_cpplatform_57np68e3avug13qemu2qof1695800258.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=9a432440813ab82d2g0184aa", "progress": 100, "finished": 1, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "建议素食者每天摄入10~15克（约一汤勺）亚麻籽。有特殊生理需要的人群，如孕妇、幼儿，可以补充海藻来源的DHA（200毫克/70千克体重）。", "chapter": "3.3 如何摄入优质脂肪？", "date": "2023-11-13", "color": 1}], "ideas": []}, {"id": "907664", "title": "轻断食：戒糖篇", "author": "麦克尔·莫斯利博士", "cover": "https://cdn.weread.qq.com/weread/cover/84/YueWen_907664/s_YueWen_907664.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=adc329605dd990adceeb12d", "progress": 72, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "无论你参照的是什么节食法，你都要保证它有足够多的优质蛋白质。", "chapter": "第五章 VLCD（极低热量饮食）回归：并不会反弹的快速减肥", "date": "2023-11-05", "color": 1}], "ideas": []}, {"id": "22851271", "title": "洛克菲勒写给儿子的38封信", "author": "洛克菲勒", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/271/22851271/s_22851271.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=2a7323c0715caec72a785f5", "progress": 57, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "选择天堂还是地狱都是由自己决定的，如果你将工作赋予了意义，不管你做什么工作，你都会感到由衷的快乐。", "chapter": "第3封 天堂与地狱比邻", "date": "2023-08-26", "color": 1}], "ideas": []}, {"id": "35825377", "title": "做饭没有那么烦", "author": "任频捷", "cover": "https://cdn.weread.qq.com/weread/cover/94/YueWen_35825377/s_YueWen_35825377.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=5be32cf07222a6e15bebd0a", "progress": 12, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "猪肉本身有寒性，用八角、桂皮等辛热的调料作为佐料和猪肉一起炖煮，中和猪肉的咸寒之性，就增强了猪肉的补肾功能，将其变成了壮阳的温补食物。", "chapter": "001 鹌鹑蛋红烧肉", "date": "2023-07-08", "color": 1}], "ideas": []}, {"id": "26688761", "title": "汽车为什么会跑：图解汽车构造与原理（精装典藏版）", "author": "陈新亚", "cover": "https://cdn.weread.qq.com/weread/cover/60/YueWen_26688761/s_YueWen_26688761.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=e5c3207071973cf9e5c8477", "progress": 65, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "简单地说，如果左右两个车轮之间没有硬轴连接、一侧车轮跳动时不会影响到另一侧车轮，就可以定义为独立悬架。", "chapter": "6.2 悬架形式", "date": "2023-08-22", "color": 1}], "ideas": []}, {"id": "25960461", "title": "脾虚的孩子不长个、胃口差、爱感冒（全新修订升级版）", "author": "罗大伦", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/461/25960461/s_25960461.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=964328f0718c200d964b16d", "progress": 80, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "焦山楂主要是针对肉食的，而焦三仙有三味药，除了焦山楂，还有焦神曲、焦麦芽，除了消肉积，对于米面等引起的积食，效果也非常好，所以更加全面些。", "chapter": "22．孩子的舌苔脱落究竟是怎么回事", "date": "2023-07-04", "color": 1}], "ideas": []}, {"id": "921066", "title": "数学简史", "author": "蔡天新", "cover": "https://cdn.weread.qq.com/weread/cover/16/YueWen_921066/s_YueWen_921066.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=a00321d05e0deaa00f74036", "progress": 0, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "1665年，英国牛顿研究流数术，他和德国莱布尼茨先后创立", "chapter": "附录1", "date": "2023-07-02", "color": null}], "ideas": []}, {"id": "3300051187", "title": "郭淑云论治脾胃病", "author": "邵明义 李墨航", "cover": "https://cdn.weread.qq.com/weread/cover/95/cpplatform_d2hz6pif2vpw7skay4fb16/s_cpplatform_d2hz6pif2vpw7skay4fb161678072857.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=b2732e00813ab7a7eg017073", "progress": 100, "finished": 1, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "疗脾胃虚弱，气机阻滞，食少不化的脘腹痞满证。（三）运用枳术汤与枳术丸及其药物选择1.枳实（枳壳）及生白术、炒白术的用药选择枳术汤与枳术丸（郭教授常取枳术丸义用作汤方治疗）中枳实、白术的剂量不同，决定了治疗的不同病机侧重点与临床的主要病症，正如《医宗金鉴》中载：“二药一缓一急，一补一泻，其用不同，只此多寡转换之间耳。”白术归经脾、胃，功在补中健脾、燥湿利水，主治脾虚失运，水湿内停诸证，诸如食少便溏、倦怠乏力、痰饮水肿等症。郭", "chapter": "第二章 学术精华", "date": "2023-06-26", "color": null}], "ideas": []}, {"id": "23605972", "title": "天国之秋（甲骨文系列）", "author": "裴士锋", "cover": "https://cdn.weread.qq.com/weread/cover/58/YueWen_23605972/s_YueWen_23605972.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=b5e32040716832d4b5ed8f6", "progress": 5, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "而本书的基本论点之一，乃是一八六一年美国内战的爆发迫使英国有所行动，从而影响了中国内战的结局。中国与美国是当时英国最大的两个经济市场，为了解英国在这两场战争中的角色，我们得记住，英国面临着同时失去这两大市场的风险。", "chapter": "英文版自序", "date": "2023-05-13", "color": 1}], "ideas": []}, {"id": "33638775", "title": "苏东坡新传", "author": "李一冰", "cover": "https://cdn.weread.qq.com/weread/cover/2/yuewen_33638775/s_yuewen_336387751685962456.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=ed732f2072014977ed74bf5", "progress": 1, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "狱中第一次面会，幼子李雍骑脚踏车到土城看守所面见父亲，一冰先生托买苏东坡诗集。李雍到台北书肆购得《古香斋施注苏诗》，送入狱中。一冰先生在狱中四年，将苏诗两千多首背得滚瓜烂熟。", "chapter": "寻找李一冰", "date": "2023-05-04", "color": 1}], "ideas": []}, {"id": "3300011978", "title": "春秋（套装共4册）（一部严谨有趣、 新鲜有梗、干货满满的春秋历史；权力游戏， 幽微人性，人际法则；知名自媒体“脑洞历史观”十年积累诚意之作）", "author": "小马连环", "cover": "https://cdn.weread.qq.com/weread/cover/28/cpplatform_ag5v96cvnptzzhnkjghvow/s_cpplatform_ag5v96cvnptzzhnkjghvow1701933313.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=f8432360813ab6b2dg018be7", "progress": 3, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "春秋时，诸侯的儿子常常在名字前冠以公子二字，孙子则冠以公孙二字。", "chapter": "第一章 多行不义必自毙", "date": "2023-04-28", "color": 1}], "ideas": []}, {"id": "23358825", "title": "周礼（中华经典名著全本全注全译丛书）", "author": "徐正英 常佩雨译注", "cover": "https://cdn.weread.qq.com/weread/cover/62/YueWen_23358825/s_YueWen_23358825.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=78b32b8071646d6978bd275", "progress": 0, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "可见“司空”原本掌管营建土穴，后泛指一切工程。", "chapter": "上册", "date": "2023-04-25", "color": 1}], "ideas": []}, {"id": "841375", "title": "中国简史", "author": "吕思勉", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/375/841375/s_841375.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=7c3328405cd69f7c32734b6", "progress": 100, "finished": 1, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "从董卓进长安起，到晋武帝平吴止，共经过九十二年的战乱，真是渴望太平的时候了。", "chapter": "第十三章 晋的统一和内乱", "date": "2023-04-18", "color": 1}], "ideas": []}, {"id": "27480133", "title": "蔡澜说书法：静下心来 写写字", "author": "[新加坡]蔡澜", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/133/27480133/s_27480133.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=ddb328b071a35045ddbe534", "progress": 99, "finished": 1, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "且就洞庭赊月色将船买酒白云边", "chapter": "蔡澜书法欣赏", "date": "2023-04-06", "color": 1}], "ideas": []}, {"id": "38151319", "title": "科学：无尽的前沿", "author": "范内瓦·布什 拉什·D.霍尔特", "cover": "https://cdn.weread.qq.com/weread/cover/63/YueWen_38151319/s_YueWen_38151319.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=00832e00724624970080718", "progress": 84, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "科学的进步一旦应用于实践，就意味着更多的岗位、更高的工资、更短的劳作、更丰富的农作物，人们可以有更多的闲暇用于娱乐、学习，可以抛弃烦琐的生活，远离长久以来的劳苦。", "chapter": "引言", "date": "2023-03-18", "color": 1}], "ideas": []}, {"id": "24925754", "title": "周期", "author": "霍华德·马克斯", "cover": "https://cdn.weread.qq.com/weread/cover/16/YueWen_24925754/s_YueWen_24925754.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=af132b10717c563aaf1555f", "progress": 10, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "第一，阅读大师名著，让我受益良多。这些大师包括彼得·伯恩斯坦、约翰·肯尼斯·加尔布雷斯、纳西姆·尼古拉斯·塔勒布、查理·埃利斯。", "chapter": "序言", "date": "2023-03-09", "color": 1}], "ideas": []}, {"id": "31422200", "title": "不可能的存在之真：拉康哲学映像（修订本）", "author": "张一兵", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/200/31422200/s_31422200.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=12b3246071df76f812b4092", "progress": 7, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "有病的其实不仅是精神病人，事实上全部的人都疯了；人不是人，而是披着象征性人皮的空无。", "chapter": "一、拉康出生、活着和死去", "date": "2023-03-08", "color": 1}], "ideas": []}, {"id": "721367", "title": "白说", "author": "白岩松", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/367/721367/s_721367.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=4e3321805b01d74e3fa7481", "progress": 21, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "不能简单地以当下的得失论成败，很多所谓失败，只不过是此时的一个世俗观念，或者某种立场下的判断而已。", "chapter": "漂亮的失败是另一种成功", "date": "2023-02-25", "color": 1}], "ideas": []}, {"id": "3300038402", "title": "寻觅意义", "author": "王德峰", "cover": "https://cdn.weread.qq.com/weread/cover/86/cpPlatform_dBA8CcERMXPBuGgTkn8zF2/s_cpPlatform_dBA8CcERMXPBuGgTkn8zF2.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=65032a70813ab7580g0121a9", "progress": 5, "finished": 1, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "佛教最基本的原理是四个字：缘起性空这是佛教的各种宗派共同承认的，不承认这一条，就不能算佛教的宗派。", "chapter": "中西方文化差异的渊源", "date": "2023-02-23", "color": 1}], "ideas": []}, {"id": "23665518", "title": "自私的基因（40周年增订版）", "author": "理查德·道金斯", "cover": "https://cdn.weread.qq.com/weread/cover/60/YueWen_23665518/s_YueWen_23665518.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=fb732f6071691b6efb7de4b", "progress": 6, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "。我的目的是研究自私行为和利他行为在生物学上的意义。", "chapter": "第1章 为什么会有人呢？", "date": "2023-02-16", "color": null}], "ideas": []}, {"id": "32886497", "title": "货币未来：从金本位到区块链", "author": "赛费迪安·阿莫斯", "cover": "https://cdn.weread.qq.com/weread/cover/71/YueWen_32886497/s_YueWen_32886497.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=722328e071f5cee17229964", "progress": 51, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "央行仍在持有并积累更多黄金储备的事实证明，尽管黄金没有政府的加持，它的货币属性依旧坚", "chapter": "政府应该管理货币供给吗", "date": "2022-12-28", "color": null}], "ideas": []}, {"id": "22671790", "title": "第三次浪潮", "author": "阿尔文·托夫勒", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/790/22671790/s_22671790.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=68a325b07159f1ae68a79f0", "progress": 93, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "第二次浪潮的来临使我们从“为自用而生产”的农业社会进入“为交易而生产”的工业社会。", "chapter": "第二十章 产消合一制度的崛起", "date": "2022-12-27", "color": null}], "ideas": []}, {"id": "918478", "title": "大江大河四部曲（ 《大江大河》《淬火年代》影视原著）", "author": "阿耐", "cover": "https://cdn.weread.qq.com/weread/cover/45/yuewen_918478/s_yuewen_9184781704254279.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=92f32a305e03ce92f070017", "progress": 100, "finished": 1, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "去年春节杨巡轰轰烈烈地相亲，这个春节杨巡修身养性，除了走亲访友，就是在家看杨逦带来的书，圣人一般。", "chapter": "第223章 1995年(2)", "date": "2022-11-21", "color": null}], "ideas": []}, {"id": "934471", "title": "养育女孩（成长版）", "author": "史蒂夫·比达尔夫", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/471/934471/s_934471.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=0b732e105e42470b7a22094", "progress": 0, "finished": 1, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "不幸的是，有1/3的孩子到十八九岁时，他们兴趣的火花就熄灭了。如果我们不表示鼓励和支持，火花是会熄灭的。", "chapter": "第五章 点燃孩子兴趣的火花", "date": "2022-10-22", "color": null}], "ideas": []}, {"id": "41497405", "title": "做自己的中医", "author": "范怨武", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/405/41497405/s_41497405.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=67932ef07279333d679cb7a", "progress": 0, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "肾主骨生髓，脑为髓海，所以脑力就是肾力。", "chapter": "他不是真的懒，他是得了“懒病”", "date": "2022-10-27", "color": null}], "ideas": []}, {"id": "43296303", "title": "不迎不拒，向喜而生", "author": "罗近月", "cover": "https://cdn.weread.qq.com/weread/cover/70/YueWen_43296303/s_YueWen_43296303.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=837328a07294a62f8374d6e", "progress": 98, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "万物皆有裂缝，那是光照进来的地方。", "chapter": "自序：不着急，慢慢地长成你自己", "date": "2022-10-21", "color": null}], "ideas": []}, {"id": "574021", "title": "零边际成本社会", "author": "杰里米·里夫金", "cover": "https://cdn.weread.qq.com/weread/cover/69/YueWen_574021/s_YueWen_574021.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=7723219058c24577241d3ed", "progress": 89, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "在协同时代，时间是稀缺资源，注意力是非常宝贵的，让自己从每天几个小时的驾车中解脱出来，并把空出来的时间花在虚拟世界更有趣的活动上，这种意义非常大。", "chapter": "第十三章 从市场机制到共享机制", "date": "2022-10-08", "color": null}], "ideas": []}, {"id": "23370744", "title": "7天学会养兰花", "author": "陈进 王剑", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/744/23370744/s_23370744.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=a803219071649bf8a800797", "progress": 99, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "“入门草”主要有春兰宋梅、汪字、集圆、科技草翠盖梅；蕙兰解佩梅、端蕙梅；莲瓣兰大雪素、白雪公主、点苍梅，春剑科技草杂交大富贵，建兰大宝岛、富山奇蝶、荷花素、大叶铁骨素、金丝马尾爪，墨兰白墨、金鸟、泗港水、日向", "chapter": "一、品种的确定", "date": "2022-10-04", "color": null}], "ideas": []}, {"id": "830920", "title": "甘地：苦行的圣雄", "author": "莫·卡·甘地", "cover": "https://cdn.weread.qq.com/weread/cover/78/YueWen_830920/s_YueWen_830920.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=582325205cadc85827b68a1", "progress": 21, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "，原因是我早已走出了无神论的荒漠。贝桑特夫人在当时备受关注，她已经转变为有神论者。我读过她的《我如何成为一个通神论者》一书。", "chapter": "第20章 初次接触各种宗教", "date": "2022-09-18", "color": null}], "ideas": []}, {"id": "25794540", "title": "你也能写一手好的毛笔字·行书", "author": "高育娟", "cover": "https://cdn.weread.qq.com/weread/cover/82/YueWen_25794540/s_YueWen_25794540.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=54732d40718997ec547cb70", "progress": 94, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "[插图]", "chapter": "十三、赵孟頫《赤壁赋》详解与高频字例", "date": "2022-09-08", "color": null}], "ideas": []}, {"id": "917177", "title": "梁冬说庄子：人间世", "author": "梁冬", "cover": "https://cdn.weread.qq.com/weread/cover/34/YueWen_917177/s_YueWen_917177.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=59b326605dfeb959b88de8e", "progress": 0, "finished": 1, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "一个人情商的高低，本质上就是他能否随时切换自己看世界的角度。", "chapter": "你与人沟通的模式，决定了你生存的环境", "date": "2022-09-02", "color": null}], "ideas": []}, {"id": "3300011787", "title": "教出懂规矩的孩子", "author": "凯文·莱曼", "cover": "https://cdn.weread.qq.com/weread/cover/87/3300011787/s_3300011787.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=48b32de0813ab6b1ag017777", "progress": 28, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "指出孩子行为的目的性之后，他就不会觉得这么做很好玩了。", "chapter": "如何树立你的威信？", "date": "2022-08-23", "color": null}], "ideas": []}, {"id": "911389", "title": "中国人的酒文化", "author": "木空", "cover": "https://cdn.weread.qq.com/weread/cover/43/YueWen_911389/s_YueWen_911389.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=b33320805de81db339d9f22", "progress": 25, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "西汉时的郦食其，自称“高阳酒徒”，而同朝叫饶宽的那位，自称“酒狂”；魏代的蒋济，自称“酒徒”；唐朝自起外号的人多，“五斗先生”是王绩，汝南李琎叫“酿王”，诗人元吉自号“醉民”，白居易又称“醉司马”“醉尹”“醉傅”“醉吟先生”，皮日休自叫“醉士”，诗僧可朋自号“醉朋”；五代后蜀常聿修自称“呷大夫”；北宋隐士种放自号“云溪醉侯”，欧阳修自号“醉翁”。", "chapter": "第一章 谁在问酒最中国", "date": "2022-08-17", "color": null}], "ideas": []}, {"id": "23528206", "title": "中国最美古诗词：你应该熟读的中国古诗+你应该熟读的中国古词+你应该熟读的中国古文（全集）", "author": "陈引驰编著", "cover": "https://cdn.weread.qq.com/weread/cover/18/yuewen_23528206/s_yuewen_235282061678881898.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=b19324207167030eb195ab1", "progress": 0, "finished": 1, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "对酒当歌，人生几何？譬如朝露，去日苦多。慨当以慷，忧思难忘。[插图]何以解忧？唯有杜康。", "chapter": "短歌行", "date": "2022-08-14", "color": null}], "ideas": []}, {"id": "25184495", "title": "当我谈跑步时，我谈些什么", "author": "[日]村上春树", "cover": "https://cdn.weread.qq.com/weread/cover/10/yuewen_25184495/s_yuewen_251844951740049944.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=5aa32dc0718048ef5aab966", "progress": 0, "finished": 1, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "可是当你不顾一切地坚持跑完，便觉得仿佛所有的东西都从躯体最深处挤榨了出来，一种类似自暴自弃的爽快感油然而生。", "chapter": "第一章 2005年8月5日 夏威夷州考爱岛 谁能够笑话米克·贾格尔呢", "date": "2022-07-14", "color": null}], "ideas": []}, {"id": "25515176", "title": "几何原本", "author": "欧几里得", "cover": "https://cdn.weread.qq.com/weread/cover/34/YueWen_25515176/s_YueWen_25515176.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=5bc32b70718554a85bc9f39", "progress": 2, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "西方科学技术最初是通过基督教会的传教士们传入中国的。1582年，明万历年间，意大利人利玛窦（1552—1610年）与徐光启（1562—1633年）合作翻译了《几何原本》前六卷，这是传教士来中国翻译的第一部科学著作。", "chapter": "导读", "date": "2022-07-12", "color": null}], "ideas": []}, {"id": "39130689", "title": "区块链国富论：论全球信用算法共识的未来财富", "author": "韩锋 贺敏 张秀彩 鲍松", "cover": "https://cdn.weread.qq.com/weread/cover/19/YueWen_39130689/s_YueWen_39130689.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=8eb327c0725516418eb0064", "progress": 100, "finished": 1, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "类型数据也是函数”这个观点背后的本体论就是量子的非定域整体性，这是其可计算的根本", "chapter": "量子力学带来了对世界全新的认知", "date": "2022-07-10", "color": null}], "ideas": []}, {"id": "26629836", "title": "半小时漫画经济学系列（共4册）", "author": "陈磊·半小时漫画团队", "cover": "https://cdn.weread.qq.com/weread/cover/46/YueWen_26629836/s_YueWen_26629836.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=04932040719656cc0493372", "progress": 0, "finished": 1, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "经济周期有大有小，很多小周期构成了一个大周期，明斯基时刻说的是大周期的转折点。", "chapter": "二 金融危机就要来了：明斯基时刻", "date": "2022-06-29", "color": null}], "ideas": []}, {"id": "41286961", "title": "鹤老师说经济：揭开财富自由的底层逻辑", "author": "鹤老师", "cover": "https://cdn.weread.qq.com/weread/cover/73/YueWen_41286961/s_YueWen_41286961.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=ced322f07275fd31ced8b47", "progress": 0, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "永远记住这句话：你用纸币去追实物，你就永远追不上，因为劳动力回报不可能追上资本回报。这是经济学的铁律，不以人的意志为转移。", "chapter": "理财最失败的典型", "date": "2022-06-01", "color": null}], "ideas": []}, {"id": "29629987", "title": "如何看懂艺术", "author": "翁昕", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/987/29629987/s_29629987.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=90a3225071c41e2390a1a70", "progress": 97, "finished": 1, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "标志着人文主义思想在文艺复兴时代的胜利。", "chapter": "人文主义的胜利", "date": "2022-05-29", "color": null}], "ideas": []}, {"id": "845199", "title": "货币的祸害", "author": "米尔顿·弗里德曼", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/199/845199/s_845199.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=8ed325705ce58f8ed9fd533", "progress": 0, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "我试图用许多国家最近的和历史的数据对通货膨胀的成因和对策进行分析和审视，以此来阐述我的核心观点：无论何时何地，通货膨胀永远是一种货币现象。", "chapter": "自序", "date": "2022-05-30", "color": null}], "ideas": []}, {"id": "25504056", "title": "超新星纪元（唯一未删减完整版）", "author": "刘慈欣", "cover": "https://cdn.weread.qq.com/weread/cover/47/YueWen_25504056/s_YueWen_25504056.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=192326b071852938192bda1", "progress": 100, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "玩儿原则比经济原则更具有开拓性和创造力，玩儿需要到很远的地方去，玩儿需要不断看到新奇的世界奥秘，玩儿将由低级向高级发展，最终像大人时代的经济一样推动科学的发展，而这种推动力会比经济大得多，最终使得人类文明产生一次爆炸性的飞跃，达到或超过在这个冷酷的宇宙中生存下去的临界速度。", "chapter": "沉睡时期", "date": "2022-05-25", "color": null}], "ideas": []}, {"id": "23410463", "title": "邓小平传1904-1974（全二册）", "author": "中央文献研究室", "cover": "https://cdn.weread.qq.com/weread/cover/15/YueWen_23410463/s_YueWen_23410463.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=59232b207165371f592b680", "progress": 0, "finished": 1, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "二十九日晚，邓小平到中南海见毛泽东。毛泽东握着他的手说：“努力工作，保护身体。”毛泽东问他这些年是怎么过来的，他回答了两个字：“等待”。", "chapter": "第三十八章 复出", "date": "2022-05-23", "color": null}], "ideas": []}, {"id": "32443224", "title": "我在印度的701天", "author": "郭菲", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/224/32443224/s_32443224.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=da53211071ef0b58da58b79", "progress": 3, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "你有幸站在这个国家一定的高度上驻足观望，方能挣脱旅游的蒙昧，沉浸其间，去领悟去发现，这才是真正的旅行。", "chapter": "序言", "date": "2022-05-19", "color": null}], "ideas": []}, {"id": "696498", "title": "重塑心灵", "author": "李中莹", "cover": "https://cdn.weread.qq.com/weread/cover/48/YueWen_696498/s_YueWen_696498.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=d9c32f705aa0b2d9c73dd23", "progress": 49, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "情绪、压力、困扰都不是源自外界的事物，而是由自己内在的信念、价值观和规条产生出来的。不相信自己有能力或有可能，是自己得不到成功快乐的最大障碍。", "chapter": "NLP的基本精神：12条前提假设", "date": "2022-05-22", "color": null}], "ideas": []}, {"id": "25309122", "title": "重构：数字化转型的逻辑", "author": "安筱鹏", "cover": "https://cdn.weread.qq.com/weread/cover/44/YueWen_25309122/s_YueWen_25309122.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=2d33229071822fc22d339cf", "progress": 0, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "工业4.0的核心就是数据", "chapter": "二、工业4.0：是什么", "date": "2022-04-15", "color": null}], "ideas": []}, {"id": "23549130", "title": "极简周易", "author": "谷园", "cover": "https://cdn.weread.qq.com/weread/cover/5/YueWen_23549130/s_YueWen_23549130.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=f7832050716754caf78d9c7", "progress": 0, "finished": 1, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "凡好读书的人，容易掉进一个陷阱，就是让别人的思想在自己的脑袋里跑马，容易让别人的思想牵着自己走。其实，即便那个作者是孔子、老子或者有怎样大的名头，虚心学习固然是好的，但也万万不可忘掉自我！生也有涯，而知也无涯，道理是说不尽的，知识是学不完的，守住自我，让自我觉醒绽放，今生足矣。", "chapter": "人生观——为人之道", "date": "2022-03-29", "color": null}], "ideas": []}, {"id": "29600050", "title": "一本书看懂地缘世界", "author": "王伟", "cover": "https://cdn.weread.qq.com/weread/cover/16/YueWen_29600050/s_YueWen_29600050.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=c893207071c3a932c8937d0", "progress": 0, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "中国背靠亚欧大陆地势最高的青藏高原、面向太平洋，拥有海陆之利（这恰恰是“一带一路”倡议的基础）；美国拥有太平洋和大西洋的两洋之利；俄罗斯拥有极其广阔的国土和丰富的资源之利；欧洲以领先的教育、科技水平和历史人文积淀，拥有先发之利。", "chapter": "自序 世界与中国", "date": "2022-03-29", "color": null}], "ideas": []}, {"id": "31231802", "title": "李光耀观天下（精装版）", "author": "李光耀", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/802/31231802/s_31231802.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=59d32f9071dc8f3a59d7271", "progress": 0, "finished": 1, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "伊朗的野心至少一部分源自于它的自我评估：一个有别于阿拉伯世界、唯我独尊的文明力量。伊朗人对自己的历史非常自豪。几年前看到一位伊朗部长上英国广播公司节目接受提问时这么回应：“在亚洲，其实也只有两大文明值得一谈：中国与波斯。”这句话恰恰反映了伊朗人的想法。他们眷恋有过辉煌岁月的王朝，所以更有觊觎之心。", "chapter": "七 中东：春残无夏", "date": "2022-03-29", "color": null}], "ideas": []}, {"id": "32037617", "title": "心安即是归处", "author": "季羡林", "cover": "https://cdn.weread.qq.com/weread/cover/35/YueWen_32037617/s_YueWen_32037617.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=c0b32d0071e8daf1c0b18f5", "progress": 99, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "读什么样的书呢？自己专业的书当然要读，这不在话下。自己专业以外的书也应该“随便翻翻”。知识面越广越好，得到的信息越多越好，否则很容易变成鼠目寸光的人。鼠目寸光不但不利于自己专业的探讨，也不利于生存竞争，不利于自己的发展，最终为大时代所抛弃。", "chapter": "第3章 有福读书，可慰平生", "date": "2022-03-24", "color": null}], "ideas": []}, {"id": "24987143", "title": "从丹药到枪炮", "author": "欧阳泰", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/143/24987143/s_24987143.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=0b032e70717d46070b01281", "progress": 98, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "既然早期的火药配方很难反应，也很难点燃，那么当时就不太可能是用作火枪、火焰喷射器和炸药。这一事实——而不是儒家学者不爱运用新技术——解释了，为何中国人没有马上制造火枪和炸药。", "chapter": "第二章 早期的火药战争", "date": "2022-03-16", "color": null}], "ideas": []}, {"id": "907336", "title": "耶路撒冷三千年", "author": "西蒙·蒙蒂菲奥里", "cover": "https://cdn.weread.qq.com/weread/cover/10/YueWen_907336/s_YueWen_907336.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=5a2323e05dd8485a2cfe05f", "progress": 58, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "罗马人的兵营），并将其改建成“俄国大院”。此后俄国", "chapter": "37 福音派传教士 公元1840年—公元1855年", "date": "2022-03-09", "color": null}], "ideas": []}, {"id": "27414891", "title": "DNF遇上哈利波特", "author": "星雨下", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/891/27414891/s_27414891.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=da132c4071a2516bda1dee6", "progress": 0, "finished": 1, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "。　　回想起前世悲惨的结局，卡尔表情有些黯淡，不过很快兴", "chapter": "迷茫的穿越者", "date": "2022-03-08", "color": null}], "ideas": []}, {"id": "41731907", "title": "路径：加速实现财务自由", "author": "彼得·默劳克 托尼·罗宾斯", "cover": "https://cdn.weread.qq.com/weread/cover/16/YueWen_41731907/s_YueWen_41731907.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=80732c40727cc743807103d", "progress": 0, "finished": 1, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "40%的美国人拿不出400美元应对紧急事件，只有通过借钱、变卖家当才能凑齐这笔钱。美国招聘网站凯业必达的一项数据显示，78%的美国劳动者都是“月光族”，基本没有存款。", "chapter": "第十三章 金钱与幸福", "date": "2022-03-03", "color": null}], "ideas": []}, {"id": "27423331", "title": "刘慈欣短篇科幻小说合集（28册）", "author": "刘慈欣", "cover": "https://cdn.weread.qq.com/weread/cover/5/YueWen_27423331/s_YueWen_27423331.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=2993255071a27263299b172", "progress": 95, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "卖油人把油通过一个铜钱的方孔倒进油壶中，所需的技巧与将军把箭射中靶心同样高超，差异只在于他们的身份。”", "chapter": "引子", "date": "2022-02-20", "color": null}], "ideas": []}, {"id": "41626005", "title": "人口大逆转", "author": "查尔斯·古德哈特 马诺吉·普拉丹", "cover": "https://cdn.weread.qq.com/weread/cover/12/YueWen_41626005/s_YueWen_41626005.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=b1c32b40727b2995b1c313e", "progress": 0, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "尽管市场正确地强调了周期性力量，但它们忽视了长期结构性因素（同时也是生产函数的一部分）即将发生巨大变化。", "chapter": "导读 作者和译者的对话", "date": "2022-02-15", "color": null}], "ideas": []}, {"id": "803742", "title": "与神对话.3", "author": "尼尔·唐纳德·沃尔什", "cover": "https://cdn.weread.qq.com/weread/cover/30/YueWen_803742/s_YueWen_803742.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=083321305c439e083ff065c", "progress": 0, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "这个星球数百年来的行为模式是这样的：别“放纵”你们的情感。假如你们感到悲哀，要征服它；假如你们感到愤怒，要平息它；假如你们感到羡慕，要为之而羞愧；假如你们感到害怕，要超越它；假如你们感到爱，要控制它、限制它、忍住它、逃离它——反正你们要想尽办法，千万别在此时此地完整地表达它。", "chapter": "Chapter 02", "date": "2022-02-10", "color": null}], "ideas": []}, {"id": "785675", "title": "中国人的精神", "author": "辜鸿铭", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/675/785675/s_785675.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=57c325d05bfd0b57c90f5c5", "progress": 99, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "平静而受到庇佑的心态能够让我们认清事物的生命：那就是充满想象力的理智，那就是中国人的精神。", "chapter": "中国人的精神 ", "date": "2022-01-26", "color": null}], "ideas": []}, {"id": "26914570", "title": "影响世界的中国植物", "author": "《影响世界的中国植物》主创团队", "cover": "https://cdn.weread.qq.com/weread/cover/66/YueWen_26914570/s_YueWen_26914570.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=03332a00719aaf0a0336715", "progress": 4, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "3亿年前，蜻蜓成为最早征服蓝天的生物。", "chapter": "如果把地球的46亿年浓缩为1天", "date": "2022-01-13", "color": null}], "ideas": []}, {"id": "860294", "title": "脑机穿越：脑机接口改变人类未来", "author": "米格尔·尼科莱利斯", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/294/860294/s_860294.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=cb9324505d2086cb932ebb5", "progress": 5, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "尼科莱利斯指出，“边界”有三重不同的含义：其一，大脑的运作并非靠孤立的个体神经元，而是靠神经元集群（这一点超越了单一神经元定位-功能主义的局部科学观）；其二，将神经元集群的活动与身体的相互塑形联系起来，突破大脑-身体“两分法”的边界；其三，让大脑超越身体，延展到另一个身体-大脑，延展到任何“器物”“机器”，进而延展到外部世界。用著名互联网思想家凯文·凯利的话来说，我们将迎来“人的机器化和机器的生命化同步展开”的时代。未来的科技，将作为与有机体共同发育、成长的“第7元素”，成为这个世界的“基元”。", "chapter": "推荐序", "date": "2022-01-13", "color": null}], "ideas": []}, {"id": "853791", "title": "生命的未来", "author": "爱德华·威尔逊", "cover": "https://cdn.weread.qq.com/weread/cover/41/YueWen_853791/s_YueWen_853791.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=e8632c005d071fe86a60b13", "progress": 60, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "一个生态系统中存在的物种数愈多，该生态系统愈稳定，生产量也愈丰富。", "chapter": "第五章 生物圈值多少", "date": "2021-12-30", "color": null}], "ideas": []}, {"id": "23457794", "title": "后谷歌时代：大数据的没落与区块链经济的崛起", "author": "乔治·吉尔德", "cover": "https://cdn.weread.qq.com/weread/cover/13/YueWen_23457794/s_YueWen_23457794.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=4d232fa07165f0024d290fc", "progress": 89, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "这就像是今天的大学，正以高昂的价格出售一张废纸，并宣称这是学生们拯救灵魂的唯一途径。大学称其为文凭，并正以此牟利。说我们是异教徒也没有关系，但1517基金会将致力于消除这种虚妄的文凭观。", "chapter": "第十章 1517", "date": "2022-01-11", "color": null}], "ideas": []}, {"id": "26297678", "title": "富爸爸：第二次致富机会", "author": "罗伯特·清崎", "cover": "https://cdn.weread.qq.com/weread/cover/19/YueWen_26297678/s_YueWen_26297678.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=d0c329d07191454ed0c9266", "progress": 0, "finished": 1, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "给“民粹”这个名词下定义是件不容易的事情，因为它无法用贫穷或富有，或者是自由派还是保守派来区分。“民粹”基本上来说就是“一般大众目前的智慧水平”。", "chapter": "第十七章 “投资的风险很高”的另外一面", "date": "2021-12-25", "color": null}], "ideas": []}, {"id": "31934007", "title": "人生由我", "author": "梅耶·马斯克", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/7/31934007/s_31934007.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=f3e32eb071e74637f3e8311", "progress": 8, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "2016年，梅耶、埃隆和托斯卡在特斯拉新车型Model 3发布会上", "chapter": "图片", "date": "2021-12-11", "color": null}], "ideas": []}, {"id": "833594", "title": "专业主义", "author": "大前研一", "cover": "https://cdn.weread.qq.com/weread/cover/28/YueWen_833594/s_YueWen_833594.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=92e328b05cb83a92eef77c6", "progress": 32, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "人的大脑有一种习性，那就是“只能看到想看的东西”，因此我们需要特别注意从成功的体验中得到的知识和理论。", "chapter": "怀疑一切", "date": "2021-12-01", "color": null}], "ideas": []}, {"id": "23434518", "title": "超人诞生：人类增强的新技术", "author": "稻见昌彦", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/518/23434518/s_23434518.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=776329d0716595167768300", "progress": 99, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "远程临场", "chapter": "3 人类能否现身于别处？", "date": "2021-11-27", "color": null}], "ideas": []}, {"id": "31296267", "title": "生命密码（套装共2册）", "author": "尹烨", "cover": "https://cdn.weread.qq.com/weread/cover/18/YueWen_31296267/s_YueWen_31296267.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=f69329f071dd8b0bf69fef7", "progress": 100, "finished": 1, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "第三代试管婴儿技术实现了对胚胎基因的筛选。然而，一种令人不寒而栗的可能性是，基因筛选在不久的将来会愈演愈烈，最终从长相、智力等方面出发，对人类胚胎进行选择，衍生出名副其实的“人工设计婴儿”。", "chapter": "“送子观音”还是“技术恶魔”？", "date": "2021-11-26", "color": null}], "ideas": []}, {"id": "37178837", "title": "价值共生：数字化时代的组织管理", "author": "陈春花", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/837/37178837/s_37178837.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=dc5324b072374dd5dc5ac13", "progress": 100, "finished": 1, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "机", "chapter": "第二章 重新定义组织管理", "date": "2021-11-25", "color": null}], "ideas": []}, {"id": "41230446", "title": "丰盛", "author": "杨定一", "cover": "https://cdn.weread.qq.com/weread/cover/8/YueWen_41230446/s_YueWen_41230446.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=5f8321c07275206e5f8e8df", "progress": 79, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "这种心态是很重要的。你如果能守住这一生最大的目标——醒觉，其他的一切，自然都可以成为你的工具。这种心态的转变，本身带来一种完整的正向的路径，让我们随时期待进入它。", "chapter": "19 不再恐惧", "date": "2021-11-19", "color": null}], "ideas": []}, {"id": "3000066312", "title": "活得安详", "author": "[法]一行禅师", "cover": "https://cdn.weread.qq.com/outpic/312/3000066312.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=26b32580811e1bce7g0124fc", "progress": 91, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "从这个意义上讲，空意味着这张纸包含着一切事物，包含着整个宇宙。", "chapter": "第四章 修行的心", "date": "2021-11-18", "color": null}], "ideas": []}, {"id": "906828", "title": "好好学习：个人知识管理精进指南", "author": "成甲", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/828/906828/s_906828.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=c12326405dd64cc12cb68b8", "progress": 96, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "人与人之间的差别，大于人与猪的差别。", "chapter": "序一 准备好，在临界点爆发", "date": "2021-11-16", "color": null}], "ideas": []}, {"id": "32346332", "title": "让你的时间更有价值：空闲时间就是你的未来财富（独家定制版）", "author": "张萌", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/332/32346332/s_32346332.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=26832b0071ed90dc2687755", "progress": 100, "finished": 1, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "人永远没办法挣到自己认知范围之外的钱，除非你有特别好的运气。可是凭运气挣到的钱，迟早也会凭自己的实力全部赔进去。", "chapter": "第一节 一切改变都从“换脑”开始", "date": "2021-11-12", "color": null}], "ideas": []}, {"id": "38486009", "title": "社群学习", "author": "吴河图 杨帆", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/9/38486009/s_38486009.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=6be32940724b3ff96bed524", "progress": 49, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "合，在形态上有行列交叉之式，即为矩阵式组织”。矩阵式组织的特点在于围绕一个目标或者任务，打破原有的组织结构，使组织由金字", "chapter": "第一节 什么是社群学习", "date": "2021-11-06", "color": null}], "ideas": []}, {"id": "858733", "title": "仓央嘉措：我和我的人生擦肩而过", "author": "李明境", "cover": "https://cdn.weread.qq.com/weread/cover/12/YueWen_858733/s_YueWen_858733.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=2a932b205d1a6d2a9e17eb0", "progress": 14, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "乘风破浪，让风沙弥漫的西藏天空，从此渐趋无尘之境。", "chapter": "五世达赖喇嘛罗桑嘉措", "date": "2021-06-12", "color": null}], "ideas": []}, {"id": "25623457", "title": "人口浪潮：人口变迁如何塑造现代世界", "author": "保罗·莫兰", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/457/25623457/s_25623457.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=06632d807186fba10664631", "progress": 80, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "这个时代标志着人口历史上一次有意义的突破，它是由工业革命带来的人口变化，不论是从地理层面，还是历史层面，都产生了全球性的永久变革，具有里程碑式意义。", "chapter": "第二章 人口数量的重要性", "date": "2021-06-01", "color": null}], "ideas": []}, {"id": "23508853", "title": "马克思社会技术思想论纲", "author": "田鹏颖", "cover": "https://cdn.weread.qq.com/weread/cover/22/YueWen_23508853/s_YueWen_23508853.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=596328307166b7755963229", "progress": 53, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "科技的发展，造成生产力和生产关系、经济基础和上层建筑之间的矛盾，要解决这些矛盾，就要进行社会革命，采用有效的社会技术。", "chapter": "第一章 马克思社会技术思想之维度", "date": "2021-05-23", "color": null}], "ideas": []}, {"id": "917831", "title": "诗意的原子", "author": "科特·施塔格", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/831/917831/s_917831.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=796322605e0147796bd60ca", "progress": 0, "finished": 1, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "很多人不知道，我们犁的土都是星尘，随风四处飘散；而在一杯雨水中，我们饮下了宇宙。", "chapter": "前言 原子的你", "date": "2021-05-21", "color": null}], "ideas": []}, {"id": "621669", "title": "只有偏执狂才能生存", "author": "安迪·格鲁夫", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/669/621669/s_621669.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=faf32320597c65faf1d56e6", "progress": 30, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "在雾中驾驶时，跟着前车的尾灯灯光行路会容易得多。“尾灯”战略的危险在于，一旦赶上并超过了前面的车，就没有尾灯可以导航，从而失去找到新方向的信心与能力。当", "chapter": "战略行动", "date": "2021-05-17", "color": null}], "ideas": []}, {"id": "859922", "title": "湘行散记", "author": "沈从文", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/922/859922/s_859922.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=ac632ee05d1f12ac60e14f8", "progress": 96, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "若崖石过高，还可以用竹篙将花打下，尽它堕入清溪洄流里，再从溪里把花捞起。除了兰芷以外，还有不少香草香花，在溪边崖下繁殖。那种黛色无际的崖石，那种一丛丛幽香眩目的奇葩，那种小小洄旋的溪流，合成一个如何不可言说迷人心目的圣境！若没有这种地方，屈原便再疯一点，据我想来，他文章未必就能写得那么美丽。", "chapter": "桃源与沅州", "date": "2021-04-30", "color": null}], "ideas": []}, {"id": "840995", "title": "万历十五年（精装版）", "author": "黄仁宇", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/995/840995/s_840995.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=091322d05cd5230913042e3", "progress": 20, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "古为今用", "chapter": "第二章 首辅申时行", "date": "2021-04-24", "color": null}], "ideas": []}, {"id": "35040309", "title": "偏见的本质", "author": "戈登·奥尔波特", "cover": "https://cdn.weread.qq.com/weread/cover/70/YueWen_35040309/s_YueWen_35040309.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=23a32d307216ac3523a47e6", "progress": 5, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "大部分对抗是幻想中的恐惧的产物。然而，虚构的恐惧能够造成真实的痛苦。", "chapter": "前 言", "date": "2021-04-15", "color": null}], "ideas": []}, {"id": "856521", "title": "金钱永不眠：资本世界的暗流涌动和金融逻辑", "author": "香帅无花", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/521/856521/s_856521.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=5a8324d05d11c95a8c1226b", "progress": 100, "finished": 1, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "资产管理市场在未来进一步扩大仍是极大概率事件，老百姓对股市和其他金融产品的着魔也只会更盛，不会衰退。", "chapter": "为什么中国人那么关心股市？", "date": "2021-04-10", "color": null}], "ideas": []}, {"id": "630498", "title": "给你1天72小时", "author": "李晨", "cover": "https://cdn.weread.qq.com/weread/cover/24/YueWen_630498/s_YueWen_630498.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=66c32880599ee266c373866", "progress": 0, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "“适可而止”, “见好就收”，是一种大智慧。在所花的时间和精力达到“拐点”的时候，边际递减效应开始显现的时候，不妨结束手头的任务，开始新的挑战吧！", "chapter": "第二部分 学会选择，懂得放弃，增加投资回报率", "date": "2021-04-08", "color": null}], "ideas": []}, {"id": "635921", "title": "基业长青（珍藏版）", "author": "[美]吉姆·柯林斯", "cover": "https://cdn.weread.qq.com/weread/cover/60/YueWen_635921/s_YueWen_635921.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=4993214059b411499dc1b44", "progress": 0, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "利润是生存的必要条件，而且是达成更重要目的的手段，但是对很多高瞻远瞩公司而言，利润不是目的，利润就像人体需要的氧气、食物、水和血液一样，这些东西不是生命的目的。但是，没有它们，就没有生命。", "chapter": "核心理念：探索利润神话", "date": "2021-04-08", "color": null}], "ideas": []}, {"id": "24240708", "title": "读懂孩子的心", "author": "樊登", "cover": "https://cdn.weread.qq.com/weread/cover/95/YueWen_24240708/s_YueWen_24240708.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=03d324a07171e24403d65b7", "progress": 76, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "最后，结合我的经验，为大家分享书中的小贴士：    ·害怕，我也能做。我害怕这件事，但我照样能做，这才叫“勇敢”。    ·了解孩子的想法，知道他们为什么感到焦虑。    ·帮助孩子划定他们的舒适区，并且一步一步地扩大这个舒适区。", "chapter": "第3章 与孩子一起成长", "date": "2021-04-02", "color": null}], "ideas": []}, {"id": "838820", "title": "我们为什么要去火星？", "author": "斯蒂芬·彼得拉内克", "cover": "https://cdn.weread.qq.com/weread/cover/45/YueWen_838820/s_YueWen_838820.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=793329605ccca47937176fc", "progress": 100, "finished": 1, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "我们很快就会达到一个由人类自己而非大自然来主宰人类进化过程的时代。", "chapter": "第七章 按照地球的样子改造火星", "date": "2021-03-16", "color": null}], "ideas": []}, {"id": "837944", "title": "区块链：从数字货币到信用社会", "author": "长铗 韩锋等", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/944/837944/s_837944.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=61932d305cc93861945b6dc", "progress": 100, "finished": 1, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "区块链为我们启动了信用机器，让政府、公司、机构与个体作为平等的节点呈现在分布式网络上，各自管理自己的身份与信用，共享一部不可修改的交易总账。", "chapter": "后记", "date": "2021-03-17", "color": null}], "ideas": []}, {"id": "852290", "title": "未来简史：从智人到智神", "author": "尤瓦尔·赫拉利", "cover": "https://cdn.weread.qq.com/weread/cover/44/YueWen_852290/s_YueWen_852290.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=cf3326205d0142cf3606771", "progress": 40, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "世界上已经不再有自然造成的饥荒，只有政治造成的饥荒。如果现在还有人在叙利亚、苏丹和索马里饿死，罪魁祸首其实是那些政客。", "chapter": "第1章 人类的新议题", "date": "2021-02-22", "color": null}], "ideas": []}, {"id": "841446", "title": "疯狂人类进化史", "author": "史钧", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/446/841446/s_841446.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=d5232d105cd6e6d52b141ef", "progress": 19, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "最近提出的“寄生虫假说”则认为，毛发是寄生虫的理想天堂，那里营养充足，温暖而安全，其中必定会滋生大量跳蚤、虱子之类的“吸血鬼”，很多有毛动物都死于寄生虫引发的疾病，而人类裸露的皮肤有助于保持身体清洁，让寄生虫无处躲藏。所以，脱去毛发是抵制寄生虫的有效手段。", "chapter": "第2章 人为什么不长毛", "date": "2021-01-27", "color": null}], "ideas": []}, {"id": "31403562", "title": "物质是什么", "author": "吉姆·巴戈特", "cover": "https://cdn.weread.qq.com/weread/cover/56/YueWen_31403562/s_YueWen_31403562.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=5303266071df2e2a5304da5", "progress": 79, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "只是无形的量子场相互作用的结果。", "chapter": "第16章 没有物质的质量", "date": "2021-01-20", "color": null}], "ideas": []}, {"id": "832210", "title": "第四次工业革命", "author": "[德]克劳斯·施瓦布 世界经济论坛北京代表处", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/210/832210/s_832210.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=f4e323a05cb2d2f4e3b586c", "progress": 48, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "从本质而言，区块链是一种可共享、可编程、安全、可信的分类账，任何单一用户都无法控制它，但是所有人都能监督它。", "chapter": "大趋势，大机遇，大挑战", "date": "2020-12-29", "color": null}], "ideas": []}, {"id": "25890900", "title": "给爸爸妈妈的儿童性教育指导书", "author": "明白小学堂著绘", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/900/25890900/s_25890900.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=8dd323d0718b10548dd552e", "progress": 82, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "在遇到让自己不舒服的情况时，敢于表达出来，甚至在被触摸隐私部位时敢于说“不”，才是正确的表达。", "chapter": "爸爸妈妈应该知道的事", "date": "2021-01-04", "color": null}], "ideas": []}, {"id": "907578", "title": "债务和魔鬼：货币、信贷和全球金融体系重建", "author": "阿代尔·特纳", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/578/907578/s_907578.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=435326905dd93a435338a72", "progress": 7, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "信贷是银行资产，货币是银行负债，两者是一块硬币的两面。信贷发放的过程就是货币创造的过程，而信贷偿还过程就是货币湮灭（货币“回笼”）的过程。", "chapter": "中文版序言", "date": "2020-11-29", "color": null}], "ideas": []}, {"id": "29373667", "title": "技术的本质（经典版）", "author": "布莱恩·阿瑟", "cover": "https://cdn.weread.qq.com/weread/cover/31/YueWen_29373667/s_YueWen_29373667.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=4d83260071c034e34d8523f", "progress": 52, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "基因是生物进化的基本单元，与此类似，我们可以把“现象”称为技术的“基因”。", "chapter": "技术的本质", "date": "2020-12-28", "color": null}], "ideas": []}, {"id": "23514583", "title": "我的世界观", "author": "阿尔伯特·爱因斯坦", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/583/23514583/s_23514583.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=83c329e07166cdd783c051d", "progress": 13, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "简朴而平易的生活，对每个人的身心都是有益的。", "chapter": "我的世界观", "date": "2020-10-04", "color": null}], "ideas": []}, {"id": "23691301", "title": "复杂经济学：以复杂视角解关税影响", "author": "布莱恩·阿瑟", "cover": "https://cdn.weread.qq.com/weread/cover/51/YueWen_23691301/s_YueWen_23691301.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=19932f00716980251993466", "progress": 24, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "经济可看作是进化的复杂系统”", "chapter": "结缘圣塔菲研究所", "date": "2020-09-19", "color": null}], "ideas": []}, {"id": "MP_WXS_3274059253", "title": "迪言爽听", "author": "公众号", "cover": "http://rescdn.qqmail.com/weread/cover/0/0/t8_0.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=8db427d224d505f5758535f33323734303539323533f4b", "progress": 0, "finished": 1, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "我认为美国掌控了全世界70%的高端人才。", "chapter": "", "date": "2020-09-03", "color": null}], "ideas": []}, {"id": "915509", "title": "哈佛教授的心理学原理", "author": "威廉·詹姆斯", "cover": "https://cdn.weread.qq.com/weread/cover/81/YueWen_915509/s_YueWen_915509.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=df832b705df835df8ad0d27", "progress": 11, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "当好的情绪受到激发时，务必要施以真切的行动。一名爱听音乐的发烧友需要在情绪迸发的时刻表现出自己的满足和喜爱，如此，参与演出的人员才会受到情感上的慰藉，并因此感到快乐。", "chapter": "6．习惯是社会德育的天使", "date": "2020-09-03", "color": null}], "ideas": []}, {"id": "857319", "title": "币缘论：货币政治的演化", "author": "王湘穗", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/319/857319/s_857319.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=f25329605d14e7f2598093f", "progress": 100, "finished": 1, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "尼克松政府放弃金本位的做法，并不是被动的决定，而是向外转嫁国际收支赤字危机的主动选择", "chapter": "第七章 多元共生的全球体系", "date": "2020-08-26", "color": null}], "ideas": []}, {"id": "609288", "title": "菊与刀", "author": "本尼迪克特", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/288/609288/s_609288.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=c4132040594c08c41c28129", "progress": 68, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "所谓杀人犯，就是残害他人肉体的人；而所谓嘲笑者，是残害他人心灵的人。", "chapter": "第8章 名声的价值", "date": "2020-07-23", "color": null}], "ideas": []}, {"id": "30766471", "title": "沉默的大多数", "author": "王小波", "cover": "https://cdn.weread.qq.com/weread/cover/20/yuewen_30766471/s_yuewen_307664711727351996.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=84632ce071d57587846de1c", "progress": 14, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "人既然活着，就有权保证他思想的连续性，到死方休。更何况那些高尚和低下完全是以他们自己的立场来度量的，假如我全盘接受，无异于请那些善良的思想母鸡到我脑子里下蛋，而我总不肯相信，自己的脖子上方，原来是长了一座鸡窝。", "chapter": "思维的乐趣", "date": "2020-08-17", "color": null}], "ideas": []}, {"id": "925530", "title": "尼采的人生哲学", "author": "张笑恒", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/530/925530/s_925530.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=a5f322305e1f5aa5fd5ec92", "progress": 8, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "【如果痛苦的不应是你，那么快乐为什么属于你】    痛苦来时，不要问为什么会是我，快乐来的时候，你这样问过自己吗？", "chapter": "以审美的眼光看人生", "date": "2020-05-25", "color": null}], "ideas": []}, {"id": "913883", "title": "人，诗意地栖居：超译海德格尔", "author": "海德格尔", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/883/913883/s_913883.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=85032d605df1db850ee14a8", "progress": 88, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "海德格尔认为，盲目崇拜科学和技术用文化来说明一切直至产生了文化政治、美学垄断了对艺术的解释、诸神退隐以及主观主义和客观主义、个人主义和集体主义不加遏制地趋于极端，等等，就是现时代世界变成图画之后必然要产生的种种现", "chapter": "七 世界图画的时代", "date": "2020-05-12", "color": null}], "ideas": []}, {"id": "849769", "title": "就业、利息和货币通论", "author": "约翰·凯恩斯", "cover": "https://cdn.weread.qq.com/weread/cover/29/YueWen_849769/s_YueWen_849769.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=d6632d705cf769d6646fc55", "progress": 4, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "。因为假如正统的经济学出现了错误，那么这种错误不会出现在为了保持逻辑的一致性而构筑起来的上层结构中，而会出现在这个理论的前提缺少明确性和普遍性时。因此除了通过采用高度抽象论述和很多的批判性争论之外", "chapter": "原序", "date": "2020-05-10", "color": null}], "ideas": []}, {"id": "MP_WXS_3214793539", "title": "嘉宾商学", "author": "公众号", "cover": "http://rescdn.qqmail.com/weread/cover/0/0/t8_0.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=fc542ec224d505f5758535f3332313437393335333922b", "progress": 0, "finished": 1, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "什么是ROI？投资回报率。", "chapter": "", "date": "2020-05-04", "color": null}], "ideas": []}, {"id": "25398015", "title": "黑旗：ISIS的崛起", "author": "乔比·沃里克", "cover": "https://cdn.weread.qq.com/weread/cover/5/YueWen_25398015/s_YueWen_25398015.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=657327f071838aff65740ec", "progress": 0, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "巴沙尔·阿萨德（Bashar al-Assad）出人意料地成为了叙利亚总统。", "chapter": "第二章 他是个真正的领袖", "date": "2020-04-09", "color": null}], "ideas": []}, {"id": "25566726", "title": "文明的冲突", "author": "塞缪尔·亨廷顿", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/726/25566726/s_25566726.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=248329f071861e0624888f5", "progress": 32, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "世界观和因果关系理论对国际政治是不可缺少的指导", "chapter": "第一部分 一个多文明的世界", "date": "2019-11-18", "color": null}], "ideas": []}, {"id": "917658", "title": "股市趋势技术分析（原书第10版）", "author": "罗伯特D.爱德华兹 约翰·迈吉 W.H.C.巴塞蒂", "cover": "https://cdn.weread.qq.com/weread/cover/78/YueWen_917658/s_YueWen_917658.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=09f325105e009a09f7bb132", "progress": 16, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "但不论是在股市还是其他地方，耐心都是一种美德。实际上，要想避免犯错，耐心是必不可少的条件。", "chapter": "4.2 道氏理论并不是绝对可靠的", "date": "2019-11-06", "color": null}], "ideas": []}, {"id": "25131298", "title": "棉花帝国：一部资本主义全球史", "author": "斯文·贝克特", "cover": "https://cdn.weread.qq.com/weread/cover/89/YueWen_25131298/s_YueWen_25131298.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=e7132c00717f7922e71ffd1", "progress": 97, "finished": 0, "hlCount": 1, "ideaCount": 0, "highlights": [{"text": "1492年，克里斯托弗·哥伦布在美洲登陆，这是重塑全球联系的第一个重大事件。这一旅程引发了世界上规模最大的土地掠夺。", "chapter": "第2章 缔造战争资本主义", "date": "2019-10-25", "color": null}], "ideas": []}, {"id": "854001", "title": "菜根谭", "author": "[明]洪应明", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/1/854001/t6_854001.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=b1a32fe05d07f1b1af232bf", "progress": 47, "finished": 0, "hlCount": 0, "ideaCount": 1, "highlights": [], "ideas": [{"content": "君子为腹不为目", "abstract": "物欲", "chapter": "英敏以学摄，激昂以德融", "date": "2026-02-21", "star": null}]}, {"id": "651142", "title": "范仲淹（名人传记丛书）", "author": "皮波人物国际名人研究中心编著", "cover": "https://cdn.weread.qq.com/weread/cover/65/YueWen_651142/t6_YueWen_651142.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=387324b059ef8638781d362", "progress": 99, "finished": 0, "hlCount": 0, "ideaCount": 1, "highlights": [], "ideas": [{"content": "范仲淹：智者无忧，忍者无敌，仁者无怨\n\n忍穷\n求古仁人之心\n不以物喜，不以己悲。\n宋初原有东京开封、西京洛阳；宋仁宗时，又建大名府为北京，现在加上南京共有四京。", "abstract": "", "chapter": "", "date": "2023-04-25", "star": 100}]}, {"id": "24979528", "title": "华杉讲透《大学中庸》", "author": "华杉", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/528/24979528/t6_24979528.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=b8f32aa0717d2848b8f2034", "progress": 6, "finished": 0, "hlCount": 0, "ideaCount": 1, "highlights": [], "ideas": [{"content": "存天理灭人欲，中庸之道，止于至善。", "abstract": "朱熹老师平时也喜欢喝点小酒，那我们再修正一下，美食美酒都是天理，但暴饮暴食，吃胖了，吃出糖尿病，吃出三高，喝醉了，喝吐了，喝伤了，这就是人欲。这样，你就每顿饭都可以修炼一下“存天理、灭人欲”，修炼一下“止于至善”了", "chapter": "", "date": "2022-11-27", "star": null}]}, {"id": "925440", "title": "修身养性大智慧（孔子学堂）", "author": "欧阳彦之", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/440/925440/t6_925440.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=689323a05e1f0068910e687", "progress": 31, "finished": 0, "hlCount": 0, "ideaCount": 1, "highlights": [], "ideas": [{"content": "好书", "abstract": "", "chapter": "", "date": "2021-06-08", "star": 100}]}, {"id": "22297551", "title": "时间的玫瑰（全新升级版）", "author": "但斌", "cover": "https://cdn.weread.qq.com/weread/cover/89/YueWen_22297551/t6_YueWen_22297551.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=71032f5071543bcf710696c", "progress": 99, "finished": 0, "hlCount": 0, "ideaCount": 1, "highlights": [], "ideas": [{"content": "是最大的单一消费市场。", "abstract": "按一般的判断，实际上有一个共识：在未来20~30年的时间里，中国如果没有大的动荡，经济规模会超过美国，再次成为世界上最大的经济体。", "chapter": "", "date": "2021-01-06", "star": null}]}, {"id": "32441749", "title": "关于痛苦的七堂哲学课", "author": "斯科特·塞缪尔森", "cover": "https://wfqqreader-1252317822.image.myqcloud.com/cover/749/32441749/t6_32441749.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=c713260071ef0595c71043a", "progress": 98, "finished": 0, "hlCount": 0, "ideaCount": 1, "highlights": [], "ideas": [{"content": "苦 集  灭  道", "abstract": "第一，人生充满痛苦。第二，痛苦是欲望和无知造成的。第三，痛苦可以解除。第四，解除方法是遵循“中道”，即后来佛教的基础。", "chapter": "", "date": "2020-11-23", "star": null}]}, {"id": "3000007325", "title": "解构现代化+去依附+八次危机+百年激进+居危思危+新兴七国比较研究温铁军作品全9册", "author": "温铁军", "cover": "https://cdn.weread.qq.com/outpic/325/3000007325.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=86632490811e1a5dcg015c1a", "progress": 0, "finished": 1, "hlCount": 0, "ideaCount": 1, "highlights": [], "ideas": [{"content": "等待上架", "abstract": "", "chapter": "", "date": "2019-09-20", "star": 100}]}, {"id": "24987062", "title": "债务危机", "author": "瑞·达利欧", "cover": "https://cdn.weread.qq.com/weread/cover/78/YueWen_24987062/t6_YueWen_24987062.jpg", "link": "https://weread.qq.com/book-detail?type=1&v=9e832080717d45b69e8ec16", "progress": 0, "finished": 0, "hlCount": 0, "ideaCount": 1, "highlights": [], "ideas": [{"content": "以时间为序，经期", "abstract": "从个人角度看，我经历了1966—1971年国际货币体系（“布雷顿森林体系”）的削弱和最终崩溃，美国20世纪70年代的通胀泡沫和1978—1982年的泡沫破裂，拉丁美洲国家20世纪80年代的通胀性萧条，日本20世纪80年代后期的泡沫经济和1988—1991年的泡沫破裂，导致2000年科技泡沫破裂的全球债务泡沫，以及2008年的债务大危机。而通过研究历史，我体验了5世纪西罗马帝国的崩溃，1789年美国的债务重组，20世纪20年代德国魏玛共和国的", "chapter": "", "date": "2019-03-28", "star": null}]}, {"id": "MP_WXS_3264620466", "title": "未知书名", "author": "公众号", "cover": "http://wx.qlogo.cn/mmhead/Q3auHgzwzM7FWMglDYy2AfyXHaTiaZH0orNWeH0bx0vsqzu8ZcgMwTA/0", "link": "https://weread.qq.com/book-detail?type=1&v=b694265224d505f5758535f33323634363230343636fc6", "progress": 0, "finished": 1, "hlCount": 0, "ideaCount": 1, "highlights": [], "ideas": [{"content": "这个世界叫比特世界", "abstract": "刘慈欣认为，人类正处于大迁徙的时代，正在从现实世界向虚拟世界迁徙。而区块链的出现，是虚拟世界变成现实世界平行的重要一步，补充了现实世界中有，虚拟世界没有的东西。可能在未来的某一天，现实和虚拟世界对调，虚拟成为现实，而现实成为虚拟。", "chapter": "", "date": "2018-10-01", "star": null}]}];
